JL.controllers.prototype.set_xr_session = function( session ){
	this.xr_session = session;
	if( !this.xr_control_sticks ) this.xr_control_sticks = {};
};

JL.controllers.prototype.init_gamepad = function( gamepad ){
	gamepad.type = this.ids[ gamepad._id || gamepad.id ];

	for( var idx = 0; idx < gamepad.buttons.length; idx++ ){
		var button = gamepad.buttons[ idx ];
		button.name = this.keycode_to_name( gamepad.type, 'button', idx );
		button.key  = this.get_key(         gamepad.type, button.name   );
	}

	gamepad.sticks = [];
	for( var idx = 0; idx < gamepad.axes.length; idx++ ){
		var stick = {};
		stick.name = this.keycode_to_name( gamepad.type, 'stick', idx );
		stick.key  = this.get_key(         gamepad.type, stick.name   );

		gamepad.sticks.push( stick );
	}
};

JL.controllers.prototype.update_gamepads_list = function(){
	this.gamepads = ( ( navigator.getGamepads ? navigator.getGamepads() : navigator.webkitGetGamepads ) || [] ).filter( x => x );

	for( var gamepad of this.gamepads ) this.init_gamepad( gamepad );
};

JL.controllers.prototype.connect = function( e ){
	if( this.callbacks.on_connect ) this.callbacks.on_connect( e );
	this.update_gamepads_list();
};

JL.controllers.prototype.disconnect = function( e ){
	if( this.callbacks.on_disconnect ) this.callbacks.on_disconnect( e );
	this.update_gamepads_list();
};

JL.controllers.prototype.clear_all = function(){
	for( var gamepad of this.gamepads ){
		for( var button of gamepad.buttons ){
			button.holding = false;
		}
	}
};

JL.controllers.prototype.disable = function( disabled_exceptions ){
	this.disabled = true;
	this.disabled_exceptions = disabled_exceptions || false;

	this.clear_all();

	if( this.callbacks.on_disable ) this.callbacks.on_disable();
};

JL.controllers.prototype.enable = function(){
	this.disabled = false;
	this.disabled_exceptions = false;

	if( this.callbacks.on_enable ) this.callbacks.on_enable();
};

JL.controllers.prototype.get = function(name){
	var keys = this.keys.filter(function(key){ return key.name == name; });
	if(keys.length > 0) return keys.pop();
	return false;
};

JL.controllers.prototype.get_from_keycode = function(code){
	var keys = this.keys.filter(function(key){ return key.code == code; });
	if(keys.length > 0) return keys.pop();
	return false;
};

JL.controllers.prototype.get_key = function( controller_type, name ){
	for( var key of this.keys ){
		try{
			if( key.controllers[ controller_type ] == name ) return key;
		} catch(e){}
	}
	return false;
};

JL.controllers.prototype.keycode_to_name = function( controller_type, input_type, code ){
	var keys  = this.keycodes[ controller_type ][ input_type ];
	var names = Object.keys( keys );
	return names.find(function( n ){ return ( keys[ n ] == code ); });
};

JL.controllers.prototype.set_bindings = function( bindings ){
	try{ this.clear_all(); } catch(e){}

	this.keys = bindings;

	for( var key of this.keys ) key.code = this.keycodes[ key.name ];

	this.update_gamepads_list();
};

JL.controllers.prototype.on_button_press = function( button, button_key ){
	var button_key = button_key || button.key;

	if( this.disabled_exceptions ){
		if( !this.disabled_exceptions.includes( button_key.name ) ) return;
	}

	if( button.holding ) try{ button_key.hold( button.value ); } catch(e){}
	else{
		try{ button_key.down(); } catch(e){}

		if( this.callbacks.on_key_down ) this.callbacks.on_key_down();
	}

	button.holding = true;
};

JL.controllers.prototype.loop = function(){
	if( !this.disabled || this.disabled_exceptions ){
		for( var gamepad of this.gamepads ){
			for( var button of gamepad.buttons ){
				if( button.pressed || button.touched ){
					if( button.key ) this.on_button_press( button );
				}
				else{
					if( button.holding ){
						if( this.disabled_exceptions ){
							if( !this.disabled_exceptions.includes( button.key.name ) ) break;
						}
						try{ button.key.up(); } catch(e){}

						if( this.callbacks.on_key_up ) this.callbacks.on_key_up();
					}

					button.holding = false;
				}
			}

			for( var idx = 0; idx < gamepad.axes.length; idx++ ){
				var axis = gamepad.axes[ idx ];
				var stick = gamepad.sticks[ idx ];
				if( Math.abs( axis ) > 0.1 ){
					if( stick.key ){
						if( this.disabled_exceptions ){
							if( !this.disabled_exceptions.includes( stick.key.name ) ) break;
						}

						if( stick.holding ) try{ stick.key.hold( axis ); } catch(e){}
						else{
							try{ stick.key.down(); } catch(e){}

							if( this.callbacks.on_key_down ) this.callbacks.on_key_down();
						}

						stick.holding = true;
					}
				}
				else{
					if( stick.holding ){
						if( this.disabled_exceptions ){
							if( !this.disabled_exceptions.includes( stick.key.name ) ) break;
						}
						try{ stick.key.up(); } catch(e){}

						if( this.callbacks.on_key_up ) this.callbacks.on_key_up();
					}

					stick.holding = false;
				}
			}
		}

		if( this.xr_session ){
			// Note: button press events seem to only be accessible from within the "xr_session.inputSources" forEach.
			// 	-Also, saving name and key values to the individual buttons/sticks don't seem to work either.
			for( var input_source of this.xr_session.inputSources ){
				var hand = input_source.handedness;
				var gamepad = input_source.gamepad;

				for( var idx = 0; idx < gamepad.buttons.length; idx++ ){
					var button = gamepad.buttons[ idx ];
					if( button.pressed ){
						var button_name = this.keycode_to_name( 'vr_' + hand[0], 'button', idx );
						var button_key  = this.get_key(         'vr_' + hand[0], button_name   );

						if( button_key ) this.on_button_press( button, button_key );
					}
					else{
						if( button.holding ){
							var button_name = this.keycode_to_name( 'vr_' + hand[0], 'button', idx );
							var button_key  = this.get_key(         'vr_' + hand[0], button_name   );

							if( this.disabled_exceptions ){
								if( !this.disabled_exceptions.includes( button_key.name ) ) break;
							}
							try{ button_key.up(); } catch(e){}

							if( this.callbacks.on_key_up ) this.callbacks.on_key_up();
						}

						button.holding = false;
					}
				}

				if( gamepad.axes ){
					for( var idx = 0; idx < gamepad.axes.length; idx++ ){
						var axis = gamepad.axes[ idx ];
						var stick_name = this.keycode_to_name( 'vr_' + hand[0], 'stick', idx );

						if( !this.xr_control_sticks[ stick_name ] ) this.xr_control_sticks[ stick_name ] = {};
						var stick = this.xr_control_sticks[ stick_name ];

						if( Math.abs( axis ) > 0.1 ){
							var stick_key  = this.get_key( 'vr_' + hand[0], stick_name );

							if( stick_key ){
								if( this.disabled_exceptions ){
									if( !this.disabled_exceptions.includes( stick_key.name ) ) break;
								}

								if( stick.holding ) try{ stick_key.hold( axis ); } catch(e){}
								else{
									try{ stick_key.down(); } catch(e){}

									if( this.callbacks.on_key_down ) this.callbacks.on_key_down();
								}

								stick.holding = true;
						 	}
						}
						else{
							if( stick.holding ){
								var stick_key  = this.get_key( 'vr_' + hand[0], stick_name );
								if( this.disabled_exceptions ){
									if( !this.disabled_exceptions.includes( stick_key.name ) ) break;
								}
								try{ stick_key.up(); } catch(e){}

								if( this.callbacks.on_key_up ) this.callbacks.on_key_up();
							}

							stick.holding = false;
						}
					}
				}
				
			}
		}
	}
};

