JL.keyboard = function( bindings, callbacks, p ){
	var self = this;

	var p = p || {};

	this.callbacks = callbacks || {};

	this.excluded_elements = p.excluded_elements || [ 'input', 'select', 'textarea' ];

	for( var k of [ 'no_loop' ] ) this[ k ] = p[ k ];

	this.keycodes = {
		"BACKSPACE"        :   8,
		"TAB"              :   9,
		"ENTER"            :  13,
		"SHIFT"            :  16,
		"CTRL"             :  17,
		"ALT"              :  18,
		"PAUSE BREAK"      :  19,
		"CAPS LOCK"        :  20,
		"ESCAPE"           :  27,
		"SPACEBAR"         :  32,
		"PAGE UP"          :  33,
		"PAGE DOWN"        :  34,
		"END"              :  35,
		"HOME"             :  36,
		"LEFT ARROW"       :  37,
		"UP ARROW"         :  38,
		"RIGHT ARROW"      :  39,
		"DOWN ARROW"       :  40,
		"INSERT"           :  45,
		"DELETE"           :  46,
		"0"                :  48,
		"1"                :  49,
		"2"                :  50,
		"3"                :  51,
		"4"                :  52,
		"5"                :  53,
		"6"                :  54,
		"7"                :  55,
		"8"                :  56,
		"9"                :  57,
		"A"                :  65,
		"B"                :  66,
		"C"                :  67,
		"D"                :  68,
		"E"                :  69,
		"F"                :  70,
		"G"                :  71,
		"H"                :  72,
		"I"                :  73,
		"J"                :  74,
		"K"                :  75,
		"L"                :  76,
		"M"                :  77,
		"N"                :  78,
		"O"                :  79,
		"P"                :  80,
		"Q"                :  81,
		"R"                :  82,
		"S"                :  83,
		"T"                :  84,
		"U"                :  85,
		"V"                :  86,
		"W"                :  87,
		"X"                :  88,
		"Y"                :  89,
		"Z"                :  90,
		"LEFT WINDOW KEY"  :  91,
		"RIGHT WINDOW KEY" :  92,
		"SELECT KEY"       :  93,
		"NUMPAD 0"         :  96,
		"NUMPAD 1"         :  97,
		"NUMPAD 2"         :  98,
		"NUMPAD 3"         :  99,
		"NUMPAD 4"         : 100,
		"NUMPAD 5"         : 101,
		"NUMPAD 6"         : 102,
		"NUMPAD 7"         : 103,
		"NUMPAD 8"         : 104,
		"NUMPAD 9"         : 105,
		"MULTIPLY"         : 106,
		"ADD"              : 107,
		"SUBTRACT"         : 109,
		"DECIMAL POINT"    : 110,
		"DIVIDE"           : 111,
		"F1"               : 112,
		"F2"               : 113,
		"F3"               : 114,
		"F4"               : 115,
		"F5"               : 116,
		"F6"               : 117,
		"F7"               : 118,
		"F8"               : 119,
		"F9"               : 120,
		"F10"              : 121,
		"F11"              : 122,
		"F12"              : 123,
		"NUM LOCK"         : 144,
		"SCROLL LOCK"      : 145,
		";"                : 186,
		"="                : 187,
		","                : 188,
		"-"                : 189,
		"."                : 190,
		"/"                : 191,
		"`"                : 192,
		"["                : 219,
		"BACK SLASH"       : 220,
		"]"                : 221,
		"'"                : 222
	};

	this.set_bindings( bindings );

	document.addEventListener('keydown', function(event) {
		if( !self.disabled || self.disabled_exceptions ){
			if( !self.focused_on_excluded_element() ){
				if( !self.pressed.includes( event.keyCode ) ){
					var bindings = self.get_bindings_with_keycode( event.keyCode );
					if( bindings.length ){
						self.pressed.push( event.keyCode );

						for( var binding of bindings ){
							if( self.disabled_exceptions ){
								if( !binding.is_disabled_exception( self.disabled_exceptions ) ) break;
							}

							binding.press_key( event.keyCode );

							try{
								if( binding.down ){
									if( binding.is_pressed() ) binding.down( event );
								}
							} catch(e){}
						}
					}
				}

				if( self.callbacks.on_key_down ) self.callbacks.on_key_down();
			}
		}
	});

	document.addEventListener('keyup', function(event) {
		if( !self.disabled || self.disabled_exceptions ){
			if( !self.focused_on_excluded_element() ){
				var bindings = self.get_bindings_with_keycode( event.keyCode );
				if( bindings.length ){
					var pressed_index = self.pressed.indexOf( event.keyCode );
					if( pressed_index != -1 ) self.pressed.splice( pressed_index, 1 );

					for( var binding of bindings ){
						if( self.disabled_exceptions ){
							if( !binding.is_disabled_exception( self.disabled_exceptions ) ) break;
						}

						try{
							if( binding.up ) binding.up( event );
						} catch(e){}

						binding.release_key( event.keyCode );
					}
				}

				if( self.callbacks.on_key_up ) self.callbacks.on_key_up();
			}
		}
	});
};

JL.keyboard.prototype.clear_all = function(){
	this.pressed = [];
	for( var binding of this.bindings ) binding.pressed = false;
};

JL.keyboard.prototype.disable = function( disabled_exceptions ){
	this.disabled = true;
	this.disabled_exceptions = disabled_exceptions || false;

	this.clear_all();

	if( this.callbacks.on_disable ) this.callbacks.on_disable();
};

JL.keyboard.prototype.enable = function(){
	this.disabled = false;
	this.disabled_exceptions = false;

	if( this.callbacks.on_enable ) this.callbacks.on_enable();
};

JL.keyboard.prototype.get = function(name){
	var bindings = this.bindings.filter(function( b ){ return b.get_name() == name; });
	if(bindings.length > 0) return bindings.pop();
	return false;
};

JL.keyboard.prototype.get_bindings_with_keycode = function( code ){
	return this.bindings.filter(function( b ){ return b.has_keycode( code ); });
};

JL.keyboard.prototype.get_from_keycode = function(code){
	for( var b of this.bindings ){
		if( b.code == code ) return b;
	}

	var bindings = this.bindings.filter(function(key){ return key.code == code; });
	if(bindings.length > 0) return bindings.pop();
	return false;
};

JL.keyboard.prototype.focused_on_excluded_element = function(){
	var active_element = document.activeElement;
	
	if( active_element ){
		if( this.excluded_elements.includes( active_element.tagName.toLowerCase() ) ) return true;
	}

	return false;
};

JL.keyboard.prototype.set_bindings = function( bindings ){
	var self = this;

	try{ this.clear_all(); } catch(e){}

	this.bindings = bindings.map(function( b ){
		// For keyboard shortcuts with multiple keys pressed at the same time 
		if( b.combo ){
			b.codes = b.combo.map(function( name ){ return self.keycodes[ name ]; });
			b.get_name = function(){ return ( this.name !== undefined ? this.name : this.combo.join('+') ); };
			b.has_keycode = function( code ){
				return this.codes.includes( code );
			};
			b.is_disabled_exception = function( exceptions ){
				return this.combo.every(function(   name ){
					return exceptions.includes( name );
				});
			};
			b.is_pressed  = function(){ return Object.values( this.pressed ).every( v => v ); };
			b.pressed     = {};
			b.press_key   = function( code ){ return this.pressed[ code ] = true; };
			b.release_key = function( code ){ return this.pressed[ code ] = false; };
			for( var c of b.codes ) b.pressed[ c ] = false;
		}
		// For keyboard shortcuts with only one key pressed at a time.
		else{
			b.code = self.keycodes[ b.name ];
			b.get_name = function(){ return this.name; };
			b.has_keycode = function( code ){
				return ( this.code == code );
			};
			b.is_disabled_exception = function( exceptions ){
				return exceptions.includes( this.name );
			};
			b.is_pressed  = function(){ return this.pressed; };
			b.press_key   = function(){ return this.pressed = true; };
			b.release_key = function(){ return this.pressed = false; };
		}

		return b;
	});

	if( this.prevent_default_down ){ window.removeEventListener( 'keydown', this.prevent_default_down ); delete this.prevent_default_down; }
	if( this.prevent_default_up   ){ window.removeEventListener( 'keyup'  , this.prevent_default_up   ); delete this.prevent_default_up;   }

	var prevent_default_bindings = this.bindings.filter(function( b ){ return b.prevent_default; });
	if( prevent_default_bindings.length ){
		var down_codes = JL.functions.filter_duplicates( prevent_default_bindings.filter(function( b ){ return b.down || b.hold; }).map(function( b ){ return b.codes || b.code; }).flat() );
		var up_codes   = JL.functions.filter_duplicates( prevent_default_bindings.filter(function( b ){ return b.up            ; }).map(function( b ){ return b.codes || b.code; }).flat() );

		if( down_codes.length ){ this.prevent_default_down = function( e ){ var c = e.keyCode; if( down_codes.includes(c) ){ if( self.get_from_keycode(c).prevent_default() ){ e.preventDefault(); } } }; window.addEventListener( "keydown", this.prevent_default_down, false ); }
		if(   up_codes.length ){ this.prevent_default_up   = function( e ){ var c = e.keyCode; if(   up_codes.includes(c) ){ if( self.get_from_keycode(c).prevent_default() ){ e.preventDefault(); } } }; window.addEventListener( "keyup"  , this.prevent_default_up  , false ); }
	}

	this.holdable_bindings = this.bindings.filter(function( b ){ return b.hold; });

	if( this.holdable_bindings.length ) this.start_loop();
	else                                this.stop_loop();
};

JL.keyboard.prototype.set_event_callback = function( key, callback_fn ){
	this.callbacks[ key ] = callback_fn;
};

JL.keyboard.prototype.start_loop = function(){
	if( !this.no_loop ){
		if( this.loop_interval === undefined ){
			var self = this;
			this.loop_interval = setInterval( function(){ self.loop(); }, 20 );
		}
	}
};

JL.keyboard.prototype.stop_loop = function(){
	if( this.loop_interval !== undefined ){
		clearInterval( this.loop_interval );
		delete this.loop_interval;
	}
};

JL.keyboard.prototype.loop = function(){
	var self = this;
	if( !this.disabled || this.disabled_exceptions ){
		if( !this.focused_on_excluded_element() ){
			var bindings = this.holdable_bindings;
			if( this.disabled_exceptions ) bindings = bindings.filter( x => x.is_disabled_exception( self.disabled_exceptions ) );
			for( var b of bindings ){
				try{
					if( b.is_pressed() ) b.hold();
				} catch(e){}
			}
		}
	}
};

/*
-----------------
| Example Usage |
-----------------

new JL.keyboard(
	[
		{ combo : [ "CTRL", "C" ], controllers : { ps4 : 'Left Stick Press'  }, down : function(){ console.log( 123 ); } },
		{ name : "R"             , controllers : { ps4 : 'Right Stick Press' }, up   : function(){ console.log( 123 ); } },
		{ name : "ESCAPE"        , controllers : { vr_r : 'B' }               , down : function(){ console.log( 123 ); } },
		{ name : "UP ARROW"      , controllers : { vr_r : 'A' }               , hold : function(){ console.log( 123 ); }, prevent_default : function(){ return ( 'condition' == true ); }, },
	],
	{
		on_key_up  : function(){ console.log( 123 ); },
		on_disable : function(){ console.log( 123 ); }
	}
);
*/

try{ JL = JL; } catch(e){ JL = {}; }

JL.json_edit = function( p ){
	if( JL.json_edit.add_css ) JL.json_edit.add_css();

	this.set_parent({ id : 'body' });

	[ 'id', 'on_change', 'structure', 'target_object', 'value' ].forEach(function( k ){
		this[ k ] = p[ k ];
	}, this);

	if( !this.value ) this.value = {};

	[ 'parent' ].forEach(function( k ){
		if( p[ k ] ) this[ 'set_' + k ]( p[ k ] );
	}, this);

	this.graph_config = {};

	this.draw();
};

