JL.json_edit.class_load_inputs = function( p ){
	var self = this;
	if( this._inputs ){
		JL.json_edit.prototype.assign_values({ target : this, inputs : this._inputs.filter( x => !x.no_this_assign ), values : p });
		JL.json_edit.prototype.assign_values({ target : p   , inputs : this._inputs.filter( x => !x.no_p_assign    ), values : p });
	}
};

JL.json_edit.prototype.assign_to_structure = function( p ){
	var structure = this.get_structure( p.path, p.root_structure );

	// Note : don't use JL.functions.recursive_assign here. Otherwise it won't work with replacing values that are arrays (ex: setting 'options' for dropdown structures).
	if( structure ) return Object.assign( structure, p.value );
};

JL.json_edit.prototype.assign_values = function( p ){
	var self = this;

	var values = p.values || this.value || {};

	var recursive_helper = function( inputs, curr_path ){
		for( var input of inputs ){
			var key  = input.key;
			var path = ( curr_path || [] ).slice();
			if( key !== undefined ) path.push( key );

			var input_val = JL.functions.get_nested_object( values, path );

			if(          input.condition ){
				if( !input.condition({
					structure  : input,
					path,
					value      : input_val,
					json_edit  : self,
					root_value : values,
				}) ){
					continue;
				}
			}

			var val;
			if( input_val !== undefined ){
				val = ( input.get_value ?
					input.get_value( input_val ) :
					input_val
				);
			}
			else{
				val = ( input.get_default ?
					input.get_default.apply( p.target, [{ structure : input, json_edit : self, }] ) :
					input.default
				);

				if( input.type == 'webgl.graphics_object' ){
					if( input.copy_default ) val = JL.webgl.functions.get_graphics_object( val ).copy({ unique_label : true });
				}
			}

			if( val === undefined ) continue;

			JL.functions.set_nested_object( p.target, path, val );

			if( input.min !== undefined ) val = ( val < input.min ? input.min : val );
			if( input.max !== undefined ) val = ( val > input.max ? input.max : val );

			if     ( input.type == 'float'    ) JL.functions.set_nested_object( p.target, path, Number(   val ) );
			else if( input.type == 'int'      ) JL.functions.set_nested_object( p.target, path, parseInt( val ) );
			else if( input.type == 'function' ){
				if( JL.functions.is_str( val ) ) JL.functions.set_nested_object( p.target, path, eval(`(${val})`) );
				else                             JL.functions.set_nested_object( p.target, path, val );
			}
			else if( input.type == 'webgl.graphics_object' ){
				var g_o = JL.webgl.functions.get_graphics_object( val );
				if( p.index_graphics_objects ) g_o = JL.webgl.ui.item.edit.index_graphics_object( g_o );
				JL.functions.set_nested_object( p.target, path, g_o );
			}
			else if( input.type == 'webgl.space_object' ){
				// 2025-11-13 -- trying to get JL.webgl.environment.starting_space_objects (array of space_objects) to work from Edit interface.
				JL.functions.set_nested_object( p.target, path, val );
				// JL.functions.set_nested_object( p.target, path, JL.webgl.functions.get_space_object( val ) );
			}
			else if( input.structure ){
				if( input.type == 'arr' ){
					for( var child_idx in ( val || [] ) ){
						if( JL.functions.is_object( input.structure ) ) recursive_helper( [ input.structure ], path.slice().concat([ child_idx ]) );
						else                                            recursive_helper(   input.structure  , path.slice().concat([ child_idx ]) );
					}
				}
				else if( input.type == 'obj' ){
					for( var child_structure of input.structure ){
						recursive_helper( [ child_structure ], path.slice() );
					}
				}
			}
		}
	};

	recursive_helper( ( p.inputs || this.structure || [] ).slice() );
};

JL.json_edit.prototype.traverse_structure = function( p ){
	var root_structure = p.structure || this.structure;

	var stop_traversing = false;

	var on_step = function( step_structure ){
		if( p.on_step ){
			p.on_step( step_structure, {
				assign : function( v ){ Object.assign( step_structure, v ); }
			} );
			if( p.on_step.stop_traversing ) stop_traversing = true;
		}
	};

	var recursive_helper = function( curr_structure ){
		if( !stop_traversing ){
			for( var s of curr_structure ){
				on_step( s );

				if( s.structure ){
					if     ( JL.functions.is_array(  s.structure ) ) recursive_helper(  s.structure  );
					else if( JL.functions.is_object( s.structure ) ) recursive_helper([ s.structure ]);
				}
			}
		}
	};

	recursive_helper( root_structure );
};

JL.json_edit.prototype.traverse_values = function( p ){
	var root_value     = p.value || this.value;
	var root_structure = p.inputs || p.structure || this.structure;

	var stop_traversing = false;

	var on_step = function( step_value, step_structure, step_path, params ){
		if( p.on_step ){
			p.on_step( step_value[ step_structure.key ], step_structure, {
				path : step_path,
				set  : function( v ){
					if( step_structure.key !== undefined ) step_value[ step_structure.key ] = v;
					else if( params.index !== undefined ) params.parent[ params.index ] = v;
					// JL.functions.set_nested_object( root_value, step_path, v );
				}
			} );
			if( p.on_step.stop_traversing ) stop_traversing = true;
		}
	};

	var recursive_helper = function( curr_values, curr_structure, curr_path, params ){
		if( !stop_traversing ){
			for( var s of curr_structure ){
				on_step( curr_values, s, curr_path.slice(), params );

				if( s.type == 'arr' ){
					if( s.structure && curr_values[ s.key ] ){
						if( JL.functions.is_object( s.structure ) && s.structure.type != 'obj' ){ // Array of vals/arrs
							if( s.structure.type == 'arr' ){
								// for( var val of curr_values[ s.key ] ){
								for( var i = 0; i < curr_values[ s.key ].length; i++ ){
									var val = curr_values[ s.key ][ i ];
									if( JL.functions.is_array( val ) ){   // Array of arrs
										var c_val = {};
										c_val[ i ] = val;
										recursive_helper(
											c_val,
											[ Object.assign( Object.assign( {}, s.structure ), { key : i } ) ],

											curr_path.slice().concat([ s.key, i ]),
											{ parent : curr_values[ s.key ] }
										);
									}
									else{  // Array of vals
										recursive_helper(
											// -------------
											// val, s.structure,
											// -------------
											{ x : val },
											Object.assign( Object.assign( {}, s.structure ), { key : 'x' } ),
											// -------------

											curr_path.slice().concat([ s.key, i ]),
											{ parent : curr_values[ s.key ] }
										);
									}
								}
							}
							else{
								for( var index in curr_values[ s.key ] ){
									var _v = curr_values[ s.key ][ index ];
									var _s = s.structure;
									if( ![ 'int', 'float', 'str', 'bool' ].includes( s.structure.type ) ){
										_v = { x : curr_values[ s.key ][ index ] };
										_s = Object.assign( Object.assign( {}, s.structure ), { key : 'x' } );
									}
									on_step(
										_v, _s,
										// 2024-07-31
										curr_path.slice().concat([ s.key, index ]),
										/// curr_path.slice().concat([ index ]),
										{ parent : curr_values[ s.key ], index, }
									);
								}
							}
						}
						else{  // Array of objs
							var child_structure = s.structure;
							if( JL.functions.is_object( s.structure ) ) child_structure = s.structure.structure;

							if( child_structure ){
								for( var i = 0; i < curr_values[ s.key ].length; i++ ){
									var val = curr_values[ s.key ][ i ];
									recursive_helper(
										// 2025-11-10 -- traversal of some arrays of objs wasn't working (ex: for s_o._person accessories)
										val, child_structure,
										// val, s.structure,
										curr_path.slice().concat([ s.key, i ]),
										{ parent : curr_values[ s.key ] }
									);
								}
							}
						}
					}
				}
				else if( s.type == 'obj' ){
					if( s.structure && curr_values[ s.key ] ){
						recursive_helper(
							curr_values[ s.key ], s.structure,
							curr_path.slice().concat([ s.key ]),
							{ parent : curr_values }
						);
					}
				}
			}
		}
	};

	recursive_helper( root_value, root_structure, [] );
};

JL.json_edit.prototype.set_parent = function( parent ){
	this.parent = parent;

	this.root_id = this.parent.id + ' .jl-json-edit';
};

JL.json_edit.prototype.guess_structure = function( key, value ){
	var structure = {};

	var recursive_helper = function( _key, _val, structure ){
		structure.key = _key;

		if( JL.functions.is_matrix( _val ) ){ // Matrix class used in JL.webgl
			structure.type      = 'mat';
			structure.structure = [ recursive_helper( 'elements', _val.elements, { no_label : 1, length : _val.elements.length } ) ];

			structure.structure[ 0 ].structure.force_single_line_arr = 1;
			structure.structure[ 0 ].structure.length                = _val.elements[ 0 ].length;
			structure.structure[ 0 ].structure.no_label              = 1;
			structure.structure[ 0 ].structure.structure.no_label    = 1;
		}
		else if( JL.functions.is_object( _val ) ){
			structure.type = 'obj';
			structure.structure = [];
			for( var k of Object.keys( _val ) ) structure.structure.push( recursive_helper( k, _val[ k ], {} ) );
		}
		else if( JL.functions.is_array( _val ) ){
			structure.type = 'arr';
			if( !structure.structure ) structure.structure = [];
			if( JL.functions.is_object( _val[ 0 ] ) ){
				for( var k of Object.keys( _val ) ) structure.structure.push( recursive_helper( k, _val[ 0 ][ k ], {} ) );
			}
			else{
				structure.structure = recursive_helper( undefined, _val[ 0 ], {} );
			}
		}
		else if( JL.functions.is_str( _val ) ) structure.type = 'str';
		else if( !isNaN(              _val ) ) structure.type = 'float';
		else                                   structure.type = 'str';

		return structure;
	};

	return recursive_helper( key, value, {} );
};

JL.json_edit.prototype.get_id = function( path, p ){
	var p = p || {};
	var parts = [];
	if( p.prefix !== undefined ) parts.push( p.prefix );
	parts = parts.concat([
		this.id,
		( path || [] ).join('-')
	]);
	if( p.suffix !== undefined ) parts.push( p.suffix );
	return parts.join('--');
};

JL.json_edit.prototype.get_structure = function( path, root_structure ){
	var curr_structure = root_structure || this.structure;

	if( !path ) return curr_structure;

	for( var k of path ){
		if( !curr_structure ) return false;

		if( JL.functions.is_int( k ) ) continue;

		if( JL.functions.is_array( curr_structure ) ){
			curr_structure = curr_structure.find( s => s.key == k );
		}
		else{
			if( JL.functions.is_array( curr_structure.structure ) ){
				curr_structure = curr_structure.structure.find( s => s.key == k );
			}
			else if( JL.functions.is_object( curr_structure.structure ) ){
				curr_structure = curr_structure.structure[ k ];
			}
		}
	}

	return curr_structure;
};

JL.json_edit.prototype.get_value = function( path, root_value ){
	return JL.functions.get_nested_object( root_value || this.value, path );
};

JL.json_edit.prototype.remove_value = function( path ){
	JL.functions.remove_nested_object( this.value, path );
};

JL.json_edit.prototype.set_value = function( p ){
	var self = this;

	var val = p.value;

	if( val !== undefined ){
		switch( p.type ){
			case 'float' : val =   Number( val ); break;
			case 'int'   : val = parseInt( val ); break;
		}

		if( p.structure ){
			if( p.structure.min !== undefined ) val = ( val < p.structure.min ? p.structure.min : val );
			if( p.structure.max !== undefined ) val = ( val > p.structure.max ? p.structure.max : val );
		}
	}

	var prev_value = JL.functions.get_nested_object( this.value, p.path );

	var is_changed = ( prev_value !== val );

	var prev_root_value;
	if( is_changed ){
		try{ prev_root_value = $.extend( true, {}, this.value ); } catch(e){}
	}

	JL.functions.set_nested_object( this.value, p.path, val );

	if( p.set_selected ) this.arr_edit_selected_entries( p.path[ p.path.length - 1 ], function(){ return val; });

	if( is_changed ){
		for( var obj of [ p.structure, this ] ){
			if( obj ){
				if( !p.no_on_change ){
					if( obj.on_change ){
						obj.on_change({
							structure  : p.structure,
							path       : p.path,
							value      : val,
							root_value : this.value,
							json_edit  : this,
							set_value  : function( value ){
								self.set_value({ path : p.path, value });
							},
							prev_root_value, prev_value,
						});
					}
				}
				if( obj.redraw_json_edit_on_change ) this.draw();
				else{
					$( '#' + this.get_id( p.path ) ).val( val );
				}
			}
		}
	}
};

JL.json_edit.prototype.set_root_value = function( new_root, p ){
	var p = p || {};

	this.value = new_root;

	if( !p.no_draw ) this.draw();
};

JL.json_edit.prototype.can_be_randomized = function( p ){
	var output = false;
	this.traverse_structure( Object.assign({
		on_step : function( structure, params ){
			if( structure.min !== undefined && structure.max !== undefined ){
				output = true;
				this.stop_traversing = true;
			}
		},
	}, p || {} ) );
	return output;
};

JL.json_edit.prototype.randomize_all_values = function( p ){
	this.traverse_values( Object.assign({
		on_step : function( value, structure, params ){
			if( structure.min !== undefined && structure.max !== undefined ){
				params.set( JL.functions.random_number( structure.min, structure.max ) );
			}
		},
	}, p || {} ) );
};

JL.json_edit.prototype.randomize_value = function( p ){
	p.value = JL.functions.random_number( p.structure.min, p.structure.max );
	this.set_value( p );
};

JL.json_edit.prototype.sort_ui_rows = function( structure ){
	var output = structure.slice().sort(function( a, b ){
		var a_val = ( a.ui_row !== undefined ? a.ui_row : ( a.ui_order !== undefined ? a.ui_order : '~' ) );
		var b_val = ( b.ui_row !== undefined ? b.ui_row : ( b.ui_order !== undefined ? b.ui_order : '~' ) );
		if( a_val > b_val ) return  1;
		if( a_val < b_val ) return -1;
		return 0;
	});
	return output;
};

JL.json_edit.prototype.add_event = function( type, id, path, fn ){
	this.events.push({ type, id, path, fn });
};

JL.json_edit.prototype.arr_add_entry = function( p ){
	var path = p.path || [];

	var arr_structure = p.arr_structure || this.get_structure( path ) || {};

	var new_entry = this.get_default_value( p );

	// 2025-08-07 -- trying to add support for 'on_change' when adding an element to an array.
	// var val;

	var new_entry_path = path.slice();

	var new_entry_path_suffix = [];

	try{
		if( p.index !== undefined ){
			JL.functions.get_nested_object( this.value, path ).splice( p.index + 1, 0, new_entry );
			// 2025-08-07 -- trying to add support for 'on_change' when adding an element to an array.
			// val = JL.functions.get_nested_object( this.value, path );

			new_entry_path.push( p.index + 1 );

			if( arr_structure._entry_collapse_statuses ) arr_structure._entry_collapse_statuses.splice( p.index + 1, 0, arr_structure.entries_collapsed || 0 );
		}
		else{	
			// 2025-08-07 -- trying to add support for 'on_change' when adding an element to an array.
			var val = JL.functions.get_nested_object( this.value, path ).concat([ new_entry ]);
			// val = JL.functions.get_nested_object( this.value, path ).concat([ new_entry ]);

			new_entry_path.push( val.length - 1 );

			if( arr_structure._entry_collapse_statuses ) arr_structure._entry_collapse_statuses.push( arr_structure.entries_collapsed || 0 );
		}
	}
	catch(e){
		// 2025-08-07 -- trying to add support for 'on_change' when adding an element to an array.
		// val = [ new_entry ];

		new_entry = [ new_entry ];

		new_entry_path_suffix.push( 0 );

		if( arr_structure._entry_collapse_statuses ) arr_structure._entry_collapse_statuses = [ arr_structure.entries_collapsed || 0 ];
	}

	// 2025-08-07 -- trying to add support for 'on_change' when adding an element to an array.
	this.set_value({ value : new_entry, path : new_entry_path, structure : arr_structure });
	// JL.functions.set_nested_object( this.value, path, val );

	return new_entry_path.concat( new_entry_path_suffix );
};

// For the "Add entry" buttons / menu options.
JL.json_edit.prototype.arr_add_new_entry = function( p ){
	var structure = p.structure;
	p.type    = structure.val_type;
	p.default = structure.val_default;
	if( structure.val_type === 'arr' ) p.default = p.default.slice();
	if( structure.structure ){
		if( p.is_array_of_vals ){
			for( var k of [ 'type', 'default', 'options', 'get_options', 'get_autocomplete', ] ){
				if( p[ k ] === undefined ) p[ k ] = structure.structure[ k ];
			}
		}
	}
	this.arr_add_entry( p );
	if( !p.no_draw ) this.draw();
};

JL.json_edit.prototype.arr_add_new_selected_entries = function( p ){
	for( var entry of this.selected_array_entries.sort( (a,b) => ( a.index > b.index ? -1 : 1 ) ) ){
		var params = Object.assign( {}, entry, { path : entry.parent_path, no_draw : true } );
		params.index = entry.index + ( p.offset || 0 );
		this.arr_add_new_entry( params );
	}
	this.draw();
};

JL.json_edit.prototype.arr_clear_selection = function(){
	this.selected_array_entries = [];
	this.draw();
};

JL.json_edit.prototype.arr_copy_selected_entries = function( p ){
	var p = p || {};

	var copied_entries_paths = [];

	for( var entry of this.selected_array_entries.sort( (a,b) => ( a.path > b.path ? -1 : 1 ) ) ){
		entry.copy_val = JL.functions.deep_copy( this.get_value( entry.path ) );

		var args = Object.assign( {}, entry, { path : entry.parent_path, no_draw : true, default : entry.copy_val } );
		if( p.push_to_end_of_array ) delete args.index;
		copied_entries_paths.push( this.arr_add_entry( args ) );
	}

	if( !p.no_draw ) this.draw();

	return copied_entries_paths;
};

JL.json_edit.prototype.arr_delete_entry = function( p ){
	var ele_path = ( p.path || [] );

	var arr_path = ele_path.slice();
	var ele_idx  = arr_path.pop();

	var arr = JL.functions.get_nested_object( this.value, arr_path ).slice();

	var deleted_entry = arr.splice( ele_idx, 1 )[ 0 ];

	var arr_structure = p.arr_structure || this.get_structure( path );
	if( arr_structure._entry_collapse_statuses ) arr_structure._entry_collapse_statuses.splice( ele_idx, 1 );

	if( p.arr_structure.pre_remove_entry ){
		var _p = {
			prev_value : JL.functions.get_nested_object( this.value, arr_path ),
			value      : arr,
		};
		p.arr_structure.pre_remove_entry.apply( this.value, [ _p ] );
		if( _p.cancel ) return;
	}
	
	this.set_value({ value : arr, path : arr_path, structure : p.arr_structure });

	if( arr_structure.on_delete_entries ){
		if( !p.deleting_multiple_entries ) arr_structure.on_delete_entries({ arr, deleted_entries : [ deleted_entry ], });
	}
	else if( arr_structure.on_delete_entry ){
		arr_structure.on_delete_entry(  { arr, deleted_entry, });
	}

	if( !p.no_draw ) this.draw();

	return deleted_entry;
};

JL.json_edit.prototype.arr_delete_selected_entries = function( p ){
	var p = p || {};

	var deleted_entries = [];

	for( var entry of this.selected_array_entries.sort( (a,b) => ( a.index > b.index ? -1 : 1 ) ) ){
		deleted_entries.push(
			this.arr_delete_entry({ path : entry.path, arr_structure : entry.structure, no_draw : true, deleting_multiple_entries : 1, })
		);
	}

	var arr, arr_structure;
	if( this.selected_array_entries.length ){
		var entry     = this.selected_array_entries[ 0 ];
		arr_structure = entry.structure || this.get_structure( entry.path );
		arr           = JL.functions.get_nested_object( this.value, ( entry.path || [] ).slice(0,-1) ).slice();
	}

	if( arr_structure.on_delete_entries ) arr_structure.on_delete_entries({ arr, deleted_entries, });

	if( !p.no_draw ) this.draw();
};

JL.json_edit.prototype.arr_randomize_selected_entries = function( p ){
	var p = p || {};

	for( var entry of this.selected_array_entries.sort( (a,b) => ( a.index > b.index ? -1 : 1 ) ) ){
		var args = JL.functions.deep_copy( p );

		args.path[ args.path.length - 2 ] = entry.index;

		this.randomize_value( args );
	}

	if( !p.no_draw ) this.draw();
};

JL.json_edit.prototype.arr_range_copy_selected_entries = function( p ){
	var self = this;

	var min  = p.min ;
	var max  = p.max ;
	var step = p.step;

	if( step <= 0 ) return;

	if( min > max ){
		var tmp = min;
		min = max;
		max = tmp;
	}

	var values = JL.functions.get_range_array( min, max, step );

	this.arr_select_this_if_necessary({ path : p.path.slice( 0, p.path.length - 1 ), command : function(){
		for( var value of values ){
			for( var path of self.arr_copy_selected_entries({ no_draw : true, push_to_end_of_array : true }) ){
				self.set_value({ value, path : path.slice().concat([ p.key ]), });
			}
		}
	} });

	if( !p.no_draw ) this.draw();
};

JL.json_edit.prototype.arr_edit_selected_entries = function( key, edit_value_fn ){
	for( var entry of this.selected_array_entries ){
		var structure = undefined;
		if( entry.structure.structure ){
			if( JL.functions.is_object( entry.structure.structure ) ) structure = entry.structure.structure.structure;
			else{
				structure = entry.structure.structure.find( s => s.key == key );
			}
		}
		if( structure ){
			var path = entry.path.concat([ key ]);
			this.set_value({
				path, structure,
				type  : structure.type,
				value : edit_value_fn({
					value : this.get_value( path ),
					entry, path, structure, 
				}),
			});
		}
	}
};

JL.json_edit.prototype.arr_increment_selected_entries = function( p ){
	this.arr_edit_selected_entries( p.key, function( _p ){ return Number( ( _p.value + p.val ).toFixed( 12 ) ); });

	if( !p.no_draw ) this.draw();
};

JL.json_edit.prototype.arr_multiply_selected_entries = function( p ){
	this.arr_edit_selected_entries( p.key, function( _p ){ return Number( ( _p.value * p.val ).toFixed( 12 ) ); });

	if( !p.no_draw ) this.draw();
};

JL.json_edit.prototype.arr_edit_value = function( p, change_fn ){
	var ele_path = ( p.path || [] );

	var arr_path = ele_path.slice();
	var ele_idx  = parseInt( arr_path.pop() );

	// 2025-12-19 -- trying to add support for 'on_change' when modifying an array.
	var arr = JL.functions.get_nested_object( this.value, arr_path ).slice();
	// var arr = JL.functions.get_nested_object( this.value, arr_path );

	change_fn( arr, ele_idx );

	var arr_structure = p.arr_structure || this.get_structure( p.path.slice( 0, p.path.length - 1 ) );
	if( arr_structure._entry_collapse_statuses ) change_fn( arr_structure._entry_collapse_statuses, ele_idx );
	
	// 2025-12-19 -- trying to add support for 'on_change' when modifying an array.
	this.set_value({ value : arr, path : arr_path, structure : arr_structure });
	// JL.functions.set_nested_object( this.value, arr_path, arr );

	if( !p.no_draw ) this.draw();
};

JL.json_edit.prototype.arr_is_entry_selected = function( entry ){
	if( JL.functions.is_object( entry ) ){
		var path_str = entry.path_str || entry.path.join('/');
		return this.selected_array_entries.find( x => ( x.path_str == path_str ) );
	}
	return this.selected_array_entries.find( x => ( x.path_str == entry ) );
};

JL.json_edit.prototype.arr_move_entry = function( p ){
	this.arr_edit_value( p, function( arr, ele_idx ){
		var val = arr.splice( ele_idx, 1 )[ 0 ];
		arr.splice( Math.max( p.offset + ele_idx, 0 ), 0, val );
	});
};

JL.json_edit.prototype.arr_move_selected_entries = function( p ){
	for( var entry of this.selected_array_entries.sort( (a,b) => Math.sign( p.offset ) * ( a.path_str > b.path_str ? -1 : 1 ) ) ){
		this.arr_move_entry( Object.assign( { path : entry.path, no_draw : true }, p ) );
	}
	this.draw();
};

JL.json_edit.prototype.arr_select_all = function( p ){
	for( var i = 0; i < this.get_value( p.path ).length; i++ ){
		var entry_path = ( p.path || [] ).concat([ i ]);

		if( !this.arr_is_entry_selected({ path_str : entry_path.join('/') }) ){
			$( '#' + this.get_id(                entry_path, { prefix : 'select' } ) ).trigger( 'click' );
		}
	}
}; 

JL.json_edit.prototype.arr_select_entry = function( p ){
	if( !this.arr_is_entry_selected( p.entry ) ) this.selected_array_entries.push( $.extend( true, {}, p.entry ) );
	$( '#' + p.id ).addClass( 'active' );
	this.arr_on_select_entry( p );
};

JL.json_edit.prototype.arr_deselect_entry = function( p ){
	this.selected_array_entries = this.selected_array_entries.filter( x => x.path_str !== p.entry.path_str );
	$( '#' + p.id ).removeClass( 'active' );
	this.arr_on_select_entry( p );
};

JL.json_edit.prototype.arr_on_select_entry = function( p ){
	if( p.entry.structure.on_select ) p.entry.structure.on_select({ selected_entries : this.get_selected_entries() });
};

JL.json_edit.prototype.arr_toggle_select_entry = function( p ){
	this[ 'arr_' + ( this.arr_is_entry_selected( p.entry ) ? 'de' : '' ) + 'select_entry' ]( p );
};

JL.json_edit.prototype.arr_get_entry_to_select = function( path ){
	var parent_path = path.slice( 0, path.length - 1 );
	var structure   = this.get_structure( parent_path );
	
	return {
		parent_path, structure,
		is_array_of_vals : JL.functions.is_object( structure.structure ),
		path_str         : path.join('/'),
		path             : path.slice(),
		index            : path[ path.length - 1 ],
	};
};

JL.json_edit.prototype.arr_select_this_if_necessary = function( p ){
	var select_id    = p.select_id   ;
	var select_entry = p.select_entry;

	if( !select_id ){
		if( p.path ) select_id = this.get_id( p.path, { prefix : 'select' } );
	}
	if( !select_entry ){
		if( p.path ) select_entry = this.arr_get_entry_to_select( p.path );
	}

	var none_selected;
	if( !this.selected_array_entries.length ){
		this.arr_select_entry({
			id    : select_id,
			entry : select_entry,
		});
		none_selected = true;
	}

	p.command({ selected_entries : this.selected_array_entries, });

	if( none_selected ){
		this.arr_deselect_entry({
			id    : select_id,
			entry : select_entry,
		});
	}
};

JL.json_edit.prototype.get_selected_entries = function( p ){
	var p = p || {};

	var output = JL.functions.deep_copy( this.selected_array_entries );

	for( var o of output ) o.value = this.get_value( o.path );

	return output;
};

JL.json_edit.prototype.arr_is_entry_collapsed = function( p ){
	var idx = p.path[ p.path.length - 1 ];
	var arr_structure = p.arr_structure || this.get_structure( p.path.slice( 0, p.path.length - 1 ) );
	try       { return arr_structure._entry_collapse_statuses[ idx ]; }
	catch( e ){ return false; }
};

JL.json_edit.prototype.arr_toggle_collapse_entry = function( p ){
	this[ 'arr_' + ( this.arr_is_entry_collapsed( p ) ? 'expand' : 'collapse' ) + '_entry' ]( p );
};

JL.json_edit.prototype.arr_set_entry_collapse = function( p, val ){
	var idx = p.path[ p.path.length - 1 ];
	var arr_structure = p.arr_structure || this.get_structure( p.path.slice( 0, p.path.length - 1 ) );
	arr_structure._entry_collapse_statuses[ idx ] = val;
	if( !p.no_draw ) this.draw({ preserve_selected : 1 });
};

JL.json_edit.prototype.arr_set_all_collapse = function( p, val ){
	var arr_structure = p.arr_structure || this.get_structure( p.path );
	arr_structure._entry_collapse_statuses = arr_structure._entry_collapse_statuses.map( x => val );
	if( !p.no_draw ) this.draw({ preserve_selected : 1 });
};

JL.json_edit.prototype.arr_set_selected_collapse = function( p, val ){
	var arr_structure = p.arr_structure || this.get_structure( p.path );
	for( var i = 0; i < arr_structure._entry_collapse_statuses.length; i++ ){
		if( this.arr_is_entry_selected({ path : p.path.slice().concat([ i ]) }) ){
			arr_structure._entry_collapse_statuses[ i ] = val;
		}
	}

	if( !p.no_draw ) this.draw({ preserve_selected : 1 });
};

JL.json_edit.prototype.arr_collapse_entry            = function( p ){ this.arr_set_entry_collapse(    p, 1 ); };
JL.json_edit.prototype.arr_collapse_all              = function( p ){ this.arr_set_all_collapse(      p, 1 ); };
JL.json_edit.prototype.arr_collapse_selected_entries = function( p ){ this.arr_set_selected_collapse( p, 1 ); };
JL.json_edit.prototype.arr_expand_entry              = function( p ){ this.arr_set_entry_collapse(    p, 0 ); };
JL.json_edit.prototype.arr_expand_all                = function( p ){ this.arr_set_all_collapse(      p, 0 ); };
JL.json_edit.prototype.arr_expand_selected_entries   = function( p ){ this.arr_set_selected_collapse( p, 0 ); };

JL.json_edit.prototype.arr_sort = function( p ){
	var arr = JL.functions.get_nested_object( this.value, p.path ).slice();

	var sort_indices = JL.functions.get_sort_indices( arr, p.sort );

	arr = JL.functions.sort_from_indices_array( arr, sort_indices );

	var arr_structure = p.arr_structure || this.get_structure( p.path );
	if( arr_structure._entry_collapse_statuses ){
		arr_structure._entry_collapse_statuses = JL.functions.sort_from_indices_array( arr_structure._entry_collapse_statuses, sort_indices );
	}

	this.set_value({ value : arr, path : p.path, structure : p.arr_structure });

	if( !p.no_draw ) this.draw();
};

JL.json_edit.prototype.get_webgl_space_object_options = function( structure ){
        var options = JL.webgl.active_environment.get_all_space_objects().sort( (a,b) => ( a._id - b._id ) ).map(function( s ){
                var type;
                try{
                        Object.keys( JL.webgl.active_environment._environment_config.space_objects ).forEach(function( t ){
                                if(  JL.webgl.active_environment._environment_config.space_objects[ t ].find( x => x._id == s._id ) ){
                                        type = t;
                                        return;
                                }
                        });
                } catch(e){}

                return {
                        name         : '#' + s._id + ( type ? ' [' + type + ']' : '' ) + ( s.name !== undefined ? ' - ' + s.name : '' ),
                        value        : s._id,
                        space_object : s,
                };
        });

	if( structure.custom_options ) options = structure.custom_options({ value : this.value, options : options || [] });
	return options;
};

JL.json_edit.prototype.collapse_section = function( p ){
	JL.json_edit.collapse_states[ p.id ] = ( p.val !== undefined ? p.val : JL.json_edit.collapse_states[ p.id ] );
	$( '#' + p.id_val )[ ( JL.json_edit.collapse_states[ p.id ] ? 'add' : 'remove' ) + 'Class' ]( 'collapsed' );
};

JL.json_edit.prototype.get_default_value = function( p ){
	var default_val = p.default;
	if( default_val === undefined ){
		if( p.get_default ){
			default_val = p.get_default.apply( this.value, [{ structure : p.structure, json_edit : this, }] );
			if( p.type == 'webgl.graphics_object' ) default_val = JL.webgl.ui.item.edit.index_graphics_object( default_val );
		}
		else{
			switch( p.type ){
				case 'float':
				case 'int':
					default_val = 0;
					if( p.max !== undefined ) default_val = Math.min( default_val, p.max );
					if( p.min !== undefined ) default_val = Math.max( default_val, p.min );
					break;
				case 'bool':
					default_val = false;
					break;
				case 'str':
					default_val = '';
					break;
				case 'function':
					default_val = function(){};
					break;
				case 'arr':
					default_val = [];
					if( p.length === undefined ){
						default_val = JL.functions.get_filled_array(
							this.get_default_value( p.structure || {} ),
							p.length
						);
					}
					break;
				case 'dropdown':
					var first_option = ( p.options || ( p.get_options ? p.get_options() : [] ) )[ 0 ];
					default_val = ( first_option.value !== undefined ? first_option.value : first_option );
					break;
				case 'mat':
					default_val = Matrix.I(4);
					break;
				case 'webgl.space_object':
					var options = this.get_webgl_space_object_options( p );
					if( options && options.length ) default_val = options[ 0 ].value;
					else                            default_val = false;
					break;
				case 'webgl.graphics_object':
					default_val = false;

					if( p.optional ){
						default_val = ( !p.turn_optional_on ? undefined : this.get_graphics_object_options({ structure : p, })[0] );
					}
					break;
				default:
					default_val = {};
					try     { var children_structures = p.structure.structure || []; }
					catch(e){ var children_structures = []; }
					if( JL.functions.is_object( children_structures ) ){
						default_val = this.get_default_value( children_structures );
					}
					else{
						children_structures.forEach(function( s ){
							if( !s.optional ) default_val[ s.key ] = this.get_default_value( s );
						}, this);
					}
					break;
			}
		}
	}
	if( p.assign_to_default ) default_val = Object.assign( default_val, p.assign_to_default );
	return default_val;
};

JL.json_edit.prototype.get_graphics_object_options = function( p ){
	var options = [];
	if( p.structure.get_options ) options = p.structure.get_options();
	else{
		if( !p.structure.default ) options.push( 'No graphics_object' );
		options = options.concat(
			JL.webgl.functions.list_graphics_objects().filter( m => m.path[ 0 ] != '_in_library' ).map(function( m ){
				return m.graphics_object._id;
			})
		);
	}
	return options;
};

JL.json_edit.prototype.reset_to_default = function( p ){
	if( p.path && p.structure ){
		this.set_value({
			path      : p.path,
			value     : this.get_default_value( p.structure ),
			type      : p.structure.type,
			structure : p.structure,
		});
	}

	if( !p.no_draw ) this.draw();
};

JL.json_edit.prototype.get_input_html = function( value, structure, id ){
	var autocomplete    = ( structure.get_autocomplete ? structure.get_autocomplete.apply( this.value ) : structure.autocomplete || [] );
	var autocomplete_id = 'autocomplete-' + id;
	var update_fn = '';

	var title, placeholder;
	if( structure.get_placeholder ) placeholder = structure.get_placeholder();
	if( title === undefined ) title = placeholder;

	var classes = ( structure.classes || '' );
	if( autocomplete.length ) classes += ' has-autocomplete';

	var style = structure.style;

	var value = value;
	if( structure.convert_to_hr ) value = structure.convert_to_hr( value, { structure, } );

	var ele = 'input';
	if( structure.multi_line ) ele = 'textarea';

	var is_textarea = ( ele == 'textarea' );

	var html_val = ( value === undefined ? '' : value );

	var output = '<' + ele + ' id="' + id + '" ' + 
		( is_textarea ? '' : ' value="' + html_val + '" ' ) + 
		' class="' + classes + '" ' + 
		' onchange="' + update_fn + '" ' + 
		( style       === undefined ? '' : ' style="'       + style       + '" ' ) +
		( title       === undefined ? '' : ' title="'       + title       + '" ' ) +
		( placeholder === undefined ? '' : ' placeholder="' + placeholder + '" ' ) +
		[ 'type', 'step', 'min', 'max' ].map(function( k ){
			return ( structure[ k ] === undefined ? '' : k + '="' + structure[ k ] + '"' );
		}).join(' ') +
		( !autocomplete.length ? '' : 
			' list="' + autocomplete_id + '" '
		) +
		( !structure.no_edit ? '' : ' ' +
			[ 'onmousedown', 'onmouseup' ].map( k => k + '="if( event.which == 1 ){ event.preventDefault(); };"' ).join(' ')
		) +
		' onkeyup="if( event.keyCode == 13 ){' + update_fn + '}">' + 
			( is_textarea ? html_val : '' ) + 
		'</' + ele + '>';

	if( autocomplete.length ){
		output += '<datalist id="' + autocomplete_id + '">' +
			autocomplete.map(function( a ){
				var lbl, val;
				if( JL.functions.is_object( a ) ){
					lbl = a.lbl;
					val = a.val;
				}
				else{
					lbl = a;
					val = a;
				}
				return '<option value="' + val + '">' + lbl + '</option>';
			}).join('') +
		'</datalist>';
	}

	if( structure.slider ){
		var container_id = 'container-' + id;
		var slider_id    = 'slider-' + id;
		output = '<div id="' + container_id + '" class="slider-input-field">' + output + '</div>' + 
			 '<div id="' + slider_id + '"    class="slider-input-field slider"></div>';

		this.sliders.push({
			slider_container     : { id : '#' + slider_id    },
			input_container      : { id : '#' + container_id },
			input_already_exists : true,
			min                  : structure.min,
			max                  : structure.max,
			default              : value,
		});
	}
	
	return output;
};

JL.json_edit.prototype.get_html = function( _params ){
	var self = this;

	var structure = _params.structure || this.structure; 
	var path      = _params.path      || [];
	var value     = _params.value; 

	var lbl_classes = '';
	var val_classes = '';

	var tr_start = '<tr>';
	var tr_end   = '</tr>';

	var has_lbl = true;

	var no_change_event = false;

	var right_click_options = {
		contents : [],
		lbl      : [],
	};

	if(          structure.condition ){
		if( !structure.condition({
			structure, path, value,
			json_edit  : this,
			root_value : this.value,
		}) ){
			if( structure.key ) path.push( structure.key );
			this.remove_value( path );
			return '';
		}
	}

	if( structure.get_structure ){ // Useful for recursive structures.
		if( value !== undefined ){
			if( !structure.structure ){
				structure.structure = structure.get_structure({
					structure, path, value,
					json_edit  : this,
					root_value : this.value,
				});
			}
		}
	}

	if(     structure.custom_init ){
		structure.custom_init({
			structure, path, value,
			json_edit  : this,
			root_value : this.value,
		});
	};

	if( _params.parent_structure ){
		if( _params.parent_structure._entry_collapse_statuses ){
			if( this.arr_is_entry_collapsed({ path, arr_structure : _params.parent_structure, }) ){
				if( !structure.show_while_collapsed ) return '';
			}
		}

		var modify_children_structures = _params.parent_structure.modify_children_structures;
		if( modify_children_structures ){
			var _p = { structure, path, value };

			_p.modify_children_start = structure.modify_children_start = _params.parent_structure.modify_children_start || _params.parent_structure.key;
			_p.modify_children_path  = path.slice( path.indexOf( _p.modify_children_start ) );

			modify_children_structures( _p );

			if( !_p.stop_traversing ){
				if( structure.modify_children_structures ){
					modify_children_structures = JL.functions.concat_functions([
						modify_children_structures,
						structure.modify_children_structures
					]);
				}

				structure.modify_children_structures = modify_children_structures;
			}
		}
	}

	if( structure.lbl_classes ) lbl_classes += ' ' + structure.lbl_classes;
	if( structure.val_classes ) val_classes += ' ' + structure.val_classes;

	if( structure.is_single_line_arr ){
		has_lbl = false;
		var ele_idx = path[ path.length - 1 ];
		tr_start = ( ele_idx !== 0                                ? '' : '<table><tr>'   );
		tr_end   = ( ele_idx !== structure.single_line_length - 1 ? '' : '</tr></table>' );
		val_classes += ' single-line-arr-val is-single-line';
	}

	if( structure.is_tabular_layout ){
		has_lbl = false;
		var ele_idx = structure._ele_idx;
		tr_start = '';
		tr_end   = ( ele_idx !== structure.single_line_length - 1 ? '' : '</tr>' );
		val_classes += ' is-single-line';
	}

	if( structure.ui_row !== undefined ){
		has_lbl  = false;
		tr_start = '';
		tr_end   = '';
		val_classes += ' is-single-line';
	}

	if( structure.has_label ){
		has_lbl = true;
	}

	if( structure.no_label ){
		has_lbl = false;
	}

	var label    = ( structure.label !== undefined ? structure.label : structure.key );
	var contents = '';

	if( structure.key !== undefined ) path.push( structure.key );

	if( label === undefined )  label = path[ path.length - 1 ];

	if( value === undefined && !structure.optional ){
		if     ( structure.get_default           ) value = structure.get_default.apply( self.value, [{ structure, json_edit : this, }] );
		else if( structure.default !== undefined ) value = structure.default;

		if( structure.type == 'webgl.graphics_object' ){
			if( !JL.functions.is_int( value ) ){
				value = JL.webgl.ui.item.edit.index_graphics_object( value );
			}
		}

		if( value !== undefined ) JL.functions.set_nested_object( this.value, path, value );
	}

	var id = this.get_id( path );

	var id_lbl = 'lbl-' + id;
	var id_val = 'val-' + id;

	var collapse_id = 'collapse-' + id;

	structure.collapsed = ( JL.json_edit.collapse_states[ collapse_id ] !== undefined ? JL.json_edit.collapse_states[ collapse_id ] : structure.collapsed );

	if( value === undefined && structure.optional ){
		var add_id = this.get_id( path, { prefix : 'add' } );

		contents = '<div id="' + add_id + '" class="add-value">+</div>';

		this.add_event( 'click', add_id, path, function( e ){
			self.set_value({ path, value : self.get_default_value( Object.assign( { turn_optional_on : 1, }, structure ) ), type : structure.type, structure });

			if( structure.type == 'arr' ){
				var is_array_of_vals = JL.functions.is_object( structure.structure );
				self.arr_add_new_entry({ structure, path, is_array_of_vals, });
			}

			self.draw();
		} );

	}
	else{
		var get_on_change_value = function( p ){ return $( p.event.target ).val(); };
		var on_change           = function( p ){ self.set_value({ path, value : p.value, type : structure.type, structure, set_selected : 1 }); };

		switch( structure.type ){
			case 'arr':
				var add_end_id = this.get_id( path, { prefix : 'add' } );

				var is_array_of_vals = JL.functions.is_object( structure.structure ); // includes array_of_arrays
				var is_array_of_objs = JL.functions.is_array(  structure.structure );

				var is_single_line_arr = false;
				var is_tabular_layout  = false;
				try{
					if( is_array_of_vals ){
						if(
							(
								[ 'float', 'int', 'str', 'webgl.graphics_object' ].includes( structure.structure.type ) &&
								structure.length !== undefined &&
								structure.length <= 4
							) ||
							structure.force_single_line_arr
						){
							is_single_line_arr                     = true;
							structure.structure.is_single_line_arr = true;
							structure.structure.single_line_length = structure.length;
							if( structure.max_vals_to_display !== undefined ){
								structure.structure.single_line_length = Math.min( structure.structure.single_line_length, structure.max_vals_to_display );
							}
						}
					}
					else if( is_array_of_objs ){
						if(
							structure.structure.length <= 4 &&
							!structure.structure.find(function( s ){
								return ( ![ 'float', 'int', 'bool', 'str', 'webgl.graphics_object' ].includes( s.type ) || s.structure );
							}) ||
							structure.force_single_line_arr
						){
							is_tabular_layout = true;
							structure.structure.forEach(function( s, i ){
								s.is_tabular_layout  = true;
								s._ele_idx           = i;
								s.single_line_length = structure.structure.length;
								if( structure.max_vals_to_display !== undefined ){
									s.single_line_length = Math.min( s.single_line_length, structure.max_vals_to_display );
								}
							});
						}
					}
				}
				catch(e){}

				value = value || [];

				if( is_array_of_vals ){
					if( structure.length !== undefined ){
						if( value.length != structure.length ){
							if ( value.length < structure.length ){
								value = value.concat(
									JL.functions.get_filled_array(
										this.get_default_value( structure.structure ),
										structure.length - value.length
									)
								);
							}
							else{ value = value.slice( 0, structure.length ); }
							JL.functions.set_nested_object( this.value, path, value );
						}
					}
				}

				this.add_event( 'click', add_end_id, path, function( e ){
					self.arr_add_new_entry({ structure, path, is_array_of_vals, });
				} );

				if( is_array_of_objs ){
					if( !( structure._entry_collapse_statuses || structure._no_collapsible_entries ) ){
						if( structure.structure.find( s => s.show_while_collapsed ) ){
							structure._entry_collapse_statuses = JL.functions.get_filled_array( structure.entries_collapsed || 0, value.length );
						}
						else{
							structure._no_collapsible_entries = true;
						}
					}
				}

				var vals_to_display = value;
				if( structure.max_vals_to_display !== undefined ) vals_to_display = value.slice( 0, structure.max_vals_to_display );

				contents = vals_to_display.map(function( val, val_idx ){
					var child_structure;
					if( structure.structure ){
						if( is_array_of_objs ) child_structure = $.extend( true, [], structure.structure );
						else                   child_structure = $.extend( true, {}, structure.structure );
					}
					else{
						child_structure = { key : val_idx, type : structure.val_type };
					}
					var child_path = ( path || [] ).concat([ val_idx ]);

					var select_entry = {
						structure,
						is_array_of_vals,
						path_str    : child_path.join('/'),
						path        : child_path.slice(),
						parent_path :       path.slice(),
						index       : val_idx,
						// 2024-12-20
						// copy_val    : $.extend( true, {}, val ),
					};

					var select_id = self.get_id( child_path, { prefix : 'select' } );
					var delete_id = self.get_id( child_path, { prefix : 'remove' } );

					var collapse_id, is_collapsed;
					if( structure._entry_collapse_statuses ){
						collapse_id  = self.get_id( child_path, { prefix : 'collapse' } );
						is_collapsed = structure._entry_collapse_statuses[ val_idx ];
					}

					self.add_event( 'click', delete_id, child_path, function( e ){
						self.arr_delete_entry({ path : child_path, arr_structure : structure });
					} );

					self.add_event( 'click', select_id, child_path, function( e ){
						self.arr_toggle_select_entry({
							id    : select_id,
							entry : select_entry,
						});
					} );

					if( !structure.no_sort ){
						self.right_click_menus.push({ target : '#' + select_id, options : [
							{ label : 'Move selected up', inputs : [{ type : 'number', value : 1 }], onclick : function( e ){
								self.arr_select_this_if_necessary({ select_id, select_entry, command : function(){
									self.arr_move_selected_entries({ offset : -Number( $( e.inputs[ 0 ] ).val() ) });
								} });
							} },
							{ label : 'Move selected down', inputs : [{ type : 'number', value : 1 }], onclick : function( e ){
								self.arr_select_this_if_necessary({ select_id, select_entry, command : function(){
									self.arr_move_selected_entries({ offset :  Number( $( e.inputs[ 0 ] ).val() ) });
								} });
							} },
						], });
					}

					if( !structure.no_add_new_entry ){
						self.right_click_menus.push({ target : '#' + select_id, options : [
							{ label : 'Add new entry (above selected)', onclick : function(){
								self.arr_select_this_if_necessary({ select_id, select_entry, command : function(){
									self.arr_add_new_selected_entries({ offset : -1 });
								} });
							} },
							{ label : 'Add new entry (below selected)', onclick : function(){
								self.arr_select_this_if_necessary({ select_id, select_entry, command : function(){
									self.arr_add_new_selected_entries({ offset : 0 });
								} });
							} },
						], });
					}

					self.right_click_menus.push({ target : '#' + select_id, options : [
						{ label : 'Copy selected', onclick : function(){
							self.arr_select_this_if_necessary({ select_id, select_entry, command : ( !structure.custom_copy ?
								function(){ self.arr_copy_selected_entries(); } :
								function( _p ){
									for( var entry of _p.selected_entries ){
										structure.custom_copy( Object.assign( {}, _p, { entry, json_edit : self, value : self.get_value( entry.path ), } ) );
									}
									if( structure.custom_post_copy ){
										structure.custom_post_copy( Object.assign( {}, _p, { json_edit : self, } ) );
									}
								}
							) });
						} },
						{ label : 'Delete selected', onclick : function(){
							self.arr_select_this_if_necessary({ select_id, select_entry, command : function(){
							 	self.arr_delete_selected_entries();
							} });
						} },
						{ label : 'Select all', onclick : function( e ){
							self.arr_select_all({ path : path.slice() });
						} },
						{ label : 'Clear selection', onclick : function(){
							self.arr_clear_selection();
						} },
					], });

					var is_selected = self.arr_is_entry_selected( select_entry );

					var arr_entry_controls = [
						'<td id="' + select_id + '" class="array-item-button noselect select-item ' + ( is_selected ? 'active' : '' ) + '">&#x2713;</td>',
						'<td id="' + delete_id + '" class="array-item-button noselect delete-item">-</td>',
					];

					if( structure._entry_collapse_statuses ){
						arr_entry_controls.push(
							'<td id="' + collapse_id + '" class="array-item-button collapse-item">' + 
								( is_collapsed ? '&gt;' : '&lt;' ) + 
							'</td>'
						);

						self.add_event( 'click', collapse_id, child_path, function( e ){
							self.arr_toggle_collapse_entry({ path : select_entry.path, });
						} );

						var options = [
							{ label : 'Collapse selected', onclick : function( e ){
								self.arr_select_this_if_necessary({ select_id, select_entry, command : function(){
									self.arr_collapse_selected_entries({ path });
								} });
							} },
							{ label : 'Expand selected', onclick : function( e ){
								self.arr_select_this_if_necessary({ select_id, select_entry, command : function(){
									self.arr_expand_selected_entries({ path });
								} });
							} },
						];

						if( structure._entry_collapse_statuses.find( x => !x ) !== undefined ) options.push({ label : 'Collapse all', onclick : function( e ){ self.arr_collapse_all({ path }); } });
						if( structure._entry_collapse_statuses.find( x =>  x ) !== undefined ) options.push({ label : 'Expand all'  , onclick : function( e ){ self.arr_expand_all({   path }); } });

						self.right_click_menus.push({ target : '#' + collapse_id, options, });
					}

					var html_arr = '';

					if( is_tabular_layout ){
						if( !val_idx ) html_arr += '<table><tr>';
					}
					else if( !is_single_line_arr ) html_arr += '<table><tr>';

					if( !( structure.length !== undefined || is_tabular_layout ) ) html_arr += arr_entry_controls.join('');

					if( !is_single_line_arr && !is_tabular_layout ) html_arr += '<td class="child-arr"><table>';

					if( is_tabular_layout ){
						if( val_idx == 0 ){
							var has_table_header = structure.structure.every( s => !s.no_label );
							if( has_table_header ){
								html_arr += arr_entry_controls.map( x => '<th></th>' ).join('') +
									structure.structure.map(function( s ){
										return '<th>' + ( s.label !== undefined ? s.label : s.key ) + '</th>';
									}).join('') +
								'</tr><tr>';
							}
						}
						html_arr += arr_entry_controls.join('');
					}

					if( JL.functions.is_array( child_structure ) ){
						html_arr += self.get_html_level({
							path,
							structure      : child_structure,
							get_html_field : function( child_field_structure ){
								return self.get_html({
									value            : val[ child_field_structure.key ],
									structure        : child_field_structure,
									path             : child_path.slice(),
									parent_structure : structure,
								});
							},
						});
					}
					else{
						html_arr += self.get_html({
							value            : val,
							structure        : child_structure,
							path             : child_path.slice(),
							parent_structure : structure,
						});
					}

					if( is_tabular_layout ){
						if( val_idx == value.length - 1 ) html_arr += '</tr></table>';
					}
					else if( !is_single_line_arr ) html_arr += '</table></td></tr></table>';

					return html_arr;
				}).join('') +
				( structure.length !== undefined || structure.no_append ? '' : 
					'<div id="' + add_end_id + '" class="add-value">+</div>'
				);

				// 2025-10-20 -- trying to add graph support for arrays of arrays (ex: g_o.polygon points).
				// if( is_array_of_objs ){
					if( structure.graph ){
						var graph_id = self.get_id( path, { prefix : 'graph' } );

						contents = '<svg id="' + graph_id + '" class="jl-json-edit-graph jl-graph"></svg>' + contents;

						if( structure.graph.x === undefined ) structure.graph.x = 'x';
						if( structure.graph.y === undefined ) structure.graph.y = 'y';

						var max_abs_val  = 0;
						var graph_values = value.map(function( entry ){
							var x = entry[ structure.graph.x ];
							var y = entry[ structure.graph.y ];
							max_abs_val = Math.max( Math.abs( x ), Math.abs( y ), max_abs_val );
							return { x, y };
						});

						if( !this.graph_config[ graph_id ] ) this.graph_config[ graph_id ] = {};
						if(  this.graph_config[ graph_id ].graph_radius === undefined ){
							this.graph_config[ graph_id ].graph_radius = Math.max( 10, Math.ceil( 1.5 * max_abs_val ) );
						}

						var graph_radius = this.graph_config[ graph_id ].graph_radius;

						this.graphs.push({ type : structure.graph.type || 'scatter_plot', args : {
							id           : graph_id,
							grid_lines   : {},
							data         : graph_values,
							// tooltip  : {
							// 	header : function( d ){ return [ d.x0, d.x1 ].join(' - '); },
							// 	value  : function( d ){ return JSON.stringify( d ); },
							// },
							min_x        : ( structure.graph.invert_x ?  1 : -1 ) * graph_radius,
							max_x        : ( structure.graph.invert_x ? -1 :  1 ) * graph_radius,
							min_y        : ( structure.graph.invert_y ?  1 : -1 ) * graph_radius,
							max_y        : ( structure.graph.invert_y ? -1 :  1 ) * graph_radius,
							margins      : { top: 15, right: 15, bottom: 25, left: 25 },
							x_axis       : { num_ticks : 4 },
							y_axis       : { num_ticks : 4 },
							graph_width  : 150,
							graph_height : 150,
							dot_classes  : 'dot',
							mouse        : [{
								left_click : function( p ){
									var assign_to_default = {};
									assign_to_default[ structure.graph.x ] = JL.functions.round( p.val.x );
									assign_to_default[ structure.graph.y ] = JL.functions.round( p.val.y );
									self.arr_add_new_entry({ structure, path, is_array_of_vals, assign_to_default });
								},
								right_click : function( p ){
									var click_x = JL.functions.round( p.val.x );
									var click_y = JL.functions.round( p.val.y );

									var closest_point_idx  = -1;
									var closest_point_dist = Infinity;
									for( var i = 0; i < value.length; i++ ){
										var entry = value[ i ];
										var dist = Math.abs( entry[ structure.graph.x ] - click_x ) + 
											   Math.abs( entry[ structure.graph.y ] - click_y );

										if( dist < 2 ){
											if( dist <= closest_point_dist ){
												closest_point_idx  = i;
												closest_point_dist = dist;
											}
										}
									}

									if( closest_point_idx != -1 ){
										self.arr_delete_entry({
											path          : path.concat([ closest_point_idx ]),
											arr_structure : structure,
										});
									}
								},
								wheel : function( p ){
									if( p.spin.y ){
										self.graph_config[ graph_id ].graph_radius = Math.max( self.graph_config[ graph_id ].graph_radius + ( p.spin.y / 50 ), 1 );
										self.draw();
									}
								},
							}],
						}, });

						if( [ 'line_graph' ].includes( structure.graph.type ) ){
							right_click_options.lbl.push(
								{
									label   : 'Radially expand points (+)',
									inputs  : [{ type : 'number', value : 0 }],
									onclick : function( e, p ){
										var val = $( e.inputs[ 0 ] ).val();

										var key_x = p.structure.graph.x;
										var key_y = p.structure.graph.y;

										var already_traversed = [];
										var unique_points = p.value.filter(function( pt ){
											var pt_id = pt[ key_x ] + '_' + pt[ key_y ];
											if( already_traversed.includes( pt_id ) ) return false;
											already_traversed.push( pt_id );
											return true;
										});

										var center_x = 0;
										var center_z = 0;
										unique_points.forEach(function( pt ){
											center_x += Number( pt[ key_x ] );
											center_z += Number( pt[ key_y ] );
										});
										center_x /= unique_points.length;
										center_z /= unique_points.length;

										p.value.forEach(function( pt ){
											if( val > 0 || Math.abs( pt[ key_x ] - center_x ) > 1 ) pt[ key_x ] = Number( pt[ key_x ] ) + ( pt[ key_x ] >= center_x ? 1 : -1 ) * val;
											if( val > 0 || Math.abs( pt[ key_y ] - center_z ) > 1 ) pt[ key_y ] = Number( pt[ key_y ] ) + ( pt[ key_y ] >= center_z ? 1 : -1 ) * val;
										});

										p.set_value( p.value );
									}
								},
								{
									label   : 'Scale points WRT origin (*)',
									inputs  : [{ type : 'number', value : 1 }],
									onclick : function( e, p ){
										var val = $( e.inputs[ 0 ] ).val();

										var key_x = p.structure.graph.x;
										var key_y = p.structure.graph.y;

										p.value.forEach(function( pt ){
											pt[ key_x ] = Number( pt[ key_x ] ) * val;
											pt[ key_y ] = Number( pt[ key_y ] ) * val;
										});

										p.set_value( p.value );
									}
								}
							);
						}
					}
				// }

				right_click_options.lbl.push({ label : 'Reverse', onclick : function(){
					self.set_value({ path, value : value.reverse() });

					var arr_structure = self.get_structure( path );
					if( arr_structure._entry_collapse_statuses ){
						arr_structure._entry_collapse_statuses = arr_structure._entry_collapse_statuses.reverse();
					}

					self.draw();
				} });

				right_click_options.lbl.push({ label : 'Shuffle', onclick : function(){
					var shuffled_indices = JL.functions.shuffle_array( JL.functions.get_range_array( 0, value.length - 1 ) );

					self.set_value({ path, value : JL.functions.sort_from_indices_array( value, shuffled_indices ) });

					var arr_structure = self.get_structure( path );
					if( arr_structure._entry_collapse_statuses ){
						arr_structure._entry_collapse_statuses = JL.functions.sort_from_indices_array( arr_structure._entry_collapse_statuses, shuffled_indices );
					}

					self.draw();
				} });

				right_click_options.lbl.push({ label : 'Delete All Entries', onclick : function(){
					self.set_value({ path, value : [] });
					self.draw();
				} });

				if( JL.functions.is_array( structure.structure ) ){
					var o = {};
					for( var s of structure.structure ) o[ s.key ] = s.type;
					if( [ 'x', 'y', 'z' ].filter( k => ( o[ k ] == 'float' ) ).length >= 2 ){
						right_click_options.lbl.push({
							label   : 'Smooth curve [new_num_points]',
							inputs  : [{ type : 'number', value : 10 }],
							onclick : function( e, p ){
								p.set_value( JL.functions.get_smoothed_curve_points( p.value, Number( $( e.inputs[ 0 ] ).val() ) ) );
							}
						});
					}
				}

				break;
			case 'bool':
				get_on_change_value = function( p ){ return $( p.event.target ).is( ':checked' ); };
				contents = '<input id="' + id + '" type="checkbox" ' + 
							( value ? ' checked ' : '' ) + 
							' />';
				break;
			case 'custom':
				if( structure.edit_value ){
					this.add_event( 'click', id, path, function(){
						structure.edit_value( path, value );
					});
				}

				var name = '&lt;no name&gt;';
				try{ name = structure.get_value_name( value ); } catch(e){}

				contents = '<div id="' + id + '" class="edit-custom-button" >' + name + '</div>';
				break;
			case 'datetime':
				if( value instanceof Date ){
					value = JL.functions.strftime( '%Y-%m-%d %H:%M:%S', value );
					JL.functions.set_nested_object( this.value, path, value );
				}

				var value_dt = new Date( value );
				if( !JL.functions.is_valid_date_object( value_dt ) ){
					value_dt = new Date();

					value = JL.functions.strftime( '%Y-%m-%d %H:%M:%S', value_dt );
					JL.functions.set_nested_object( this.value, path, value );
				}

				no_change_event = true;

				this.datetime_pickers.push({
					parent    : { id : '#' + id, },
					value     : value_dt,
					on_change : function( dp ){
						var new_dt = dp.get_value();
						on_change({
							prev_value : JL.functions.strftime( '%Y-%m-%d %H:%M:%S', value_dt ),
							value      : JL.functions.strftime( '%Y-%m-%d %H:%M:%S', new_dt   ),
						});
					},
				});

				contents = '<div id="' + id + '"></div>';
				break;
			case 'webgl.space_object':
			case 'dropdown':
				var options = structure.options;
				if( options === undefined && structure.get_options ) options = structure.get_options({ value : this.value, json_edit : this, });

				if( structure.type == 'webgl.space_object' ) options = this.get_webgl_space_object_options( structure );

				structure._options = options;

				var  is_selected = structure.is_selected;
				if( !is_selected ) is_selected = function( curr_val, selected_val ){ return ( curr_val === selected_val ); };

				get_on_change_value = function( p ){
					var val = $( p.event.target ).val();
					if     ( JL.functions.is_int( val ) ) val = parseInt( val );
					else if( !isNaN( val )              ) val = Number(   val );
					return val;
				};

				contents = '<select id="' + id + '" >' +
					( options || [] ).map(function( o ){
						var option = ( JL.functions.is_object( o ) ? o : { name : o } );
						var val = ( option.hasOwnProperty( 'value' ) ? option.value : option.name );
						return '<option value=' + JSON.stringify( val ) + ' ' + ( is_selected( val, value ) ? 'selected' : '' ) + '>' +
							option.name +
						'</option>';
					}).join('') +
				'</select>';
				break;
			case 'webgl.graphics_object':
				var value_g_o = JL.webgl.functions.get_graphics_object( value );

				try     { var value_id = value_g_o._id; }
				catch(e){ var value_id; }

				on_change = function( p ){
					var val_str = p.value;
					var val_g_o;
					if( val_str != 'No graphics_object' ){
						var m = JL.webgl.functions.get_graphics_object( val_str );
						if( m === undefined ){
							var lbl = val_str.split('/');

							var g_o_params = {
								label    : lbl,
								async    : false,
								filename : JL.webgl.dir.models + '/' + val_str + '/model.obj',
								texture  : JL.webgl.dir.models + '/' + val_str + '/texture.png',
							};

							if( structure.assign_graphics_object_params ){
								JL.functions.recursive_assign( g_o_params, structure.assign_graphics_object_params({
									on_change : p,
									path, structure, value, json_edit : self, 
								}) );
							}

							var loaded_g_o = new JL.webgl.graphics_object.obj( g_o_params );
							m = JL.webgl.functions.get_graphics_object( val_str );
						}
						val_g_o = JL.webgl.ui.item.edit.index_graphics_object( m );
					}
					else{ val_g_o = val_str; }

					self.set_value({ path, value : val_g_o, });
					self.draw();
				};

				right_click_options.contents.push({ label : 'Create New Graphics Object', onclick : function(){
					self.set_value({ path,
						value : JL.webgl.ui.item.edit.index_graphics_object(
							JL.webgl.ui.item.edit.item_types.graphics_object.add_graphics_object({ no_ui : true })
						),
					});
					self.draw();
				} });

				if( value && value != 'No graphics_object' ){
					right_click_options.contents.push({ label : 'Edit Graphics Object', onclick : function(){
						// 2025-10-03 -- trying to get editing to work when going directly from one g_o to another.
						// 	-Ex: editing a repeating_g_o from a g_o.polygon.
						if(    !JL.webgl.ui.item.edit.item_types.graphics_object.is_editing ){
							JL.webgl.ui.item.edit.item_types.graphics_object.draw_overview();
						}
						// JL.webgl.ui.item.edit.item_types.graphics_object.draw_overview();

						JL.webgl.ui.item.edit.item_types.graphics_object.edit_graphics_object_by_path( value_g_o._path, {
							back_button : {
								onclick : 'JL.webgl.ui.item.edit.item_types.space_object.edit();',
							},
						});
					} });

					right_click_options.contents.push({ label : 'Use Clone of Graphics Object', onclick : function(){
						self.set_value({ path,
							value : JL.webgl.ui.item.edit.index_graphics_object(
								JL.webgl.functions.get_graphics_object( value ).copy({ unique_label : true })
							),
						});
						self.draw();
					} });
				}

				var options = this.get_graphics_object_options({ structure, });

				// 2025-11-10 -- trying to change input from dropdown to text field with autocomplete.
				// var  is_selected = structure.is_selected;
				// if( !is_selected ) is_selected = function( curr_val, selected_val ){ return ( curr_val === selected_val ); };
				// contents = '<select id="' + id + '" >' +
				// 	( options || [] ).map(function( option ){
				// 		return '<option value="' + option + '" ' + ( is_selected( option, value_id ) ? 'selected' : '' ) + '>' +
				// 			option +
				// 		'</option>';
				// 	}).join('') +
				// '</select>';

				contents = this.get_input_html(
					value_id,
					Object.assign(
						{ autocomplete : options, classes : 'webgl-graphics-object' },
						JL.functions.deep_copy( structure )
					),
					id
				);

				break;
			case 'mat':
				value = value || {};
				var mat_structure = $.extend( true, [], structure.structure || [] ).filter( s => s.key == 'elements' ).slice( 0, 1 );

				var expand_button = '';
				if( structure.is_tabular_layout ){ // If obj is in an array.
					var is_collapsible = ( structure.collapsed !== undefined );
					if( structure.optional || is_collapsible ){
						var obj_collapse_id = 'obj-collapse-' + id;
						expand_button = '<tr><td id="' + obj_collapse_id + '" class="array-item-button collapse-item" rowspan=' + ( mat_structure.length + 1 ) + '>' + 
							( is_collapsible ? '&lt;' : '' ) + 
						'</td></tr>';

						if( structure.optional ){
							self.right_click_menus.push({ target : '#' + obj_collapse_id, options : [
								{ label : 'Delete value', onclick : function(){
									self.set_value({ path, value : undefined, type : structure.type, structure });
									self.draw();
								} },
							], });
						}

						if( is_collapsible ){
							self.add_event( 'click', obj_collapse_id, path, function(){
								self.collapse_section({ id_val, id : collapse_id, val : true, });
							} );
						}
					}
				}

				contents = '<table>' + expand_button +
					self.get_html_level({
						path,
						structure      : mat_structure,
						get_html_field : function( field_structure ){
							var key = field_structure.key;
							try     { var val = value[ key ]; }
							catch(e){ var val; }
							return self.get_html({
								value            : val,
								structure        : field_structure,
								path             : path.slice(),
								parent_structure : structure, 
							});
						},
					}) +
				'</table>';
				break;
			case 'obj':
				value = value || {};
				var obj_structure = $.extend( true, [], structure.structure || [] );

				var structured_keys = obj_structure.map( x => x.key );

				Object.keys( value ).forEach(function( key ){
					if( !structured_keys.includes( key ) ){
						var derived_structure = self.guess_structure( key, value[ key ] );
						derived_structure.right_click = { lbl : [
							{ label : 'Delete key', onclick : function(){
								self.set_value({
									path,
									value     : undefined,
									type      : derived_structure.type,
									structure : derived_structure,
								});
								self.draw();
							} },
						] };
						obj_structure.push( derived_structure );
					}
				});

				right_click_options.lbl.push({
					label   : 'Add key',
					inputs  : [{ type : 'text', placeholder : 'new_key' }],
					onclick : function( e, p ){
						p.value[ $( e.inputs[ 0 ] ).val() ] = '';
						p.set_value( p.value );
					},
				});

				var expand_button = '';
				if( structure.is_tabular_layout ){ // If obj is in an array.
					var is_collapsible = ( structure.collapsed !== undefined );
					if( structure.optional || is_collapsible ){
						var obj_collapse_id = 'obj-collapse-' + id;
						expand_button = '<tr><td id="' + obj_collapse_id + '" class="array-item-button collapse-item" rowspan=' + ( obj_structure.length + 1 ) + '>' + 
							( is_collapsible ? '&lt;' : '' ) + 
						'</td></tr>';

						if( structure.optional ){
							self.right_click_menus.push({ target : '#' + obj_collapse_id, options : [
								{ label : 'Delete value', onclick : function(){
									self.set_value({ path, value : undefined, type : structure.type, structure });
									self.draw();
								} },
							], });
						}

						if( is_collapsible ){
							self.add_event( 'click', obj_collapse_id, path, function(){
								self.collapse_section({ id_val, id : collapse_id, val : true, });
							} );
						}
					}
				}

				contents = '<table>' + expand_button +
					self.get_html_level({
						path,
						structure      : obj_structure,
						get_html_field : function( field_structure ){
							var key = field_structure.key;
							try     { var val = value[ key ]; }
							catch(e){ var val; }
							return self.get_html({
								value            : val,
								structure        : field_structure,
								path             : path.slice(),
								parent_structure : structure, 
							});
						},
					}) +
				'</table>';
				break;
			case 'function':
				contents = '<textarea id="' + id + '" class="' + ( structure.classes || '' ) + '" ' + 
					'onkeydown="if( event.key == \'Tab\' ){ event.preventDefault(); var start = this.selectionStart; var end = this.selectionEnd; this.value = this.value.substring( 0, start ) + \'\t\' + this.value.substring( end ); this.selectionStart = this.selectionEnd = start + 1; }"' + 
					'>' + 
					( value !== undefined ? value.toString() : 'function(){\n}' ) +
				'</textarea>';
				break;
			case 'float':
				contents = this.get_input_html(   Number( value ), Object.assign( $.extend( true, [], structure ), { type : 'number' } ), id );
				break;
			case 'int':
				contents = this.get_input_html( parseInt( value ), Object.assign( $.extend( true, [], structure ), { type : 'number' } ), id );
				break;
			case 'str':
			default:
				contents = this.get_input_html( value, structure, id );
				break;
		}

		if( !no_change_event ){
			this.add_event( 'change', id, path, function( event ){
				var p = { event };
				p.prev_value = value;
				p.value      = get_on_change_value( p );

				if( structure.convert_to_cpu ) p.value = structure.convert_to_cpu( p.value, { structure, path } );
				// if( structure.pre_change ){
				// 	structure.pre_change( p );
				// }
				on_change( p );
				// if( structure.post_change ) structure.post_change( p );
			});
		}

		if( structure.webgl_camera ){
			this.add_event( 'focus', id, path, function(){
				JL.webgl.ui.item.edit.reset_camera();
				JL.webgl.active_camera.set_values( structure.webgl_camera );
			});
			if( structure.slider ){
				this.add_event( 'click', 'slider-' + id, path, function(){
					JL.webgl.ui.item.edit.reset_camera();
					JL.webgl.active_camera.set_values( structure.webgl_camera );
				});
			}
		}
		if( structure.on_focus ) this.add_event( 'focus', id, path, structure.on_focus );

		if( ![ 'min', 'max' ].map( x => structure[ x ] ).includes( undefined ) ){
			if( JL.functions.is_int( path[ path.length - 2 ] ) ){ // values are in array
				right_click_options.contents.push({ label : 'Randomize selected values', onclick : function(){
					self.arr_select_this_if_necessary({ path : path.slice( 0, -1 ), command : function(){
						self.arr_randomize_selected_entries({ path, type : structure.type, structure });
					} });
				} });
			}
			else{
				right_click_options.contents.push({ label : 'Randomize value', onclick : function(){
					self.randomize_value({ path, type : structure.type, structure });
					self.draw();
				} });
			}
		}

		if( !structure.no_edit && JL.functions.is_int( path[ path.length - 2 ] ) && [ 'float', 'int' ].includes( structure.type ) ){
			right_click_options.contents = right_click_options.contents.concat([
				{ label : 'Multiply selected values', inputs : [{ type : 'number', value : 1 }], onclick : function( e, p ){
					var val = Number( $( e.inputs[ 0 ] ).val() );

					var key = p.key;
					if( key === undefined ) key = path[ path.length - 1 ];

					self.arr_multiply_selected_entries({ key, val, no_draw : true });

					if( !self.arr_is_entry_selected( p.path.slice( 0, -1 ).join('/') ) ) p.set_value( p.value * val );
					else                                                                 self.draw({ preserve_selected : true });
				} },
				{ label : 'Increment selected values', inputs : [{ type : 'number', value : 0 }], onclick : function( e, p ){
					var val = Number( $( e.inputs[ 0 ] ).val() );

					var key = p.key;
					if( key === undefined ) key = path[ path.length - 1 ];

					self.arr_increment_selected_entries({ key, val, no_draw : true });

					if( !self.arr_is_entry_selected( p.path.slice( 0, -1 ).join('/') ) ) p.set_value( p.value + val );
					else                                                                 self.draw({ preserve_selected : true });
				} },
			]);
		}

		if( JL.functions.is_int( path[ path.length - 2 ] ) && ![ 'obj', 'arr' ].includes( structure.type ) ){
			var arr_structure = this.get_structure( path.slice( 0, path.length - 1 ) );
			if( arr_structure.structure ){
				if( JL.functions.is_array( arr_structure.structure ) || arr_structure.structure.type == 'obj' ){ // Array of objs
					if( !arr_structure.no_sort ){
						right_click_options.contents.push({ label : 'Sort array by value',
							selects : [{ options : [{ label : 'Low -> High', value : 1 }, { label : 'High -> Low', value : -1 }] }],
							onclick : function( e, p ){
								var sort_dir = Number( $( e.selects[ 0 ] ).val() );

								var key = path[ path.length - 1 ];

								self.arr_sort({
									path : path.slice( 0, path.length - 2 ),
									sort : function( a, b ){
										return sort_dir * ( a[ key ] > b[ key ] ? 1 : -1 );
									},
								});
							},
						});
					}

					if( !structure.no_edit && [ 'int', 'float', ].includes( structure.type ) ){
						right_click_options.contents.push({ label : 'Range copy selected objects [min/max/step]',
							inputs  : [
								{ type : 'number', value :  0 },
								{ type : 'number', value : 10 },
								{ type : 'number', value :  1 },
							],
							onclick : function( e, p ){
								self.arr_range_copy_selected_entries({
									path,
									key  : path[ path.length - 1 ],
									min  : Number( $( e.inputs[ 0 ] ).val() ),
									max  : Number( $( e.inputs[ 1 ] ).val() ),
									step : Number( $( e.inputs[ 2 ] ).val() ),
								});
							},
						});
					}
				}
			}
			right_click_options.contents.push({ label : 'Select all with same value',
				selects : [{ options : [{ label : 'Clear prev selected', value : 'clear' }, { label : 'Add to selection', value : 'add' }] }],
				onclick : function( e, p ){
					switch( $( e.selects[ 0 ] ).val() ){
						case 'clear':
							self.arr_clear_selection();
							break;
					}

					var arr_path = path.slice( 0, path.length - 2 );

					var arr = self.get_value( arr_path );

					var key = path[ path.length - 1 ];

					arr.forEach(function( entry, i ){
						var entry_path = ( arr_path || [] ).concat([ i ]);

						if( entry[ key ] == value ){
							if( !self.arr_is_entry_selected({ path_str : entry_path.join('/') }) ){
								$( '#' + self.get_id(                entry_path, { prefix : 'select' } ) ).trigger( 'click' );
							}
						}
					});
				}
			});
		}

		if( structure.default !== undefined || structure.get_default !== undefined ){
			right_click_options.lbl.push({ label : 'Reset to Default', onclick : function(){
				self.reset_to_default({ path, structure, });
			} });
		}

		if( structure.collapsed !== undefined ){
			contents = '<div id="' + collapse_id + '" class="collapse-toggle" onclick="$( \'#' + id_val + '\' ).toggleClass( \'collapsed\' );">EXPAND</div>' + contents;

			right_click_options.lbl.push({ label : 'Collapse section', onclick : function(){
				self.collapse_section({ id_val, id : collapse_id, val : true, });
			} });
		}

		if( structure.optional ){
			var option = { label : 'Delete value', onclick : function(){
				self.set_value({ path, value : undefined, type : structure.type, structure });
				self.draw();
			} };
			right_click_options.lbl.push(      option );
			right_click_options.contents.push( option );
		}
	}


	if( structure.left_click ){
		this.add_event( 'click', id_val, path, function(){
			structure.left_click({ value, path, structure, json_edit : self, });
		});
	}

	if( structure.right_click ){
		// 2025-09-16
		for( var k in structure.right_click ){
		// Object.keys( structure.right_click ).forEach(function( k ){
			var r_c = structure.right_click[ k ];
			if( r_c ){
				right_click_options[ k ] = right_click_options[ k ].concat(
					r_c.slice().filter( c => ( !c.condition || c.condition({
						structure, path, value, json_edit : self,
					}) ) )
				);
			}
		}
		// });
	}

	[
		{ key : 'contents', id          },
		{ key : 'lbl'     , id : id_lbl },
	].forEach(function( g ){
		if( right_click_options[ g.key ].length ){
			var options = right_click_options[ g.key ];
			options.forEach(function( o, i ){
				options[ i ].args = [{
					// Note: not sure why, but including 'structure' in the following causes a 'too much recursion' error when destroying the right_click_menu object. [2024-12-23]
					// 	-Using a deep_copy of structure might work. [2025-10-21]
					structure : JL.functions.deep_copy( structure ),
					value, path,
					key       : structure.key,
					json_edit : self,
					set_value : function( v ){
						self.set_value({ path, value : v, type : structure.type, structure });
						self.draw({ preserve_selected : true });
					},
				}];
			});
			this.right_click_menus.push({ target : '#' + g.id, options, });
		}
	}, this);

	if( structure.hidden ) return '';

	if( structure.collapsed ){
		if(
			!( structure.is_tabular_layout && structure.optional && value === undefined )
		){
			val_classes += ' collapsed';
		}
		this.add_event( 'click', collapse_id, path, function(){
			self.collapse_section({ id_val, id : collapse_id, val : false, });
		} );
	}

	return tr_start +
		( !has_lbl ? '' : '<td id="' + id_lbl + '" class="lbl ' + lbl_classes + '">' + label    + ( structure.added_lbl_html ? structure.added_lbl_html( value ) : '' ) + '</td>' ) +
		                  '<td id="' + id_val + '" class="val ' + val_classes + '">' + contents + ( structure.added_val_html ? structure.added_val_html( value ) : '' ) + '</td>'   +
	tr_end;
};

JL.json_edit.prototype.get_html_level = function( p ){
	var self = this;

	var prev_ui_row;

	var structure      = p.structure;
	var get_html_field = p.get_html_field;
	var path           = p.path || [];

	return this.sort_ui_rows( structure ).map(function( child_structure, i, fields ){
		var level_html = '';

		if( child_structure.ui_row !== undefined && child_structure.ui_row !== prev_ui_row ){
			level_html += '<tr><td colspan="2"><table class="ui-row-table"><tr>';
			var curr_idx   = i;
			var curr_field = fields[ curr_idx ];
			while( curr_idx <= fields.length - 1 && curr_field.ui_row == child_structure.ui_row ){
				if( !child_structure.hidden && !child_structure.no_label ){
					var id = 'lbl-' + self.get_id( path.slice().concat([ curr_field.key ]) );

					level_html += '<td id="' + id + '" class="lbl">' + 
						curr_field.key + 
					'</td>';
				}

				curr_idx++;
				curr_field = fields[ curr_idx ];
			}
			level_html += '</tr><tr>';
		}

		level_html += get_html_field( child_structure );

		if( child_structure.ui_row !== undefined ){
			if( i == fields.length - 1 ) level_html += '</tr></table></td></tr>';
			else{
				var next_ui_row = fields[ i + 1 ].ui_row;
				if( child_structure.ui_row !== next_ui_row ) level_html += '</tr></table></td></tr>';
			}
		}

		prev_ui_row = child_structure.ui_row;

		return level_html;
	}).join('');
};

JL.json_edit.prototype.draw = function( p ){
	var self = this;

	var p = p || {};

	if( this.right_click_menus ) this.right_click_menus.forEach(function( m ){ m.destroy(); });

	this.events            = [];
	this.datetime_pickers  = [];
	this.graphs            = [];
	this.sliders           = [];
	this.right_click_menus = [];

	if( !this.collapsed_array_entries ) this.collapsed_array_entries = [];

	if( !p.preserve_selected ) this.selected_array_entries = [];

	this.html_element = $(
		'<div class="jl-json-edit">' + 
			'<table>' +
				this.get_html_level({
					structure      : this.structure,
					get_html_field : function( structure ){
						try     { var value = self.value[ structure.key ]; }
						catch(e){ var value; }
						return self.get_html({ value, structure });
					},
				}) +
			'</table>' +
			'<div id="jl-json-edit-item-menu">' + 
				'<div class="contents"></div>' + 
			'</div>' +
		'</div>'
	);

	try     { var scroll_top = $( self.parent.id ).scrollTop() || 0; }
	catch(e){ var scroll_top = 0; }

	$( this.parent.id ).html( this.html_element );

	this.events.forEach(function( c ){
		$( '#' + c.id ).off( c.type ).on( c.type, c.fn );
	}, this);

	this.sliders.forEach(function( s ){
		new JL.slider( s );
	}, this);

	this.graphs.forEach(function( g ){
		JL.graph[ 'draw_' + g.type ]( g.args );
	}, this);

	for( var d of this.datetime_pickers ) new JL.datetime_picker( d );

	var right_click_menus = {};
	for( var r of this.right_click_menus ){
		if( !right_click_menus[ r.target ] ) right_click_menus[ r.target ] = r;
		else                                 right_click_menus[ r.target ].options = right_click_menus[ r.target ].options.concat( r.options );
	}
	this.right_click_menus = Object.values( right_click_menus );

	this.right_click_menus.forEach(function( c, i ){
		this.right_click_menus[ i ] = new JL.right_click_menu( c );

		var target = $( c.target );
		if( !c.target.startsWith( '#lbl' ) ) target = target.parent();
	}, this);

	// 2025-12-01 -- Not sure if this line is doing anything anymore. This line made g_o interface return to the top with every change (focus/blur was probably affecting scroll position).
	// $( '.jl-json-edit input.right' ).each(function(){ var ele = $( this )[0]; ele.selectionStart = 99999; ele.focus(); ele.blur(); });

	if( scroll_top ) $( self.parent.id ).scrollTop( scroll_top );
};

