try{ JL = JL; } catch(e){ JL = {}; }

JL.slider = function( p ){
	var self = this;

	if( JL.slider.add_css ) JL.slider.add_css();

	this.set_slider_container({ id : 'body' });

	[ 'input_already_exists', 'mouse', 'on_change', 'on_mousedown', 'value_map' ].forEach(function( k ){
		this[ k ] = p[ k ];
	}, this);

	[ 'input_container', 'slider_container' ].forEach(function( k ){
		if( p[ k ] ) this[ 'set_' + k ]( p[ k ] );
	}, this);

	this.min  = ( p.min  !== undefined ? p.min  :   0 );
	this.max  = ( p.max  !== undefined ? p.max  : 100 );
	this.step = p.step;

	if( !this.mouse ){
		try{ this.mouse = JL.webgl.ui.mouse; } catch(e){}
	}

	this.length = this.max - this.min;

	this.draw();

	this.set_value( p.default !== undefined ? p.default : this.min );
};

JL.slider.add_css = function(){
	JL.functions.add_css(`
		.jl-slider{
			padding-top:5px;
			height:15px;
			cursor : pointer;
			overflow:hidden;
		}

		.jl-slider .jl-slider-bar{
			background:rgba(78, 161, 255, 0.4);
			height:3px;
			position:relative;
		}

		.jl-slider .jl-slider-dot{
			position:absolute;
			background:#4ea1ff;
			border-radius:100px;
			width :8px;
			height:8px;
			top:0;
			bottom:0;
			left:0;
			margin:auto;
			margin-left:-4px;
		}
	`);

	delete this.add_css;
};

JL.slider.prototype.set_slider_container = function( slider_container ){
	this.slider_container = slider_container;

	this.value_id = this.slider_container.id + ' .jl-slider input';
};

JL.slider.prototype.set_input_container  = function( input_container ){
	this.input_container = input_container;

	this.input_id = this.input_container.id + ' input';
};

JL.slider.prototype.get_value = function(){
	var val = this.value;

	if( this.value_map ) val = this.value_map( val );

	return val;
};

JL.slider.prototype.set_value = function( val ){
	var curr_val = val; 
	if( this.step ) curr_val = this.step * Math.round( val / this.step );
	if( curr_val !== this.value ){
		this.value = curr_val;

		this.percent = ( this.value - this.min ) / this.length;

		$( this.slider_element ).find( '.jl-slider-dot' ).css({
			left : this.percent * 100 + '%',
		});

		if( this.input_id ){
			$( this.input_id ).val( this.value );
			if( this.input_already_exists ) $( this.input_id ).trigger( 'change' );
		}

		if( this.on_change ) this.on_change( this.value );
	}
};

JL.slider.prototype.calculate_value_from_mouse = function( x_pos ){
	var bar_element = $( this.slider_element ).children( '.jl-slider-bar' )[ 0 ];
	return this.length * Math.max( 0, Math.min( ( x_pos - $( bar_element ).offset().left ) / bar_element.offsetWidth, 1 ) ) + this.min;
};

JL.slider.prototype.draw = function(){
	var self = this;

	var on_change = function(){
		self.set_value( this.value );
	};

	var on_user_change = function(){
		self.set_value( this.value, true );
	};

	this.slider_element = $(
		'<div class="jl-slider">' + 
			'<div class="jl-slider-bar">' + 
				'<div class="jl-slider-dot"></div>' +
			'</div>' +
		'</div>'
	);

	$( this.slider_container.id ).append( this.slider_element );

	var on_drag = function( e ){
		self.set_value( self.calculate_value_from_mouse( e.clientX ) );
		try{ self.on_mousedown(); } catch(e){}
	};

	$( this.slider_element ).on( 'mousedown', function( e ){
		on_drag( e );

		if( self.mouse ){
			if( !self.is_dragging ){
				var on_stop = function(){
					self.mouse.pop_set_of_event_functions();

					delete self.is_dragging;
				};

				self.mouse.push_set_of_event_functions([
					{ type : 'move_global', fn : on_drag }, 
					{ type : 'out'        , fn : on_stop }, 
					{ type : 'up_left'    , fn : on_stop }, 
				]);

				self.is_dragging = true;
			}
		}
	} );

	if( this.input_container ){
		if( !this.input_already_exists ){
			this.input_element = $( '<input type="number" ></input>' );

			$( this.input_container.id ).html( this.input_element );
		}
		$( this.input_id ).on( 'change', on_user_change );
	}
};

