try{ JL = JL; } catch(e){ JL = {}; }

JL.sorted_array = function( p ){
	this.init( p );
};

JL.sorted_array.prototype.init = function( p ){
	var p = p || {};

	this.compare = p.compare || function(a,b){ return ( a < b ? -1 : a > b ? 1 : 0 ); };
	this.items   = [];

	if( p.sorted_items ) this.items = p.sorted_items.slice();

	if( p.items ){
		for( var item of p.items ) this.insert( item.key, item.val );
	}
};

JL.sorted_array.prototype.insert = function( key, val ){
	var i = 0;
	var j = this.items.length - 1;

	while( i <= j ){
		var mid = Math.floor( ( i + j ) / 2 );
		var c   = this.compare( key, this.items[ mid ].key );

		if( c === 0 ){
			this.items[ mid ].val = val;
			return;
		}

		if( c < 0 ) j = mid - 1;
		else        i = mid + 1;
	}

	this.items.splice( i, 0, { key, val } );
};

JL.sorted_array.prototype.remove = function( key ){
	var idx = this.find_index( key );
	if( idx !== undefined ) this.items.splice( idx, 1 );
};

JL.sorted_array.prototype.find_index = function( key ){
	if( key === undefined ) return;

	var i = 0;
	var j = this.items.length - 1;

	while( i <= j ){
		var mid = Math.floor( ( i + j ) / 2 );
		var c   = this.compare( key, this.items[ mid ].key );

		if( c === 0 ) return mid;

		if( c < 0 ) j = mid - 1;
		else        i = mid + 1;
	}
};

JL.sorted_array.prototype.find = function( key ){
	var idx = this.find_index( key );

	if( idx !== undefined ) return this.items[ idx ].val;
};

JL.sorted_array.prototype.get_array = function(){
	return this.items.map( x => x.val );
};

