//
// gluPerspective
//
function makePerspective(fovy, aspect, znear, zfar)
{
    var ymax = znear * Math.tan(fovy * Math.PI / 360.0);
    var ymin = -ymax;
    var xmin = ymin * aspect;
    var xmax = ymax * aspect;

    return makeFrustum(xmin, xmax, ymin, ymax, znear, zfar);
}

//
// glFrustum
//
function makeFrustum(left, right,
                     bottom, top,
                     znear, zfar)
{
    var X = 2*znear/(right-left);
    var Y = 2*znear/(top-bottom);
    var A = (right+left)/(right-left);
    var B = (top+bottom)/(top-bottom);
    var C = -(zfar+znear)/(zfar-znear);
    var D = -2*zfar*znear/(zfar-znear);

    return $M([[X, 0, A, 0],
               [0, Y, B, 0],
               [0, 0, C, D],
               [0, 0, -1, 0]]);
}

//
// glOrtho
//
function makeOrtho(left, right, bottom, top, znear, zfar){
    var tx = ( right + left   ) / ( left   - right );
    var ty = ( top   + bottom ) / ( bottom - top   );
    var tz = ( zfar  + znear  ) / ( znear  - zfar  );

    return $M([[2 / (right - left), 0, 0, tx],
           [0, 2 / (top - bottom), 0, ty],
           [0, 0, 2 / (znear - zfar), tz],
           [0, 0, 0, 1]]);
}

function Vector() {}
Vector.prototype = {
    modulus: function() {
        return Math.sqrt(this.dot(this))
    },
    dup: function() {
        return Vector.create(this.elements)
    },
    map: function(a) {
        var b = [];
        this.each(function(x, i) {
            b.push(a(x, i))
        });
        return Vector.create(b)
    },
    each: function(a) {
        var n = this.elements.length,
            k = n,
            i;
        do {
            i = k - n;
            a(this.elements[i], i + 1)
        } while (--n)
    },
    x: function(k) {
        return this.map(function(x) {
            return x * k
        })
    },
    dot: function(a) {
        var V = a.elements || a;
        var i, product = 0,
            n = this.elements.length;
        if (n != V.length) {
            return null
        }
        do {
            product += this.elements[n - 1] * V[n - 1]
        } while (--n);
        return product
    },
    setElements: function(a) {
        this.elements = (a.elements || a).slice();
        return this
    },
	print : function(){
		console.log( this.elements.map( x => x ).join(', ') );
	}
};
Vector.create = function(a) {
    var V = new Vector();
    return V.setElements(a)
};
Vector.i = Vector.create([1, 0, 0]);
Vector.j = Vector.create([0, 1, 0]);
Vector.k = Vector.create([0, 0, 1]);

function Matrix() {}
Matrix.prototype = {
    col: function(j) {
        if (j > this.elements[0].length) {
            return null
        }
        var a = [],
            n = this.elements.length,
            k = n,
            i;
        do {
            i = k - n;
            a.push(this.elements[i][j - 1])
        } while (--n);
        return Vector.create(a)
    },
    dup: function() {
        return Matrix.create(this.elements)
    },
    map: function(a) {
        var b = [],
            ni = this.elements.length,
            ki = ni,
            i, nj, kj = this.elements[0].length,
            j;
        do {
            i = ki - ni;
            nj = kj;
            b[i] = [];
            do {
                j = kj - nj;
                b[i][j] = a(this.elements[i][j], i + 1, j + 1)
            } while (--nj)
        } while (--ni);
        return Matrix.create(b)
    },
    isSameSizeAs: function(a) {
        var M = a.elements || a;
        if (typeof(M[0][0]) == 'undefined') {
            M = Matrix.create(M).elements
        }
        return (this.elements.length == M.length && this.elements[0].length == M[0].length)
    },
    canMultiplyFromLeft: function(a) {
        var M = a.elements || a;
        if (typeof(M[0][0]) == 'undefined') {
            M = Matrix.create(M).elements
        }
        return (this.elements[0].length == M.length)
    },
    x: function(a) {
	// Note: if things look good, remove the following lines [2024-03-26]
        // if (!a.elements) {
        //     return this.map(function(x) {
        //         return x * a
        //     })
        // }
        var b = a.modulus ? true : false;
        var M = a.elements || a;
	// Note: if things look good, remove the following lines [2024-03-26]
        // if (typeof(M[0][0]) == 'undefined') {
        //     M = Matrix.create(M).elements
        // }
        // if (!this.canMultiplyFromLeft(M)) {
        //     return null
        // }
        var d = this.elements.length,
            ki = d,
            i, nj, kj = M[0].length,
            j;
        var e = this.elements[0].length,
            elements = [],
            sum, nc, c;
        do {
            i = ki - d;
            elements[i] = [];
            nj = kj;
            do {
                j = kj - nj;
                sum = 0;
                nc = e;
                do {
                    c = e - nc;
                    sum += this.elements[i][c] * M[c][j]
                } while (--nc);
                elements[i][j] = sum
            } while (--nj)
        } while (--d);
        var M = Matrix.create(elements);
        return b ? M.col(1) : M
    },
    transpose: function() {
        var a = this.elements.length,
            cols = this.elements[0].length;
        var b = [],
            ni = cols,
            i, nj, j;
        do {
            i = cols - ni;
            b[i] = [];
            nj = a;
            do {
                j = a - nj;
                b[i][j] = this.elements[j][i]
            } while (--nj)
        } while (--ni);
        return Matrix.create(b)
    },
    isSquare: function() {
        return (this.elements.length == this.elements[0].length)
    },
    toRightTriangular: function() {
        var M = this.dup(),
            els;
        var n = this.elements.length,
            k = n,
            i, np, kp = this.elements[0].length,
            p;
        do {
            i = k - n;
            if (M.elements[i][i] == 0) {
                for (j = i + 1; j < k; j++) {
                    if (M.elements[j][i] != 0) {
                        els = [];
                        np = kp;
                        do {
                            p = kp - np;
                            els.push(M.elements[i][p] + M.elements[j][p])
                        } while (--np);
                        M.elements[i] = els;
                        break
                    }
                }
            }
            if (M.elements[i][i] != 0) {
                for (j = i + 1; j < k; j++) {
                    var a = M.elements[j][i] / M.elements[i][i];
                    els = [];
                    np = kp;
                    do {
                        p = kp - np;
                        els.push(p <= i ? 0 : M.elements[j][p] - M.elements[i][p] * a)
                    } while (--np);
                    M.elements[j] = els
                }
            }
        } while (--n);
        return M
    },
    determinant: function() {
        if (!this.isSquare()) {
            return null
        }
        var M = this.toRightTriangular();
        var a = M.elements[0][0],
            n = M.elements.length - 1,
            k = n,
            i;
        do {
            i = k - n + 1;
            a = a * M.elements[i][i]
        } while (--n);
        return a
    },
    isSingular: function() {
        return (this.isSquare() && this.determinant() === 0)
    },
    augment: function(a) {
        var M = a.elements || a;
        if (typeof(M[0][0]) == 'undefined') {
            M = Matrix.create(M).elements
        }
        var T = this.dup(),
            cols = T.elements[0].length;
        var b = T.elements.length,
            ki = b,
            i, nj, kj = M[0].length,
            j;
        if (b != M.length) {
            return null
        }
        do {
            i = ki - b;
            nj = kj;
            do {
                j = kj - nj;
                T.elements[i][cols + j] = M[i][j]
            } while (--nj)
        } while (--b);
        return T
    },
    inverse: function() {
        if( !this.isSquare() ) return null;

	if( this.elements.length == 4 ){
		var m = this.elements;

		var m_00_11 = m[0][0]*m[1][1];
		var m_00_12 = m[0][0]*m[1][2];
		var m_00_13 = m[0][0]*m[1][3];

		var m_01_10 = m[0][1]*m[1][0];
		var m_01_12 = m[0][1]*m[1][2];
		var m_01_13 = m[0][1]*m[1][3];
		var m_01_32 = m[0][1]*m[3][2];

		var m_03_10 = m[0][3]*m[1][0];
		var m_03_11 = m[0][3]*m[1][1];
		var m_03_12 = m[0][3]*m[1][2];

		var m_02_10 = m[0][2]*m[1][0];
		var m_02_11 = m[0][2]*m[1][1];
		var m_02_13 = m[0][2]*m[1][3];

		var m_20_31 = m[2][0]*m[3][1];
		var m_20_32 = m[2][0]*m[3][2];
		var m_20_33 = m[2][0]*m[3][3];

		var m_21_30 = m[2][1]*m[3][0];
		var m_21_32 = m[2][1]*m[3][2];
		var m_21_33 = m[2][1]*m[3][3];

		var m_22_30 = m[2][2]*m[3][0];
		var m_22_31 = m[2][2]*m[3][1];
		var m_22_33 = m[2][2]*m[3][3];

		var m_23_30 = m[2][3]*m[3][0];
		var m_23_31 = m[2][3]*m[3][1];
		var m_23_32 = m[2][3]*m[3][2];

		var result = [ [], [], [], [] ];
		var r = [
			 m[1][1]*m_22_33 - m[1][1]*m_23_32 - m[1][2]*m_21_33 + m[1][2]*m_23_31 + m[1][3]*m_21_32 - m[1][3]*m_22_31,
			-m[0][1]*m_22_33 + m_01_32*m[2][3] + m[0][2]*m_21_33 - m[0][2]*m_23_31 - m[0][3]*m_21_32 + m[0][3]*m_22_31,
			 m_01_12*m[3][3] - m_01_32*m[1][3] - m_02_11*m[3][3] + m_02_13*m[3][1] + m_03_11*m[3][2] - m_03_12*m[3][1],
			-m_01_12*m[2][3] + m_01_13*m[2][2] + m_02_11*m[2][3] - m_02_13*m[2][1] - m_03_11*m[2][2] + m_03_12*m[2][1],

			-m[1][0]*m_22_33 + m[1][0]*m_23_32 + m[1][2]*m_20_33 - m[1][2]*m_23_30 - m[1][3]*m_20_32 + m[1][3]*m_22_30,
			 m[0][0]*m_22_33 - m[0][0]*m_23_32 - m[0][2]*m_20_33 + m[0][2]*m_23_30 + m[0][3]*m_20_32 - m[0][3]*m_22_30,
			-m_00_12*m[3][3] + m_00_13*m[3][2] + m_02_10*m[3][3] - m_02_13*m[3][0] - m_03_10*m[3][2] + m_03_12*m[3][0],
			 m_00_12*m[2][3] - m_00_13*m[2][2] - m_02_10*m[2][3] + m_02_13*m[2][0] + m_03_10*m[2][2] - m_03_12*m[2][0],

			 m[1][0]*m_21_33 - m[1][0]*m_23_31 - m[1][1]*m_20_33 + m[1][1]*m_23_30 + m[1][3]*m_20_31 - m[1][3]*m_21_30,
			-m[0][0]*m_21_33 + m[0][0]*m_23_31 + m[0][1]*m_20_33 - m[0][1]*m_23_30 - m[0][3]*m_20_31 + m[0][3]*m_21_30,
			 m_00_11*m[3][3] - m_00_13*m[3][1] - m_01_10*m[3][3] + m_01_13*m[3][0] + m_03_10*m[3][1] - m_03_11*m[3][0],
			-m_00_11*m[2][3] + m_00_13*m[2][1] + m_01_10*m[2][3] - m_01_13*m[2][0] - m_03_10*m[2][1] + m_03_11*m[2][0],

			-m[1][0]*m_21_32 + m[1][0]*m_22_31 + m[1][1]*m_20_32 - m[1][1]*m_22_30 - m[1][2]*m_20_31 + m[1][2]*m_21_30,
			 m[0][0]*m_21_32 - m[0][0]*m_22_31 - m_01_32*m[2][0] + m[0][1]*m_22_30 + m[0][2]*m_20_31 - m[0][2]*m_21_30,
			-m_00_11*m[3][2] + m_00_12*m[3][1] + m_01_32*m[1][0] - m_01_12*m[3][0] - m_02_10*m[3][1] + m_02_11*m[3][0],
			 m_00_11*m[2][2] - m_00_12*m[2][1] - m_01_10*m[2][2] + m_01_12*m[2][0] + m_02_10*m[2][1] - m_02_11*m[2][0],
		];

		// Note : if things look fine, delete the following section [2024-03-26]
		// var r = [];
		// r.push(  m[1][1]*m[2][2]*m[3][3] - m[1][1]*m[3][2]*m[2][3] - m[1][2]*m[2][1]*m[3][3] + m[1][2]*m[3][1]*m[2][3] + m[1][3]*m[2][1]*m[3][2] - m[1][3]*m[3][1]*m[2][2] );
		// r.push( -m[0][1]*m[2][2]*m[3][3] + m[0][1]*m[3][2]*m[2][3] + m[0][2]*m[2][1]*m[3][3] - m[0][2]*m[3][1]*m[2][3] - m[0][3]*m[2][1]*m[3][2] + m[0][3]*m[3][1]*m[2][2] );
		// r.push(  m[0][1]*m[1][2]*m[3][3] - m[0][1]*m[3][2]*m[1][3] - m[0][2]*m[1][1]*m[3][3] + m[0][2]*m[3][1]*m[1][3] + m[0][3]*m[1][1]*m[3][2] - m[0][3]*m[3][1]*m[1][2] );
		// r.push( -m[0][1]*m[1][2]*m[2][3] + m[0][1]*m[2][2]*m[1][3] + m[0][2]*m[1][1]*m[2][3] - m[0][2]*m[2][1]*m[1][3] - m[0][3]*m[1][1]*m[2][2] + m[0][3]*m[2][1]*m[1][2] );

		// r.push( -m[1][0]*m[2][2]*m[3][3] + m[1][0]*m[3][2]*m[2][3] + m[1][2]*m[2][0]*m[3][3] - m[1][2]*m[3][0]*m[2][3] - m[1][3]*m[2][0]*m[3][2] + m[1][3]*m[3][0]*m[2][2] );
		// r.push(  m[0][0]*m[2][2]*m[3][3] - m[0][0]*m[3][2]*m[2][3] - m[0][2]*m[2][0]*m[3][3] + m[0][2]*m[3][0]*m[2][3] + m[0][3]*m[2][0]*m[3][2] - m[0][3]*m[3][0]*m[2][2] );
		// r.push( -m[0][0]*m[1][2]*m[3][3] + m[0][0]*m[3][2]*m[1][3] + m[0][2]*m[1][0]*m[3][3] - m[0][2]*m[3][0]*m[1][3] - m[0][3]*m[1][0]*m[3][2] + m[0][3]*m[3][0]*m[1][2] );
		// r.push(  m[0][0]*m[1][2]*m[2][3] - m[0][0]*m[2][2]*m[1][3] - m[0][2]*m[1][0]*m[2][3] + m[0][2]*m[2][0]*m[1][3] + m[0][3]*m[1][0]*m[2][2] - m[0][3]*m[2][0]*m[1][2] );

		// r.push(  m[1][0]*m[2][1]*m[3][3] - m[1][0]*m[3][1]*m[2][3] - m[1][1]*m[2][0]*m[3][3] + m[1][1]*m[3][0]*m[2][3] + m[1][3]*m[2][0]*m[3][1] - m[1][3]*m[3][0]*m[2][1] );
		// r.push( -m[0][0]*m[2][1]*m[3][3] + m[0][0]*m[3][1]*m[2][3] + m[0][1]*m[2][0]*m[3][3] - m[0][1]*m[3][0]*m[2][3] - m[0][3]*m[2][0]*m[3][1] + m[0][3]*m[3][0]*m[2][1] );
		// r.push(  m[0][0]*m[1][1]*m[3][3] - m[0][0]*m[3][1]*m[1][3] - m[0][1]*m[1][0]*m[3][3] + m[0][1]*m[3][0]*m[1][3] + m[0][3]*m[1][0]*m[3][1] - m[0][3]*m[3][0]*m[1][1] );
		// r.push( -m[0][0]*m[1][1]*m[2][3] + m[0][0]*m[2][1]*m[1][3] + m[0][1]*m[1][0]*m[2][3] - m[0][1]*m[2][0]*m[1][3] - m[0][3]*m[1][0]*m[2][1] + m[0][3]*m[2][0]*m[1][1] );

		// r.push( -m[1][0]*m[2][1]*m[3][2] + m[1][0]*m[3][1]*m[2][2] + m[1][1]*m[2][0]*m[3][2] - m[1][1]*m[3][0]*m[2][2] - m[1][2]*m[2][0]*m[3][1] + m[1][2]*m[3][0]*m[2][1] );
		// r.push(  m[0][0]*m[2][1]*m[3][2] - m[0][0]*m[3][1]*m[2][2] - m[0][1]*m[2][0]*m[3][2] + m[0][1]*m[3][0]*m[2][2] + m[0][2]*m[2][0]*m[3][1] - m[0][2]*m[3][0]*m[2][1] );
		// r.push( -m[0][0]*m[1][1]*m[3][2] + m[0][0]*m[3][1]*m[1][2] + m[0][1]*m[1][0]*m[3][2] - m[0][1]*m[3][0]*m[1][2] - m[0][2]*m[1][0]*m[3][1] + m[0][2]*m[3][0]*m[1][1] );
		// r.push(  m[0][0]*m[1][1]*m[2][2] - m[0][0]*m[2][1]*m[1][2] - m[0][1]*m[1][0]*m[2][2] + m[0][1]*m[2][0]*m[1][2] + m[0][2]*m[1][0]*m[2][1] - m[0][2]*m[2][0]*m[1][1] );

		var det = m[0][0]*r[ 0 ] + m[0][1]*r[ 4 ] + m[0][2]*r[ 8 ] + m[0][3]*r[ 12 ];

		for( var i = 0; i < 16; i++ ) result[ Math.floor( i / 4 ) ].push( r[i] / det );

		return Matrix.create( result );
	}
	else{
        	if( this.isSingular() ) return null;

		var a = this.elements.length,
		    ki = a,
		    i, j;
		var M = this.augment(Matrix.I(a)).toRightTriangular();
		var b, kp = M.elements[0].length,
		    p, els, divisor;
		var c = [],
		    new_element;
		do {
		    i = a - 1;
		    els = [];
		    b = kp;
		    c[i] = [];
		    divisor = M.elements[i][i];
		    do {
			p = kp - b;
			new_element = M.elements[i][p] / divisor;
			els.push(new_element);
			if (p >= ki) {
			    c[i].push(new_element)
			}
		    } while (--b);
		    M.elements[i] = els;
		    for (j = 0; j < i; j++) {
			els = [];
			b = kp;
			do {
			    p = kp - b;
			    els.push(M.elements[j][p] - M.elements[i][p] * M.elements[j][i])
			} while (--b);
			M.elements[j] = els
		    }
		} while (--a);
		return Matrix.create(c)
	}
    },
    setElements: function(a) {
        var i, elements = a.elements || a;
        if (typeof(elements[0][0]) != 'undefined') {
            var b = elements.length,
                ki = b,
                nj, kj, j;
            this.elements = [];
            do {
                i = ki - b;
                nj = elements[i].length;
                kj = nj;
                this.elements[i] = [];
                do {
                    j = kj - nj;
                    this.elements[i][j] = elements[i][j]
                } while (--nj)
            } while (--b);
            return this
        }
        var n = elements.length,
            k = n;
        this.elements = [];
        do {
            i = k - n;
            this.elements.push([elements[i]])
        } while (--n);
        return this
    },
    flatten : function (){
        if( !this.elements.length ) return [];
        
        var result = [];
        for (var j = 0; j < this.elements[0].length; j++)
            for (var i = 0; i < this.elements.length; i++)
                result.push(this.elements[i][j]);
        return result;
    },
	transform : function( t ){
		this.elements = this.x( t ).elements;
	},
	translate : function( v ){
		this.transform( Matrix.Translation( $V( v ) ) );
	},
	rotate : function( angle, v ){
		this.transform( Matrix.Rotation( angle * Math.PI / 180, $V( v ) ) );
	},
	scale : function( v ){
		this.transform( Matrix.Scale( $V( v ) ) );
	},
	norm : function(){
		try{ return this.inverse().transpose(); } catch(e){ return Matrix.I(4); };
	},
	print : function(){
		console.log( this.elements.map( x => x.join(', ') ).join('\n') );
	},
	// Note : not 100% sure the following function calculates correct values.
	get_euler_angles : function(){
		return {
			x : Math.atan2(  this.elements[2][1], this.elements[2][2] ),
			z : Math.atan2(  this.elements[1][0], this.elements[0][0] ),
			y : Math.atan2( -this.elements[2][0], Math.sqrt( this.elements[2][1] * this.elements[2][1] + this.elements[2][2] * this.elements[2][2] ) ),
		};
	},
	// Note : not 100% sure the following function calculates correct values. (negative scale values are probably wrong)
	get_scale : function(){
		return [
			Math.sqrt( this.elements[0][0] * this.elements[0][0] + this.elements[0][1] * this.elements[0][1] + this.elements[0][2] * this.elements[0][2] ),
			Math.sqrt( this.elements[1][0] * this.elements[1][0] + this.elements[1][1] * this.elements[1][1] + this.elements[1][2] * this.elements[1][2] ),
			Math.sqrt( this.elements[2][0] * this.elements[2][0] + this.elements[2][1] * this.elements[2][1] + this.elements[2][2] * this.elements[2][2] ),
		];
	},
	identity : function(){
		var j_length = this.elements[ 0 ].length;
		for( var i = 0; i < this.elements.length; i++ ){
			for( var j = 0; j < j_length; j++ ) this.elements[ i ][ j ] = ( i == j ? 1 : 0 );
		}
	},
};
Matrix.create = function(a) {
    var M = new Matrix();
    return M.setElements(a)
};
Matrix.create4x4 = function(a) {
    var M = new Matrix();
    var ele = [
	[ a[ 0], a[ 4], a[ 8], a[12] ],
	[ a[ 1], a[ 5], a[ 9], a[13] ],
	[ a[ 2], a[ 6], a[10], a[14] ],
	[ a[ 3], a[ 7], a[11], a[15] ],
    ];
    return M.setElements(ele)
};
Matrix.I = function(n) {
    var a = [],
        k = n,
        i, nj, j;
    do {
        i = k - n;
        a[i] = [];
        nj = k;
        do {
            j = k - nj;
            a[i][j] = (i == j) ? 1 : 0
        } while (--nj)
    } while (--n);
    return Matrix.create(a)
};
Matrix.Translation = function(v){
    var r = Matrix.I(4);
    r.elements[0][3] = v.elements[0];
    r.elements[1][3] = v.elements[1];
    r.elements[2][3] = v.elements[2];
    return r;
};
Matrix.Rotation = function(b, a) {
    var s = Math.sin(b),
        c = Math.cos(b);
    var d = a.dup();
    var e = d.modulus();
    var x = d.elements[0] / e,
        y = d.elements[1] / e,
        z = d.elements[2] / e,
        t = 1 - c;
    return Matrix.create([
        [ t * x * x + c    , t * x * y - s * z, t * x * z + s * y, 0 ],
        [ t * x * y + s * z, t * y * y + c    , t * y * z - s * x, 0 ],
        [ t * x * z - s * y, t * y * z + s * x, t * z * z + c    , 0 ],
	[                 0,                 0,                 0, 1 ]
    ])
};
Matrix.Scale = function(v){
    var r = Matrix.I(4);
    r.elements[0][0] = v.elements[0];
    r.elements[1][1] = v.elements[1];
    r.elements[2][2] = v.elements[2];
    return r;
};

var $V = Vector.create;
var $M = Matrix.create;

try{ JL = JL; } catch(e){ JL = {}; }

$.ajaxSetup({ cache: false, });

JL.webgl = {
	all_environments  : [],
	all_space_objects : [],
	body              : {},
	canvas_ids        : {
		primary   : 'primary-canvas',
		secondary : 'secondary-canvas',
	},
	constants         : {},
	dir               : {
		dist         : './assets/lib/jl/webgl/dist',
		environments : './assets/js/environments',
		jl           : './assets/lib/jl',
		jl_webgl     : './assets/lib/jl/webgl',
		js           : './assets/js',
		models       : './assets/models',
		textures     : './assets/textures',
	},
	environments      : {},
	graphics_objects  : {},
	html_parent       : 'body',
	main              : {},
	object            : {},
	space_object_ids  : [],
	space_objects     : {},
	space_object      : {},
	ui                : { item : {} },
	variables         : {
		default_environment : [ 'main' ],
	},
};

JL.webgl.init = function( cfg ){
	var self = this;

	var cfg = cfg || {};

	if( cfg.attr ) JL.functions.recursive_assign( this, cfg.attr );

	[
		{ key : 'camera'      , obj : this.camera.prototype               , },
		{ key : 'device'      , obj : this.device                         , },
		{ key : 'device.vr'   , obj : this.device.options.vr              , },
		{ key : 'environment' , obj : this.environment.prototype          , },
		{ key : 'load'        , obj : this.load                           , },
		{ key : 'main'        , obj : this.main                           , },
		{ key : 'shader'      , obj : this.shader.prototype               , },
		{ key : 'space_object', obj : this.space_object._regular.prototype, },
	].forEach(function( field ){
		if( cfg[ field.key ] ){
			if( cfg[ field.key ].custom_functions ) Object.assign( field.obj, cfg[ field.key ].custom_functions );
		}
	}, this);

	if( cfg.controllers ){
		this.ui.controllers = new JL.controllers( cfg.controllers );
		this.main.pre_render = JL.functions.concat_functions([
			( this.main.pre_render || function(){} ),
			function(){ self.ui.controllers.loop(); },
		]);
	}

	if( cfg.keyboard ){
		this.ui.keyboard = new JL.keyboard( [], undefined, { no_loop : 1, } );

		if( cfg.keyboard.bindings ) Object.assign( JL.webgl.ui.key_bindings.bindings, cfg.keyboard.bindings );

		if( cfg.keyboard.events ){
			for( var evt of cfg.keyboard.events ) this.ui.keyboard.set_event_callback( evt.name, evt.callback );
		}

		document.addEventListener( 'blur', function( event ){ self.ui.keyboard.clear_all(); });

		this.main.pre_render = JL.functions.concat_functions([
			( this.main.pre_render || function(){} ),
			function(){ self.ui.keyboard.loop(); },
		]);
	}

	if( cfg.animations ) JL.webgl.animations = JL.webgl.animations.concat( cfg.animations );

	if( cfg.effects ) Object.assign( this.shaders.effects, cfg.effects );

	if( cfg.shader ){
		if( cfg.shader.animations     ) Object.assign( this.shaders.animations , cfg.shader.animations     );
		if( cfg.shader.attr           ) Object.assign( this.shaders.config.attr, cfg.shader.attr           );
		if( cfg.shader.glsl_functions ) Object.assign( this.shaders.functions  , cfg.shader.glsl_functions );
		if( cfg.shader.materials      ) Object.assign( this.shaders.materials  , cfg.shader.materials      );
	}

	if( cfg.mouse ){
		var m = cfg.mouse || {};
		if(    !JL.functions.get_nested_object( m, [ 'events', 'blur' ] ) ){
			JL.functions.set_nested_object( m, [ 'events', 'blur' ], [{ fn : function( e ){ try{ JL.webgl.ui.keyboard.clear_all(); } catch(e){} } }]);
		}
		if(    !JL.functions.get_nested_object( m, [ 'events', 'move' ] ) ){
			JL.functions.set_nested_object( m, [ 'events', 'move' ], [{
				fn : function( e ){
					try{
						var c = JL.webgl.active_camera.target_config;
						if( c.no_control ) return;
					}
					catch(e){}

					if( this.shift_key.pressed ){
						if( this.pressed.left ){
							var atan = Math.atan2( this.curr.y - this.center.y, this.curr.x - this.center.x ) - Math.atan2( this.prev.y - this.center.y, this.prev.x - this.center.x );
							var roll = atan;
							if( Math.abs( roll ) > Math.abs( atan + JL.webgl.constants.PI2 ) ) roll = atan + JL.webgl.constants.PI2;
							if( Math.abs( roll ) > Math.abs( atan - JL.webgl.constants.PI2 ) ) roll = atan - JL.webgl.constants.PI2;
							JL.webgl.active_camera.roll_view( -roll * JL.functions.constants.to_degrees );
						}
						if( this.pressed.middle ){
							if( JL.webgl.variables.is_editing ){
								JL.webgl.active_camera.strafe_view(
									-( this.curr.x - this.prev.x ) / 64,
									 ( this.curr.y - this.prev.y ) / 64, 0
								);
							}
						}
					}
					else{
						if( this.pressed.left  ) JL.webgl.active_camera.mouse_rotate( ( this.curr.y - this.prev.y ) / 8, JL.webgl.variables.orientation * ( this.curr.x - this.prev.x ) / 8 );
						if( this.pressed.right ) JL.webgl.active_camera.zoom_view( 0.5 * ( 20 * ( 2 * ( this.curr.y - this.prev.y ) - window.innerHeight ) / window.innerHeight + 20 ) );
						if( this.pressed.middle ){
							if( JL.webgl.variables.is_editing ){
								JL.webgl.active_camera.mouse_rotate( ( this.curr.y - this.prev.y ) / 4, JL.webgl.variables.orientation * ( this.curr.x - this.prev.x ) / 4 );
							}
						}
					}

					if( !this.visible ) this.show();
				}
			}]);
		}
		if(    !JL.functions.get_nested_object( m, [ 'events', 'wheel' ] ) ){
			JL.functions.set_nested_object( m, [ 'events', 'wheel' ], [{
				fn : function( e ){
					try{
						var c = JL.webgl.active_camera.target_config;
						if( c.no_control ) return;
					}
					catch(e){}

					var e = window.event || e;
					if( JL.webgl.variables.is_editing ){
						JL.webgl.active_camera.strafe_view(
							0, 0,
							( e.wheelDelta || -e.detail ) / 4
						);
					}
					else{
						JL.webgl.active_camera.zoom_view( -Math.max( -1, Math.min( 1, ( e.wheelDelta || -e.detail ) ) ) / 4 );
					}
				}
			}]);
		}
		if(    !JL.functions.get_nested_object( m, [ 'events', 'touch_move' ] ) ){
			JL.functions.set_nested_object( m, [ 'events', 'touch_move' ], [{ fn : function( e ){
				if( JL.webgl.device.is( "desktop" ) ) e.preventDefault();
			} }]);
		}
		if(    !JL.functions.get_nested_object( m, [ 'events', 'touch_move_1' ] ) ){
			JL.functions.set_nested_object( m, [ 'events', 'touch_move_1' ], [{ fn : function( e, touch ){
				try{
					var c = JL.webgl.active_camera.target_config;
					if( c.no_control ) return;
				}
				catch(e){}

				var touch = e.touches[0];
				JL.webgl.active_camera.mouse_rotate(
					( this.curr.touch_1.y - this.prev.touch_1.y ) / 4,
					JL.webgl.variables.orientation * ( this.curr.touch_1.x - this.prev.touch_1.x ) / 4
				);
			} }]);
		}
		if(    !JL.functions.get_nested_object( m, [ 'events', 'touch_move_2' ] ) ){
			JL.functions.set_nested_object( m, [ 'events', 'touch_move_2' ], [{ fn : function( e, touch_1, touch_2 ){
				try{
					var c = JL.webgl.active_camera.target_config;
					if( c.no_control ) return;
				}
				catch(e){}

				var dist_curr = this.distance_xy( this.curr.touch_1, this.curr.touch_2 );
				var dist_prev = this.distance_xy( this.prev.touch_1, this.prev.touch_2 );
				JL.webgl.active_camera.zoom_view( ( dist_prev - dist_curr ) / 4 );
			} }]);
		}
		this.ui.mouse = new JL.mouse( m );
	}

	JL.webgl.active_camera = new JL.webgl.camera();

	// This function is derived here because the materials need to be defined first.
	JL.webgl.shaders.functions._get_mapped_material = `Material _get_mapped_material( in vec3 material_color, in vec3 graphics_object_color, in vec3 light_color ){
		float _128 = 128.0/255.0;` +
		Object.values( JL.webgl.shaders.materials ).filter( x => x.mapped_color ).concat( Object.values( JL.webgl.shaders.materials ).find( x => x.mapped_default ) ).map(function( material, material_idx ){
			if( !material ) return '';
			return ( material_idx > 0 ? 'else ' : '' ) + ( material.mapped_color ? 'if( material_color.rgb == vec3(' + material.mapped_color + ') )' : '' ) + '{' + 
				'return Material( ' + material.specular_color + ', ' + material.shininess + ');' +
			'}';
		}).join('') +
	`}`;

	var html_parent_obj = $( this.html_parent );

	html_parent_obj.append( '<link rel="stylesheet" href="' + this.dir.dist + '/fonts/font_awesome_4_3/font.css">' );
	html_parent_obj.append( '<div id="jl-webgl-curr-item-ui"></div>' );

	JL.functions.add_css(`
		#jl-webgl-fullscreen-toggle{
			position:absolute;
			right :10px;
			bottom: 9px;
			font-size:18px;
			color:#fff;
			text-shadow: 1px 1px 0px #000;
			cursor:pointer;
			z-index:1;
		}

		@media only screen and ( min-width : 992px ){
			#jl-webgl-fullscreen-toggle{
				display:none;
			}
		}
	`);

	html_parent_obj.append( '<div id="jl-webgl-fullscreen-toggle" onclick="JL.functions.toggle_fullscreen();"><i class="fa fa-arrows-alt"></i></div>' );

	if( cfg.hashlinks ){
		var custom_params = ( cfg.hashlinks.params || {} );

		this.hashlinks = new JL.hashlinks( Object.assign({
			ar          : { select: function( val ){ if( val ){ JL.webgl.ui.ar.turn_on(); } }                          },
			device      : {},
			edit        : {},
			environment : {},
		}, custom_params ) );

		var on_start_fns = [];
		if( this.hashlinks.params.edit && !custom_params.edit ){
			on_start_fns.push( function(){
				var v = self.hashlinks.get_val( 'edit' );
				if( v !== undefined ) JL.webgl.variables.is_editing = v;
			} );
		}
		if( this.hashlinks.params.environment && !custom_params.environment ){
			on_start_fns.push( function(){
				var v = self.hashlinks.get_val( 'environment' );
				if( v ) JL.webgl.variables.default_environment = v.split(',');
			} );
		}
		if( this.hashlinks.params.device ) on_start_fns.push( function(){ var v = self.hashlinks.get_val( 'device' ); if(v){ JL.webgl.device.set(v); } } );
		if(  cfg.hashlinks.on_start      ) on_start_fns.push( cfg.hashlinks.on_start );
		if( !cfg.hashlinks.no_auto_start ) on_start_fns.push( function(){ JL.webgl.load.start(); } );
		this.hashlinks.on_start = JL.functions.concat_functions( on_start_fns );

		if( !cfg.hashlinks.no_auto_start ) this.hashlinks.start();
	}

	this.load.init_config();
};

// -------------
// | Constants |
// -------------

JL.webgl.constants.PI         =     Math.PI;
JL.webgl.constants.PI2        = 2 * Math.PI;
JL.webgl.constants.start_time = ( new Date() ).getTime();

JL.webgl.constants.max_texture        = 0;
JL.webgl.constants.default_resolution = '4k';
JL.webgl.constants.resolutions        = [ '1k', '2k', '4k', '8k', 'highest' ];

// -------------
// | Variables |
// -------------

JL.webgl.variables.orientation        = 1;
JL.webgl.variables.texture_resolution = JL.webgl.constants.default_resolution;

JL.webgl.functions = {};

JL.webgl.functions.get_xyz = function(mat){
        var m = (mat ? mat.elements : JL.webgl.mat.model.elements);
	var position = {};
        position.x = -(m[0][0]*m[0][3] + m[1][0]*m[1][3] + m[2][0]*m[2][3]);
        position.y = -(m[0][1]*m[0][3] + m[1][1]*m[1][3] + m[2][1]*m[2][3]);
        position.z = -(m[0][2]*m[0][3] + m[1][2]*m[1][3] + m[2][2]*m[2][3]);
	return position;
};
JL.webgl.functions.get_up_vector = function( mat, mag ){
	var output = mat.elements[ 1 ].slice( 0, 3 );
	if( mag ) output = output.map( x => mag * x );
	return output;
};
JL.webgl.functions.get_right_vector = function( mat, mag ){
	var output = mat.elements[ 0 ].slice( 0, 3 );
	if( mag ) output = output.map( x => mag * x );
	return output;
};
JL.webgl.functions.get_forward_vector = function( mat, mag ){
	var mag = -( mag || 1 );
	return mat.elements[ 2 ].slice( 0, 3 ).map( x => mag * x );
};

JL.webgl.functions.get_full_effects_list = function( effects ){
	var full_effects_list = [];

	var recursive_helper = function( effect_name, curr_depth ){
		if( curr_depth > 4 ) return;

		var effect = JL.webgl.shaders.effects[ effect_name ];

		if( !effect ){
			console.log( 'Error: effect not found -- ' + effect_name );
		}
		else{
			if( effect.included_effects ){
				for( var included_effect_name of effect.included_effects ){
					recursive_helper( included_effect_name, curr_depth + 1 );
				}
			}

			if( !full_effects_list.includes( effect_name ) ) full_effects_list.push( effect_name );
		}
	};

	for( var effect_name of effects ){
		if( effect_name ) recursive_helper( effect_name, 0 );
	}

	return full_effects_list;
};

JL.webgl.functions.get_instanced_fields = function( effects ){
	var output = [];

	for( var effect_name of JL.webgl.functions.get_full_effects_list( effects ) ){
		var cfg = JL.webgl.shaders.effects[ effect_name ];

		if( cfg.append ){
			if( cfg.append.instanced ){
				var fields = cfg.append.instanced.map( x => x.items );
				if( fields ){
					output = output.concat(
						fields.map(function( attr ){
							var c = JL.webgl.shaders.config.attr[ attr ];
							return {
								field : attr,
								type  : c.type,
								cols  : c.labels,
							};
						})
					);
				}
			}
		}
	}

	return output;
};

JL.webgl.functions.add_or_replace_to_textures_config = function( textures, texture ){
	var textures = textures || [];

	var type = texture.type || 'main';

	var found_match = false;
	if( type == 'main' ){
		for( var i = 0; i < textures.length; i++ ){
			var t = textures[ i ];
			if( !t.type || t.type == type ){
				textures[ i ] = texture;
				found_match = true;
				break;
			}
		}
	}
	else{
		for( var i = 0; i < textures.length; i++ ){
			var t = textures[ i ];
			if( t.type == type ){
				textures[ i ] = texture;
				found_match = true;
				break;
			}
		}
	}

	return textures;
};

JL.webgl.functions.get_textures_list = function( obj, p ){
	var p = p || {};

	var uniforms = this.get_uniforms_list( obj, Object.assign({ all : true }, p ) );

	var textures = uniforms.filter(function( uniform ){
		if( uniform[ 0 ].endsWith( '_texture' ) ) return true;
		return false;
	});

	// 2025-08-14
	// if( !textures.length ){
		try{
			if( !obj.properties.color ) textures.push([ 'frags_texture', 'main' ]);
		} catch(e){}
	// }

	return textures;
};

JL.webgl.functions.get_uniforms_list = function( obj, p ){
	var self = this;

	var p = p || {};

	var  is_graphics_object = false;
	try{ is_graphics_object = obj.shader.uniforms; } catch(e){}

	var uniforms = [];

	if( is_graphics_object ) uniforms = obj.shader.uniforms.slice();
	else{
		try     { var effects = this.get_full_effects_list( obj.properties.effects ); }
		catch(e){ var effects = []; }

		var per_shading = p.per_shading || 'frags';

		for( var effect_name of effects ){
			var effect = JL.webgl.shaders.effects[ effect_name ];
			try{
				for( var u of effect.append.uniforms ){
					var uniform = [
						( u.shader == 'per_shading' ? per_shading : u.shader ) + '_' + u.type,
						u.var,
					];
					if( !uniforms.find( x => JL.functions.arrays_equal( x, uniform ) ) ) uniforms.push( uniform );
				}
			} catch(e){}
			try{
				for( var u of effect.remove[ 'this.uniforms' ] ){
					uniforms = uniforms.filter( x => !JL.functions.arrays_equal( x, u ) );
				}
			} catch(e){}
		}
	}

	if( p.all ) return uniforms;

	return uniforms.filter(function( uniform ){
		try{
			var parts = uniform[ 0 ].split('_');
			var type  = parts[ 1 ];

			var uniform_cfg = self.get_uniform_config( uniform );

			if( !uniform_cfg ) return false;

			if( uniform[ 0 ].endsWith( '_texture' ) ) return false;

			if( parts[ 2 ] == 'arr' ){
				if( JL.webgl.shaders.uniforms.arrs.find( v => v.name == type ).get_arr[ uniform[1] ] ) return false;
			}
			else{
				if( uniform_cfg.derive          && uniform_cfg.derive[          uniform[1] ] ) return false;
				if( uniform_cfg.custom_defaults && uniform_cfg.custom_defaults[ uniform[1] ] ) return false;
			}

			return true;
		}
		catch(e){}
	});
};

JL.webgl.functions.get_uniform_config = function( uniform ){
	var type = uniform[ 0 ].split('_')[ 1 ];

	return JL.webgl.shaders.uniforms.vars.find( v => v.name == type );
};

JL.webgl.functions.get_uniform_val = function( obj, uniform ){
	var val;
	try{
		val = obj.get_uniform( uniform );
		try{ val = val.slice(); } catch(e){}
	}
	catch(e){
		val = JL.functions.get_nested_object( obj, uniform );
		if( JL.functions.is_array( val ) ) val = val.map( x => Number( x ) );
		else if( !isNaN( val ) )           val = Number( val );

		if( val === undefined ) val = JL.webgl.functions.get_uniform_config( uniform ).default;
	}

	return val;
};

JL.webgl.functions.get_instanced_attr = function( effects ){
	var output = [];

	var full_effects_list = this.get_full_effects_list( effects );

	for( var effect_name of full_effects_list ){
		var effect = JL.webgl.shaders.effects[ effect_name ];

		try{
			output = output.concat( effect.append.instanced.map( x => x.items ) );
		} catch(e){}
	}

	return output;
};

JL.webgl.functions.create_background = function( p ){
	return JL.webgl.environment.prototype.add_space_object(
		Object.assign({ no_parent : true, }, p ),
		JL.webgl.space_object._background
	);
};

JL.webgl.functions.append_graphics_object = function( main_g_o, g_o_to_add, g_o_params ){
	if( !main_g_o ) return g_o_to_add.copy( g_o_params );
	return main_g_o.concat([ Object.assign({ mesh : g_o_to_add }, g_o_params ) ], { preserve_buffers : 1 });
};

JL.webgl.functions.create_graphics_object = function( config ){
	var params = config.params || config;

	var args = [];
	if( config.args ) args = config.args;
	args.push( params );

	try     { var type = params._type || config.type; }
	catch(e){ var type = config.type;                 }

	if( JL.functions.is_str( type ) ) type = JL.webgl.graphics_object[ type ];
	if( !type                       ) type = JL.webgl.graphics_object.obj;
	return new type( ...args );
};

JL.webgl.functions.delete_graphics_object = function( path ){
	var g_o = JL.webgl.graphics_objects;
	path.forEach(function( key, i, arr ){
		if( i < arr.length - 1 ) g_o  = g_o[ key ];
		else{                    delete g_o[ key ]; }
	});
};

JL.webgl.functions.get_derived_graphics_objects_label = function( p ){ // for things like floors/ceilings in building s_o's
	var output = [ '_environments' ].slice();

	var p = p || {};

	var env = JL.webgl.active_environment;
	if( p.space_object ){
		if( p.space_object.environment ) env = p.space_object.environment;
	}
	if( env ){
		if( env.keys ) output = output.concat( env.keys );
	}

	return output;
};

JL.webgl.functions.get_graphics_object_id = function( g_o ){
	var g_o_params = ( g_o.params || g_o );
	var output = Object.keys( JL.webgl.active_environment._environment_config.graphics_objects ).find(function( id ){
		var m = JL.webgl.active_environment._environment_config.graphics_objects[ id ];
		var m_params = ( m.params || m );
		return [ 'keys', 'label' ].every(function( k ){
			return JL.functions.arrays_equal( m_params[ k ] || [], g_o_params[ k ] || [] );
		});
	});
	if( output === undefined ) return;
	return parseInt( output );
};

JL.webgl.functions.index_graphics_object = function( g_o ){
	if( g_o === undefined ) return;

	var g_o_id;

	// 2026-01-05 -- trying to address bug with dynamically constructed .obj g_o's in s_o._particle_system.rain throwing errors in Edit interface.
	var g_o     = this.get_graphics_object( g_o );
	var g_o_cfg = g_o._config || g_o;
	// var g_o_cfg = this.get_graphics_object( g_o )._config;

	g_o_id = this.get_graphics_object_id( g_o_cfg );
	if( g_o_id === undefined ){
		g_o_id = 1;
		while( JL.webgl.active_environment._environment_config.graphics_objects[ g_o_id ] ) g_o_id++;
		JL.webgl.active_environment._environment_config.graphics_objects[ g_o_id ] = g_o_cfg;
	}

	return g_o_id;
};

JL.webgl.functions.get_graphics_object = function( id ){
	if( id instanceof JL.webgl.graphics_object._main ) return id;
	if( JL.functions.is_array(  id ) ) return JL.functions.get_nested_object( JL.webgl.graphics_objects, id );
	if( JL.functions.is_int(    id ) ){
		if( JL.webgl.active_environment ){
			try{
				var match = JL.webgl.active_environment._environment_config.graphics_objects[ id ];
				if( match ) return this.get_graphics_object( match ); // This is to convert a graphics_object config to an actual graphics_object.
			}
			catch(e){}
		}
		else if( JL.webgl.all_environments ){
			for( var env_id of JL.webgl.all_environments ){
				var env = this.get_environment( env_id );
				try{
					var match = env._environment_config.graphics_objects[ id ];
					if( match ) return this.get_graphics_object( match ); // This is to convert a graphics_object config to an actual graphics_object.
				}
				catch(e){}
			}
		}
	}
	if( JL.functions.is_str(    id ) ) return JL.functions.get_nested_object( JL.webgl.graphics_objects, id.split('/') );
	if( JL.functions.is_object( id ) ){
		var path = ( id.path || id.label || id.keys );
		if( !path ){
			if( id.params ) path = ( id.params.label || id.params.keys );
		}

		// 2025-10-03
		// if( path ) return JL.functions.get_nested_object( JL.webgl.graphics_objects, path ) || this.create_graphics_object( id );
		if( path ) return JL.functions.get_nested_object( JL.webgl.graphics_objects, path );

		else       return id;
	}
	return undefined;
};

JL.webgl.functions.get_space_object = function( p, _p ){
	if( p instanceof JL.webgl.space_object._regular ) return p;

	var _p = _p || {};

	if( JL.functions.is_int( p ) ){
		try     { return ( _p.environment || JL.webgl.active_environment ).get_all_space_objects().find( o => ( o._id === p ) ); }
		catch(e){ return JL.webgl.all_space_objects.find( o => ( o._id === p ) ); }
	}

	var env = ( _p.environment || p.environment || JL.webgl.active_environment );

	var space_objects_lists = [ JL.webgl.all_space_objects.slice(), ];
	if( env ) space_objects_lists.unshift( env.get_all_space_objects() );

	if( p.class ) p.type = this.get_space_object_class[ p.class ];

	var id      = p.id || {};
	var id_keys = Object.keys( id ).filter( k => ![ 'type', 'class' ].includes( k ) );
	for( var list of space_objects_lists ){
		if( p.type ) list = list.filter( s => ( s instanceof p.type ) );

		var match = list.find(function( o ){ return id_keys.every( k => o[ k ] === id[ k ] ); });
		if( match ) return match;
	}
};

JL.webgl.functions.get_space_object_from_physics_body_id = function( body_id, env ){
	var env = env || JL.webgl.active_environment;

	return this.get_space_object( env.physics_body_id_to_space_object_id[ body_id ] );
};

JL.webgl.functions.get_space_object_class = function( path ){
	return JL.functions.get_nested_object( JL.webgl.space_object, ( JL.functions.is_str( path ) ? path.split('/') : path ) );
};

JL.webgl.functions.get_all_space_object_types = function(){
	var custom_classes = {};
	var    lib_classes = {};

	var recursive_helper = function( path ){
		var curr_obj = JL.functions.get_nested_object( JL.webgl.space_object, path );

		for( var k in curr_obj ){
			var curr_key = path.concat([ k ]).join('/');

			var child_obj = curr_obj[k];

			var is_space_object = ( child_obj.prototype instanceof JL.webgl.space_object._regular );

			if( JL.functions.is_object( child_obj ) || is_space_object ){
				if( is_space_object ){
					if( curr_key.startsWith('_') )    lib_classes[ curr_key ] = true;
					else                           custom_classes[ curr_key ] = true;
				}

				recursive_helper( path.concat( k ) );
			}
		}
	};
	recursive_helper([]);

	delete lib_classes[ '_regular' ];

	return JL.functions.filter_duplicates([ '_regular',
		...Object.keys( custom_classes ).sort( (a,b) => ( a > b ? 1 : -1 ) ),
		...Object.keys(    lib_classes ).sort( (a,b) => ( a > b ? 1 : -1 ) ),
	]);
};

JL.webgl.functions.get_environment = function( id ){
	if( id instanceof JL.webgl.environment ) return id;
	if( JL.functions.is_array(  id ) ) return JL.functions.get_nested_object( JL.webgl.environments, id );
	if( JL.functions.is_str(    id ) ) return JL.functions.get_nested_object( JL.webgl.environments, id.split('/') );
	return undefined;
};

JL.webgl.functions.init_environment = function( keys, p ){
	var params = $.extend( true, {}, p );
	if( !params.keys ) params.keys = keys;
	var env = new JL.webgl.environment( params );
	JL.functions.set_nested_object( JL.webgl.environments, keys, env );
	return env;
};

JL.webgl.functions.list_all_backgrounds = function(){
	return JL.webgl.all_space_objects.filter( o => ( o.type == 'Background' ) );
};

JL.webgl.functions.list_graphics_objects = function( root ){
	var graphics_objects = [];

	var recursive_helper = function( curr_obj, path ){
		Object.keys( curr_obj ).forEach(function( key ){
			var child_obj  = curr_obj[ key ];
			var child_path = ( path ? path.slice() : [] ).concat( key );
			if( child_obj instanceof JL.webgl.graphics_object._main ) graphics_objects.push({ path : child_path, graphics_object : child_obj });
			else{ recursive_helper( child_obj, child_path ); }
		});
	};

	recursive_helper( root || JL.webgl.graphics_objects );

	return graphics_objects;
};

JL.webgl.functions.load_and_select_environment = function( p ){
	var callback = function( env ){
		env.select();

		if( p.callback ) p.callback( env );
	};

	var existing_environment = JL.functions.get_nested_object( JL.webgl.environments, p.keys );

	if( !existing_environment || !( existing_environment instanceof JL.webgl.environment ) ) JL.webgl.load.assets({ environments : [ p ], callback });
	else{
		callback( existing_environment );
	}
};

JL.webgl.functions.resolution_to_pixels = function( res ){
	switch( res ){
		case '1k'      : return 1024;
		case '2k'      : return 2048;
		case '4k'      : return 4096;
		case '8k'      : return 8192;
		case 'highest' : return this.resolution_to_pixels( JL.webgl.constants.max_resolution );
		default        : return this.resolution_to_pixels( JL.webgl.constants.default_resolution );
	}
};

JL.webgl.functions.set_global_effects = function( p ){
	var old_global_effects = ( JL.webgl.variables.global_effects || [] ).slice();
	var new_global_effects = [];

	if( p.environment ){
		if( p.environment.fog ) new_global_effects.push( '_fog' );
	}

	JL.webgl.variables.global_effects = new_global_effects;

	if( !JL.functions.arrays_equal( old_global_effects, new_global_effects ) ){
		this.update_all_shaders();
	}

	return JL.webgl.variables.global_effects;
};

JL.webgl.functions.update_all_shaders = function(){
	for( var s of Object.values( JL.webgl.shaders.loaded ) ){
		s.init_shader();
	}
};

JL.webgl.functions.encode_text_to_pixels = function( p ){
	var width  = 256;
	var height = 256;

	var pixels = new Array( width * height * 4 );

	for( var i = 0; i < p.text.length; i++ ) pixels[ i ] = JL.functions.constants.font_chars.indexOf( p.text[ i ] );

	return { pixels, width, height };
};

JL.webgl.canvas = {};

JL.webgl.canvas.create = function( name, id, p ){
	var p = p || {};

	if( p.width ) $( JL.webgl.html_parent ).append( '<canvas id="' + id + '" aria-label="Interactive 3D Content" width="' + p.width + '" height="' + p.height + '" style="' + ( p.style || '' ) + '" oncontextmenu="return false;"></canvas>' );

	this[ name ]   = {};
	this[ name ].c = document.getElementById( id );

	if( !p.no_ctx ) this[ name ].ctx = this[ name ].c.getContext('2d');

	return this[ name ];
};

// ------------------------------------------------------------|
// | Primary canvas -- main canvas for rendering WebGL content |
// ------------------------------------------------------------|

JL.webgl.canvas.create( 'primary', JL.webgl.canvas_ids.primary, { width : '2048', height : '1024', no_ctx : true } );

JL.webgl.canvas.primary.resize = function(){
	var is_naive_vr = ( JL.webgl.device.is( 'vr' ) && JL.webgl.device.options.vr.web_standard == 'naive' );

	var window_obj = $(window);

        this.c.style.width  = window_obj.width() * ( is_naive_vr ? 0.5 : 1 );
        this.c.style.height = window_obj.height();

	this.c.width  = this.c.clientWidth; 
	this.c.height = this.c.clientHeight;

	JL.webgl.gl.viewport( 0, 0, JL.webgl.gl.canvas.width, JL.webgl.gl.canvas.height );

	// Calculation for static canvas size : $("#" + JL.webgl.canvas_ids.primary).width() / $("#" + JL.webgl.canvas_ids.primary).height();
	JL.webgl.variables.aspect_ratio  = this.c.width / this.c.height;
	JL.webgl.variables.field_of_view = 45 - ( JL.webgl.variables.aspect_ratio > 5 ? Math.min( Math.floor( 10 * ( JL.webgl.variables.aspect_ratio - 5 ) ), 20 ) : 0 );
 
	if( is_naive_vr && JL.webgl.canvas.secondary ){
		JL.webgl.canvas.secondary.c.style.width  = this.c.style.width;
		JL.webgl.canvas.secondary.c.style.height = this.c.style.height;
	}

	if( this.post_resize ) this.post_resize();
};

JL.webgl.canvas.primary.post_resize = function(){
	if( JL.webgl.ui.mouse ) JL.webgl.ui.mouse.set_screen_center( JL.webgl.canvas.primary.c.width/2, JL.webgl.canvas.primary.c.height/2 );
};

// ----------------------------------------|
// | Secondary canvas -- used for naive VR |
// ----------------------------------------|

JL.webgl.canvas.create_secondary_canvas = function(){
	JL.webgl.canvas.create( 'secondary', JL.webgl.canvas_ids.secondary, { width : '2048', height : '1024' } );
	JL.webgl.canvas.secondary.mirror = function(){
		this.ctx.clearRect( 0, 0, this.c.width, this.c.height );
		this.ctx.drawImage( JL.webgl.canvas.primary.c, 0, 0 );
	};

	this.create_secondary_canvas = function(){};
};

// -----------------------------------------------------
// | Text canvas - used for rendering text to textures |
// -----------------------------------------------------

JL.webgl.canvas.create( 'text', 'text-canvas', { width : '1024', height : '512', style : 'display:none;' } );
JL.webgl.canvas.text.resize = function( width, height ){
	this.ctx.canvas.width  = width;
	this.ctx.canvas.height = height;
};
JL.webgl.canvas.text.get_texture = function( text, params ){
	var params = params || {};

	var ctx = this.ctx;

	if( params.size ) this.resize( params.size[ 0 ], params.size[ 1 ] );

	var text = text || '';

	var lines;

	if( params.single_line ){
		lines = [ text ];
	}
	else{
		lines = text.split('\n');

		if( text.length > 15 && text.includes(' ') ){
			lines = text.split(' ');
		}
	}

	var font_size   = params.font_size || ( text.length <= 10 ? 80 : 80 - 2 * ( text.length - 10 ) );
	var font_family = params.font_family || 'Open Sans';

	ctx.fillStyle = params.background || 'transparent';
	ctx.clearRect(0, 0, ctx.canvas.width, ctx.canvas.height);
	ctx.fillRect( 0, 0, ctx.canvas.width, ctx.canvas.height);

	ctx.font         = '400 ' + font_size + 'px "' + font_family + '"';
	ctx.textBaseline = 'middle';

	ctx.textAlign   = params.text_align    || 'center';
	ctx.fillStyle   = params.color         || 'white';
	ctx.strokeStyle = params.outline_color || 'transparent';
	ctx.lineWidth   = params.outline_width || 0;

	// Note : these 'miter' settings are to prevent text outline artifacts for letters with sharp corners (like A, V, and W)
	ctx.lineJoin   = 'miter';
	ctx.miterLimit = 2;

	var line_height = params.line_height || font_size;

	var offset_left = ( params.offset_left != undefined ? params.offset_left : ctx.canvas.width  / 2 );
	var offset_top  = ( params.offset_top  != undefined ? params.offset_top  : ctx.canvas.height / 2 ) - ( 0.5 * ( lines.length - 1 ) * line_height );

	for( var line_idx = 0; line_idx < lines.length; line_idx++ ){
		var line = lines[ line_idx ];
		var line_top = offset_top + line_idx * line_height;
		if( ctx.strokeStyle != 'transparent' ) ctx.strokeText( line, offset_left, line_top );
		ctx.fillText( line, offset_left, line_top );
	}

	if( params.border ){
		ctx.lineWidth   = params.border.width || 1;
		ctx.strokeStyle = params.border.color || '#000';
		ctx.strokeRect( 0, 0, ctx.canvas.width, ctx.canvas.height );
	}

	if( params.customizations ) params.customizations( ctx );

	var texture = params.texture || JL.webgl.gl.createTexture();
	texture.image = this.c;

	return texture;
};

JL.webgl.mat = {};
JL.webgl.mat.stack = [];
JL.webgl.mat.identity = function(){
	this.model = Matrix.I(4);
};
JL.webgl.mat.perspective = function(angle, aspect, near, far){
	this.projection = makePerspective(angle, aspect, near, far);
};
JL.webgl.mat.ortho = function(left, right, bottom, top, near, far){
	this.projection = makeOrtho(left, right, bottom, top, near, far);
};
JL.webgl.mat.mult = function(m){
	this.model = this.model.x(m);
};
JL.webgl.mat.push = function(){
	this.stack.push(this.model.dup());
};
JL.webgl.mat.pop = function(){
	if (!this.stack.length) throw("Can't pop from an empty matrix stack.");
	this.model = this.stack.pop();
};
JL.webgl.mat.transform = function( transform, matrix ){
	if( matrix ) return matrix.x( transform );
	this.mult( transform );
	return this.model;
};
JL.webgl.mat.translate = function( v, matrix ){
	return this.transform( Matrix.Translation( $V( v ) ), matrix );
};
JL.webgl.mat.rotate = function(angle, v, matrix){
	return this.transform( Matrix.Rotation( angle * JL.functions.constants.to_radians, $V( v ) ), matrix );
};
JL.webgl.mat.scale = function( v, matrix ){
	return this.transform( Matrix.Scale( $V( v ) ), matrix );
};
JL.webgl.mat.norm = function( matrix ){
	var result = Matrix.I(4);
        var matrix_inverse = matrix.inverse();
        if( matrix_inverse != null ) result = matrix_inverse.transpose();
        return result;
};
JL.webgl.mat.dot = function( v1, v2 ){
	var output = 0;
	for( var i = 0; i < v1.length; i++ ) output += v1[ i ] * v2[ i ];
	return output;
};
JL.webgl.mat.cross = function( v1, v2 ){
	return [
		v1[ 1 ] * v2[ 2 ] - v1[ 2 ] * v2[ 1 ],
		v1[ 0 ] * v2[ 2 ] - v1[ 2 ] * v2[ 0 ],
		v1[ 0 ] * v2[ 1 ] - v1[ 1 ] * v2[ 0 ]
	];
};
JL.webgl.mat.get_look_at = function( p ){
	var view_pos = p.view_pos || [ JL.webgl.active_camera.target.x, JL.webgl.active_camera.target.y, JL.webgl.active_camera.target.z ];

	var z_axis = p.forward;
	if( !z_axis ){
		var target_pos = p.target_pos || [ JL.webgl.active_camera.position.x, JL.webgl.active_camera.position.y, JL.webgl.active_camera.position.z ];
		z_axis = JL.functions.normalize([
			view_pos[ 0 ] - target_pos[ 0 ],
			view_pos[ 1 ] - target_pos[ 1 ],
			view_pos[ 2 ] - target_pos[ 2 ],
		]);
	}

	var up = p.up || [ 0, 1, 0 ];

	// Add a slight offset to the up vector if the up and forward vectors are equal.
	if(
		z_axis.every( (x,i) => x ==  up[ i ] ) || 
		z_axis.every( (x,i) => x == -up[ i ] ) 
	){ up[ up[ 1 ] == 0 && up[ 2 ] == 0 ? 1 : 0 ] += 0.00001; }

	var x_axis = JL.functions.normalize( this.cross( up, z_axis ) );
	x_axis[ 1 ] *= -1; // Not sure why this value needs to be negated. Without it, everything gets distorted.

	var y_axis = this.cross( z_axis, x_axis );
	y_axis[ 1 ] *= -1; // Not sure why this value needs to be negated. Without it, everything gets distorted.

	if( p.use_view_matrix ){
		return Matrix.create([
			[ x_axis[ 0 ], x_axis[ 1 ], x_axis[ 2 ], -this.dot( x_axis, view_pos ) ],
			[ y_axis[ 0 ], y_axis[ 1 ], y_axis[ 2 ], -this.dot( y_axis, view_pos ) ],
			[ z_axis[ 0 ], z_axis[ 1 ], z_axis[ 2 ], -this.dot( z_axis, view_pos ) ],
			[           0,           0,           0,                             1 ],
		]);
	}

	return Matrix.create([
		[ x_axis[ 0 ], y_axis[ 0 ], z_axis[ 0 ], view_pos[ 0 ] ],
		[ x_axis[ 1 ], y_axis[ 1 ], z_axis[ 1 ], view_pos[ 1 ] ],
		[ x_axis[ 2 ], y_axis[ 2 ], z_axis[ 2 ], view_pos[ 2 ] ],
		[           0,           0,           0,             1 ],
	]);
};
JL.webgl.mat.get_quaternion = function( matrix ){
	var quat = {};
	var m = ( matrix || this.model )["elements"];

	quat.w = Math.sqrt(1 + m[0][0] + m[1][1] + m[2][2]) / 2;
	var w4 = 4 * quat.w;

	quat.x = (m[2][1] - m[1][2]) / w4;
	quat.y = (m[0][2] - m[2][0]) / w4;
	quat.z = (m[1][0] - m[0][1]) / w4;
	return quat;
};
JL.webgl.mat.set_from_quaternion = function(q, matrix){
	var mat = matrix || this.model;
	var m = mat.elements;

	var xx = q.x * q.x, xy = q.x * q.y, xz = q.x * q.z, xw = q.x * q.w;
	var yy = q.y * q.y,                 yz = q.y * q.z, yw = q.y * q.w;
	var zz = q.z * q.z,                                 zw = q.z * q.w;

	m[0][0] = 1 - 2 * (yy + zz);
	m[1][1] = 1 - 2 * (xx + zz);
	m[2][2] = 1 - 2 * (xx + yy);

	m[0][1] = 2 * (xy - zw);
	m[1][2] = 2 * (yz - xw);
	m[2][0] = 2 * (xz - yw);

	m[0][2] = 2 * (xz + yw);
	m[1][0] = 2 * (xy + zw);
	m[2][1] = 2 * (yz + xw);

	return mat;
};
JL.webgl.mat.slerp = function(qa, qb, t, matrix){
	var m = matrix || this.model;
	var qm = {};
	var cosHalfTheta = qa.w * qb.w + qa.x * qb.x + qa.y * qb.y + qa.z * qb.z;
	
	if( Math.abs(cosHalfTheta) >= 1 ) return this.set_from_quaternion(qa, m);
	else{
		var halfTheta = Math.acos(cosHalfTheta);
		var sinHalfTheta = Math.sqrt(1 - cosHalfTheta*cosHalfTheta);

		if( Math.abs(sinHalfTheta) < 0.001 ){
			qm.w = ( qa.w + qb.w ) / 2;
			qm.x = ( qa.x + qb.x ) / 2;
			qm.y = ( qa.y + qb.y ) / 2;
			qm.z = ( qa.z + qb.z ) / 2;
			return this.set_from_quaternion(qm, m);
		}
		else{
			var ratioA = Math.sin( (1-t) * halfTheta ) / sinHalfTheta;
			var ratioB = Math.sin(    t  * halfTheta ) / sinHalfTheta;

			qm.w = ratioA * qa.w + ratioB * qb.w;
			qm.x = ratioA * qa.x + ratioB * qb.x;
			qm.y = ratioA * qa.y + ratioB * qb.y;
			qm.z = ratioA * qa.z + ratioB * qb.z;
			return this.set_from_quaternion(qm, m);
		}
	}
};
JL.webgl.mat.interpolate = function(start, end, a, b){
	var result = Matrix.I(4);
	result = JL.webgl.mat.slerp( JL.webgl.mat.get_quaternion(start), JL.webgl.mat.get_quaternion(end), b, result );
	for(var i=0; i<4; i++){ result.elements[i][3] = a * start.elements[i][3] + b * end.elements[i][3]; }
	return result;
};
JL.webgl.mat.reduction_factor = function(mat){
	var m = mat.elements;
	return Math.max(Math.abs(m[0][3]), Math.abs(m[1][3]), Math.abs(m[2][3])) / 100;
};
JL.webgl.mat.reduce = function(mat){
	var matrix = Matrix.I(4).x(mat);
	var m = matrix.elements;
	var divisor = this.reduction_factor(matrix);
	if(divisor > 1){
		m[0][3] = m[0][3] / divisor;
		m[1][3] = m[1][3] / divisor;
		m[2][3] = m[2][3] / divisor;
	}
	return matrix;
};

JL.webgl.camera = function(){
	this.x = 0;
	this.y = 0;
	this.z = 0;

	this.rad = 10;
	this.lat = 0;
	this.lon = 0;

	this.roll = 0;
	this.pitch = 0;
	this.yaw = 0;

	this.mobile_orientation = {
		alpha : 0,
		beta  : 0,
		gamma : 0,
	};

	this.target = "";
	this.target_list = "";
	this.target_index = 0;

	this.previous_ui_framework = '';

	this.position = { x : 0, y : 0, z : 0 };

	this.direction = [0,0,0];

	this.clip = {};
	this.clip.near = 0;
	this.clip.far  = 0;
	this.clip.min  = 0.01;
	this.clip.max  = 593314.0;

	this.lerp_loop     = "";
	this.lerp_percent  = 0;
	this.lerp_duration = 100;
	this.not_lerping   = true;

	this.local_matrix  = Matrix.I(4);

	this.axis_lock = true;

	this.set_derive_position_function();

	if( this.custom_init ) this.custom_init();
};

JL.webgl.camera.prototype.translate = function(x, y, z){
        var translation = Matrix.Translation($V([x, y, z]));
        this.local_matrix = translation.x(this.local_matrix);
};

JL.webgl.camera.prototype.rotate = function(angle, v){
	if(this.axis_lock){
		if(v[0] == 1)      this.lat += angle;
		else if(v[1] == 1) this.lon += angle;
	}
	else{
        	var rotation = Matrix.Rotation( angle * JL.functions.constants.to_radians, $V([v[0], v[1], v[2]]) );
	        this.local_matrix = rotation.x(this.local_matrix);
	}
};

JL.webgl.camera.prototype.mouse_rotate = function( x, y ){
	if( this.target ){
		var rot_factor = ( this.target.camera_mouse_rotate_factor ? this.target.camera_mouse_rotate_factor( x, y ) : 1 );

		if( JL.webgl.ui.mouse.ctrl_key.pressed ){
			var x_abs = Math.abs( x );
			var y_abs = Math.abs( y );
			if( x_abs > y_abs ) this.rotate( x * rot_factor, [1,0,0] );
			if( y_abs > x_abs ) this.rotate( y * rot_factor, [0,1,0] );
		}
		else{
			this.rotate( x * rot_factor, [1,0,0] );
			this.rotate( y * rot_factor, [0,1,0] );
		}
	}
};

JL.webgl.camera.prototype.set_values = function( p ){
	Object.assign( this, p );
};

JL.webgl.camera.prototype.reset_view = function( p ){
	var p = p || {};

	var target = p.target || this.target;

	this.x = 0;
	this.y = 0;
	this.z = 0;

	this.lat           =     5;
	this.lon           =   -90;
	this.rad           =  0.25;
	this.offset        = false;
	this.target_config = {};
	if( target.camera_config ){
		for( var k of [ 'lat', 'lon', 'rad', 'offset', ] ){
			if( target.camera_config[ k ] !== undefined ) this[ k ] = target.camera_config[ k ];
		}
		this.target_config = target.camera_config;
		// 2026-02-12
		// Object.assign( this, target.camera_config );
	}

	if( !this.axis_lock ){
		this.local_matrix = Matrix.I(4);
		this.rotate( this.lon, [0,1,0] );
		this.rotate( this.lat, [1,0,0] );
	}

	JL.webgl.variables.orientation = 1;
	if( JL.webgl.device.is( 'vr' ) ) this.rad = 0;
	if( JL.webgl.device.options.vr.activated ){
		if( target._vr_to_scale && target.radius ) this.y = -target.radius;
		JL.webgl.device.options.vr.set_scale();
	}

	if( JL.webgl.variables.is_editing ) JL.webgl.ui.item.edit.reset_view();
};

JL.webgl.camera.prototype.roll_view = function( val ){
	this.rotate( val, [0,0,1] );
};

JL.webgl.camera.prototype.strafe_view = function( x, y, z ){
	if( x ){
		var right_vector = JL.webgl.functions.get_right_vector( this.view_matrix );
		this.x += x * right_vector[ 0 ];
		this.y += x * right_vector[ 1 ];
		this.z += x * right_vector[ 2 ];
	}
	if( y ){
		this.x += y * this.up[ 0 ];
		this.y += y * this.up[ 1 ];
		this.z += y * this.up[ 2 ];
	}
	if( z ){
		this.x += z * this.forward[ 0 ];
		this.y += z * this.forward[ 1 ];
		this.z += z * this.forward[ 2 ];
	}
};

JL.webgl.camera.prototype.zoom_view = function( val ){
	var target = this.target;

	var cfg = target._zoom;

	var object_radius = ( target.radius || 0.5 );
	var max           = 40 * object_radius;
	var min           =     -object_radius;

	var zoom_rate = 1;

	if( cfg ){
		if( cfg.rate ) zoom_rate = cfg.rate( target );
		if( cfg.min  ) min       = cfg.min( object_radius );
		if( cfg.max  ) max       = cfg.max( object_radius );
	}

	var radius = this.rad + object_radius * val * zoom_rate;
	this.rad = JL.functions.clamp( radius, min, max );
};

JL.webgl.camera.prototype.select_target = function( p ){
	var match;
	if( p.criteria ){
		var criteria_keys = Object.keys( p.criteria );
		match = this.target_list.find(function( target ){
			return criteria_keys.every(function( key ){
				return ( target[ key ] == p.criteria[ key ] );
			});
		});

		if( !match ){
			var recursive_search = function( obj ){
				if( match ) return;

				if( criteria_keys.every(function( key ){ return ( obj[ key ] == p.criteria[ key ] ); }) ){
					match = obj;
					return;
				}

				if( obj.all_children ){
					for( var c of obj.all_children ){
						if( !match ) recursive_search( c );
					}
				}
			};

			recursive_search( JL.webgl.active_environment._root_object );
		}
	}
	else if( p.index ){
		match = this.target_list[ p.index % this.target_list.length ];
	}
	
	if( match ) match.select( this.target_list );
};

JL.webgl.camera.prototype.set_target = function( target, params ){
	if(target instanceof Array){
		this.target_list = target;
		this.target_index = 0;

		if( params ){
			if(params.index != undefined) this.target_index = params.index;
		}

		target = this.target_list[this.target_index];

		if( this.on_set_target_list ) this.on_set_target_list();
	}

	this.target = target;

	try{
		this.previous_ui_framework = this.target.ui_framework();
	} catch(e){}

	this.reset_view();

	if( this.tour ){
		if( this.tour.on && !this.tour.start ){
			this.tour.start = this.target_list[ this.target_index ];
			this.tour.end   = this.target_list[(this.target_index+1) % this.target_list.length];
		}
	}
};

JL.webgl.camera.prototype.next_object = function( offset ){
	this.target_index += offset;
	while( this.target_index < 0 ) this.target_index += this.target_list.length;
	this.target_index = this.target_index % this.target_list.length;

	this.target_list[ this.target_index ].select(this.target_list);
};

JL.webgl.camera.prototype.reset_ui = function(){
        $(".jl-tour-transition-fade").css("opacity", 1);
};

JL.webgl.camera.prototype.interpolate = function(params){
	this.lerp(params);
	this.not_lerping = false;
};

JL.webgl.camera.prototype.lerp = function(params){
	var self = this;

	if(this.lerp_percent == 0) this.lerp_init(params);
	this.lerp_percent += 1 / this.lerp_duration;

	if(this.lerp_percent < 1){
		this._tour_transition.init_values( params.start, params.end, this.lerp_percent );

		if(this.target != params.end && !this.not_lerping) this.lerp_loop = setTimeout(function(){self.lerp(params)}, 15);
	}
        else{
		this.lerp_kill(function(){ params.end.select(self.target_list); });
                if(params.callback) params.callback();
        }
};

JL.webgl.camera.prototype.lerp_init = function(params){
	this.lerp_distance = JL.functions.distance(params.start, params.end);

	this._tour_transition = JL.webgl.active_environment.add_space_object({
		no_parent : true,
		start     : params.start,
		end       : params.end,
		percent   : this.lerp_percent,
	}, JL.webgl.camera.tour_transition );

	this.set_target( this._tour_transition );

	this.not_lerping = false;
};

JL.webgl.camera.prototype.lerp_kill = function(select_obj){
	this.lerp_percent = 0;
	this.not_lerping = true;
	this.reset_ui();
	(select_obj ? select_obj() : this.next_object(0));
	this.tour.start = this.target;
	this.tour.end   = this.target_list[(this.target_index+1)%this.target_list.length];
	clearTimeout(this.lerp_loop);
};

JL.webgl.camera.prototype.matrix_is_in_frustum = function( mat ){
	var clip_mat = JL.webgl.mat.projection.x( this.view_matrix.x( mat ) );
	var w = clip_mat.elements[ 3 ][ 3 ];
	return (
		Math.abs( clip_mat.elements[ 0 ][ 3 ] ) < w && 
		Math.abs( clip_mat.elements[ 1 ][ 3 ] ) < w && 
		0 < clip_mat.elements[ 2 ][ 3 ] && clip_mat.elements[ 2 ][ 3 ] < w
	);
};

JL.webgl.camera.prototype.point_is_in_frustum = function( point ){
	var mat = Matrix.I(4);
	mat.elements[ 0 ][ 3 ] = point[ 0 ];
	mat.elements[ 1 ][ 3 ] = point[ 1 ];
	mat.elements[ 2 ][ 3 ] = point[ 2 ];
	return this.matrix_is_in_frustum( mat );
};

JL.webgl.camera.prototype.object_is_in_frustum = function( obj ){
	return this.matrix_is_in_frustum( obj.matrix || JL.webgl.mat.model );
};

JL.webgl.camera.prototype.vr_offset = function( matrix ){
	if( JL.webgl.device.is( 'vr' ) && !JL.webgl.device.options.vr.activated && this.target.get_vr_offset ) matrix.translate( this.target.get_vr_offset() );
};

