	this.clip.near  = clip.near;
	this.clip.far   = clip.far;
	this.clip.near *= clip.clip_factor;
	this.clip.far  *= clip.clip_factor;

	// -- Old Calculations from WxSatS --

	// var camera_radius = ( JL.webgl.device.is( 'vr' ) ? this.target.camera_config.rad : this.rad );

	// var planet_clip = (this.earth_rad > 1 ? this.earth_rad - 1 : 1) ;

	// var clip_factor = 2 * Math.min( camera_radius, planet_clip );

	// if(this.target.is("Planet", "Moon", "Exoplanet", "Star")){
