	// }
	// else if(this.target.is("Rocket")){
	// 	if(this.earth_rad <= 1) clip_factor = 0.00012;
	// }
	// else if( this.target.radius ){
	// 	clip_factor = 5 * this.target.radius;
	// }
	// else if( this.target.camera_config ){
	// 	clip_factor = 5 * ( this.target.camera_config.rad || 1 );
	// }
	// else if(!this.target.real_size && !(this.target.is("Building", "Floor", "Person", "Tornado", "Animal"))){
	// 	clip_factor = Math.max( clip_factor, 0.16 );
	// 	if( camera_radius <= 0 ) clip_factor = 0.5;
	// }
