JL.webgl.camera.prototype.apply_target_transforms = function( t, matrix ){
	if( t.draw_xyz ){
		matrix.translate([ -t.x, -t.y, -t.z ]);
		if( t == this.target ) this.vr_offset( matrix );
	}
	else{
		if( t.flatten_pitch ) matrix.rotate( t.lat, [0,0,1] );
		matrix.translate([ -t.orbit_radius, 0, 0 ]);
		if( t == this.target ) this.vr_offset( matrix );
		matrix.rotate( -t.lat, [0,0,1] );
		matrix.rotate( -t.lon, [0,1,0] );
	}
	return matrix;
};

JL.webgl.camera.prototype.get_view_matrix = function(tgt){
	var self = this;

	var matrix = Matrix.I(4);

	var original_target = this.target;
	if(tgt) this.set_target(tgt);

	if( !this.target ) return matrix;

	var target = this.target;

	matrix.translate([0,0,-this.rad]);

	if(this.axis_lock){
		matrix.rotate(this.lat, [1,0,0]);
		matrix.rotate(this.lon, [0,1,0]);
	}
	else{
		matrix.transform(this.local_matrix);
	}

	// 2026-02-12
	if( this.offset ) matrix.translate([ -this.offset[0], -this.offset[1], -this.offset[2] ]);
	// if( this.offset ) matrix.translate( this.offset );

	if( JL.webgl.device.is( 'vr' ) ){
		if( !JL.webgl.device.options.vr.activated ){
			matrix.rotate(this.mobile_orientation.gamma, [0,0,1]);
			matrix.rotate(this.mobile_orientation.alpha, [0,1,0]);
			matrix.rotate(this.mobile_orientation.beta,  [1,0,0]);
		}
	}

	if(target.draw_from_matrix){
		this.vr_offset( matrix );
		matrix.transform( ( target.target_matrix || target.matrix ).inverse() );
	}
	else if( target.camera_from_matrix ){
		this.vr_offset( matrix );
		if( target.camera_config_matrix ) matrix.transform( target.camera_config_matrix );
		matrix.transform( target.matrix.inverse() );
	}
	else{
		if( this.target_config.follow_roll_pitch_yaw ){
			if( target.yaw   ) matrix.rotate(-target.yaw,   [0,1,0]);
			if( target.roll  ) matrix.rotate(-target.roll,  [0,0,1]);
			if( target.pitch ) matrix.rotate(-target.pitch, [1,0,0]);
		}

		matrix = this.apply_target_transforms( target, matrix );

		matrix.rotate(-this.roll,  [0,0,1]);
		matrix.rotate(-this.pitch, [1,0,0]);

		if(target.offset) matrix.translate([-target.offset[0], -target.offset[1], -target.offset[2]]);

		var curr_target = target;
		while( curr_target.parent_object ){
			var curr_parent = curr_target.parent_object;
			matrix.rotate(-curr_parent.yaw,   [0,1,0]);
			matrix.rotate(-curr_parent.roll,  [0,0,1]);
			matrix.rotate(-curr_parent.pitch, [1,0,0]);

			if(curr_parent.axial_tilt){
				matrix.rotate(-curr_parent.lon       , [0,1,0]);
				matrix.rotate(-curr_parent.axial_tilt, [0,0,1]);
				matrix.rotate( curr_parent.lon       , [0,1,0]);
			}

			matrix = this.apply_target_transforms( curr_parent, matrix );

			curr_target = curr_parent;
		}
	}

	matrix.translate([-this.x, -this.y, -this.z]);

	if(tgt) this.set_target(original_target);

	return matrix;
};

JL.webgl.camera.prototype.on_update = function(){
};

JL.webgl.camera.prototype.derive_position__default = function(){
	Object.assign( this.position, JL.webgl.functions.get_xyz( this.view_matrix ) );
};

JL.webgl.camera.prototype.derive_position__vr = function( view_offset ){
	if( view_offset ){
		this.view_matrix = view_offset.x( this.view_matrix );
		this.prev_view_offset = view_offset;
	}
	else if( this.prev_view_offset ){
		this.view_matrix = this.prev_view_offset.x( this.view_matrix );
	}

	var view_inv = this.view_matrix.inverse();
	this.position.x = view_inv.elements[ 0 ][ 3 ];
	this.position.y = view_inv.elements[ 1 ][ 3 ];
	this.position.z = view_inv.elements[ 2 ][ 3 ];
};

JL.webgl.camera.prototype.set_derive_position_function = function( name ){
	switch( name ){
		case 'vr':
			this.derive_position = function(  view_offset ){
				this.derive_position__vr( view_offset );
			};
			break;
		default:
			this.derive_position = function( view_offset ){
				this.derive_position__default();
			};
			break;
	};
};

JL.webgl.camera.prototype.draw = function( view_offset ){
	try{
		var args = JL.webgl.active_environment.args;
		if( args.auto_rotate ){
			this.lon += args.auto_rotate_speed || 0.05;
			this.lon %= 360;
		}
	} catch(e){}

	this.view_matrix = this.target.view_matrix || this.get_view_matrix();

	this.derive_position( view_offset );

	var direction = [this.position.x - this.target.x, this.position.y - this.target.y, this.position.z - this.target.z];
	var mag = Math.sqrt(direction[0] * direction[0] + direction[1] * direction[1] + direction[2] * direction[2]);

	this.direction[ 0 ] = this.position.x + ( direction[ 0 ] / mag );
	this.direction[ 1 ] = this.position.y + ( direction[ 1 ] / mag );
	this.direction[ 2 ] = this.position.z + ( direction[ 2 ] / mag );

	this.forward = JL.webgl.functions.get_forward_vector( this.view_matrix );
	this.up      = JL.webgl.functions.get_up_vector(      this.view_matrix );

	// For VR + instanced_impostor_xyz
	if( view_offset ){
		this.forward = JL.functions.normalize( this.forward );
		this.up      = JL.functions.normalize( this.up      );
	}

	this.matrix = this.view_matrix.inverse();

	this.on_update();
};

JL.webgl.load = { groups : {}, loaded_scripts : [] };

JL.webgl.load.assets = function( p ){
	var self = this;

	if( this.is_loading_assets ){
		console.log( 'Error: JL.webgl.load.assets is currently loading something else. ', p );
		return ;
	}
	this.is_loading_assets = true;

	var env_cfgs = ( p.environments || [] ).slice();

	var accumulator = {};
	for( var k of [ 'scripts', 'env_keys', 'groups', 'graphics_objects', '_environment_configs' ] ) accumulator[ k ] = [];

	// Note: both pre_load_scripts and second_attempt_scripts are not included in loading_queue.
	var pre_load_scripts       = [];
	var second_attempt_scripts = [];

	var recursive_helper = function(){
		var env_params = env_cfgs.shift() || {};

		var load_from_config = function( cfg ){
			try     { var keys = cfg.environment.keys || env_params.keys; }
			catch(e){ var keys = env_params.keys; }

			if( keys ) accumulator.env_keys.push( keys );
			
			accumulator.scripts = accumulator.scripts.concat( cfg.scripts || [] );

			if( cfg.space_objects ){
				for( var space_object_type of Object.keys( cfg.space_objects ) ){
					var space_object_path = space_object_type.split('/');

					if( space_object_type == '_regular' ) continue;

					if( space_object_type == '_person' ) accumulator.groups.push( '_Person' );

					if( !JL.webgl.functions.get_space_object_class( space_object_path ) ){
						accumulator.scripts.push({
							space_object_type,
							url             : JL.webgl.dir.environments + '/' + keys.join('/') + '/space_object/' + space_object_type + '.js',
							suppress_errors : true,
						});
					}
				}
			}

			accumulator.graphics_objects = accumulator.graphics_objects.concat( Object.values( cfg.graphics_objects || {} ) );

			accumulator.groups = accumulator.groups.concat( ( env_params.groups || [] ).slice() );
			// 2025-01-20
			// if( cfg.groups ) accumulator.groups = accumulator.groups.concat( cfg.groups.slice() );
			if( cfg.environment ){
				if( cfg.environment.import_load_groups ){
					for( var imp of cfg.environment.import_load_groups ){
						if     ( imp.keys     ) pre_load_scripts.push({ url : JL.webgl.dir.js + '/environments/' + imp.keys.join('/') + '/Load.js', suppress_errors : true });
						else if( imp.filename ) pre_load_scripts.push({ url : imp.filename, suppress_errors : true });
					}
				}
				if( cfg.environment.load_groups ) accumulator.groups = accumulator.groups.concat( cfg.environment.load_groups.slice() );
			}

			if( keys ){
				if( !JL.functions.get_nested_object( JL.webgl.environments, keys ) ){
					pre_load_scripts.push(
						{ url : JL.webgl.dir.js + '/environments/' + keys.join('/') + '/Load.js', suppress_errors : true },
						{ url : JL.webgl.dir.js + '/environments/' + keys.join('/') + '/Main.js', suppress_errors : true },
					);
				}
			}

			accumulator._environment_configs.push( cfg );

			if( env_cfgs.length ) recursive_helper();
			else{
				self._scripts({ scripts : pre_load_scripts, callback : function(){
					var env;
					for( var i = 0; i < accumulator.env_keys.length; i++ ){
						var env_keys = accumulator.env_keys[ i ];
						env = JL.functions.get_nested_object( JL.webgl.environments, env_keys );

						var curr_environment_config = accumulator._environment_configs[ i ];

						if( !env || !( env instanceof JL.webgl.environment ) ){
							if( JL.webgl.variables.is_editing ){
								if( !Object.keys( curr_environment_config ).length ){
									curr_environment_config.environment = { // Default new environment for editing
										lights : [{ ambient : 0.2, color : [1,1,1], position : [0,100,0] }],
									}
								}
							}
							env = JL.webgl.functions.init_environment( env_keys, curr_environment_config.environment );
							env.set_environment_config( curr_environment_config );
						}
						else if( curr_environment_config.environment ){ env.re_construct({ params : curr_environment_config.environment }); }

						if( env ){
							if( env.load_groups ) accumulator.groups = accumulator.groups.concat( env.load_groups.slice() );
							if( Object.values( curr_environment_config || {} ).length ) env.set_environment_config( curr_environment_config );
						}
					}

					if( p.groups ) accumulator.groups = accumulator.groups.concat( p.groups );

					accumulator.groups = JL.functions.filter_duplicates( accumulator.groups );

					var loading_queue = [];
					loading_queue = loading_queue.concat(
						( p.scripts || [] ).concat( accumulator.scripts ).map(function( g ){
							return {
								type : 'script',
								item : g,
								name : ( g.url || g ),
							};
						})
					);
					loading_queue = loading_queue.concat(
						accumulator.graphics_objects.map(function( g ){
							return {
								type : 'graphics_object',
								item : g,
								name : ( g.label || g.keys || [] ).join('/'),
							};
						})
					);

					while( accumulator.groups.length && !self.groups[ accumulator.groups[0] ] ) accumulator.groups.shift();
					
					loading_queue = loading_queue.concat(
						accumulator.groups.map(function( name ){ return { type : 'group', name }; })
					);

					var percentage = 1 / loading_queue.length;
					for( var i = 0; i < loading_queue.length; i++ ){
						loading_queue[ i ].index      = i;
						loading_queue[ i ].progress   = i / loading_queue.length;
						loading_queue[ i ].percentage = percentage;
					}
					var list = $.extend( true, [], loading_queue );
					for( var x of loading_queue ) x.list = list;

					var load_assets = function(){
						self._scripts({ scripts : loading_queue.filter( x => x.type == 'script' ), callback : function(){
							self._scripts({ scripts : second_attempt_scripts, callback : function(){
								if( cfg.environment ) JL.webgl.functions.set_global_effects({ environment : cfg.environment.properties });

								var graphics_objects_to_load = loading_queue.filter( x => x.type == 'graphics_object' );
								try     { var graphics_objects_progress_start = graphics_objects_to_load[ 0 ].progress; }
								catch(e){ var graphics_objects_progress_start = 0; }

								self._graphics_objects({
									graphics_objects : graphics_objects_to_load,
									callback         : function(){
										self._groups({
											groups   : loading_queue.filter( x => ( x.type == 'group' && self.groups[ x.name ] ) ),
											callback : function(){
												if( self.assets_on_finish ) self.assets_on_finish();

												if( p.callback ) p.callback( env );

												delete self.is_loading_assets;
											},
										});
									},
									create_p : { environment : ( cfg.environment || {} ).properties },
									individual_graphics_object_callback : function( _p ){
										var g = $.extend( true, {}, _p.item );

										g.progress = graphics_objects_progress_start + g.percentage * _p.items_loaded;

										if( self.assets_on_update ) self.assets_on_update( g );
									},
								});
							}, });
						}, });
					};

					if( self.assets_on_start ) self.assets_on_start({ loading_queue, callback : function(){ load_assets(); }, });
					else{ load_assets(); }
				}, });
			}
		};

		if( env_params.config ) load_from_config( env_params.config );
		else if( env_params.keys ){
			$.ajax({
				url      : JL.webgl.dir.js + '/environments/' + env_params.keys.join('/') + '/environment.json',
				dataType : 'json',
				cache    : false,
				success  : function( c ){ load_from_config( c || {} ); },
				error    : function(   ){ load_from_config(      {} ); },
			});
		}
		else{ load_from_config( p ); }
	};

	recursive_helper();
};

JL.webgl.load._graphics_objects = function( p ){
	var self = this;

	var graphics_objects = p.graphics_objects;
	var callback         = p.callback;

	var num_loaded = 0;

	var load_interval = setInterval(function(){
		if( num_loaded >= graphics_objects.length ){
			clearInterval( load_interval );
			callback();
		}
	}, 30);

	graphics_objects.forEach(function( m_obj ){
		var m = m_obj.item || m_obj;

		var params = m.params || m;

		var label = m.label || params.label;
		var  keys = m.keys  || params.keys;

		if( m.params ){
			[ 'label', 'keys' ].forEach(function( k ){
				if( m[ k ] ) m.params[ k ] = m[ k ];
			});
		}

		var cb = params.callback;
		params.callback = function( graphics_object ){
			if( cb ) cb( graphics_object );
			if( p.individual_graphics_object_callback ) p.individual_graphics_object_callback({ items_loaded : num_loaded, graphics_object, item : m_obj });
			num_loaded++;
		};

		if( !label && !keys ){
			console.log( 'Error : neither "label" nor "keys" are defined for the following graphics_object.' );
			console.log( m );
		}

		if( !JL.functions.get_nested_object( JL.webgl.graphics_objects, label ) ) JL.webgl.functions.create_graphics_object( m, p.create_p );
		else                                                            params.callback();
	});
};

JL.webgl.load._groups = function( p ){
	if( !this.is_loading_objects ){
		var self = this; 

		this.is_loading_objects = true;

		var p = p || {};

		this.groups_to_load = ( p.groups || [] )

		this._group( 0, function(){
			if( p.callback ) p.callback();

			self.is_loading_objects = false;
		} );    
	}
	else{
		console.log( 'Error: JL.webgl.load._groups is currently loading another set of groups.' );
		console.log( ' >> List of groups that failed to load:', p.groups );
	}
};

JL.webgl.load._scripts = function( p ){
	var scripts = p.scripts;
	var index   = p.index || 0;

	if( index >= scripts.length ) return ( p.callback || function(){} )();

	var self = this;

	var curr_script = scripts[ index ];

	var next_iteration = function(){
		if( curr_script.item ){
			if( self.assets_on_update ) self.assets_on_update( curr_script );
		}
		self._scripts({ scripts, callback : p.callback, index : index + 1 });
	};

	if( JL.functions.is_str( curr_script ) ){
		JL.functions.load_js({
			url      : curr_script,
			callback : next_iteration,
		});
	}
	else{
		var curr_script_obj = ( curr_script.item || curr_script );
		JL.functions.load_js( Object.assign( {}, curr_script_obj, {
			callback : function(){
				if( curr_script_obj.callback ) curr_script_obj.callback();
				next_iteration();
			},
		}) );
	}
};

JL.webgl.load._group = function( idx, callback ){
	var self = this;
	
	var idx = idx || 0;
	
	if( idx >= this.groups_to_load.length ){
		if( callback ) callback();
		return;
	}
	
	this.curr_group_name = this.groups_to_load[ idx ].name;

	this.curr_group_index = idx;
	
	this.curr_group = this.groups[ this.curr_group_name ];

	if( !this.curr_group ){
		if( callback ) callback();
		return;
	}

	var load_steps = function(){
		self._step( 0, function(){
			self._group( idx + 1, callback );
		} );
	};

	if( this.curr_group.scripts ){
		var cb = load_steps;
		load_steps = function(){
			self._scripts({
				scripts  : self.curr_group.scripts.filter( x => ( self.loaded_scripts.indexOf( x ) == -1 ) ),
				callback : cb
			});
		};
	}

	load_steps();
};

JL.webgl.load._step = function(idx, callback){
	var self = this;

	idx = idx || 0;

	if( !this.curr_group.steps || idx >= this.curr_group.steps.length ){
		delete this.groups[ this.curr_group_name ];
		if(callback) callback();
		return;
	}

	var step = this.curr_group.steps[idx];

	var items_loaded = 0;
	var items_total  = 0;

	var update_callback = function(){
		if( self.assets_on_update ){
			var g = $.extend( true, {}, self.groups_to_load[ self.curr_group_index ] );

			g.progress += g.percentage * 
				(
					( items_loaded / ( items_total || 1 ) ) + 
					idx
				) / 
				( self.curr_group.steps.length );

			self.assets_on_update( g );
		}
	};

	var step_callback = function(){
		update_callback();
		self._step( idx + 1, callback );
	};

	step.init(function(){
		if( step.graphics_objects ){
			items_total = step.graphics_objects.length;
			self._graphics_objects({
				graphics_objects                    : step.graphics_objects,
				callback                            : function(){ step_callback(); },
				individual_graphics_object_callback : function( _p ){
					items_loaded = _p.items_loaded;
					update_callback();
				},
			});
		}
		else{
			step_callback();
		}
	});
};

JL.webgl.load.start = function(){
	var self = this;

	JL.webgl.main.init();

	JL.webgl.mat.identity();

	var params = {
		environments : [{ keys : JL.webgl.variables.default_environment }],
		scripts      : [],
		groups       : [],
		callback     : function(){
			if( self.start_on_finish ) self.start_on_finish();
		}
	};

	this._all_add_to_callback = function( commands ){
		var callback = params.callback;
		params.callback = function(){
			callback();
			commands();
		};
	};

	JL.webgl.graphics_object.presets.init();

	JL.webgl.functions.create_graphics_object({ keys : [ '_default_player' ], type : 'sphere', properties : { effects : [ '_default_coloring' ] }, segs : 12, radius : 0.25, transforms : [{ type : 'translate', y : 0.25 },{ type : 'scale', y : 2 },] });
	JL.webgl.functions.create_graphics_object({ keys : [ '_default_item'   ], type : 'cube'  , properties : { effects : [ '_default_coloring' ] }, x : 1, y : 1, z : 1 });
	JL.webgl.functions.create_graphics_object({ keys : [ '_line'           ], type : 'cube'  , properties : { effects : [ '_plain' ], color : '1.0, 1.0, 1.0, 1.0' }, x : 1, y : 1, z : 1 });

	JL.webgl.functions.create_background({
		name             : '_default',
		graphics_objects : [{ type : 'sphere', segs : 12, radius : 99999, properties : { effects : [ '_no_fog', '_default_coloring' ] }, }],
	});

	JL.webgl.device.options[ JL.webgl.device.selected ].set();

	if( JL.webgl.variables.is_editing ) params.groups.push( '_Edit - defaults', '_Edit - custom', '_Person' );

	if( JL.webgl.device.is( 'vr' ) ) params.groups.push( '_VR' );

	if( this.queue_on_init ) this.queue_on_init( params );

	if( this.start_on_init ) this.start_on_init( params );
	else{
		this._all_add_to_callback(function(){
			JL.functions.get_nested_object( JL.webgl.environments, JL.webgl.variables.default_environment ).select();
		});
	}

	this._all_add_to_callback(function(){
		requestAnimationFrame( JL.webgl.main.loop );
	});

	this.assets( params );
};

JL.webgl.load.get_graphics_object_entry = function( p ){
	var obj    = p.obj    || {};
	var shared = p.shared || {};
	var path   = p.path   || '';

	var type = ( obj.type || shared.type );

	var input_params = ( obj.params || shared.params || {} );

	return {
		label  : obj.label || obj.keys,
		keys   : obj.keys,
		type   : type,
		args   : obj.args || shared.args || [],   // TODO : Might be able to remove this line.
		params : input_params,
	};
};

JL.webgl.load.graphics_objects_list = function( _this, objs, shared ){
	var shared = shared || {};

	if( !_this.graphics_objects ) _this.graphics_objects = [];

	objs.forEach(function( obj ){
		var path;
		if( obj.keys ) path = obj.keys.join('/');

		_this.graphics_objects.push( this.get_graphics_object_entry({ obj, shared, path, }) );
	}, this);
};

JL.webgl.load.instanced_graphics_objects = function( _this, p ){
	var self = this;

	if( !_this.graphics_objects ) _this.graphics_objects = [];

	var push_graphics_objects = function( objs ){
		objs.forEach(function( obj ){
			var path;
			if( obj.keys ) path = obj.keys.join('/');

			var graphics_object = self.get_graphics_object_entry({ obj, path, });

			var custom_init = function(){};
			var init_functions = [];

			var instanced_attributes = Object.keys( obj.instances[ 0 ] );
			instanced_attributes.forEach(function( attr_name ){
				var attr = JL.webgl.shaders.config.attr[ attr_name ];

				var label_functions = attr.labels.map(function( l, i ){
					var init_function = function( inst ){
						if( attr.type == 'float' ) inst[ attr_name ] = [ inst[ attr_name ] ];
					};
					var push_function = function( inst ){
						this[ attr_name ].push( inst[ attr_name ][ i ] );
					};

					var format_functions = [];

					if( attr.default    ) format_functions.push(function( inst ){ inst[ attr_name ]       = ( inst[ attr_name ]      !== undefined ? inst[ attr_name ]      : attr.default ); });
					if(    l.default    ) format_functions.push(function( inst ){ inst[ attr_name ][ i ]  = ( inst[ attr_name ][ i ] !== undefined ? inst[ attr_name ][ i ] :    l.default ); });
					if(    l.multiplier ) format_functions.push(function( inst ){ inst[ attr_name ][ i ] *= l.multiplier; });

					if( format_functions.length ){
						return function( inst ){
							init_function.call( this, inst );

							format_functions.forEach(function( fn ){
								fn.call( this, inst );
							}, this);

							push_function.call( this, inst );
						};
					}

					return function( inst ){
						init_function.call( this, inst );
						push_function.call( this, inst );
					};
				});

				var init_fn = function( inst ){
					label_functions.forEach(function( attr_fn ){
						attr_fn.call( this, inst );
					}, this);
				};

				init_functions.push( init_fn );
			});

			graphics_object.params.custom_init = function(){
				this.num_instances = obj.instances.length;
				obj.instances.forEach(function( instance ){
					init_functions.forEach(function( init_fn ){
						try{
							init_fn.call( this, instance );
						} catch(e){
							console.log( 'Error: failed to load : ' + path );
							console.log( '    -Location: JL.webgl.load.instanced_graphics_objects' );
							console.log( '    -graphics_object: ', graphics_object );
						}
					}, this);
				}, this);
			};

			_this.graphics_objects.push( graphics_object );
		});
	};

	if( p.filename ){
		$.ajax({
			url      : p.filename,
			dataType : 'json',
			cache    : false,
			success  : function( objs ){
				push_graphics_objects( objs );
				if( p.callback ) p.callback( objs );
			},
			error    : function( e ){
				console.log( 'Error : failed to load instanced graphics_objects -- ' + p.filename );
				console.log( e );
			}
		});
	}
	else{
		push_graphics_objects( p.objs );
	}
};

JL.webgl.load.customizable_person_graphics_objects = function( _this, p ){
	var p = p || {};

	this.graphics_objects_list( _this,
		[ 'body' ].map(function( x ){
			var model_path = JL.webgl.dir.dist + '/models/person/' + x;
			return {
				keys   : [ '_person', x ],
				params : {
					properties      : {
						effects          : [ '_animated', '_customizable_person' ],
						material         : 'person',
						preserve_buffers : 1,
					},
					filename         : model_path + '/model.obj',
					vertex_groups    : model_path + '/vertex_groups.json',
					async            : false,
				}
			};
		})
	);

	if( p.custom ){
		this.graphics_objects_list( _this,
			p.custom.map(function( x ){
				var path = x.keys.join('/');
				var cfg  = {
					keys   : x.keys,
					label  : x.label,
					params : JL.functions.recursive_assign({
						properties       : {
							effects          : [ '_animated' ].concat( x.effects || [] ),
							material         : 'person',
							preserve_buffers : 1,
						},
						vertex_groups    : JL.webgl.dir.models + '/' + path + '/vertex_groups.json',
						async            : false,
					}, x.params || {} )
				};
				if( x.texture ){
					cfg.params.textures = JL.webgl.functions.add_or_replace_to_textures_config( cfg.params.textures, {
						filename : JL.webgl.dir.models + '/' + path + '/textures/' + x.texture,
					} );
				}
				return cfg;
			})
		);
	}

	this.graphics_objects_list( _this,
		( p.clothes || [] ).concat([
			{ keys : [ 'shirt', 'short_sleeve' ] },
			{ keys : [ 'pants', 'long'         ] },
			{ keys : [ 'shoes', 'sneakers'     ] },
		]).map(function( x ){
			var keys = [ '_person', 'clothes' ].concat( x.keys );
			var model_path = JL.webgl.dir.dist + '/models/person/clothes/' + x.keys.join('/');
			var cfg  = {
				keys,
				label  : x.label,
				params : JL.functions.recursive_assign({
					properties       : {
						effects          : [ '_animated' ],
						material         : 'person',
						preserve_buffers : 1,
					},
					filename      :               model_path + '/model.obj',
					textures      : [{ filename : model_path + '/texture.png', }],
					vertex_groups :               model_path + '/vertex_groups.json',
					async         : false,
				}, x.params || {} )
			};
			if( x.texture ){
				cfg.params.textures = JL.webgl.functions.add_or_replace_to_textures_config( cfg.params.textures, {
					filename : ( x.texture.includes('/') ? x.texture : 
						JL.webgl.dir.models + '/' + keys.join('/') + '/textures/' + x.texture
					),
				} );
			}
			return cfg;
		})
	);

	this.graphics_objects_list( _this,
		( p.parts || [] ).concat([
			{ keys : [ 'eye'    , 'default'  ] },
			{ keys : [ 'eyebrow', 'thick_01' ], effects : [ '_color_add' ] },
		]).map(function( x ){
			var model_path = JL.webgl.dir.dist + '/models/person/parts/' + x.keys.join('/');
			return {
				keys   : [ '_person', 'parts' ].concat( x.keys ),
				label  : x.label,
				params : {
					properties       : {
						effects          : [ '_animated' ].concat( x.effects || [] ),
						material         : 'person',
						preserve_buffers : 1,
					},
					filename      :               model_path + '/model.obj',
					textures      : [{ filename : model_path + '/texture.png', }],
					vertex_groups :               model_path + '/vertex_groups.json',
					async         : false,
				}
			};
		})
	);

	this.graphics_objects_list( _this,
		( p.hair || [] ).concat([
			{ keys : [ 'short_01' ] },
		]).map(function( x ){
			var model_path = JL.webgl.dir.dist + '/models/person/parts/hair/' + x.keys.join('/');
			return {
				keys   : [ '_person', 'parts', 'hair', ].concat( x.keys ),
				label  : x.label,
				params : {
					properties       : {
						effects          : [ '_animated', '_color_add', '_discard_alpha', ].concat( x.effects || [] ),
						material         : 'person',
						preserve_buffers : 1,
					},
					filename      :               model_path + '/model.obj',
					textures      : [{ filename : model_path + '/texture.png', }],
					vertex_groups :               model_path + '/vertex_groups.json',
					async         : false,
				}
			};
		})
	);
};

JL.webgl.load.init_class = function( keys, load_class ){
	var curr_obj = JL.webgl;
	keys.forEach(function( key, i ){
		if( i < keys.length - 1 ){
			if( !curr_obj[ key ] ) curr_obj[ key ] = {};
			curr_obj = curr_obj[ key ];
		}
		else{
			curr_obj[ key ] = load_class();
		}
	});
};

JL.webgl.load.shader = function( name, graphics_object ){
	if( !JL.webgl.shaders.loaded[ name ] ) JL.webgl.shaders.loaded[ name ] = new JL.webgl.shader( name, graphics_object );
};

JL.webgl.load.init_config = function(){
	Object.assign( JL.webgl.load.groups, {
		"_Edit - defaults" : {
			steps : [
				{
					init : function( callback ){
						for( var k of [ 'rotate', 'strafe_view', 'zoom_view', ] ){
							JL.webgl.active_camera[ k ] = JL.functions.concat_functions([
								JL.webgl.active_camera[ k ],
								function(){ JL.webgl.ui.item.edit.update_camera_position(); }
							]);
						}

						JL.webgl.load.graphics_objects_list( this, [
							{
								keys : [ '_default_wall' ],
								type : "square",
								params : {
									transforms : [{ type : 'translate', x : 0.5, y : 0.5 }],
									properties : { effects : [ '_default_coloring' ] },
								}
							},
							{
								keys : [ '_default_feature' ],
								type : "cube",
								params : {
									x : 0.25,
									z : 0.1,
									y : 0.5 ,
									transforms : [{ type : 'translate', y : 0.5, z : 0.1 }],
									properties : { effects : [ '_default_coloring' ] },
								}
							},
							{
								keys : [ '_default_path' ],
								type : "cube",
								params : {
									x : 0.5,
									z : 0.5,
									y : 0.01,
									transforms : [{ type : 'translate', z : 0.5 }],
									properties : { effects : [ '_default_coloring' ] },
								}
							},
							{
								keys : [ '_default_pipe' ],
								type : "cylinder",
								params : {
									height     : 1,
									rad_top    : 0.5,
									rad_bot    : 0.5,
									transforms : [{ type : 'translate', y : 0.5, },{ type : 'rotate', axis : 'x', val : 90, },],
									properties : { effects : [ '_default_coloring' ] },
								}
							},
							{
								keys : [ '_default_chassis' ],
								type : "cube",
								params : {
									x : 0.6,
									y : 0.6,
									z : 1,
									transforms : [{ type : 'translate', y : 0.3 }],
									properties : { effects : [ '_default_coloring' ] },
								}
							},
							{
								keys : [ '_default_wheel' ],
								type : "cylinder",
								params : {
									height     : 0.25,
									rad_top    : 0.5,
									rad_bot    : 0.5,
									transforms : [{ type : 'rotate', axis : 'x', val : 90, },{ type : 'rotate', axis : 'y', val : 90, },],
									properties : { effects : [ '_default_coloring' ] },
								}
							},
						]);

						callback();
					}
				},
			],
		},
		"_Edit - animation" : {
			steps : [
				{
					init : function( callback ){
						JL.webgl.load.graphics_objects_list( this,
							JL.webgl.edit_animation_graphics_objects.map(function( name ){
								return {
									keys       : [ 'edit', 'animation', name ],
									label      : [ '_in_library', 'edit', 'animation', name ],
									params     : {
										in_library    : true,
										properties    : { effects : [ '_animation_edit' ] },
										vertex_groups : JL.webgl.dir.dist + '/models/edit/animation/' + name + '/vertex_groups.json',
									},
								};
							})
						);

						callback();
					}
				},
			],
		},
		"_Person" : {
			steps : [
				{
					init : function( callback ){
						JL.webgl.load.customizable_person_graphics_objects( this );
						callback();
					}
				},
			],
		},
		"_VR" : {
			steps : [
				{
					init : function(callback){
						JL.webgl.load.graphics_objects_list( this, [
							...[ 'left', 'right' ].map(function( key ){
								return {
									label  : [ '_in_library', 'vr', 'controllers', 'oculus_quest_1', key ],
									params : {
										filename   :               JL.webgl.dir.dist + '/models/vr/controllers/oculus_quest_1/' + key + '/model.obj',
										textures   : [{ filename : JL.webgl.dir.dist + '/models/vr/controllers/oculus_quest_1/' + key + '/texture.png' }],
										properties : { effects : [ '_plain' ] },
									}
								}; 
							}),
							{
								label  : [ '_in_library', 'vr', 'loading_text' ],
								type   : "square",
								params : {
									properties  : { effects : [ '_instanced_pos', '_instanced_rot', '_plain' ] },
									custom_init : function(){
										this.num_instances = 8;

										var rot_offset = -90 * JL.functions.constants.to_radians;

										for( var angle = 0; angle < JL.webgl.constants.PI2; angle += JL.webgl.constants.PI2 / this.num_instances ){
											var x = 9 * Math.cos( angle );
											var z = 9 * Math.sin( angle );

											this.pos.push( x, 0, z );
											this.rot.push( 0, rot_offset - angle, 0 );
										}
									}
								}
							},
							{
								label  : [ '_in_library', 'vr', 'loading_background' ],
								type   : "sphere",
								params : {
									radius     : 10,
									segs       : 16,
									properties : { effects : [ '_default_coloring' ] },
								}
							},
							{
								label  : [ '_in_library', 'vr', 'menu', 'container' ],
								params : {
									filename   :               JL.webgl.dir.dist + '/models/vr/menu/container/model.obj',
									textures   : [{ filename : JL.webgl.dir.dist + '/models/vr/menu/container/texture.png' }],
									properties : { effects : [ '_plain' ] },
								}
							},
							{
								label  : [ '_in_library', 'vr', 'menu', 'button' ],
								params : {
									filename   : JL.webgl.dir.dist + '/models/vr/menu/button/model.obj',
									no_texture : true,
									properties : { effects : [ '_plain' ] }
								}
							},
						] );

						callback();
					}
				}
			]
		},
	} );
};

JL.webgl.device = {
	_default : 'desktop',
	options  : {},
};
JL.webgl.device.selected = JL.webgl.device._default;

JL.webgl.device.is = function(){
        for( var i=0; i<arguments.length; i++ ){
                if( this.selected == arguments[i] ) return true;
        }
        return false;
};

JL.webgl.device.set = function( name ){
	this.selected = "desktop";
	if( Object.keys( this.options ).includes( name ) ) this.selected = name;

	if( JL.webgl.hashlinks ){
		if( JL.webgl.hashlinks.params.device ){
			if( this.selected == this._default ) JL.webgl.hashlinks.remove( 'device' );
			else                                 JL.webgl.hashlinks.add({ device : this.selected });
		}
	}

	if( this.on_set ) this.on_set();

	if( JL.webgl.gl ) JL.webgl.canvas.primary.resize();
};

JL.webgl.device.options.desktop = {};

JL.webgl.device.options.desktop.set = function(){
};

JL.webgl.device.options.mobile = {};
JL.webgl.device.options.mobile.prev_touch_1 = {x: 0, y: 0};
JL.webgl.device.options.mobile.prev_touch_2 = {x: 0, y: 0};

JL.webgl.device.options.mobile.set = function(){
	$('<style>'+
		[ '.jl-hidden-mobile' ].concat( this.to_hide || [] ).join(',') + '{ display:none !important; }'+
	'</style>').appendTo('body');
};

JL.webgl.device.options.vr = { ui : {} };

JL.webgl.device.options.vr.set = function(){
	var self = this;

	JL.webgl.device.options.mobile.set();
	JL.webgl.active_camera.rad = 0;
	JL.webgl.active_camera.zoom_view = function(){ this.rad = 0; };

	this.scale_matrix = Matrix.I(4);

	this.all_space_objects = [];

	this.web_standard = false;

	$( '#jl-webgl-fullscreen-toggle' ).html( '<i class="fa fa-simplybuilt" style="transform:rotate(180deg);"></i>' );

	JL.functions.add_css(`
		#jl-webgl-fullscreen-toggle{
			color:#0f0;
			animation: jl-webgl-blinking-vr-logo 1s infinite;
			-webkit-animation: jl-webgl-blinking-vr-logo 1s infinite;
		}

		@keyframes jl-webgl-blinking-vr-logo {
			  0% { color : #030; }
			 50% { color : #0f0; }
			100% { color : #030; }
		}

		@-webkit-keyframes jl-webgl-blinking-vr-logo {
			  0% { color : #030; }
			 50% { color : #0f0; }
			100% { color : #030; }
		}

		@media only screen and ( min-width : 992px ){
			#jl-webgl-fullscreen-toggle{ display:block; }
		}
	`);

	if( this.on_set ) this.on_set();

	this.set_webxr(function(){
		if( !self.web_standard ) self.set_naive();
	});
};

JL.webgl.device.options.vr.set_webxr = function( callback ){
	var self = this;
	if( !this.web_standard ){
		try{
			navigator.xr.isSessionSupported( 'immersive-vr' ).then(function(){
				self.web_standard = 'webxr' ;

				$( '#jl-webgl-fullscreen-toggle' ).removeAttr( 'onclick' );
				$( '#jl-webgl-fullscreen-toggle' ).attr(       'onclick', 'JL.webgl.device.options.vr.activate();' );

				if( self.on_set_webxr ) self.on_set_webxr();

				if( callback ) callback();
			});
		} catch(e){
			if( callback ) callback();
		}
	}
};

JL.webgl.device.options.vr.set_naive = function(){
	JL.webgl.canvas.create_secondary_canvas();

	window.addEventListener( 'deviceorientation', function(e){
		JL.webgl.active_camera.mobile_orientation.alpha = -2 * e.alpha;
		JL.webgl.active_camera.mobile_orientation.beta  =  2 * e.beta;
		JL.webgl.active_camera.mobile_orientation.gamma =  2 * (-e.gamma - 90);
		if( JL.webgl.active_camera.mobile_orientation.gamma < -180 ){
			JL.webgl.active_camera.mobile_orientation.beta = 360 - JL.webgl.active_camera.mobile_orientation.beta;
		}
		if( window.orientation == -90 ) JL.webgl.active_camera.mobile_orientation.gamma *= -1;
	});

	JL.webgl.canvas.primary.resize();

	this.activated = true;

	this.web_standard = 'naive';
};

JL.webgl.device.options.vr.activate = function(){
	var self = this;

	this.space_objects = {
		gamepad : {}
	};

	this.set_scale();

	JL.webgl.active_camera.set_derive_position_function( 'vr' );

	switch( this.web_standard ){
		case 'webxr':
			var ref = ( JL.webgl.active_camera.target._vr_to_scale ? 'local-floor' : 'local' );
			var session_type = 'immersive-vr';
			if( JL.webgl.ui.ar.on ) session_type = 'immersive-ar';
			navigator.xr.requestSession( session_type, { requiredFeatures : [ ref ] } ).then(function( session ){
				self.xr_session = session;
				self.xr_layer   = new XRWebGLLayer( session, JL.webgl.gl );

				self.xr_session.updateRenderState({ baseLayer : self.xr_layer });

				// self.update_immersive_reference_point();

				self.xr_session.onend = function(){ self.deactivate(); };

				self.xr_session.requestReferenceSpace( 'viewer' ).then(function( viewer_space ){
					self.viewer_reference_space = viewer_space;
					self.xr_session.requestReferenceSpace( ref ).then(function( floor_space ){
						self.floor_reference_space = floor_space;

						JL.webgl.main.change_animation_request( self.xr_session );
						self.activated = true;
					});
				});
			});

			break;

	};
};

JL.webgl.device.options.vr.deactivate = function(){
	var self = this;

	this.activated = false;

	JL.webgl.active_camera.set_derive_position_function();

	switch( this.web_standard ){
		case 'webxr':
			this.xr_session.end().then(function(){
				JL.webgl.gl.bindFramebuffer( JL.webgl.gl.FRAMEBUFFER, null );
				self.reset_canvas();
				JL.webgl.main.change_animation_request( window );
			});
			break;
	}

	for( var s of this.all_space_objects ){
		s.remove_from_draw( 'all' );
		s.draw_condition = function(){ return false; };
	}

	this.all_space_objects = [];
};

JL.webgl.device.options.vr.update_immersive_reference_point = function(){
	if( this.xr_session ){
		var required_features = ( this.xr_session.renderState.requiredFeatures || [] ).filter( x => ![ 'local', 'local-floor' ].includes(x) );

		required_features.push( JL.webgl.active_camera.target._vr_to_scale ? 'local-floor' : 'local' );

		this.xr_session.updateRenderState({ requiredFeatures : required_features });
	}
};

JL.webgl.device.options.vr.reset_canvas = function(){
	JL.webgl.canvas.primary.c.width  = 2048;
	JL.webgl.canvas.primary.c.height = 1024;

	JL.webgl.gl.viewport( 0, 0, JL.webgl.canvas.primary.c.width, JL.webgl.canvas.primary.c.height );
};

JL.webgl.device.options.vr.get_controller_graphics_object = function( p ){
	return JL.webgl.graphics_objects._in_library.vr.controllers[ p.type ][ p.hand ];
};

JL.webgl.device.options.vr.init_space_object = function( p ){
	var obj = JL.webgl.active_environment.add_space_object({
		no_parent : true,
		name      : p.name,
		attr      : {
			custom_align : function(){
				JL.webgl.mat.identity();
				JL.webgl.mat.mult( JL.webgl.active_camera.matrix.x( this.matrix ) );
			},
			ignore_xyz       : true,
			draw_from_matrix : true,
		},
	});
	obj.set_graphics_object( p.graphics_object );
	obj.matrix = Matrix.I(4);

	obj.set_scale = p.set_scale;
	obj.set_scale();

	this.all_space_objects.push( obj );

	return obj;
};

JL.webgl.device.options.vr.set_scale = function(){
	if     ( JL.webgl.active_camera.target._vr_to_scale                          ) this.scale = 1;
	else if( JL.webgl.active_environment && JL.webgl.active_environment.vr_scale ) this.scale = JL.webgl.active_environment.vr_scale;
	else                                                                           this.scale = 2.5 / JL.webgl.active_camera.target.camera_config.rad;

	for( var i = 0; i < 3; i++ ){ this.scale_matrix.elements[i][i] = this.scale; };

	for( var obj of this.all_space_objects ) obj.set_scale();

	// if( this.loading_background ){
	// 	var s = 1 / this.scale;
	// 	this.loading_background.set_scale( [ s, s, s ] );
	// }
};

JL.webgl.device.options.vr.draw_webxr_view = function( layer, views, idx ){
	var self = this;

	var view = views[ idx ];

	var viewport = layer.getViewport( view );

	JL.webgl.gl.viewport( viewport.x, viewport.y, viewport.width, viewport.height );

	this.curr_eye = view.eye;

	var render_params = {
		projection : Matrix.create4x4( view.projectionMatrix )                               ,
		view       : Matrix.create4x4( view.transform.inverse.matrix ).x( this.scale_matrix ),
	};

	render_params.preserve_objects = true;
	
	JL.webgl.render.vr( render_params );
};

JL.webgl.device.options.vr.draw = function( t, frame ){
	switch( this.web_standard ){
		case 'webxr':
			var self = this;

			var session = frame.session;

			session.updateRenderState({
				depthNear : JL.webgl.active_camera.clip.near,
				depthFar  : JL.webgl.active_camera.clip.far,
			});

			var pose = frame.getViewerPose( this.floor_reference_space );

			if( pose ){
				if( JL.webgl.ui.controllers ) JL.webgl.ui.controllers.set_xr_session( session );

				for( var input_source of session.inputSources ){
					try{
						if( input_source.gripSpace ){
							var hand = input_source.handedness;
							var input_pose = frame.getPose( input_source.gripSpace, self.viewer_reference_space );

							// Useful references for controllers:
							// 	Buttons - pressed vs value             : https://developer.mozilla.org/en-US/docs/Web/API/GamepadButton
							// 	Identifying which hand                 : https://developer.mozilla.org/en-US/docs/Web/API/Gamepad/hand
							// 	Getting the pose                       : https://developer.mozilla.org/en-US/docs/Web/API/Gamepad/pose
							//      Getting position values for controller : https://developer.mozilla.org/en-US/docs/Web/API/GamepadPose

							var gamepad = input_source.gamepad;

							if( !this.space_objects.gamepad[ hand ] && this.get_controller_graphics_object ){
								var gamepad_g_o = this.get_controller_graphics_object({
									hand, type : 'oculus_quest_1',
								});
								if( gamepad_g_o ){
									this.space_objects.gamepad[ hand ] = this.init_space_object({
										name            : 'VR Controller ' + hand,
										graphics_object : gamepad_g_o,
										set_scale       : function(){
											var s = 0.13 / JL.webgl.device.options.vr.scale;
											this.scale = [ s, s, s ];
										}
									});
								}

								// Note : code for floating menu (it was a little buggy)
								// 	-Maybe try using HTML overlays for menu / UI?
								if( hand == 'left' ){
									this.space_objects.menu = JL.webgl.active_environment.add_space_object({ parent_object : this.space_objects.gamepad.left }, self.ui.menu );
									this.space_objects.menu.set_scale = function(){
										var s = 0.013 / JL.webgl.device.options.vr.scale;
										this.change_scale([ s, s, s ]);

										this.y = 11 * s;
									};
									this.space_objects.menu.set_scale();
									this.all_space_objects.push( this.space_objects.menu );
									this.space_objects.gamepad.left.add_child( this.space_objects.menu );

									this.loading_background = JL.webgl.active_environment.add_space_object({ no_parent : true }, self.ui.loading );
								}
							}

							this.space_objects.gamepad[ hand ].matrix = JL.webgl.mat.rotate( -45, [ 1, 0, 0 ], Matrix.create4x4( input_pose.transform.matrix ).x( this.scale_matrix ) );
							/*
							// TODO : When moving in VR, have the direction the Right controller is pointing be the "forward" direction.
							// 	-Turning the Right controller will turn the user object (forward arrow)
							// 	-Pushing up and down on the Right controller joystick will move the user forward and backward.
							// 	-Pushing left and right on the Right controller joystick will move the user left and right.
							*/

							// if( hand == 'right' ){
							// 	if( JL.webgl.active_camera.target.walk ){
							// 		var q = input_pose.transform.orientation;
							// 		JL.webgl.active_camera.target.set_physics_rotation( 0, q.z, 0, q.w );
							// 		// JL.webgl.active_camera.target.set_physics_rotation( q.x, q.y, q.z, q.w );
							// 	}
							// }
						}
					} catch(e){}
				}

				var layer = session.renderState.baseLayer;
				JL.webgl.gl.bindFramebuffer( JL.webgl.gl.FRAMEBUFFER, layer.framebuffer );

				JL.webgl.mat.identity();

				// TODO : Figure out why position of controllers doesn't work on Quest 3
				// 	-Uncomment the following line to draw controllers for Quest 1
				for( var g of Object.values( self.space_objects.gamepad ) ) g.draw_update();

				JL.webgl.active_camera.draw();
				JL.webgl.main.update_objects();

				for( var idx = 0; idx < pose.views.length; idx++ ) this.draw_webxr_view( layer, pose.views, idx );
			}
			
			JL.webgl.main.animation_frame = session.requestAnimationFrame( JL.webgl.main.loop );
			break;
		case 'naive':
			JL.webgl.render.main();
			if( this.web_standard == 'naive' ) JL.webgl.canvas.secondary.mirror();
			JL.webgl.main.animation_frame = requestAnimationFrame( JL.webgl.main.loop );
			break;
	}
};

