JL.webgl.shaders.functions._rotate_vertex = `vec3 _rotate_vertex( in vec3 vertex, in vec3 rotation ){
        if( rotation.x != 0.0 ){
                float c = cos( rotation.x );
                float s = sin( rotation.x );

		vec3 v = vertex;

                vertex.y = c * v.y - s * v.z;
                vertex.z = s * v.y + c * v.z;
        }

        if( rotation.y != 0.0 ){
                float c = cos( rotation.y );
                float s = sin( rotation.y );

		vec3 v = vertex;

                vertex.x = c * v.x + s * v.z;
                vertex.z = c * v.z - s * v.x;
        }

        if( rotation.z != 0.0 ){
                float c = cos( rotation.z );
                float s = sin( rotation.z );

		vec3 v = vertex;

                vertex.x = c * v.x - s * v.y;
                vertex.y = s * v.x + c * v.y;
        }

        return vertex;
}`;

