JL.webgl.graphics_object._main.prototype.get_texture_by_type = function( type, textures_cfg_arr ){
	var textures_cfg_arr = textures_cfg_arr || this.textures;
	if( textures_cfg_arr ){
		if( type == 'main' ) return textures_cfg_arr.find( t => ( t.type == type || t.type === undefined ) );
		else                 return textures_cfg_arr.find( t => ( t.type == type ) );
	}
};

JL.webgl.graphics_object._main.prototype.set_texture = function( filename, p ){
	var p = p || {};

	var self = this;

	var type = p.type || 'main';

	p.callback = JL.functions.concat_functions([ p.callback || function(){}, function(){ self.construct_draw_function(); } ])

	if( p.video ){
		p.callback = JL.functions.concat_functions([ function(){
			if( !self.video_textures ) self.video_textures = [];
			self.video_textures.push( self.texture[ type ] );
		}, p.callback ])
	}
	else if( this.video_textures && !this.video_textures.length ) delete this.video_textures;

	if( p.sprite ){
		p.callback = JL.functions.concat_functions([ function(){
			if( !self.sprite_textures ) self.sprite_textures = [];
			self.sprite_textures.push( self.texture[ type ] );
		}, p.callback ])
	}
	else if( this.sprite_textures && !this.sprite_textures.length ) delete this.sprite_textures;

	if( p.preset ){
		this.texture[ type ] = p.preset;
		if( p.callback ) p.callback();
	}
	else if( p.video ){
		this.texture[ type ] = this.create_video_texture( filename, p );
	}
	else if( p.sprite ){
		this.texture[ type ] = this.create_sprite_texture( filename, p );
	}
	else if( JL.functions.is_canvas( filename ) ){
		this.set_canvas_texture( Object.assign( { canvas : filename }, p ) );
	}
	else if( JL.functions.is_object( filename ) ){
		this.set_pixel_array_texture( Object.assign( { pixels : filename }, p ) );
	}
	else{
		this.texture[ type ] = this.create_texture( filename, p.callback );
	}
};

JL.webgl.graphics_object._main.prototype.load_textures = function( textures, callback ){
	var self = this;

	if( textures.length ){
		var num_loaded = 0;

		var load_interval = setInterval(function(){
			if( num_loaded >= textures.length ){
				clearInterval( load_interval );
				if( callback ) callback( self );
			}
		}, 30);

		for( var texture of textures ){
			var params = texture.params || texture || {};

			var cb = params.callback;
			params.callback = function(){
				if( cb ) cb( self );
				num_loaded++;
			};

			this.set_texture( texture.filename, params );
		}
	}
	else{
		if( callback ) callback( self );
	}
};

JL.webgl.graphics_object._main.prototype.modify_texture = function( p ){
	var self = this;

	// A preset canvas could be used for multiple additive changes to a texture.
	var canvas       = p.canvas;
	var texture_name = p.type || 'main';

	var ctx;
	if( canvas ) ctx = canvas.getContext( '2d' );

	var on_canvas_load = function(){
		var returned_pixels = p.modify({
			canvas, ctx,
			pixels : JL.functions.get_canvas_pixels({ canvas, ctx }),
		});
		if( returned_pixels ) JL.functions.set_canvas_pixels({ canvas, ctx, pixels : returned_pixels });

		self.set_canvas_texture( Object.assign( {}, p, { canvas } ) );

		if( p.callback ) p.callback();
	};

	if( !canvas ){
		var filename = ( p.filename || this.texture[ texture_name ].image.src );

		if( filename ){ // Texture is an image
			canvas = document.createElement( 'canvas' );
			ctx    = canvas.getContext( '2d' );

			var img = new Image();
			img.crossOrigin = "*";
			img.onload = function(){
				canvas.width  = img.width;
				canvas.height = img.height;
				ctx.drawImage( img, 0, 0 );
				on_canvas_load();
				canvas.remove();
			};
			img.src = filename;
		}
		else{ // Texture is probably a canvas element
			canvas = this.texture[ texture_name ].image;
			ctx    = canvas.getContext( '2d' );
			on_canvas_load();
		}
	}
	else{
		on_canvas_load();
	}
};

JL.webgl.graphics_object._main.prototype.set_canvas_texture = function( p ){
	var texture = JL.webgl.gl.createTexture();

	texture.image = p.canvas;

	this.generate_texture( texture );

	p.preset = texture;

	this.set_texture( false, p );

	return texture;
};

JL.webgl.graphics_object._main.prototype.set_pixel_array_texture = function( p ){
	var texture = JL.webgl.gl.createTexture();

	[ 'pixels', 'width', 'height' ].forEach(function( k ){
		texture[ k ] = p.pixels[ k ];
	});

	this.generate_texture( texture );

	p.preset = texture;

	this.set_texture( false, p );

	return texture;
};

JL.webgl.graphics_object._main.prototype.set_text = function( text, p ){
	var p = p || {};

	var texture = JL.webgl.canvas.text.get_texture( text, p );

	this.generate_texture( texture );

	p.preset = texture;

	this.set_texture( false, p );

	return texture;
};

JL.webgl.graphics_object._main.prototype.get_uniform = function( uniform ){
	try     { var val = this[ uniform[0] ][ uniform[1] ]; }
	catch(e){ var val; }
	if( val === undefined ){
		// 2024-07-25
		// try{ val = this._config.params.attr[ uniform[0] ][ uniform[1] ]; }
		try{ val = this._config.attr[ uniform[0] ][ uniform[1] ]; }
		catch(e){}

		if( val === undefined ) val = JL.webgl.functions.get_uniform_config( uniform ).default;
	}

	return val;
};

JL.webgl.graphics_object._main.prototype.set_uniform = function( path, v ){ JL.functions.set_nested_object( this, path, v ); };

JL.webgl.graphics_object._main.prototype.set_uniforms = function( key, values ){
	this[ key ] = JL.functions.recursive_assign( this[ key ] || {}, values );
};

JL.webgl.graphics_object._main.prototype.reload = function( p ){
	var self = this;

	var p = p || {};

	// 2024-08-28
	// var new_path;
	// if     ( ( this._config.label || [] ).length ) new_path = this._config.label;
	// else if( ( this._config.keys  || [] ).length ) new_path = this._config.keys;

	// if( !new_path ){
	// 	if( p.error_callback ) p.error_callback();
	// 	return;
	// }

	// 2024-08-28
	// this.remove();

	JL.webgl.functions.create_graphics_object( JL.functions.recursive_assign( { callback : function( new_g_o ){
		var new_path;
		if     ( ( new_g_o._config.label || [] ).length ) new_path = new_g_o._config.label;
		else if( ( new_g_o._config.keys  || [] ).length ) new_path = new_g_o._config.keys;

		if( !new_path ){
			if( p.error_callback ) p.error_callback();
			return;
		}

		var next_graphics_object = JL.functions.get_nested_object( JL.webgl.graphics_objects, new_path );

		if( next_graphics_object ){
			for( var obj of JL.webgl.active_environment.get_all_space_objects() ){
				obj.search_and_replace_graphics_object( self, next_graphics_object );
			}
			// 2024-08-29
			// if( p.callback ) p.callback( next_graphics_object );
		}

		self.remove();
		JL.functions.set_nested_object( JL.webgl.graphics_objects, new_path, next_graphics_object );
		if( p.callback ) p.callback( next_graphics_object );

	// 2024-08-28
	} }, p.new_config ) );
	// } }, Object.assign( {}, this._config, p.new_config ) ) );
};

// TODO : Implement this function and have it run in a place that always gets run at the end of the constructor for all g_o's.
JL.webgl.graphics_object._main.prototype.construct_draw_function = function( p ){
	var fn_source = [ 'this.draw = function( s_o ){' ];

		fn_source.push( 'if( this.buffer ){', );

			//--------------------------//
			// Update animated textures //
			//--------------------------//

			if( this.video_textures ) fn_source.push( 'for( var t of this.video_textures ) t.update();' );

			// TODO : test
			// 	-Try implementing create_sprite_texture function (similar to video)
			//		-Maybe draw the section of sprite texture to a canvas element.
			// 		-If I can get this implemented similar to how the video textures are implemented, I might be able to have multiple sprite textures on the same g_o.
			if( this.sprite_textures ){
				// fn_source.push( 'for( var t of this.video_textures ) t.update();' );
				console.log( 'g_o.construct_draw sprite_textures : ' , this.sprite_textures );
			}

			//---------------------//
			// Activate the Shader //
			//---------------------//

			fn_source.push( 'this.shader.use();' );

			// The "vao" stuff seems to be necessary to get everything to work with instancing. Not sure why or how this works. May need to re-visit / optimize down the road.
			// 	2026-03-13 -- Restricting this line to only instanced / non-instanced g_o's broke things.
			fn_source.push( 'JL.webgl.gl.bindVertexArray( this.shader.vao );' );

			//---------------------------//
			// Bind Attributes to Shader //
			//---------------------------//

			for( var v of this.shader.attr ){
				fn_source.push(
					'JL.webgl.gl.enableVertexAttribArray( this.shader.program.attr["'+v+'"] );',
					'JL.webgl.gl.bindBuffer( JL.webgl.gl.ARRAY_BUFFER, this.buffer["'+v+'"] );',
				);
				
				if( this.dynamic_buffers && this.dynamic_buffers.includes( v ) ) fn_source.push( 'JL.webgl.gl.bufferSubData( JL.webgl.gl.ARRAY_BUFFER, 0, new Float32Array( this["'+v+'"] ), 0, ' + this[v].length + ');' );

				fn_source.push( 'JL.webgl.gl.vertexAttribPointer( this.shader.program.attr[ "' + v + '"], this.buffer["' + v + '"].item_size, JL.webgl.gl.FLOAT, false, 0, 0 );' );

				if( this.shader.instanced && this.shader.instanced.includes( v ) ) fn_source.push( 'JL.webgl.gl.vertexAttribDivisor( this.shader.program.attr["' + v + '"], 1 );' );
			}

			//-------------------------------//
			// Send Uniform Values to Shader //
			//-------------------------------//

			var shdr = this.shader.program;
			fn_source.push( 'var shdr = this.shader.program;' );

			for( var shader_type of JL.webgl.shaders.uniforms.shaders ){
				for( var v_i in JL.webgl.shaders.uniforms.vars ){
					var var_type   = JL.webgl.shaders.uniforms.vars[ v_i ];
					var type_key   = shader_type + '_' + var_type.name;
					var shader_obj = shdr[ type_key ];
					if( shader_obj ){
						fn_source.push(
							'var var_type   = JL.webgl.shaders.uniforms.vars[' + v_i + '];',
							'var type_key   = "' + type_key + '";',
							'var shader_obj = shdr[ type_key ];',

							'var vals = Object.assign( ',
								'Object.assign( {}, this[ type_key ] || {} ), ',
								's_o[ type_key ] || {}',
							');',
						);

						var shader_keys = Object.keys( shader_obj );
						for( var value_idx = 0; value_idx < shader_keys.length; value_idx++ ){
							var value_key = shader_keys[ value_idx ];
							fn_source.push(
								'var v;',
								'try{',
									'v = var_type.derive["' + value_key + '"]( s_o );',
								'}',
								'catch(e){',
									'v = vals["' + value_key + '"];',
									'if( v === undefined ){',
										'try{      v = var_type.custom_defaults["' + value_key + '"]( s_o ); }',
										'catch(e){ v = var_type.default; }',
									'}',
								'}',
							);
							if( var_type.convert ) fn_source.push( 'v = var_type.convert( v );' );
							fn_source.push(
								'var_type.gl_call( shader_obj["' + value_key + '"], v, "' + value_key + '", this, ' + value_idx + ' );',
							);
						}
					}
				}

				for( var v_i in JL.webgl.shaders.uniforms.arrs ){
					var var_type   = JL.webgl.shaders.uniforms.arrs[ v_i ];
					var type_key   = shader_type + '_' + var_type.name + '_arr';
					var shader_obj = shdr[ type_key ];
					if( shader_obj ){
						fn_source.push(
							'var var_type   = JL.webgl.shaders.uniforms.arrs[' + v_i + '];',
							'var type_key   = "' + type_key + '";',
							'var shader_obj = shdr[ type_key ];',
						);

						for( var value_key in shader_obj ){
							fn_source.push(
								'var v_list;',
								'try{',
									'v_list = var_type.get_arr["' + value_key + '"]( s_o, this );',
								'}',
								'catch(e){',
									'try{      v_list = var_type.custom_defaults["' + value_key + '"]( s_o ); }',
									'catch(e){ v_list = [ var_type.default ]; }',
								'}',

								'var val_list = ( v_list || [] );',
								'for( var i = 0; i < val_list.length; i++ ){',
									'var_type.gl_call( shader_obj["' + value_key + '"][ i ], var_type.convert( val_list[ i ] ) );',
								'}',
							);
						}
					}
				}
			}

			//-----------------//
			// Draw the Object //
			//-----------------//

			if( this.draw_arrays ) fn_source.push( 'JL.webgl.gl.drawArrays(this.primitive, 0, this.num_items);' );
			else{
				fn_source.push(
					'if(this.buffer.vertex_indices){',
						'JL.webgl.gl.bindBuffer(JL.webgl.gl.ELEMENT_ARRAY_BUFFER, this.buffer.vertex_indices);',
				);

				if( this.dynamic_buffers && this.dynamic_buffers.includes( "vertex_indices" ) ) fn_source.push( 'JL.webgl.gl.bufferSubData( JL.webgl.gl.ELEMENT_ARRAY_BUFFER, 0, new Uint16Array( this.vertex_indices ) );' );

				if( this.shader.instanced ) fn_source.push( 'JL.webgl.gl.drawElementsInstanced( this.primitive, this.buffer.num_vertex_indices, JL.webgl.gl.UNSIGNED_SHORT, 0, this.num_instances );' );
				else                        fn_source.push( 'JL.webgl.gl.drawElements(          this.primitive, this.buffer.num_vertex_indices, JL.webgl.gl.UNSIGNED_SHORT, 0 );' );

				fn_source.push( '}' );
			}

		fn_source.push( '}' );

	fn_source.push( '};' );

	eval( fn_source.join('\n') );
};

// 2026-03-13 -- replacing with g_o.construct_draw_function
JL.webgl.graphics_object._main.prototype.draw = function(){};

// Test : JL.webgl.graphics_object.triangulate.get_vert_indices([10, 0, 0, 50, 60, 60, 70, 10]);
// 	Output : [ 1, 0, 3, 3, 2, 1 ]

// For hole indices, it is an array of indices that start the hole.
// 	-Ex: [ 5 ] means verts 5 -> end are a part of the one hole.
// 	-Ex: [ 12, 20 ] means there are 2 holes: one from verts 12 - 19 and one from 20 - end.

// Examples to compare against : https://github.com/mapbox/earcut/tree/main

JL.webgl.graphics_object.triangulate = { classes : {} };

JL.webgl.graphics_object.triangulate.get_vert_indices = function( data, hole_indices, dim ){
	var dim = dim || 2;

	var has_holes  = hole_indices && hole_indices.length;
	var outer_len  = ( has_holes ? ( hole_indices[0] - 1 ) * dim : data.length );
	var outer_node = this.classes.linked_list(data, 0, outer_len, dim, true);
	var triangles  = [];

	if( !outer_node || outer_node.next === outer_node.prev ) return triangles;

	var minX, minY, maxX, maxY, x, y, invSize;

	if( has_holes ) outer_node = this.eliminate_holes( data, hole_indices, outer_node, dim );

	// if the shape is not too simple, we'll use z-order curve hash later; calculate polygon bbox
	if (data.length > 80 * dim) {
		minX = maxX = data[0];
		minY = maxY = data[1];

		for (var i = dim; i < outer_len; i += dim) {
			x = data[i];
			y = data[i + 1];
			if (x < minX) minX = x;
			if (y < minY) minY = y;
			if (x > maxX) maxX = x;
			if (y > maxY) maxY = y;
		}

		// minX, minY and invSize are later used to transform coords into integers for z-order calculation
		invSize = Math.max(maxX - minX, maxY - minY);
		invSize = invSize !== 0 ? 32767 / invSize : 0;
	}

	this.earcut_linked(outer_node, triangles, dim, minX, minY, invSize, 0);

	return triangles;
};

// eliminate colinear or duplicate points
JL.webgl.graphics_object.triangulate.filter_points = function(start, end) {
	if (!start) return start;
	if (!end) end = start;

	var p = start,
		again;

	do {
		again = false;

		if (!p.steiner && (this.is_equal_points(p, p.next) || this.triangle_area(p.prev, p, p.next) === 0)) {
			this.remove_node(p);
			p = end = p.prev;
			if (p === p.next) break;
			again = true;
		}
		else {
			p = p.next;
		}
	} while (again || p !== end);

	return end;
}

// main ear slicing loop which triangulates a polygon (given as a linked list)
JL.webgl.graphics_object.triangulate.earcut_linked = function(ear, triangles, dim, minX, minY, invSize, pass) {
    if (!ear) return;

    // interlink polygon nodes in z-order
    if (!pass && invSize) this.index_curve(ear, minX, minY, invSize);

    var stop = ear,
        prev, next;

    // iterate through ears, slicing them one by one
    while (ear.prev !== ear.next) {
        prev = ear.prev;
        next = ear.next;

        if (invSize ? this.is_hashed_ear(ear, minX, minY, invSize) : this.is_ear(ear)) {
            // cut off the triangle
            triangles.push(prev.i / dim | 0);
            triangles.push(ear.i / dim | 0);
            triangles.push(next.i / dim | 0);

            this.remove_node(ear);

            // skipping the next vertex leads to less sliver triangles
            ear = next.next;
            stop = next.next;

            continue;
        }

        ear = next;

        // if we looped through the whole remaining polygon and can't find any more ears
        if (ear === stop) {
            // try filtering points and slicing again
            if (!pass) {
                this.earcut_linked(this.filter_points(ear), triangles, dim, minX, minY, invSize, 1);

            // if this didn't work, try curing all small self-intersections locally
            } else if (pass === 1) {
                ear = this.cure_local_intersections(this.filter_points(ear), triangles, dim);
                this.earcut_linked(ear, triangles, dim, minX, minY, invSize, 2);

            // as a last resort, try splitting the remaining polygon into two
            } else if (pass === 2) {
                this.split_earcut(ear, triangles, dim, minX, minY, invSize);
            }

            break;
        }
    }
}

// check whether a polygon node forms a valid ear with adjacent nodes
JL.webgl.graphics_object.triangulate.is_ear = function(ear) {
    var a = ear.prev,
        b = ear,
        c = ear.next;

    if (this.triangle_area(a, b, c) >= 0) return false; // reflex, can't be an ear

    // now make sure we don't have other points inside the potential ear
    var ax = a.x, bx = b.x, cx = c.x, ay = a.y, by = b.y, cy = c.y;

    // triangle bbox; min & max are calculated like this for speed
    var x0 = ax < bx ? (ax < cx ? ax : cx) : (bx < cx ? bx : cx),
        y0 = ay < by ? (ay < cy ? ay : cy) : (by < cy ? by : cy),
        x1 = ax > bx ? (ax > cx ? ax : cx) : (bx > cx ? bx : cx),
        y1 = ay > by ? (ay > cy ? ay : cy) : (by > cy ? by : cy);

    var p = c.next;
    while (p !== a) {
        if (p.x >= x0 && p.x <= x1 && p.y >= y0 && p.y <= y1 &&
            this.point_in_triangle(ax, ay, bx, by, cx, cy, p.x, p.y) &&
            this.triangle_area(p.prev, p, p.next) >= 0) return false;
        p = p.next;
    }

    return true;
}

JL.webgl.graphics_object.triangulate.is_hashed_ear = function(ear, minX, minY, invSize) {
    var a = ear.prev,
        b = ear,
        c = ear.next;

    if (this.triangle_area(a, b, c) >= 0) return false; // reflex, can't be an ear

    var ax = a.x, bx = b.x, cx = c.x, ay = a.y, by = b.y, cy = c.y;

    // triangle bbox; min & max are calculated like this for speed
    var x0 = ax < bx ? (ax < cx ? ax : cx) : (bx < cx ? bx : cx),
        y0 = ay < by ? (ay < cy ? ay : cy) : (by < cy ? by : cy),
        x1 = ax > bx ? (ax > cx ? ax : cx) : (bx > cx ? bx : cx),
        y1 = ay > by ? (ay > cy ? ay : cy) : (by > cy ? by : cy);

    // z-order range for the current triangle bbox;
    var minZ = this.z_order(x0, y0, minX, minY, invSize),
        maxZ = this.z_order(x1, y1, minX, minY, invSize);

    var p = ear.prevZ,
        n = ear.nextZ;

    // look for points inside the triangle in both directions
    while (p && p.z >= minZ && n && n.z <= maxZ) {
        if (p.x >= x0 && p.x <= x1 && p.y >= y0 && p.y <= y1 && p !== a && p !== c &&
            this.point_in_triangle(ax, ay, bx, by, cx, cy, p.x, p.y) && this.triangle_area(p.prev, p, p.next) >= 0) return false;
        p = p.prevZ;

        if (n.x >= x0 && n.x <= x1 && n.y >= y0 && n.y <= y1 && n !== a && n !== c &&
            this.point_in_triangle(ax, ay, bx, by, cx, cy, n.x, n.y) && this.triangle_area(n.prev, n, n.next) >= 0) return false;
        n = n.nextZ;
    }

    // look for remaining points in decreasing z-order
    while (p && p.z >= minZ) {
        if (p.x >= x0 && p.x <= x1 && p.y >= y0 && p.y <= y1 && p !== a && p !== c &&
            this.point_in_triangle(ax, ay, bx, by, cx, cy, p.x, p.y) && this.triangle_area(p.prev, p, p.next) >= 0) return false;
        p = p.prevZ;
    }

    // look for remaining points in increasing z-order
    while (n && n.z <= maxZ) {
        if (n.x >= x0 && n.x <= x1 && n.y >= y0 && n.y <= y1 && n !== a && n !== c &&
            this.point_in_triangle(ax, ay, bx, by, cx, cy, n.x, n.y) && this.triangle_area(n.prev, n, n.next) >= 0) return false;
        n = n.nextZ;
    }

    return true;
}

// go through all polygon nodes and cure small local self-intersections
JL.webgl.graphics_object.triangulate.cure_local_intersections = function(start, triangles, dim) {
    var p = start;
    do {
        var a = p.prev,
            b = p.next.next;

        if (!this.is_equal_points(a, b) && this.is_intersecting_segments(a, p, p.next, b) && this.locally_inside(a, b) && this.locally_inside(b, a)) {

            triangles.push(a.i / dim | 0);
            triangles.push(p.i / dim | 0);
            triangles.push(b.i / dim | 0);

            // remove two nodes involved
            this.remove_node(p);
            this.remove_node(p.next);

            p = start = b;
        }
        p = p.next;
    } while (p !== start);

    return this.filter_points(p);
}

// try splitting polygon into two and triangulate them independently
JL.webgl.graphics_object.triangulate.split_earcut = function(start, triangles, dim, minX, minY, invSize) {
    // look for a valid diagonal that divides the polygon into two
    var a = start;
    do {
        var b = a.next.next;
        while (b !== a.prev) {
            if (a.i !== b.i && this.is_valid_diagonal(a, b)) {
                // split the polygon in two by the diagonal
                var c = this.split_polygon(a, b);

                // filter colinear points around the cuts
                a = this.filter_points(a, a.next);
                c = this.filter_points(c, c.next);

                // run earcut on each half
                this.earcut_linked(a, triangles, dim, minX, minY, invSize, 0);
                this.earcut_linked(c, triangles, dim, minX, minY, invSize, 0);
                return;
            }
            b = b.next;
        }
        a = a.next;
    } while (a !== start);
}

// link every hole into the outer loop, producing a single-ring polygon without holes
JL.webgl.graphics_object.triangulate.eliminate_holes = function( data, hole_indices, outer_node, dim ){
	var queue = [];

	var len = hole_indices.length;

	for( var i = 0; i < len; i++ ){
		var start = hole_indices[i] * dim;
		var end   = i < len - 1 ? hole_indices[i + 1] * dim : data.length;
		var list  = this.classes.linked_list( data, start, end, dim, false );
		if( list === list.next ) list.steiner = true;
		queue.push( this.get_leftmost( list ) );
	}

	queue.sort(function( a, b ){ return a.x - b.x; });

	// process holes from left to right
	for( var i = 0; i < queue.length; i++ ) outer_node = this.eliminate_hole( queue[i], outer_node );

	return outer_node;
}

// find a bridge between vertices that connects hole with an outer ring and and link it
JL.webgl.graphics_object.triangulate.eliminate_hole = function(hole, outer_node) {
    var bridge = this.find_hole_bridge(hole, outer_node);
    if (!bridge) {
        return outer_node;
    }

    var bridgeReverse = this.split_polygon(bridge, hole);

    // filter collinear points around the cuts
    this.filter_points(bridgeReverse, bridgeReverse.next);
    return this.filter_points(bridge, bridge.next);
}

// David Eberly's algorithm for finding a bridge between hole and outer polygon
JL.webgl.graphics_object.triangulate.find_hole_bridge = function(hole, outer_node) {
    var p = outer_node,
        hx = hole.x,
        hy = hole.y,
        qx = -Infinity,
        m;

    // find a segment intersected by a ray from the hole's leftmost point to the left;
    // segment's endpoint with lesser x will be potential connection point
    do {
        if (hy <= p.y && hy >= p.next.y && p.next.y !== p.y) {
            var x = p.x + (hy - p.y) * (p.next.x - p.x) / (p.next.y - p.y);
            if (x <= hx && x > qx) {
                qx = x;
                m = p.x < p.next.x ? p : p.next;
                if (x === hx) return m; // hole touches outer segment; pick leftmost endpoint
            }
        }
        p = p.next;
    } while (p !== outer_node);

    if (!m) return null;

    // look for points inside the triangle of hole point, segment intersection and endpoint;
    // if there are no points found, we have a valid connection;
    // otherwise choose the point of the minimum angle with the ray as connection point

    var stop = m,
        mx = m.x,
        my = m.y,
        tanMin = Infinity,
        tan;

    p = m;

    do {
        if (hx >= p.x && p.x >= mx && hx !== p.x &&
                this.point_in_triangle(hy < my ? hx : qx, hy, mx, my, hy < my ? qx : hx, hy, p.x, p.y)) {

            tan = Math.abs(hy - p.y) / (hx - p.x); // tangential

            if (this.locally_inside(p, hole) &&
                (tan < tanMin || (tan === tanMin && (p.x > m.x || (p.x === m.x && this.sector_contains_sector(m, p)))))) {
                m = p;
                tanMin = tan;
            }
        }

        p = p.next;
    } while (p !== stop);

    return m;
}

// whether sector in vertex m contains sector in vertex p in the same coordinates
JL.webgl.graphics_object.triangulate.sector_contains_sector = function(m, p) {
    return this.triangle_area(m.prev, m, p.prev) < 0 && this.triangle_area(p.next, m, m.next) < 0;
}

// interlink polygon nodes in z-order
JL.webgl.graphics_object.triangulate.index_curve = function(start, minX, minY, invSize) {
    var p = start;
    do {
        if (p.z === 0) p.z = this.z_order(p.x, p.y, minX, minY, invSize);
        p.prevZ = p.prev;
        p.nextZ = p.next;
        p = p.next;
    } while (p !== start);

    p.prevZ.nextZ = null;
    p.prevZ = null;

    this.sort_linked(p);
}

// Simon Tatham's linked list merge sort algorithm
// http://www.chiark.greenend.org.uk/~sgtatham/algorithms/listsort.html
JL.webgl.graphics_object.triangulate.sort_linked = function(list) {
    var i, p, q, e, tail, numMerges, pSize, qSize,
        inSize = 1;

    do {
        p = list;
        list = null;
        tail = null;
        numMerges = 0;

        while (p) {
            numMerges++;
            q = p;
            pSize = 0;
            for (i = 0; i < inSize; i++) {
                pSize++;
                q = q.nextZ;
                if (!q) break;
            }
            qSize = inSize;

            while (pSize > 0 || (qSize > 0 && q)) {

                if (pSize !== 0 && (qSize === 0 || !q || p.z <= q.z)) {
                    e = p;
                    p = p.nextZ;
                    pSize--;
                } else {
                    e = q;
                    q = q.nextZ;
                    qSize--;
                }

                if (tail) tail.nextZ = e;
                else list = e;

                e.prevZ = tail;
                tail = e;
            }

            p = q;
        }

        tail.nextZ = null;
        inSize *= 2;

    } while (numMerges > 1);

    return list;
}

// z-order of a point given coords and inverse of the longer side of data bbox
JL.webgl.graphics_object.triangulate.z_order = function(x, y, minX, minY, invSize) {
    // coords are transformed into non-negative 15-bit integer range
    x = (x - minX) * invSize | 0;
    y = (y - minY) * invSize | 0;

    x = (x | (x << 8)) & 0x00FF00FF;
    x = (x | (x << 4)) & 0x0F0F0F0F;
    x = (x | (x << 2)) & 0x33333333;
    x = (x | (x << 1)) & 0x55555555;

    y = (y | (y << 8)) & 0x00FF00FF;
    y = (y | (y << 4)) & 0x0F0F0F0F;
    y = (y | (y << 2)) & 0x33333333;
    y = (y | (y << 1)) & 0x55555555;

    return x | (y << 1);
}

// find the leftmost node of a polygon ring
JL.webgl.graphics_object.triangulate.get_leftmost = function(start) {
    var p = start,
        leftmost = start;
    do {
        if (p.x < leftmost.x || (p.x === leftmost.x && p.y < leftmost.y)) leftmost = p;
        p = p.next;
    } while (p !== start);

    return leftmost;
}

// check if a point lies within a convex triangle
JL.webgl.graphics_object.triangulate.point_in_triangle = function(ax, ay, bx, by, cx, cy, px, py) {
    return (cx - px) * (ay - py) >= (ax - px) * (cy - py) &&
           (ax - px) * (by - py) >= (bx - px) * (ay - py) &&
           (bx - px) * (cy - py) >= (cx - px) * (by - py);
}

// check if a diagonal between two polygon nodes is valid (lies in polygon interior)
JL.webgl.graphics_object.triangulate.is_valid_diagonal = function(a, b) {
    return a.next.i !== b.i && a.prev.i !== b.i && !this.intersects_polygon(a, b) && // dones't intersect other edges
           (this.locally_inside(a, b) && this.locally_inside(b, a) && this.middle_inside(a, b) && // locally visible
            (this.triangle_area(a.prev, a, b.prev) || this.triangle_area(a, b.prev, b)) || // does not create opposite-facing sectors
            this.is_equal_points(a, b) && this.triangle_area(a.prev, a, a.next) > 0 && this.triangle_area(b.prev, b, b.next) > 0); // special zero-length case
}

// signed area of a triangle
JL.webgl.graphics_object.triangulate.triangle_area = function(p, q, r) {
    return (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
}

// check if two points are equal
JL.webgl.graphics_object.triangulate.is_equal_points = function(p1, p2) {
    return p1.x === p2.x && p1.y === p2.y;
}

// check if two segments intersect
JL.webgl.graphics_object.triangulate.is_intersecting_segments = function(p1, q1, p2, q2) {
    var o1 = this.get_sign(this.triangle_area(p1, q1, p2));
    var o2 = this.get_sign(this.triangle_area(p1, q1, q2));
    var o3 = this.get_sign(this.triangle_area(p2, q2, p1));
    var o4 = this.get_sign(this.triangle_area(p2, q2, q1));

    if (o1 !== o2 && o3 !== o4) return true; // general case

    if (o1 === 0 && this.on_segment(p1, p2, q1)) return true; // p1, q1 and p2 are collinear and p2 lies on p1q1
    if (o2 === 0 && this.on_segment(p1, q2, q1)) return true; // p1, q1 and q2 are collinear and q2 lies on p1q1
    if (o3 === 0 && this.on_segment(p2, p1, q2)) return true; // p2, q2 and p1 are collinear and p1 lies on p2q2
    if (o4 === 0 && this.on_segment(p2, q1, q2)) return true; // p2, q2 and q1 are collinear and q1 lies on p2q2

    return false;
}

// for collinear points p, q, r, check if point q lies on segment pr
JL.webgl.graphics_object.triangulate.on_segment = function(p, q, r) {
    return q.x <= Math.max(p.x, r.x) && q.x >= Math.min(p.x, r.x) && q.y <= Math.max(p.y, r.y) && q.y >= Math.min(p.y, r.y);
}

JL.webgl.graphics_object.triangulate.get_sign = function(num) {
    return num > 0 ? 1 : num < 0 ? -1 : 0;
}

// check if a polygon diagonal intersects any polygon segments
JL.webgl.graphics_object.triangulate.intersects_polygon = function(a, b) {
    var p = a;
    do {
        if (p.i !== a.i && p.next.i !== a.i && p.i !== b.i && p.next.i !== b.i &&
                this.is_intersecting_segments(p, p.next, a, b)) return true;
        p = p.next;
    } while (p !== a);

    return false;
}

// check if a polygon diagonal is locally inside the polygon
JL.webgl.graphics_object.triangulate.locally_inside = function(a, b) {
    return this.triangle_area(a.prev, a, a.next) < 0 ?
        this.triangle_area(a, b, a.next) >= 0 && this.triangle_area(a, a.prev, b) >= 0 :
        this.triangle_area(a, b, a.prev) < 0 || this.triangle_area(a, a.next, b) < 0;
}

// check if the middle point of a polygon diagonal is inside the polygon
JL.webgl.graphics_object.triangulate.middle_inside = function(a, b) {
    var p = a,
        inside = false,
        px = (a.x + b.x) / 2,
        py = (a.y + b.y) / 2;
    do {
        if (((p.y > py) !== (p.next.y > py)) && p.next.y !== p.y &&
                (px < (p.next.x - p.x) * (py - p.y) / (p.next.y - p.y) + p.x))
            inside = !inside;
        p = p.next;
    } while (p !== a);

    return inside;
}

// link two polygon vertices with a bridge; if the vertices belong to the same ring, it splits polygon into two;
// if one belongs to the outer ring and another to a hole, it merges it into a single ring
JL.webgl.graphics_object.triangulate.split_polygon = function(a, b) {
    var a2 = new this.classes.node(a.i, a.x, a.y),
        b2 = new this.classes.node(b.i, b.x, b.y),
        an = a.next,
        bp = b.prev;

    a.next = b;
    b.prev = a;

    a2.next = an;
    an.prev = a2;

    b2.next = a2;
    a2.prev = b2;

    bp.next = b2;
    b2.prev = bp;

    return b2;
}

// create a node and optionally link it with previous one (in a circular doubly linked list)
JL.webgl.graphics_object.triangulate.insert_node = function(i, x, y, last) {
    var p = new this.classes.node(i, x, y);

    if (!last) {
        p.prev = p;
        p.next = p;

    } else {
        p.next = last.next;
        p.prev = last;
        last.next.prev = p;
        last.next = p;
    }
    return p;
}

JL.webgl.graphics_object.triangulate.remove_node = function(p) {
    p.next.prev = p.prev;
    p.prev.next = p.next;

    if (p.prevZ) p.prevZ.nextZ = p.nextZ;
    if (p.nextZ) p.nextZ.prevZ = p.prevZ;
}

// return a percentage difference between the polygon area and its triangulation area;
// used to verify correctness of triangulation
JL.webgl.graphics_object.triangulate.deviation = function(data, hole_indices, dim, triangles) {
    var has_holes = hole_indices && hole_indices.length;
    var outer_len = has_holes ? hole_indices[0] * dim : data.length;

    var polygonArea = Math.abs(this.signed_area(data, 0, outer_len, dim));
    if (has_holes) {
        for (var i = 0, len = hole_indices.length; i < len; i++) {
            var start = hole_indices[i] * dim;
            var end = i < len - 1 ? hole_indices[i + 1] * dim : data.length;
            polygonArea -= Math.abs(this.signed_area(data, start, end, dim));
        }
    }

    var trianglesArea = 0;
    for (i = 0; i < triangles.length; i += 3) {
        var a = triangles[i] * dim;
        var b = triangles[i + 1] * dim;
        var c = triangles[i + 2] * dim;
        trianglesArea += Math.abs(
            (data[a] - data[c]) * (data[b + 1] - data[a + 1]) -
            (data[a] - data[b]) * (data[c + 1] - data[a + 1]));
    }

    return polygonArea === 0 && trianglesArea === 0 ? 0 :
        Math.abs((trianglesArea - polygonArea) / polygonArea);
};

JL.webgl.graphics_object.triangulate.signed_area = function(data, start, end, dim) {
    var sum = 0;
    for (var i = start, j = end - dim; i < end; i += dim) {
        sum += (data[j] - data[i]) * (data[i + 1] + data[j + 1]);
        j = i;
    }
    return sum;
}

// turn a polygon in a multi-dimensional array form (e.g. as in GeoJSON) into a form Earcut accepts
JL.webgl.graphics_object.triangulate.flatten = function(data) {
	var dim       = data[0][0].length;
	var result    = {vertices: [], holes: [], dimensions: dim};
	var holeIndex = 0;

	for (var i = 0; i < data.length; i++) {
		for (var j = 0; j < data[i].length; j++) {
			for (var d = 0; d < dim; d++) result.vertices.push(data[i][j][d]);
		}
		if (i > 0) {
			holeIndex += data[i - 1].length;
			result.holes.push(holeIndex);
		}
	}
	return result;
};

// -----------
// | Classes |
// -----------

// create a circular doubly linked list from polygon points in the specified winding order
JL.webgl.graphics_object.triangulate.classes.linked_list = function(data, start, end, dim, clockwise) {
	var i, last;

	if( clockwise === ( JL.webgl.graphics_object.triangulate.signed_area(data, start, end, dim) > 0 ) ){
		for (i = start; i < end; i += dim) last = JL.webgl.graphics_object.triangulate.insert_node(i, data[i], data[i + 1], last);
	}
	else{
		for (i = end - dim; i >= start; i -= dim) last = JL.webgl.graphics_object.triangulate.insert_node(i, data[i], data[i + 1], last);
	}

	if( last && JL.webgl.graphics_object.triangulate.is_equal_points(last, last.next) ){
		JL.webgl.graphics_object.triangulate.remove_node(last);
		last = last.next;
	}

	return last;
};

JL.webgl.graphics_object.triangulate.classes.node = function(i, x, y) {
	// vertex index in coordinates array
	this.i = i;

	// vertex coordinates
	this.x = x;
	this.y = y;

	// previous and next vertex nodes in a polygon ring
	this.prev = null;
	this.next = null;

	// z-order curve value
	this.z = 0;

	// previous and next nodes in z-order
	this.prevZ = null;
	this.nextZ = null;

	// indicates whether this is a steiner point
	this.steiner = false;
};

JL.webgl.graphics_object._main.prototype.apply_boolean_operation = function( g_o, operation, p ){
	var p = p || {};

        var this_csg = JL.webgl.graphics_object.csg.g_o_to_polygons( this );
        var  g_o_csg = JL.webgl.graphics_object.csg.g_o_to_polygons( g_o  );

        var result = this_csg[ operation ]( g_o_csg ).toTriangles();

        var faces = [];
        for( var polygon of result ){
                var vertices = polygon.vertices;
                if( vertices.length == 3 ){
                        faces.push(
                                vertices.map(function( v ){
					if( v.attr ){
						if( v.attr.vt ) v.vt = v.attr.vt;
					}

                                        return v;
                                })
                        );
                }
        }

        this.construct_from_faces_array( faces );
	if( !p.no_buffer ) this.create_buffers();
};

// Reference for this technique:
// https://github.com/evanw/csg.js/blob/master/csg.js
// Constructive Solid Geometry (CSG) is a modeling technique that uses Boolean
// operations like union and intersection to combine 3D solids. This library
// implements CSG operations on meshes elegantly and concisely using BSP trees,
// and is meant to serve as an easily understandable implementation of the
// algorithm. All edge cases involving overlapping coplanar polygons in both
// solids are correctly handled.
// 
// All CSG operations are implemented in terms of two functions, `clipTo()` and
// `invert()`, which remove parts of a BSP tree inside another BSP tree and swap
// solid and empty space, respectively. To find the union of `a` and `b`, we
// want to remove everything in `a` inside `b` and everything in `b` inside `a`,
// then combine polygons from `a` and `b` into one solid:
// 
//     a.clipTo(b);
//     b.clipTo(a);
//     a.build(b.allPolygons());
// 
// The only tricky part is handling overlapping coplanar polygons in both trees.
// The code above keeps both copies, but we need to keep them in one tree and
// remove them in the other tree. To remove them from `b` we can clip the
// inverse of `b` against `a`. The code for union now looks like this:
// 
//     a.clipTo(b);
//     b.clipTo(a);
//     b.invert();
//     b.clipTo(a);
//     b.invert();
//     a.build(b.allPolygons());
// 
// Subtraction and intersection naturally follow from set operations. If
// union is `A | B`, subtraction is `A - B = ~(~A | B)` and intersection is
// `A & B = ~(~A | ~B)` where `~` is the complement operator.

JL.webgl.graphics_object.csg = { classes : {} };

// --------------------
// | Global Functions |
// --------------------

JL.webgl.graphics_object.csg.g_o_to_polygons = function( g ){
	var self = this;
	var faces = g.get_faces_array();
	return this.polygons_to_csg(
		faces.map(function( face ){
			return [
				new self.classes.polygon( ( face                   ).map(function( v ){ return new self.classes.vertex( v ); }) ),
				new self.classes.polygon( ( face.slice().reverse() ).map(function( v ){ return new self.classes.vertex( v ); }) ),
			];
		}).flat()
	);
};

JL.webgl.graphics_object.csg.polygons_to_csg = function( polygons ){
	var csg = new this.classes.main();
	csg.polygons = polygons;
	return csg;
};


// --------
// | Main |
// --------

JL.webgl.graphics_object.csg.classes.main = function(){
	this.polygons = [];
};

JL.webgl.graphics_object.csg.classes.main.prototype.clone = function(){
	var csg = new JL.webgl.graphics_object.csg.classes.main();
	csg.polygons = this.polygons.map(function(p){ return p.clone(); });
	return csg;
};

JL.webgl.graphics_object.csg.classes.main.prototype.toTriangles = function(){
	var triangles = [];
	for( var polygon of this.polygons ){
		var verts = Array.from( polygon.vertices, (v) => JL.functions.vector_subtract( v.v, polygon.vertices[0].v ) );

		var d1 = JL.functions.normalize( verts[ 1 ] );
		var d2 = JL.functions.normalize( JL.functions.vector_subtract( verts[ 2 ], JL.functions.scalar_multiply( JL.functions.dot_product( verts[2], d1 ), d1 ) ) );

		var coords = [];
		for( var v of verts ) coords.push( JL.functions.dot_product( v, d1 ), JL.functions.dot_product( v, d2 ) );

		var tesselated_vertices = JL.webgl.graphics_object.triangulate.get_vert_indices( coords ).map( i => polygon.vertices[ i ] );
		for( var i = 0; i < tesselated_vertices.length; i += 3 ){
			triangles.push({
				vertices : [
					tesselated_vertices[ i     ],
					tesselated_vertices[ i + 1 ],
					tesselated_vertices[ i + 2 ],
				]
			});
		}
	}
	return triangles;
};

JL.webgl.graphics_object.csg.classes.main.prototype.inverse = function(){
	var csg = this.clone();
	csg.polygons.map(function(p) { p.flip(); });
	return csg;
};

JL.webgl.graphics_object.csg.classes.main.prototype.union = function( csg ){
	var a = new JL.webgl.graphics_object.csg.classes.node(this.clone().polygons);
	var b = new JL.webgl.graphics_object.csg.classes.node( csg.clone().polygons);
	a.clipTo(b);
	b.clipTo(a);
	b.invert();
	b.clipTo(a);
	b.invert();
	a.build(b.allPolygons());
	return JL.webgl.graphics_object.csg.polygons_to_csg(a.allPolygons());
};

JL.webgl.graphics_object.csg.classes.main.prototype.subtract = function( csg ){
	var a = new JL.webgl.graphics_object.csg.classes.node(this.clone().polygons);
	var b = new JL.webgl.graphics_object.csg.classes.node( csg.clone().polygons);
	a.invert();
	a.clipTo(b);
	b.clipTo(a);
	b.invert();
	b.clipTo(a);
	b.invert();
	a.build(b.allPolygons());
	a.invert();
	return JL.webgl.graphics_object.csg.polygons_to_csg(a.allPolygons());
};

JL.webgl.graphics_object.csg.classes.main.prototype.intersect = function( csg ){
	var a = new JL.webgl.graphics_object.csg.classes.node(this.clone().polygons);
	var b = new JL.webgl.graphics_object.csg.classes.node( csg.clone().polygons);
	a.invert();
	b.clipTo(a);
	b.invert();
	a.clipTo(b);
	b.clipTo(a);
	a.build(b.allPolygons());
	a.invert();
	return JL.webgl.graphics_object.csg.polygons_to_csg(a.allPolygons());
};

// ----------
// | Vertex |
// ----------

JL.webgl.graphics_object.csg.classes.vertex = function( v ){
	Object.assign( this, v );
};

JL.webgl.graphics_object.csg.classes.vertex.prototype.clone = function(){
	return new JL.webgl.graphics_object.csg.classes.vertex( JL.functions.deep_copy( this ) );
};

JL.webgl.graphics_object.csg.classes.vertex.prototype.flip = function(){
	this.vn = JL.functions.scalar_multiply( -1, this.vn );
};

JL.webgl.graphics_object.csg.classes.vertex.prototype.interpolate = function( other, t ){
	var attr;
	if( this.attr ){
		attr = {};
		if( this.attr.vt ) attr.vt = JL.functions.interpolate_array( this.attr.vt, other.attr.vt, t );
	}

	var vert = {};
	vert.v  = JL.functions.interpolate_array( this.v , other.v , t );
	vert.vn = JL.functions.interpolate_array( this.vn, other.vn, t );
	if( this.vt ) vert.vt = JL.functions.interpolate_array( this.vt, other.vt, t );
	
	return new JL.webgl.graphics_object.csg.classes.vertex( vert );
};

// -----------
// | Polygon |
// -----------

// Represents a convex polygon. The vertices used to initialize a polygon must be coplanar and form a convex loop.
// They do not have to be vertex instances but must behave similarly (duck typing can be used for customization).
// 
// Each convex polygon has a `shared` property, which is shared between all polygons that are clones of each other or were split from the same polygon.
// This can be used to define per-polygon properties (such as surface color).
JL.webgl.graphics_object.csg.classes.polygon = function(vertices, shared) {
	this.vertices = vertices;
	this.shared   = shared;
	this.plane    = JL.webgl.graphics_object.csg.classes.plane.fromPoints(vertices[0].v, vertices[1].v, vertices[2].v);
};

JL.webgl.graphics_object.csg.classes.polygon.prototype = {
	clone: function() {
		var vertices = this.vertices.map(function(v) { return v.clone(); });
		return new JL.webgl.graphics_object.csg.classes.polygon(vertices, this.shared);
	},
	flip: function() {
		this.vertices.slice().reverse().map(function(v) { v.flip(); });
		this.plane.flip();
	}
};

// --------
// | Node |
// --------

// A node in a BSP tree.
// A BSP tree is built from a collection of polygons by picking a polygon to split along.
// That polygon (and all other coplanar polygons) are added directly to that node and the other polygons are added to the front and/or back subtrees.
// This is not a leafy BSP tree since there is no distinction between internal and leaf nodes.
JL.webgl.graphics_object.csg.classes.node = function(polygons) {
	this.plane = null;
	this.front = null;
	this.back  = null;
	this.polygons = [];
	if( polygons ) this.build( polygons );
};

JL.webgl.graphics_object.csg.classes.node.prototype.clone = function(){
	var node      = new JL.webgl.graphics_object.csg.classes.node();
	node.plane    = ( this.plane && this.plane.clone() );
	node.front    = ( this.front && this.front.clone() );
	node.back     = ( this.back  && this.back.clone()  );
	node.polygons = this.polygons.map(function( x ){ return x.clone(); });
	return node;
};

// Convert solid space to empty space and empty space to solid space.
JL.webgl.graphics_object.csg.classes.node.prototype.invert = function(){
	for( var i = 0; i < this.polygons.length; i++ ) this.polygons[i].flip();
	this.plane.flip();
	if( this.front ) this.front.invert();
	if( this.back  ) this.back.invert();
	var temp = this.front;
	this.front = this.back;
	this.back  = temp;
};

// Recursively remove all polygons in `polygons` that are inside this BSP tree.
JL.webgl.graphics_object.csg.classes.node.prototype.clipPolygons = function( polygons ){
	if( !this.plane ) return polygons.slice();
	var front = [], back = [];
	for( var i = 0; i < polygons.length; i++ ) this.plane.splitPolygon( polygons[i], front, back, front, back );
	if( this.front ) front = this.front.clipPolygons( front );
	if( this.back  ) back = this.back.clipPolygons( back );
	else back = [];
	return front.concat( back );
};

// Remove all polygons in this BSP tree that are inside the other BSP tree `bsp`.
JL.webgl.graphics_object.csg.classes.node.prototype.clipTo = function( bsp ){
	this.polygons = bsp.clipPolygons( this.polygons );
	if( this.front ) this.front.clipTo( bsp );
	if( this.back  ) this.back.clipTo(  bsp );
};

// Return a list of all polygons in this BSP tree.
JL.webgl.graphics_object.csg.classes.node.prototype.allPolygons = function(){
	var polygons = this.polygons.slice();
	if( this.front ) polygons = polygons.concat( this.front.allPolygons() );
	if( this.back  ) polygons = polygons.concat( this.back.allPolygons()  );
	return polygons;
};

// Build a BSP tree out of `polygons`.
// When called on an existing tree, the new polygons are filtered down to the bottom of the tree and become new nodes there.
// Each set of polygons is partitioned using the first polygon (no heuristic is used to pick a good split).
JL.webgl.graphics_object.csg.classes.node.prototype.build = function( polygons ){
	if( !polygons.length ) return;
	if( !this.plane ) this.plane = polygons[0].plane.clone();
	var front = [], back = [];
	for( var i = 0; i < polygons.length; i++ ) this.plane.splitPolygon( polygons[i], this.polygons, this.polygons, front, back );
	if( front.length ){
		if( !this.front ) this.front = new JL.webgl.graphics_object.csg.classes.node();
		this.front.build( front );
	}
	if( back.length ){
		if( !this.back ) this.back = new JL.webgl.graphics_object.csg.classes.node();
		this.back.build( back );
	}
};

// ---------
// | Plane |
// ---------

JL.webgl.graphics_object.csg.classes.plane = function( vn, w ){
	this.vn = vn;
	this.w  = w;
};

JL.webgl.graphics_object.csg.classes.plane.fromPoints = function(a, b, c) {
	var n = JL.functions.normalize( JL.functions.cross_product(
		JL.functions.vector_subtract( b, a ),
		JL.functions.vector_subtract( c, a ),
	) );
  return new JL.webgl.graphics_object.csg.classes.plane(n, JL.functions.dot_product( n, a ) );
};

JL.webgl.graphics_object.csg.classes.plane.prototype = {
  clone : function(){ return new JL.webgl.graphics_object.csg.classes.plane(this.vn.slice(), this.w); },
  flip  : function() {
    this.vn = JL.functions.scalar_multiply( -1, this.vn );
    this.w  = -this.w;
  },

  // Split `polygon` by this plane if needed, then put the polygon or polygon
  // fragments in the appropriate lists. Coplanar polygons go into either
  // `coplanarFront` or `coplanarBack` depending on their orientation with
  // respect to this plane. Polygons in front or in back of this plane go into
  // either `front` or `back`.
  splitPolygon: function( polygon, coplanarFront, coplanarBack, front, back ){

	var plane_epsilon = 1e-5;

    var COPLANAR = 0;
    var FRONT    = 1;
    var BACK     = 2;
    var SPANNING = 3;

    // Classify each point as well as the entire polygon into one of the above four classes.
    var polygonType = 0;
    var types = [];
    for( var i = 0; i < polygon.vertices.length; i++ ){
      var t = JL.functions.dot_product( this.vn, polygon.vertices[i].v ) - this.w;
      var type = ( t < -plane_epsilon ? BACK : ( t > plane_epsilon ? FRONT : COPLANAR ) );
      polygonType |= type;
      types.push( type );
    }

    // Put the polygon in the correct list, splitting it when necessary.
    switch (polygonType) {
      case COPLANAR : ( JL.functions.dot_product( this.vn, polygon.plane.vn ) > 0 ? coplanarFront : coplanarBack).push(polygon); break;
      case FRONT    : front.push( polygon ); break;
      case BACK     :  back.push( polygon ); break;
      case SPANNING:
	var f = [], b = [];
	for (var i = 0; i < polygon.vertices.length; i++) {
	  var j = (i + 1) % polygon.vertices.length;
	  var ti = types[i], tj = types[j];
	  var vi = polygon.vertices[i], vj = polygon.vertices[j];
	  if (ti != BACK) f.push(vi);
	  if (ti != FRONT) b.push(ti != BACK ? vi.clone() : vi);
	  if ((ti | tj) == SPANNING) {
	    var t = (this.w - JL.functions.dot_product( this.vn, vi.v ) ) / JL.functions.dot_product( this.vn, JL.functions.vector_subtract( vj.v, vi.v ) );
	    var v = vi.interpolate(vj, t);
	    f.push(v);
	    b.push(v.clone());
	  }
	}
	if( f.length >= 3 ) front.push( new JL.webgl.graphics_object.csg.classes.polygon( f, polygon.shared ) );
	if( b.length >= 3 )  back.push( new JL.webgl.graphics_object.csg.classes.polygon( b, polygon.shared ) );
	break;
    }
  }
};

