JL.webgl.physics = {};

JL.webgl.physics.load_ammo = function( callback ){
	var self = this;
	if( typeof Ammo === 'undefined' ){
		$.ajax({
			url      : JL.webgl.dir.dist + "/ammo.js",
			dataType : 'script',
			async    : false,
			success  : function(){
				Ammo().then(function(){
					self.customize_ammo();
					if( callback ) callback();
				});
			},
			error    : function( e ){
				console.log( 'Error loading physics engine -- ', e );
			}
		});
	}
	else{
		if( callback ) callback();
	}
};

JL.webgl.physics.reset_ammo = function( callback ){
	var self = this;
	delete Ammo;
	this.load_ammo( callback );
};

JL.webgl.physics.customize_ammo = function(){
	// --------------------
	// | Global Variables |
	// --------------------

	this.v3_0 = new Ammo.btVector3( 0, 0, 0 );

	// --------------
	// | Quaternion |
	// --------------

	Ammo.btQuaternion.prototype.rotate = function( rot ){
		var tmp_quat = new Ammo.btQuaternion( 0, 0, 0, 1 );
		tmp_quat.setEulerZYX(
			JL.functions.constants.to_radians * rot[ 2 ],
			JL.functions.constants.to_radians * rot[ 1 ],
			JL.functions.constants.to_radians * rot[ 0 ]
		);      
		tmp_quat.op_mulq( this );
		this.setValue( tmp_quat.x(), tmp_quat.y(), tmp_quat.z(), tmp_quat.w() );
		Ammo.destroy( tmp_quat );
		return this;
	};

	// ---------
	// | World |
	// ---------

	Ammo.btDiscreteDynamicsWorld.prototype.get_item_collisions = function( item ){
		var item_id = item.collider.body.a;
		return ( this.collisions || [] ).filter( x => ( x.getNumContacts() && ( x.getBody0().a == item_id || x.getBody1().a == item_id ) ) );
	};

	Ammo.btDiscreteDynamicsWorld.prototype.get_collision_direction = function( item, collision ){
		var contact = collision.getContactPoint();
		var direction = ( item.collider.body.a == collision.getBody0().a ? contact.m_localPointA : contact.m_localPointB );
		return JL.functions.normalize([ direction.x(), direction.y(), direction.z() ]);
	};

	Ammo.btDiscreteDynamicsWorld.prototype.item_is_on_ground = function( item, collisions ){
		if( !item.collider.body.isActive() ) return true;
		var collisions = collisions || this.get_item_collisions( item );
		for( var collision of collisions ){
			if( this.get_collision_direction( item, collision )[ 1 ] < -0.5 ) return true;
		}
		return false;
	};

	Ammo.btDiscreteDynamicsWorld.prototype.item_can_walk = function( item, collisions ){
		if( !item.collider.body.isActive() ) return true;
		var collisions = collisions || this.get_item_collisions( item );
		for( var collision of collisions ){
			if( this.get_collision_direction( item, collision )[ 1 ] < 0 ) return true;
		}
		return false;
	};

	Ammo.btDiscreteDynamicsWorld.prototype.update_collisions_list = function(){
		var num_manifolds = this.collision_dispatcher.getNumManifolds();
		this.collisions = new Array( num_manifolds );
		for( var i = 0; i < num_manifolds; i++ ){
			var curr_collisions = this.collisions[ i ] = this.collision_dispatcher.getManifoldByIndexInternal( i );

			if( curr_collisions.getNumContacts() ){
				// -- Collision events --

				var body_0 = curr_collisions.getBody0();
				var body_1 = curr_collisions.getBody1();

				var collision_event_0 = this.collision_events.find( body_0.a );
				var collision_event_1 = this.collision_events.find( body_1.a );

				// In case I need it, the following is for deriving contact points and distance:
				// for( var j = 0; j < curr_collisions.getNumContacts(); j++ ){
				// 	var contact_point = curr_collisions.getContactPoint( j );
				// 	var distance      = contact_point.getDistance();
				// }

				if( collision_event_0 ) collision_event_0( body_1, curr_collisions );
				if( collision_event_1 ) collision_event_1( body_0, curr_collisions );

				// -- Sleepable colliders --

				var sleeper_0 = this.sleepers.find( body_0.a );
				var sleeper_1 = this.sleepers.find( body_1.a );

				if( sleeper_0 || sleeper_1 ){ // Wake up collider if speed is greater than sleep threshold.
					if( sleeper_0 ){
						if( sleeper_0.is_sleeping && sleeper_0.parent_space_object.get_speed() > sleeper_0.sleep.threshold ) sleeper_0.set_sleep_state( 0 );
					}
					if( sleeper_1 ){
						if( sleeper_1.is_sleeping && sleeper_1.parent_space_object.get_speed() > sleeper_1.sleep.threshold ) sleeper_1.set_sleep_state( 0 );
					}
				}
			}
		}
	};
};

// --------------------
// | Helper Functions |
// --------------------

JL.webgl.physics.get_impulse_of_collision = function( collision ){
	var impulse = 0;
	for( var i = 0; i < collision.getNumContacts(); i++ ){
		var contact_point = collision.getContactPoint( i );
		impulse += Math.abs( contact_point.getAppliedImpulse() );
	}
	return impulse;
};

/*
-Collision filtering notes:
	// Possible way of defining collision groups
	this.world.addRigidBody( body, o.group || 1, o.mask || - 1 );
	// Other possible way of defining collision groups
	JL.webgl.active_camera.target.physics.body.setCollisionFlags( group1 | group2 | group3 )
	https://forum.playcanvas.com/t/collision-masks-groups/5337
	https://medium.com/@bluemagnificent/intro-to-javascript-3d-physics-using-ammo-js-and-three-js-dd48df81f591
	https://medium.com/@bluemagnificent/collision-detection-in-javascript-3d-physics-using-ammo-js-and-three-js-31a5569291ef
	https://andysomogyi.github.io/mechanica/bullet.html
-Ammo references:
	https://github.com/kripken/ammo.js/
	Ammo JS library : https://raw.githubusercontent.com/kripken/ammo.js/master/builds/ammo.wasm.js
	Lots of examples : https://github.com/lo-th/Ammo.lab/tree/gh-pages/demos
	Good example page : http://penguinspuzzle.appspot.com/minigolf.html
	http://schteppe.github.io/ammo.js-demos/
*/

JL.webgl.physics.collider = function ( p ){
	var p = p || {};

	var self = this;

	var mass = p.mass || 0;

	this.shapes = [];

	this.parent_class = p.parent_class || JL.webgl.space_object._physics;

	this.parent_space_object = p.parent_space_object;

	var num_shapes = ( p.shapes || [] ).length;
	if( num_shapes >  1 ) this.is_compound_shape = true;
	if( num_shapes == 1 ){
		var shape = p.shapes[ 0 ];
		if( [ 'position', 'rotation' ].find( x => shape[ x ] !== undefined ) ) this.is_compound_shape = true;
	}

	var local_inertia = new Ammo.btVector3( 0, 0, 0 );

	var transform = new Ammo.btTransform();
	transform.setIdentity();

	var transform_vector = new Ammo.btVector3( p.position.x, p.position.y, p.position.z );

	transform.setOrigin( transform_vector );

	var rotation_quat = new Ammo.btQuaternion( 0, 0, 0, 1 );

	if( p.rotation ) p.rotation.forEach(function( rot ){ rotation_quat.rotate( rot ); });

	transform.setRotation( rotation_quat );

	this.create_shape( p );

	this.shape.calculateLocalInertia( mass, local_inertia );

	var motion_state = new Ammo.btDefaultMotionState( transform );

	this.body = new Ammo.btRigidBody( new Ammo.btRigidBodyConstructionInfo( mass, motion_state, this.shape, local_inertia ) );

	if( p.damping          ) this.body.setDamping( p.damping.linear, p.damping.angular );
	if( p.friction         ) this.body.setFriction( p.friction );
	if( p.restitution      ) this.body.setRestitution( p.restitution );
	if( p.rolling_friction ) this.body.setRollingFriction( p.rolling_friction );
	if( p.axis_lock ){
		var axis_lock_vector = new Ammo.btVector3( p.axis_lock[ 0 ], p.axis_lock[ 1 ], p.axis_lock[ 2 ] );
		this.body.setAngularFactor( axis_lock_vector );
		Ammo.destroy( axis_lock_vector );
	}

	// -- Activation States --
	// ACTIVE : 1, ISLAND_SLEEPING : 2, WANTS_DEACTIVATION : 3, DISABLE_DEACTIVATION : 4, DISABLE_SIMULATION : 5
	if( p.motion ){
		switch( p.motion ){
			case 'static':
				this.body.setCollisionFlags( 0 );
				break;
			case 'kinematic':
				this.body.setCollisionFlags( 2 );
				this.body.setActivationState( 4 ); // Set body to never sleep.
				break;
			case 'no_collision':
				this.body.setCollisionFlags( 4 );
				break;
		}
	}

	if( p.world ){
		this.world = p.world;
		var collision_filter = p.collision_filter;
		if( JL.functions.is_str( collision_filter ) ) collision_filter = JL.webgl.active_environment.collision_filters[ collision_filter ];
		p.world.addRigidBody(
			this.body,
			( collision_filter ? collision_filter.group : 0 ),
			( collision_filter ? collision_filter.mask  : 0 )
		);
	}

	// Note: sleeping is not implemented properly in ammo.js (if one thing sleeps, everything sleeps because of 'island sleeping'; ammo.js doesn't support 'per-body' sleeping).
	// 	-Using this.body.setSleepingThresholds() is also broken in this manner.
	// 	-To compensate for this, I put together a custom implementation of 'per-body' sleeping.
	if( this.parent_space_object ){ // Need a parent space_object for managing per_frame functions.
		if( p.sleep ){
			this.sleep = p.sleep;
			this.world.sleepers.insert( this.body.a, this );
			this.set_sleep_state( 1 );
		}

		( this.parent_space_object.environment || JL.webgl.active_environment ).physics_body_id_to_space_object_id[ this.body.a ] = this.parent_space_object._id;
	}

	if( p.on_collide ) this.add_collision_event( p.on_collide );

	if( JL.webgl.active_environment.is_drawing_colliders ) this.create_space_object();

	Ammo.destroy( local_inertia    );
	Ammo.destroy( transform        );
	Ammo.destroy( transform_vector );
	Ammo.destroy( rotation_quat    );

	JL.webgl.active_environment.colliders.push( this );
};

JL.webgl.physics.collider.prototype._inputs = [
	{ key : 'mass', type : 'float', default : 0, no_this_assign : true },

	{ key : 'position', type : 'obj', no_this_assign : true,
		structure : [
			{ key : 'x', type : 'float', default : 0 },
			{ key : 'y', type : 'float', default : 0 },
			{ key : 'z', type : 'float', default : 0 },
		],
	},

	{ key : 'rotation' , type : 'arr', no_this_assign : true, optional : true,
		structure : { type : 'arr', structure : { type : 'float', default : 0 }, length : 3 },
	},

	{ key : 'shapes' , type : 'arr', no_this_assign : true,
		structure : [
			{ key : 'type' , type : 'dropdown',
				options : [ 
					'cube'         ,
					'sphere'       ,
					'capsule'      ,
					'cylinder'     ,
					'convex_hull'  ,
					'triangle_mesh',
				],
				default   : 'cube',
				redraw_json_edit_on_change : true, // For updating the conditional parameters in Edit UI.
			},
			{ key : 'radius'         , type : 'float', default : 0,            condition : function( p ){ return [ 'sphere'              ].includes( p.json_edit.get_value( p.path.slice().concat([ 'type' ]), p.root_value ) ); } },
			{ key : 'rad_top'        , type : 'float', default : 0,            condition : function( p ){ return [ 'cylinder'            ].includes( p.json_edit.get_value( p.path.slice().concat([ 'type' ]), p.root_value ) ); } },
			{ key : 'rad_bot'        , type : 'float', default : 0,            condition : function( p ){ return [ 'cylinder'            ].includes( p.json_edit.get_value( p.path.slice().concat([ 'type' ]), p.root_value ) ); } },
			{ key : 'width'          , type : 'float', default : 0,            condition : function( p ){ return [ 'capsule'             ].includes( p.json_edit.get_value( p.path.slice().concat([ 'type' ]), p.root_value ) ); } },
			{ key : 'height'         , type : 'float', default : 0,            condition : function( p ){ return [ 'capsule', 'cylinder' ].includes( p.json_edit.get_value( p.path.slice().concat([ 'type' ]), p.root_value ) ); } },
			{ key : 'graphics_object', type : 'webgl.graphics_object',         condition : function( p ){ return [ 'triangle_mesh'       ].includes( p.json_edit.get_value( p.path.slice().concat([ 'type' ]), p.root_value ) ); } },
			{ key : 'dimensions'     , type : 'obj',                           condition : function( p ){ return [ 'cube'                ].includes( p.json_edit.get_value( p.path.slice().concat([ 'type' ]), p.root_value ) ); },
				structure : [
					{ key : 'x', type : 'float', default : 0 },
					{ key : 'y', type : 'float', default : 0 },
					{ key : 'z', type : 'float', default : 0 },
				]
			},
			{ key : 'points'          , type : 'arr',                          condition : function( p ){ return [ 'convex_hull'         ].includes( p.json_edit.get_value( p.path.slice().concat([ 'type' ]), p.root_value ) ); },
				structure : { type : 'arr', length : 3, no_label : true, structure : { type : 'float', default : 0 } },
			},
		]
	},

	{ key : 'motion' , type : 'dropdown', optional : true, options : [ 'static', 'kinematic', 'no_collision' ] },

	{ key : 'friction'        , type : 'float', default : 0, no_this_assign : true, optional : true, },
	{ key : 'rolling_friction', type : 'float', default : 0, no_this_assign : true, optional : true, },

	{ key : 'restitution'     , type : 'float', default : 0, no_this_assign : true, optional : true, },

	{ key : 'damping', type : 'obj', no_this_assign : true, optional : true,
		structure : [
			{ key : 'linear' , type : 'float', default : 0 },
			{ key : 'angular', type : 'float', default : 0 },
		],
	},

	{ key : 'sleep', type : 'obj', optional : true,
		structure : [
			{ key : 'threshold' , type : 'float', default : 0.01 },
		],
	},

	{ key : 'type' , type : 'dropdown', optional : true, options : [ 'heightfield' ] },

	{ key : 'axis_lock' , type : 'arr', no_this_assign : true, optional : true, structure : { type : 'float' }, length : 3 },

	{ key : 'collision_filter', type : 'dropdown', optional : true, get_options : function(){ return [{ name : 'No filter', value : false }].concat( Object.keys( JL.webgl.active_environment.collision_filters || {} ) ); } },

	{ key : 'on_collide' , type : 'function', optional : true, },
];


JL.webgl.physics.collider.prototype.store_shape_info = function( p, info ){
	[ 'position', 'rotation' ].forEach(function( k ){ info[ k ] = p[ k ]; });
	this.shapes.push( info );
};

JL.webgl.physics.collider.prototype.create_shape = function( p ){
	this.shape = ( this.is_compound_shape ? 
		this.create_compound( p ) :
		this[ 'create_' + p.shapes[ 0 ].type ]( p.shapes[ 0 ], p )
	);
	this.shape.setMargin( 0 );
};

JL.webgl.physics.collider.prototype.create_cube = function( p ){
	var dim = p.dimensions || { x : 1, y : 1, z : 1 };

	this.store_shape_info( p, {
		type       : 'cube',
		dimensions : dim,
	});

	var v3_dim = new Ammo.btVector3( dim.x, dim.y, dim.z );
	var shape  = new Ammo.btBoxShape( v3_dim );
	Ammo.destroy( v3_dim );
	return shape;
};

JL.webgl.physics.collider.prototype.create_sphere = function( p ){
	var radius = p.radius || 1;

	this.store_shape_info( p, {
		type     : 'sphere',
		radius   : radius,
	});
	return new Ammo.btSphereShape( radius );
};

JL.webgl.physics.collider.prototype.create_cylinder = function( p ){
	this.store_shape_info( p, {
		type    : 'cylinder',
		rad_top : p.rad_top,
		rad_bot : p.rad_bot,
		height  : p.height,
	});

	var v3_dim = new Ammo.btVector3( p.rad_top, p.height / 2, p.rad_bot );
	var shape  = new Ammo.btCylinderShape( v3_dim );
	Ammo.destroy( v3_dim );
	return shape;
};

JL.webgl.physics.collider.prototype.create_capsule = function( p ){
	var width  = p.width  || 1;
	var height = p.height || 2;

	this.store_shape_info( p, {
		type   : 'capsule',
		width  : width,
		height : height,
	});
	return new Ammo.btCapsuleShape( width, height );
};

JL.webgl.physics.collider.prototype.create_convex_hull = function( p ){
	var shape = new Ammo.btConvexHullShape();

	var v3_point = new Ammo.btVector3();
	for( var point of p.points ){
		v3_point.setValue( point[ 0 ], point[ 1 ], point[ 2 ] );
		shape.addPoint( v3_point );
	}
	Ammo.destroy( v3_point );

	this.store_shape_info( p, {
		type   : 'convex_hull',
		points : p.points,
	});

	return shape;
};

JL.webgl.physics.collider.prototype.create_triangle_mesh = function( p, params ){
	var mesh = new Ammo.btTriangleMesh();

	var g_o = p.graphics_object;
	g_o.reload_attrs_from_buffers();

	if( g_o.vertex_indices ){
		var v3_1 = new Ammo.btVector3();
		var v3_2 = new Ammo.btVector3();
		var v3_3 = new Ammo.btVector3();

		for( var i = 0; i < g_o.vertex_indices.length; i += 3 ){
			var idx_1 = 3 * g_o.vertex_indices[ i     ];
			var idx_2 = 3 * g_o.vertex_indices[ i + 1 ];
			var idx_3 = 3 * g_o.vertex_indices[ i + 2 ];

			v3_1.setValue( g_o.v[ idx_1 ], g_o.v[ idx_1 + 1 ], g_o.v[ idx_1 + 2 ] );
			v3_2.setValue( g_o.v[ idx_2 ], g_o.v[ idx_2 + 1 ], g_o.v[ idx_2 + 2 ] );
			v3_3.setValue( g_o.v[ idx_3 ], g_o.v[ idx_3 + 1 ], g_o.v[ idx_3 + 2 ] );

			mesh.addTriangle( v3_1, v3_2, v3_3 );
		}

		Ammo.destroy( v3_1 );
		Ammo.destroy( v3_2 );
		Ammo.destroy( v3_3 );

		var shape = new Ammo.btBvhTriangleMeshShape( mesh );

		this.store_shape_info( p, {
			type            : 'triangle_mesh',
			graphics_object : g_o,
		});

		if( params.scale ){
			var v3_scale = new Ammo.btVector3( params.scale[ 0 ], params.scale[ 1 ], params.scale[ 2 ] );
			shape.setLocalScaling( v3_scale );
			Ammo.destroy( v3_scale );
		}

		return shape;
	}
};

JL.webgl.physics.collider.prototype.create_heightmap = function( p, params ){
	var heights = ( params.graphics_objects[ 0 ].heights );

	var scale = ( params.scale || [1,1,1] );

	var heights_width = heights.length;
	var heights_depth = heights[ 0 ].length;

	var ammo_height_data = Ammo._malloc( 4 * heights_width * heights_depth );

	var idx = 0;
	heights.forEach(function( row ){
		row.forEach(function( val ){
			Ammo.HEAPF32[ ammo_height_data + ( 4 * idx ) >> 2 ] = scale[ 1 ] * val;
			idx++;
		});
	});

	var height_scale = params.graphics_objects[ 0 ].height_scale || 1;

	this.store_shape_info( p, {
		type    : 'heightmap',
                scale   : scale.slice(),
		heights : $.extend( true, [], heights ),
		height_scale,
	});

	var shape = new Ammo.btHeightfieldTerrainShape(
		heights_width,
		heights_depth,
		ammo_height_data,      
		height_scale,
		-999,                                // Terrain Min Height
		 999,                                // Terrain Max Height
		1,                                   // Up Axis
		'PHY_FLOAT',                         // HDT
		false                                // Flip Quad Edges
	);

	// Note : When encountered with OOM (out of memory) error, it will most likely be due to the Ammo._malloc function.
	// 	-Ammo._malloc (allocating memory) function calls should be paired with Ammo._free (deallocating memory) function calls.
	// 	-However, it seems that the Ammo._free function doesn't actually do anything.
	// 	-Right now, I'm reloading the entire Ammo library when clearing an environment. That does seem to successfully clear memory.
	// 	-If I end up needing to clear just the heightfield data, but keep the rest of the physics engine, then I may need to do a custom build of the Ammo.js library with the _free included.
	// 		-Ex: large scale environment with lots of terrain chunks 
	// console.log( ammo_height_data );
	// Ammo._free( ammo_height_data );

	var g_o_side_length = 2 * ( params.graphics_objects[ 0 ].side || 1 );

	var v3_scale = new Ammo.btVector3(
		g_o_side_length * scale[ 0 ] / ( heights_width - 1 ), 1,
		g_o_side_length * scale[ 2 ] / ( heights_depth - 1 )
	);

	shape.setLocalScaling( v3_scale );

	Ammo.destroy( v3_scale );

	return shape;
};

JL.webgl.physics.collider.prototype.create_compound = function( p ){
	var shape = new Ammo.btCompoundShape();

	var child_transform = new Ammo.btTransform();

	p.shapes.forEach(function( c ){
		child_transform.setIdentity();

		if( c.position ){
			var v3_pos = new Ammo.btVector3( c.position.x, c.position.y, c.position.z );
			child_transform.setOrigin( v3_pos );
			Ammo.destroy( v3_pos );
		}

		if( c.rotation ){
			var child_quat = new Ammo.btQuaternion( 0, 0, 0, 1 );
			for( var rot of c.rotation ) child_quat.rotate( rot );
			child_transform.setRotation( child_quat );
			Ammo.destroy( child_quat );
		}

		shape.addChildShape( child_transform, this[ 'create_' + c.type ]( c, p ) );
	}, this);

	Ammo.destroy( child_transform );

	return shape;
};

JL.webgl.physics.collider.prototype.add_collision_event = function( on_collide ){
	var self = this;
	this.on_collide = on_collide;
	this.world.collision_events.insert( this.body.a, function( target, collision ){ self.on_collide( target, collision ); } );
};

JL.webgl.physics.collider.prototype.remove_collision_event = function(){
	this.world.collision_events.remove( this.body.a );
};

JL.webgl.physics.collider.prototype.set_sleep_state = function( val ){
	if( val ){ // put to sleep
		if( !this.is_sleeping ){
			this.is_sleeping = true;

			this.body.forceActivationState( 5 );

			clearInterval( this.sleep_interval );
		}
	}
	else{ // wake object up
		if( this.is_sleeping ){
			this.is_sleeping = false;

			this.body.forceActivationState( 1 );

			var self = this;
			this.sleep_interval = setInterval(function(){
				var speed = self.parent_space_object.get_speed();
				if( speed <= self.sleep.threshold ) self.set_sleep_state( 1 );
			}, 5000 );
		}
	}
};

JL.webgl.physics.collider.prototype.create_space_object = function(){
	if( !this.space_object ){
		var collider = this;

		var space_object_params = {
			no_graphics_objects : true,
			draw_xyz            : true,
			attr                : {
				ignore_xyz       : true,
				draw_from_matrix : true,
			},
		};
		if( this.parent_space_object ){
			space_object_params.parent_object = this.parent_space_object;
			space_object_params.child_type    = 'independent';
		}

		var obj = this.space_object = JL.webgl.active_environment.add_space_object( space_object_params );

		obj.collider = { body : this.body };

		obj.matrix = Matrix.I(4);

		[ 'calculate_position_from_physics', 'get_world_transform', 'set_graphics_object_position', 'set_graphics_object_rotation', 'translate', 'rotate' ].forEach(function( key ){
			obj[ key ] = JL.webgl.space_object._physics.prototype[ key ];
		}, this);

		obj.add_per_frame_function( function(){ this.calculate_position_from_physics(); } );

		this.shapes.forEach(function( shape, shape_idx ){
			var mesh;

			switch( shape.type ){
				case 'sphere' :
					mesh = new JL.webgl.graphics_object.sphere({
						radius     : shape.radius,
						v_segs     : 8,
						h_segs     : 8, 
						properties : { effects : [ '_collider_coloring' ] }
					});
					break;
				case 'capsule' :
					mesh = new JL.webgl.graphics_object.sphere({
						radius     : shape.width,
						v_segs     : 8,
						h_segs     : 8, 
						properties : { effects : [ '_collider_coloring' ] } 
					});
					break;
				case 'cylinder' :
					mesh = new JL.webgl.graphics_object.cylinder({
						height     : shape.height,
						rad_top    : shape.rad_top, 
						rad_bot    : shape.rad_bot, 
						num_slices : 16,
						properties : { effects : [ '_collider_coloring' ] },
					});
					break;
				case 'cube' :
					mesh = new JL.webgl.graphics_object.cube( Object.assign( { properties : { effects : [ '_collider_coloring' ] } }, shape.dimensions ) );
					break;
				case 'convex_hull' :
					var v = [];
					for( var i = 0; i < shape.points.length; i++ ){
						for( var j = i; j < shape.points.length; j++ ){
							v.push( shape.points[ i ], shape.points[ j ] );
						}
					}
					mesh = new JL.webgl.graphics_object.line({ points : { v }, primitive : JL.webgl.gl.TRIANGLE_FAN, properties : { effects : [ '_collider_coloring' ] }, } );
					break;
				case 'heightmap' :
					mesh = new JL.webgl.graphics_object.heightmap({
						heights      : shape.heights,
						sides        : [ 2, 2 ],
						num_segments : shape.heights.length,
						properties   : { effects : [ '_collider_coloring' ] }
					});
					break;
			}

			if( mesh ){
				var sub_obj = JL.webgl.active_environment.add_space_object({
					parent_object : obj,
					attr          : {
						custom_align : function(){
							JL.webgl.mat.model = obj.matrix.x( this.matrix );
						},
						draw_from_matrix : true,
					},
				});
				sub_obj.index = shape_idx;
				sub_obj.matrix = Matrix.I(4);

				if( shape.type == 'heightmap' ){
					sub_obj.remove_gl_filter( 'cull_face' );
					sub_obj.scale = shape.scale;
				}

				if( shape.type == 'capsule' ) sub_obj.scale = [ 1, shape.height, 1 ];

				sub_obj.set_graphics_object_position = JL.webgl.space_object._physics.prototype.set_graphics_object_position;
				sub_obj.set_graphics_object_rotation = JL.webgl.space_object._physics.prototype.set_graphics_object_rotation;
				sub_obj.translate                    = JL.webgl.space_object._physics.prototype.translate;
				sub_obj.rotate                       = JL.webgl.space_object._physics.prototype.rotate;

				[ 'set_graphics_object_position', 'set_graphics_object_rotation', 'translate', 'rotate' ].forEach(function( key ){
					sub_obj[ key ] = JL.webgl.space_object._physics.prototype[ key ];
				});

				if( shape.position ) sub_obj.translate( shape.position.x || 0, shape.position.y || 0, shape.position.z || 0 );

				if( shape.rotation ){
					shape.rotation.forEach(function( rot ){
						var axis_idx = rot.findIndex( x => x );
						var axis = [ 0, 0, 0 ];
						axis[ axis_idx ] = 1;
						sub_obj.rotate( rot[ axis_idx ], axis );
					});
				}

				sub_obj.set_graphics_object( mesh );
			}
		}, this );
	}
};

JL.webgl.physics.collider.prototype.destroy_space_object = function(){
	if( this.space_object ){
		this.space_object.remove();
		delete this.space_object;
	}
};

JL.webgl.space_object._regular = function(){};

// This function is used by the Edit UI to add a new space_object to the environment.
JL.webgl.space_object._regular.get_new_id = function(){
	var _id = JL.webgl.space_object._regular.prototype._inputs.find( x => x.key == '_id' ).get_default();
	JL.webgl.space_object_ids.push( _id );
	return _id;
};

JL.webgl.space_object._regular.prototype._inputs = [
	{ key : '_id'         , type : 'int', hidden : true, get_default : function(){
		if( JL.webgl.space_object_ids.length ) return Math.max( ...JL.webgl.space_object_ids.map( id => id || 0 ) ) + 1;
		else                                   return 1;
	} },

	{ key : 'parent_object', type : 'webgl.space_object', ui_row : '5_par',
		custom_options : function( p ){
			return [{ name : 'No parent', }].concat(
				p.options.filter(function( o ){ return ( o.value !== p.value._id ); })
			);
		},
	},
	{ key : 'child_type', type : 'dropdown', ui_row : '5_par',
		options : [ '', 'dependent', 'independent', 'lat_lon_rad', 'vertex_group', ],
	},
	{ key : 'child_params', type : 'obj', ui_order : '5_par_1', no_this_assign : 1,
		condition : function( p ){
			return ( p.json_edit.get_value([ 'child_type' ], p.root_value ) == 'vertex_group' );
		},

		structure : [
			{ key : 'vertex_group', type : 'dropdown',
				condition   : function( p ){ return ( p.json_edit.get_value([ 'child_type' ], p.root_value ) == 'vertex_group' ); },
				get_options : function( p ){
					var options = [ '' ];
					try{
						var parent_s_o = p.json_edit.target_object.parent_object;
						parent_s_o.derive_reference_vertex_group_indices();
						options = options.concat( Object.keys( parent_s_o.reference_vertex_group_indices ) );
					}
					catch(e){}
					return options;
				},
			},
		],
	},

	{ key : 'name'        , type : 'str', ui_order : '1' },

	// TODO : Try to redesign the following types of transformations:
	// 	-Able to do multiple iterations of each type of transformation.
	// 	-Allow these transformations to be set (more) easily from Edit UI.
	// 	-Standardize naming of these transformations.
	// 		-Ex: orientation, offset, etc... should have their names change to something more intuitive.
	// transform:pos
	{ key : 'x'           , type : 'float', default : 0, no_p_assign : true, ui_row : '2_pos' },
	{ key : 'y'           , type : 'float', default : 0, no_p_assign : true, ui_row : '2_pos' },
	{ key : 'z'           , type : 'float', default : 0, no_p_assign : true, ui_row : '2_pos' },

	// transform:sph
	{ key : 'lat'         , type : 'float', default : 0, no_p_assign : true, ui_row : '3_llr' },
	{ key : 'lon'         , type : 'float', default : 0, no_p_assign : true, ui_row : '3_llr' },
	{ key : 'orbit_radius', type : 'float', default : 0, no_p_assign : true, ui_row : '3_llr' },

	// transform:rot
	{ key : 'roll'        , type : 'float', default : 0, no_p_assign : true, ui_row : '4_rpy' },
	{ key : 'pitch'       , type : 'float', default : 0, no_p_assign : true, ui_row : '4_rpy' },
	{ key : 'yaw'         , type : 'float', default : 0, no_p_assign : true, ui_row : '4_rpy' },

	{ key : 'z_index'     , type : 'float', no_p_assign : true, ui_row : '5_z'  },
	{ key : 'scale'       , type : 'arr'  , no_p_assign : true, ui_row : '5_z' , structure : { type : 'float' }, length : 3,
				get_default : function(){ return [ 1, 1, 1 ]; },
				right_click : { lbl : [
					{
						label   : 'Set size',
						inputs  : [{ type : 'number', value : 1 }],
						onclick : function( e, p ){
							var val = Number( $( e.inputs[ 0 ] ).val() );
							p.set_value( p.value.map( _ => val ) );
						}
					}
				] },
	},

	{ key : 'draw_xyz'        , type : 'bool' , no_p_assign : true, ui_row : '6_b'  },
	{ key : 'is_impostor'     , type : 'bool' , no_p_assign : true, ui_row : '6_b'  },

	{ key : 'graphics_objects', type : 'arr', no_this_assign : true, optional : true, structure : { type : 'webgl.graphics_object' } },

	{ key : 'camera_config', type : 'obj', no_this_assign : true, optional : true,
		structure : [
			{ key : 'lat'                  , type : 'float', optional : 1 },
			{ key : 'lon'                  , type : 'float', optional : 1 },
			{ key : 'rad'                  , type : 'float', optional : 1 },
			{ key : 'offset'               , type : 'arr'  , optional : 1, length : 3, structure : { type : 'float', default : 0 } },
			{ key : 'no_control'           , type : 'bool' , optional : 1, },
			{ key : 'follow_roll_pitch_yaw', type : 'bool' , optional : 1, },
		],
	},

	{ key : 'key_bindings', type : 'arr', get_default : function(){ return []; },
		structure   : { type : 'dropdown', no_label : true, get_options : function(){ return Object.keys( JL.webgl.ui.key_bindings.bindings ); } }
	},

	{ key : 'ui_elements', type : 'arr', no_this_assign : true, optional : true, structure : {
		type : 'str', get_autocomplete : function(){ return Object.keys( JL.webgl.ui.item ); },
	} },

	{ key : 'gl_filters', type : 'arr', no_this_assign : true, optional : true, structure : [
		{ key : 'name', type : 'dropdown', options : [ 'cull_face', 'additive_blending', 'disable_depth_test', 'disable_depth_mask', 'use_depth_mask' ], },
		{ key : 'front', type : 'bool', condition : function( p ){ return ( 'cull_face' == p.json_edit.get_value( p.path.slice( 0, 2 ).concat([ 'name' ]), p.root_value ) ); }, },
	] },

	{ key : 'no_cull_face', type : 'bool' , no_this_assign : true, optional : true  },

	{ key : 'per_frame_functions', type : 'arr', no_this_assign : true, optional : true, structure : { type : 'function', no_label : true } },

	{ key : 'on_init'            , type : 'function', no_this_assign : true, optional : true },
	{ key : 'on_post_init'       , type : 'function', no_this_assign : true, optional : true },

	{ key : 'put_on_terrain', type : 'obj', no_this_assign : true, optional : true,
		structure : [
			{ key : 'terrain', type : 'webgl.space_object', optional : true,
				custom_options : function( p ){
					return p.options.filter(function( o ){ return ( o.space_object instanceof JL.webgl.space_object._terrain ); });
				},
			},
			{ key : 'y_offset'    , type : 'float', default : 0 },
			{ key : 'relative_pos', type : 'bool'  },
		],
	},
	{ key : 'dependent_on_terrain_tile', type : 'obj', optional : true,
		structure : [
			{ key : 'terrain', type : 'webgl.space_object', optional : true,
				custom_options : function( p ){
					return p.options.filter(function( o ){ return ( o.space_object instanceof JL.webgl.space_object._terrain ); });
				},
			},
			{ key : 'relative_pos', type : 'bool'  },
		],
	},

	{ key : 'independent_camera', type : 'bool', no_this_assign : true, },

	{ key : 'animated', type : 'dropdown', optional : true, get_options : function(){
		return JL.webgl.animations.map( x => x.name );
	} },

	{ key : 'animation_parameters', type : 'obj', hidden : true, },
];

JL.webgl.space_object._regular.prototype.get_inputs  = JL.webgl.graphics_object._main.prototype.get_inputs;
JL.webgl.space_object._regular.prototype.load_inputs = JL.webgl.graphics_object._main.prototype.load_inputs;

JL.webgl.space_object._regular.prototype.init = function( p ){
	var p = p || {};

	var self = this;

	this.environment = p.environment || JL.webgl.active_environment;

	if( p.dependent_on_terrain_tile ){
		p.no_parent = true;

		this.dependent_on_terrain_tile = $.extend( true, {}, p.dependent_on_terrain_tile );

		var _p = $.extend( true, {}, p );
		delete _p.dependent_on_terrain_tile;

		this.environment.wait_for_terrain_tile_to_init_space_object( Object.assign( $.extend( true, {}, p.dependent_on_terrain_tile ), {
			x        : ( p.x || 0 ),
			z        : ( p.z || 0 ),
			callback : function( response ){
				self.init( _p );

				response.tile.add_child( self, 'independent', p.child_params );
			},
		} ) );
		return;
	}

	// if( p.pre_attr ) Object.assign( this, p.pre_attr );

	this.name = p.name;

	if     (  p.gl_filters   ) this.add_gl_filters( p.gl_filters );
	else if( !p.no_cull_face ) this.add_gl_filters( [{ name : 'cull_face' }] );

	this.load_inputs( p );

	JL.webgl.space_object_ids.push( this._id );

	if( p.on_init ) p.on_init.apply( this, p );

	if( this._on_instantiate ) this._on_instantiate( p );

	// 2025-12-23 -- Renamed s_o._constructor to s_o._on_init. (if code breaks, try changing '_constructor' to '_on_init')
	// if( this._constructor ) this._constructor( p );

	if( this.  _on_init ) this.  _on_init( p ); // 1st level of inheritance -- ex: s_o._physics
	if( this. __on_init ) this. __on_init( p ); // 2nd level of inheritance -- ex: s_o._car
	if( this.___on_init ) this.___on_init( p ); // 3rd level of inheritance 

	if( p.graphics_objects ) this.add_graphics_objects( p.graphics_objects.map(function( m ){ return JL.webgl.functions.get_graphics_object( m ); }, this), { no_update_attr : true, } );
	if( p.ui_info          ) this.ui_info      = p.ui_info;

	var default_key_bindings = ( JL.webgl.variables.default_key_bindings || [] ).slice();
	if( JL.webgl.device.is( 'vr' )    ) default_key_bindings.push( 'vr_menu' );
	if( JL.webgl.variables.is_editing ) default_key_bindings.push( 'edit'    );
	this.key_bindings = JL.functions.filter_duplicates( default_key_bindings.concat( this.key_bindings || [] ) );

	var ui_elements = ( this.ui_elements || p.ui_elements );
	if( this._custom_ui_elements ) ui_elements = JL.functions.filter_duplicates( ( ui_elements || [] ).concat( this._custom_ui_elements ) );
	if( ui_elements ) this.set_ui_elements( ui_elements );

	if( p.camera_config && !this.camera_config ) this.camera_config = p.camera_config;
	if(                    !this.camera_config ) this.camera_config = this.get_camera_config();

	if( p.independent_camera ) this.target_matrix = Matrix.I(4); // Only used with physics objects, as of 2025-03-16.

	if( p.put_on_terrain ){
		this.environment.wait_for_terrain_y_value( Object.assign( $.extend( true, {}, p.put_on_terrain ), {
			x        : this.x,
			z        : this.z,
			callback : function( y ){ self.y = y; },
		} ) );
	}

        if( p.per_frame_functions ){
		for( var f of p.per_frame_functions ) this.add_per_frame_function( f );
        }

	if( !p.no_parent ){
		if( p.parent_object ){
			JL.webgl.functions.get_space_object( p.parent_object ).add_child( this, p.child_type, p.child_params );
		}
		else if( this.environment ){
			this.environment._root_object.add_child( this, p.child_type || 'independent', p.child_params );
		}
	}

	// this.construct_draw_update_function();

	this.set_attr( p.attr || {} );

	if( p.select ) this.select();

	JL.webgl.all_space_objects.push( this );

	if( this._on_post_init ) this._on_post_init( p );
	if( p.on_post_init ) p.on_post_init.apply( this, p );
};

JL.webgl.space_object._regular.prototype.set_graphics_object = function( obj, p ){
	var p = p || {};

	var is_animating = this.is_animating();

	if( is_animating ) this.stop_animating();

	if( JL.functions.is_array( obj ) ) obj = JL.webgl.functions.get_graphics_object( obj );
	if( !this.graphics_objects ) this.graphics_objects = [];
	this.graphics_objects[ 0 ] = obj;
	// 2025-07-05
	// if( typeof obj.radius != undefined ) this.rad = obj.radius;
	if( this.animated ){
		this.vertex_groups = [];   // Need this line for replacing animated graphics_objects.
		this.init_animated_graphics_object( obj );
	}
	this.change_to_draw();

	if( !p.no_update_attr ) this.set_attr({});

	if( is_animating ) this.start_animating();
};

JL.webgl.space_object._regular.prototype.add_graphics_object = function( g_o, p ){
	if( g_o === undefined ) return;

	if(
		JL.functions.is_object( g_o ) &&
		!( g_o instanceof JL.webgl.graphics_object._main )
	){
		g_o = JL.webgl.functions.create_graphics_object( g_o );
	}

	var p = p || {};

	if( !( this.graphics_objects || [] ).length ) this.set_graphics_object( g_o, { no_update_attr : true } );
	else{
		if( p.z_index !== undefined ) g_o.z_index = p.z_index;

		this.graphics_objects.push( g_o );

		this.init_animated_graphics_object( g_o );

		this.change_to_draw();
	}

	if( !p.no_update_attr ) this.set_attr({});
};

JL.webgl.space_object._regular.prototype.add_graphics_objects = function( graphics_objects, p ){
	var p = p || {};

	for( var g of graphics_objects ) this.add_graphics_object( g, { no_update_attr : true } );

	if( !p.no_update_attr ) this.set_attr({});
};

JL.webgl.space_object._regular.prototype.get_graphics_object = function( p ){
	if( !this.graphics_objects        ) return;
	if( !this.graphics_objects.length ) return;
	if( !p ) return this.graphics_objects[ 0 ];
	if( p.index !== undefined ) return this.graphics_objects[ p.index ];
	return;
};

JL.webgl.space_object._regular.prototype.get_graphics_object_from_environment_config = function( id ){
	var env = this.get_environment() || JL.webgl.active_environment;

	var g_o = env._environment_config.graphics_objects[ id ];
	var params = g_o.params || g_o;
	return JL.functions.get_nested_object( JL.webgl.graphics_objects, ( params.label || params.keys ) );
};

JL.webgl.space_object._regular.prototype.has_any_graphics_objects = function(){
	return this.graphics_objects;
};

JL.webgl.space_object._regular.prototype.has_graphics_object = function( g_o ){
	if( this._inputs ){
		var output = false;

		JL.json_edit.prototype.traverse_values({
			value     : this,
			structure : this._inputs,
			on_step   : function( val, structure ){
				if( structure.type == 'webgl.graphics_object' ){
					if( val ){
						if( JL.webgl.functions.get_graphics_object( val )._id == g_o._id ){
							output = true;
							this.stop_traversing = true;
						}
					}
				}
			},
		});

		if( output ) return output;
	}

	if( JL.webgl.variables.is_editing ){
		var g_o_path = g_o.get_path();
		return ( this.graphics_objects || [] ).find(function( m ){ return ( m.get_path() == g_o_path ); });
	}
	else{
		return ( this.graphics_objects || [] ).find(function( m ){ return ( m == g_o ); });
	}
};

JL.webgl.space_object._regular.prototype.remove_graphics_object = function( p ){
	var p = p || {};

	if     ( p._id   !== undefined ) this.graphics_objects = this.graphics_objects.filter( g => g._id !== p._id );
	else if( p.index !== undefined ) this.graphics_objects.splice( p.index, 1 );
	else                             this.graphics_objects.pop();

	this.change_to_draw();
};

JL.webgl.space_object._regular.prototype.remove_all_graphics_objects = function(){
	this.graphics_objects = [];

	this.change_to_draw();
};

JL.webgl.space_object._regular.prototype.set_graphics_objects = function( graphics_objects ){
	for( var g of graphics_objects ) this.add_graphics_object( g );
};

JL.webgl.space_object._regular.prototype.search_and_replace_graphics_object = function( old_g_o, new_g_o ){
	if( this._inputs ){
		JL.json_edit.prototype.traverse_values({
			value     : this,
			structure : this._inputs,
			on_step   : function( val, structure, step_params ){
				if( structure.type == 'webgl.graphics_object' ){
					if( val ){
						var step_g_o = JL.webgl.functions.get_graphics_object( val );
						if( step_g_o ){
							if( step_g_o._id == old_g_o._id ){
								step_params.set( new_g_o );
							}
						}
					}
				}
			},
		});
	}

	if( this.graphics_objects ){
		var old_g_o_path = old_g_o.get_path();

		this.graphics_objects.forEach(function( m, idx ){
			if( old_g_o_path == m.get_path() ){
				this.replace_graphics_object( new_g_o, idx );
			}
		}, this);
	}
};

JL.webgl.space_object._regular.prototype.replace_graphics_object = function( g_o, idx ){
	this.graphics_objects[ idx || 0 ] = g_o;

	this.init_animated_graphics_object( g_o );

	this.change_to_draw();
};

JL.webgl.space_object._regular.prototype.init_animated_graphics_object = function( g_o ){
	if( this.animated ){
		if( !this.vertex_groups ) this.vertex_groups = [];
		g_o.vertex_group_index = this.vertex_groups.length;
		if( !g_o.vertex_groups ) g_o.vertex_groups = { roots  : [], groups : [], };
		this.vertex_groups.push( g_o.vertex_groups.groups.map(function(){ return { matrix : Matrix.I(4), }; }) );
		if( !this.animations ){
			this.animations = [];
			this.deactivated_animations = [];
		}
		this.select_animation( this.animated );
	}
};

// The 'reference_vertex_groups' are used for adding a space_object as a child of a vertex_group.
JL.webgl.space_object._regular.prototype.derive_reference_vertex_group_indices = function(){
	this.reference_vertex_group_indices = {};
	for( var g_o of this.graphics_objects ){
		if( g_o.vertex_groups ){
			for( var group_idx = 0; group_idx < g_o.vertex_groups.groups.length; group_idx++ ){
				var group = g_o.vertex_groups.groups[ group_idx ];
				if( !this.reference_vertex_group_indices[ group.name ] ){
					this.reference_vertex_group_indices[ group.name ] = [ g_o.vertex_group_index, group_idx ];
				}
			}
		}
	}
};

JL.webgl.space_object._regular.prototype.set_uniforms = function( key, values ){
	this[ key ] = JL.functions.recursive_assign( this[ key ] || {}, values );
};

JL.webgl.space_object._regular.prototype.get_time_uniform = function(){ return ( new Date() ).getTime(); };

JL.webgl.space_object._regular.prototype.pause_time_uniform = function(){
	this._time_uniform = ( new Date() ).getTime();
	this._original_get_time_uniform = this.get_time_uniform;
	this.get_time_uniform = function(){ return this._time_uniform; };
};

JL.webgl.space_object._regular.prototype.resume_time_uniform = function(){
	this.get_time_uniform = this._original_get_time_uniform;
	delete this._time_uniform;
	delete this._original_get_time_uniform;
};

JL.webgl.space_object._regular.prototype.get_camera_config = function(){
        return { lat : 0, lon : 0, rad : this.scale[ 0 ] };
};

JL.webgl.space_object._regular.prototype.get_vr_offset = function(){
	if( this._get_vr_offset ){
		var result = this._get_vr_offset();
		if( result ) return result;
	}

	if( this.camera_config ) return [ -2 * this.camera_config.rad, 0, 0 ];
	return [ 0, 0, 0 ];
};

JL.webgl.space_object._regular.prototype.is = function(){
	for( var i = 0; i < arguments.length; i++ ){
		if( this.type == arguments[i] ) return true;
	}
	if( this.types ){
		for( var i = 0; i < arguments.length; i++ ){
			if( this.types.indexOf( arguments[i] ) != -1 ) return true;
		}
	}
	return false;
};

JL.webgl.space_object._regular.prototype.add_child = function( child, group, p ){
	var category = ( group || 'dependent' ) + "_children";
	child.parent_object = this;
	child.child_group   = group;

	if( child.on_add_to_parent ) child.on_add_to_parent( this );

	var construct_functions = false;

	if( group == 'vertex_group' && p && p.vertex_group ){
		this.derive_reference_vertex_group_indices();

		var indices = this.reference_vertex_group_indices[ p.vertex_group ];

		child._parent_vertex_group = { name : p.vertex_group, indices, };
	}

	[ category, 'all_children' ].forEach(function( k ){
		if( !this[ k ] ){
			this[ k ] = [];
			construct_functions = true;
		}
		this[ k ].push( child );
	}, this);

	if( construct_functions ) this.set_attr({});
};

JL.webgl.space_object._regular.prototype.remove = function( p ){
	var self = this;

	var p = p || {};

	// Added on 2024-05-26
	// 	-For cleaning up children of terrain space_objects in Edit mode.
	for( var child_obj of ( this.all_children || [] ).slice() ){
		child_obj.remove();
	}

	if( this.remove_physics ) this.remove_physics();

	if( this.on_remove ) this.on_remove();

	var parent_object = p.parent_object || this.parent_object || JL.webgl.active_environment._root_object;

	parent_object.remove_child( this, p.child_group || this.child_group );

	JL.webgl.all_space_objects = JL.webgl.all_space_objects.filter( s => s._id !== self._id );

	this.remove_from_draw();

	Object.keys( this ).forEach(function( k ){
		delete this[ k ];
	}, this);
};

JL.webgl.space_object._regular.prototype.remove_child = function( child, group ){
	var keys = [ 'all_children' ];
	if( group ) keys.push( group + '_children' );
	else        keys = Object.keys( this ).filter( x => x.endsWith( '_children' ) );

	if( child._parent_vertex_group ) delete child._parent_vertex_group;

	keys.forEach(function( k ){
		try{
			var idx =      this[ k ].indexOf( child );
			if( idx >= 0 ) this[ k ].splice( idx, 1 );
		} catch(e){}
	}, this);

	var recursive_remove_from_draw = function( c ){
		if( c.all_children ){
			c.all_children.forEach(function( x ){
				recursive_remove_from_draw( x );
			});
		}

		c.remove_from_draw();
	};

	recursive_remove_from_draw( child );
};

JL.webgl.space_object._regular.prototype.remove_all_children = function(){
	[ 'all', 'dependent', 'independent' ].forEach( function( k ){
		var key = k + '_children';
		if( this[ key ] ){
			for( var c of this[ key ] ) this.remove_child( c );
			this[ key ] = [];
		}
	}, this );
};

// For objects (and parent objects) that might not be rendered yet (ex: cable positions for Antarctic weather station).
JL.webgl.space_object._regular.prototype.calculate_absolute_xyz = function(){
	var mat = Matrix.I(4);

	var curr_space_object = this;
	while( curr_space_object ){
		if( curr_space_object.align ){
			JL.webgl.mat.push();
				JL.webgl.mat.model = Matrix.I(4);
				curr_space_object.align( false );
				mat = JL.webgl.mat.model.x( mat );
			JL.webgl.mat.pop();
		}
		curr_space_object = curr_space_object.parent_object;
	}

	return JL.webgl.functions.get_xyz( mat.inverse() );
};

// For objects (and parent objects) that are already rendered.
JL.webgl.space_object._regular.prototype.get_absolute_xyz = function(){
	return JL.webgl.functions.get_xyz( this.matrix.inverse() );
};

JL.webgl.space_object._regular.prototype.align_lat_lon_rad = function(){
        if( this.lon ) JL.webgl.mat.rotate( this.lon, [0,1,0] );
        if( this.lat ) JL.webgl.mat.rotate( this.lat, [0,0,1] );

	// Note : I have no idea why, but the following if/else is needed for wheels/camera to stay in sync with physics.
        if( this.orbit_radius ) JL.webgl.mat.translate([ this.orbit_radius, 0, 0 ]);
        else                    JL.webgl.mat.model = JL.webgl.mat.model.dup();

        if( this.flatten_pitch ) JL.webgl.mat.rotate( -this.lat, [0,0,1] );
        if( this.axial_tilt    ){
                JL.webgl.mat.rotate( -this.lon,        [0,1,0] );
                JL.webgl.mat.rotate(  this.axial_tilt, [0,0,1] );
                JL.webgl.mat.rotate(  this.lon,        [0,1,0] );
        }
};

JL.webgl.space_object._regular.prototype.align_roll_pitch_yaw = function(){
        if( this.pitch ) JL.webgl.mat.rotate( this.pitch, [1,0,0] );
        if( this.roll  ) JL.webgl.mat.rotate( this.roll , [0,0,1] );
	if( this.yaw   ) JL.webgl.mat.rotate( this.yaw  , [0,1,0] );
};

JL.webgl.space_object._regular.prototype.align_orientation = function(){
	if( this.orientation ){
		if( this.orientation[0] ) JL.webgl.mat.rotate( this.orientation[0], [1,0,0] );
                if( this.orientation[1] ) JL.webgl.mat.rotate( this.orientation[1], [0,1,0] );
                if( this.orientation[2] ) JL.webgl.mat.rotate( this.orientation[2], [0,0,1] );
	}
};

JL.webgl.space_object._regular.prototype.add_per_frame_function = function( update_function, function_vals, add_params ){
	if( !this.per_frame_functions ) this.per_frame_functions = [];

	var index = -1;
	if( add_params ){
		if( add_params.index !== undefined ) index = add_params.index;
	}

	var per_frame_function = this.init_per_frame_function( update_function, function_vals );

	if( index == -1 ) this.per_frame_functions.push( per_frame_function );
	else              this.per_frame_functions.splice( index, 0, per_frame_function );
};

JL.webgl.space_object._regular.prototype.remove_per_frame_functions = function( matching_criteria ){
	if( !matching_criteria ){
		delete this.per_frame_functions;
		return;
	}

	if( this.per_frame_functions ){
		var self = this;
		this.per_frame_functions = this.per_frame_functions.filter(function( update_function ){
			return !self.is_per_frame_matching( update_function, matching_criteria );
		});
		if( !this.per_frame_functions.length ) delete this.per_frame_functions;
	}
};

JL.webgl.space_object._regular.prototype.get_per_frame_functions = function( matching_criteria ){
	try{
		var self = this;
		return this.per_frame_functions.filter(function( update_function ){
			return self.is_per_frame_matching( update_function, matching_criteria );
		});
	} catch(e){}
	return [];
};

JL.webgl.space_object._regular.prototype.set_per_frame_function = function( new_function, function_vals ){
	var updated_a_function = false;

	new_function = this.init_per_frame_function( new_function, function_vals );

	for( var i = 0; i < ( this.per_frame_functions || [] ).length; i++){
		if( this.is_per_frame_matching( this.per_frame_functions[ i ], function_vals ) ){
			this.per_frame_functions[ i ] = new_function;
			updated_a_function = true;
		}
	}

	if( !updated_a_function ) this.add_per_frame_function( new_function, function_vals );

};

JL.webgl.space_object._regular.prototype.init_per_frame_function = function( update_function, function_vals ){
	return Object.assign( update_function.bind( this ), function_vals );
};

JL.webgl.space_object._regular.prototype.is_per_frame_matching = function( update_function, matching_criteria ){
	return Object.keys( matching_criteria ).every(function( x ){ return update_function[ x ] == matching_criteria[ x ]; });
};

JL.webgl.space_object._regular.prototype.update_xyz = function(){
	var pos = JL.webgl.functions.get_xyz( this.matrix.inverse() );
	for( var v in pos ) this[v] = pos[v];
};

JL.webgl.space_object._regular.prototype.align_xyz = function(){
	JL.webgl.mat.push();
		this.align( false );
		this.calculate_position_xyz();
	JL.webgl.mat.pop();
};

JL.webgl.space_object._regular.prototype.calculate_position_xyz = function(){
	if( !this.draw_xyz && !this.ignore_xyz ) this.update_xyz();
};

JL.webgl.space_object._regular.prototype.is_parent = function( item ){
	var curr = this;
	while( !( curr.parent_object == '' || curr.parent_object == undefined ) ){
		if( curr == item ) return true;
		curr = curr.parent_object;
	}
	return false;
};

JL.webgl.space_object._regular.prototype.get_environment = function(){
	var curr = this;
	while( curr.parent_object ){
		if( curr.parent_object._environment ) return curr.parent_object._environment;
		curr = curr.parent_object;
	}
	return false;
};

JL.webgl.space_object._regular.prototype.has_same_environment = function( obj ){
	try{
		var this_env = this.get_environment();
		var that_env =  obj.get_environment();
		return ( this_env.keys == that_env.keys ) 
	} catch(e){ return false; }
};

JL.webgl.space_object._regular.prototype.set_name_box = function( p ){
	var p = p || {};

        this.name_box = ( JL.webgl.active_environment || JL.webgl.environment.prototype ).add_space_object({
		parent_object   : this,
		child_type      : p.child_list || "lat_lon_rad",
		text            : this.name,
		is_impostor     : true,
		draw_condition  : p.draw_condition,
		absolute_size   : p.absolute_size,
		text_properties : p.text_properties,
	}, JL.webgl.space_object._text );

	if( p.scale !== undefined ) this.name_box.scale = this.name_box.scale.map( x => p.scale * x );

	[ 'x', 'y', 'z' ].forEach(function( x ){
		if( p[ x ] !== undefined ) this.name_box[ x ] = p[ x ];
	}, this);

	this.name_box.z_index = 2001;

	if( p.global_buttons ) this.global_buttons.push( ...p.global_buttons );
};

JL.webgl.space_object._regular.prototype.throw_projectile = function( p ){
	var accuracy_x = ( p.accuracy_x !== undefined ? p.accuracy_x : p.accuracy ) || 0;
	var accuracy_y = ( p.accuracy_y !== undefined ? p.accuracy_y : p.accuracy ) || 0;
	var accuracy_z = ( p.accuracy_z !== undefined ? p.accuracy_z : p.accuracy ) || 0;

	var pos = this.get_absolute_xyz();

	var obj_params = p.obj_params || {};

	obj_params.x = ( obj_params.x || 0 );
	obj_params.y = ( obj_params.y || 0 );
	obj_params.z = ( obj_params.z || 0 );

	if( p.forward_offset ){
		if( this.matrix ){
			var forward = JL.webgl.functions.get_forward_vector( this.matrix );

			obj_params.x += p.forward_offset * forward[0];
			obj_params.y += p.forward_offset * forward[1];
			obj_params.z -= p.forward_offset * forward[2];
		}
	}

	obj_params.x += pos.x;
	obj_params.y += pos.y;
	obj_params.z += pos.z;

	var projectile = p.projectile || this.environment.add_space_object( obj_params, p.obj_type || JL.webgl.space_object._physics );

	// Need this line, otherwise it appears at the origin for one frame (before the model matrix is updated by the physics engine)
	projectile.calculate_position_from_physics(); 

	projectile.copy_physics_rotation( this );

	projectile.kinematic_rotate([
		( p.spread_x || 0 ) * ( 1 - accuracy_x ) * JL.functions.random_number( -1, 1 ),
		( p.spread_y || 0 ) * ( 1 - accuracy_y ) * JL.functions.random_number( -1, 1 ),
		( p.spread_z || 0 ) * ( 1 - accuracy_z ) * JL.functions.random_number( -1, 1 ),
	]);

	projectile.apply_force( p.force_x || 0, p.force_y || 0, p.force_z || 0 );

	return projectile;
};

JL.webgl.space_object._regular.prototype.select = function( tour_list, p ){
	var p = p || {};

	var tour_list = tour_list || [ this ];

	if( JL.webgl.active_camera.target ){
		if( JL.webgl.active_camera.target.on_deselect  ) JL.webgl.active_camera.target.on_deselect();
		if( JL.webgl.active_camera.target._on_deselect ) JL.webgl.active_camera.target._on_deselect();
	}

	if( this.on_select ) this.on_select();

	var environment = this.get_environment();
	if( environment && !environment.is_active ) environment.select();

	if( this._on_select ) this._on_select( tour_list, p );

	this.set_key_bindings();

	if( p.tour_off_pre ) JL.webgl.active_camera.tour.stop();

	this.ui_onchange();
	this.ui_onselect();

	var index = tour_list.indexOf( this );
	( index != -1 ? JL.webgl.active_camera.set_target(tour_list, {index: index}) : JL.webgl.active_camera.set_target([ this ]) );

	if( JL.webgl.active_camera.tour ){ 
		if( JL.webgl.active_camera.tour.on && this.tour_on ) this.tour_on();
	}

	if( p.tour_off ) JL.webgl.active_camera.tour.stop();

	if( this._custom_on_post_select ) this._custom_on_post_select( tour_list, p );

	if( this.on_post_select ) this.on_post_select();
};

JL.webgl.space_object._regular.prototype.derive_ui_element = function( ui_class ){
	if     ( typeof ui_class === 'string' ||  ui_class instanceof String ) ui_class =    JL.webgl.ui.item[ ui_class ];
	else if( JL.functions.is_array( ui_class ) ) ui_class = JL.functions.get_nested_object( JL.webgl.ui.item, ui_class );
	return ui_class;
};

JL.webgl.space_object._regular.prototype.derive_ui_functions = function(){
	var self = this;

	var html_functions = [ 'ui_framework' ];
	var   js_functions = [ 'ui_onchange', 'ui_onselect', 'ui_onupdate', 'ui_afterchange', 'ui_draw' ];
	var  all_functions = html_functions.concat( js_functions );

	var functions = {};

	this.key_bindings_ui = [];

	this.ui_classes.forEach(function( c ){
		var ui_class = this.derive_ui_element( c );

		if( ui_class.css ){
			JL.functions.add_css( ui_class.css );
			delete ui_class.css;
		}

		if( ui_class.key_bindings ) this.key_bindings_ui = this.key_bindings_ui.concat( ui_class.key_bindings );

		all_functions.forEach(function( x ){
			if( ui_class[ x ] ){
				if( !functions[ x ] ) functions[ x ] = [];
				functions[ x ].push( ui_class[ x ] );
			}
		}, this);
	}, this);

	html_functions.forEach(function( x ){
		if( functions[ x ] ) self[ x ] = function(){ return functions[ x ].map( fn => fn.call( self ) ).join(''); };
		else                 self[ x ] = JL.webgl.space_object._regular.prototype[ x ];
	});

	js_functions.forEach(function( x ){
		if( functions[ x ] ) self[ x ] = function(){ functions[ x ].forEach(function( fn ){ fn.call( self ); }); };
		else                 self[ x ] = JL.webgl.space_object._regular.prototype[ x ];
	});
};

JL.webgl.space_object._regular.prototype.add_ui_elements = function( p ){
	var self = this;

	if( p.clear ) this.ui_classes = [];

	this.ui_classes = ( this.ui_classes || [] ).concat( p.classes );

	if( !p.preserve_order ) this.ui_classes = this.ui_classes.sort( (a,b) => ( a > b ? 1 : -1 ) );

	this.derive_ui_functions();

	if( !p.no_select ){
		this.ui_onchange();
		this.ui_onselect();
	}
};

JL.webgl.space_object._regular.prototype.remove_ui_elements = function( classes ){
	if( !classes ) this.ui_classes = [];
	else{
		this.ui_classes = this.ui_classes.filter(function( c ){
			var c_str = JSON.stringify( c );
			return !classes.find(function( x ){
				return ( JSON.stringify( x ) == c_str );
			});
		});
	}

	this.add_ui_elements({ classes : this.ui_classes, clear : true });

	JL.webgl.active_camera.previous_ui_framework = JL.webgl.active_camera.target.ui_framework();
};

JL.webgl.space_object._regular.prototype.set_ui_elements = function( classes ){
	this.add_ui_elements({
		classes,
		no_select : true,
		clear     : true,
	});
};

JL.webgl.space_object._regular.prototype.ui_framework = function(){ return ''; };
JL.webgl.space_object._regular.prototype.ui_onselect  = function(){};
JL.webgl.space_object._regular.prototype.ui_onupdate  = function(){};
JL.webgl.space_object._regular.prototype.ui_onchange  = function(){
	// ui_framework => Returns the necessary HTML containers (as a string).
	// ui_onchange  => Only put in place if the previous ui_onchange function differs from the current one.
	// ui_onselect  => Always runs when the current object is selected.
	// ui_onupdate  => Always runs every frame.

	var ui_framework = this.ui_framework();

	if( JL.webgl.active_camera.previous_ui_framework == ui_framework ) return;

	$( "#jl-webgl-curr-item-ui" ).html( this.ui_framework() );

	if( this.ui_afterchange ) this.ui_afterchange();
};

JL.webgl.space_object._regular.prototype.set_key_bindings = function(){
	if( JL.webgl.ui.key_bindings ) JL.webgl.ui.key_bindings.set( ( this.key_bindings || [] ).concat( this.key_bindings_ui || [] ) );
};

JL.webgl.space_object._regular.prototype.select_animation = function( input ){
	this.animations = [];
	var add_params = input;
	if( JL.functions.is_str( input ) ) add_params = { name : input };
	this.add_animation( add_params );
};

JL.webgl.space_object._regular.prototype.select_temporary_animation = function( p ){
	var self = this;

	if( JL.functions.is_str( p ) ) p = { name : p };

	if( !p.attr ) p.attr = {};

	if( !p.attr.num_iterations ) p.attr.num_iterations = 1;

	this._prev_animations = ( this.animations || [] ).slice();

	var on_finish_fns = [ function(){
		self.animations = self._prev_animations.slice();

		if( self._prev_animations.length ) self.start_animating();
		else                               self.stop_animating();
	} ];
	if( p.attr.on_finish ) on_finish_fns.push( p.attr.on_finish );

	p.attr.on_finish = JL.functions.concat_functions( on_finish_fns );

	this.select_animation( p );
};

JL.webgl.space_object._regular.prototype.add_animation = function( p ){
	var new_animation;

	if( p instanceof JL.webgl.animation ) new_animation = p;
	else{
		var match = ( p instanceof JL.webgl.animation ? p : 
			JL.webgl.animations.find(function( a ){ return ( a.name == p.name ); })
		);

		if( match ){
			new_animation = new JL.webgl.animation( Object.assign({
				space_object : this,
			}, $.extend( true, {}, match ), p.attr ) );
		}
	}

	if( !new_animation ) return;

	if( !p.init_only ){
		this.animations.push( new_animation );

		for( var g_o of this.graphics_objects ){
			for( var group of g_o.vertex_groups.groups ){
				var anim_group = this.animations[ 0 ].get_group( g_o.vertex_group_index, group.name );
				if( anim_group ){
					var s_o_group = this.vertex_groups[ g_o.vertex_group_index ][ anim_group.index ];

					s_o_group.anim_group = anim_group;
				}
			}
		}
	}

	return new_animation;
};

JL.webgl.space_object._regular.prototype.remove_animation = function( ids ){
	this.animations = this.animations.filter(function( a ){
		return !( Object.keys( ids ).every( k => a[ k ] === ids[ k ] ) );
	});
	if( !this.animations.length ) this.stop_animating();
};

