JL.webgl.space_object._person.get_camera_config = function( name ){
	var lon      = 0;
	var rad      = 1;
	var offset_y = 0.7;
	if(
		[ 'eye', ].find(function( s ){ return name.startsWith( s ); })
	){
		rad      = 0.1;
		offset_y = 0.93;
	}
	else if(
		[ 'gut', ].find(function( s ){ return name.startsWith( s ); })
	){
		lon = -90;
		rad = 0.6;
	}
	else if(
		[ 'foot', ].find(function( s ){ return name.startsWith( s ); })
	){
		rad      = 0.25;
		offset_y = 0.05;
	}
	else if(
		[ 'hair', ].includes( name ) ||
		[ 'chin', 'cheek', 'jaw', 'mouth', 'nose' ].find(function( s ){ return name.startsWith( s ); })
	){
		if(
			[ 'chin_depth', 'nose_middle_height', 'nose_tip_depth', 'nose_tip_y', ].includes( name )
		){
			lon = -90;
		}

		rad      = 0.25;
		offset_y = 0.9;
	}
	return { lat : 0, lon, rad, offset : [ 0, offset_y, 0 ] };
};

[ 'parts', 'shape' ].forEach(function( group ){
	JL.webgl.space_object._person.prototype._inputs.find( x => x.key == group ).structure.forEach(function( input ){
		var webgl_camera = JL.webgl.space_object._person.get_camera_config( input.key );
		JL.json_edit.prototype.traverse_structure({
			structure : [ input ],
			on_step   : function( _input, p ){
				p.assign({ webgl_camera });
			},
		} );
	});
});

// -- Begin config -- //

JL.webgl.space_object._person.dist_factor = function( curr_point, center_point, max_dist ){
	[ 'x', 'y', 'z' ].forEach(function( x ){
		if( curr_point[   x ] === undefined ) curr_point[   x ] = 0;
		if( center_point[ x ] === undefined ) center_point[ x ] = 0;
	});
	return Math.max( 0.0, Math.min( ( 1.0 - JL.functions.distance( curr_point, center_point ) / max_dist ), 1.0 ) );
};

JL.webgl.space_object._person.bulge = function( p ){
	var idx = p[ p.axis + '_idx' ];

	p.m.v[ idx ] = p.m.curr_v[ idx ] + p.val * Math.pow( JL.webgl.space_object._person.dist_factor( p.pt, p.center, p.radius ), 0.25 );
};

JL.webgl.space_object._person.stretch = function( p ){
	var idx   = p[ p.axis + '_idx' ];
	var x     = p.m.curr_v[ idx ];
	var end_1 = p.end_1;
	var end_2 = p.end_2;
	if( p.end_1[ p.axis ] > p.end_2[ p.axis ] ){
		end_1 = p.end_2;
		end_2 = p.end_1;
	}

	var middle   = p.middle   || (           p.end_2[ p.axis ] + p.end_1[ p.axis ] ) / 2;
	var max_dist = p.max_dist || ( Math.abs( p.end_2[ p.axis ] - p.end_1[ p.axis ] ) / 2 );

	if( x > middle ) p.m.v[ idx ] = x + p.val *  JL.webgl.space_object._person.dist_factor( p.pt, end_2, max_dist );
	else             p.m.v[ idx ] = x + p.val * -JL.webgl.space_object._person.dist_factor( p.pt, end_1, max_dist );
};

JL.webgl.space_object._person.scale = function( p ){
	var center = Object.assign( { x : 0, y : 0, z : 0 }, ( p.center || {} ) );
	if( p.x_idx !== undefined ) p.m.v[ p.x_idx ] = ( p.m.curr_v[ p.x_idx ] - center.x ) * p.val + center.x;
	if( p.y_idx !== undefined ) p.m.v[ p.y_idx ] = ( p.m.curr_v[ p.y_idx ] - center.y ) * p.val + center.y;
	if( p.z_idx !== undefined ) p.m.v[ p.z_idx ] = ( p.m.curr_v[ p.z_idx ] - center.z ) * p.val + center.z;
};

JL.webgl.space_object._person.widen = function( p ){
	var center   = Object.assign( { x : 0, y : 0, z : 0 }, ( p.center || {} ) );
	var max_dist = p.max_dist || 0.01;
	var original = p.m.curr_v;
	if( p.x_idx !== undefined ) p.m.v[ p.x_idx ] = original[ p.x_idx ] + p.val * Math.sign( original[ p.x_idx ] ) * ( 1.0 - JL.webgl.space_object._person.dist_factor( { x : original[ p.x_idx ] }, center, max_dist ) );
	if( p.y_idx !== undefined ) p.m.v[ p.y_idx ] = original[ p.y_idx ] + p.val * Math.sign( original[ p.y_idx ] ) * ( 1.0 - JL.webgl.space_object._person.dist_factor( { y : original[ p.y_idx ] }, center, max_dist ) );
	if( p.z_idx !== undefined ) p.m.v[ p.z_idx ] = original[ p.z_idx ] + p.val * Math.sign( original[ p.z_idx ] ) * ( 1.0 - JL.webgl.space_object._person.dist_factor( { z : original[ p.z_idx ] }, center, max_dist ) );
};

