// -- End config -- //

JL.webgl.space_object._person.prototype.__on_init = function( p ){
	var self = this;

	// 2024-11-15
	// this.ignore_xyz = true;
	// this.draw_xyz   = true;

	this.environment = p.environment || JL.webgl.active_environment;

	if( p.size !== undefined ) this.scale = [ p.size, p.size, p.size ];

	this.traits = p.traits || {};

	if( this.parts.accessories ){
		for( var i = 0; i < this.parts.accessories.length; i++ ){
			var key = 'accessory_' + ( i + 1 );
			var cfg = this.parts.accessories[ i ];
			this.parts[ key ] = cfg;
			if( cfg.graphics_object ) this.parts[ key ].graphics_object = JL.webgl.functions.get_graphics_object( cfg.graphics_object );
		}
		delete this.parts.accessories;
	}

	this.parts_names = Object.keys( this.parts ).filter( k => k != 'accessories' );

	for( var key of this.parts_names ){
		if( !this.parts[ key ] ) this.parts[ key ] = {};
	}

	if( this.random ){
		if( this.random.color_hair ){
			if( this.parts.hair ){
				if     ( this.random.color_hair == 'natural' ) this.parts[ 'hair' ].color = this.get_random_color_hair();
				else if( this.random.color_hair == 'any'     ) this.parts[ 'hair' ].color = [ Math.random(), Math.random(), Math.random(), 0 ];
			}
		}
		if( this.random.color_lips ){
			if     ( this.random.color_lips == 'natural' ) this.parts[ 'body' ].color_lips = this.get_random_color_lips();
			else if( this.random.color_lips == 'any'     ) this.parts[ 'body' ].color_lips = [ Math.random(), Math.random(), Math.random() ];
		}
		if( this.random.color_skin ){
			if     ( this.random.color_skin == 'natural' ) this.parts[ 'body' ].color_skin = this.get_random_color_skin();
			else if( this.random.color_skin == 'any'     ) this.parts[ 'body' ].color_skin = [ Math.random(), Math.random(), Math.random() ];
		}
	}

	for( var key of this.parts_names ){
		var part = this.parts[ key ];

		if( !this.parts[ key ].graphics_object ){
			if( part.graphics_object ) this.parts[ key ].graphics_object = JL.webgl.functions.get_graphics_object( part.graphics_object );
		}

		if( part.graphics_object && !part.shared_graphics_object ) this.parts[ key ].graphics_object = part.graphics_object.copy();

		var graphics_object_properties = JL.functions.deep_copy( part.properties || {} );

		if( part.color      ) JL.functions.recursive_assign( graphics_object_properties, { frags_vec4 : { color_add  : part.color      } } );
		if( part.color_skin ) JL.functions.recursive_assign( graphics_object_properties, { frags_vec3 : { color_skin : part.color_skin } } );
		if( part.color_lips ) JL.functions.recursive_assign( graphics_object_properties, { frags_vec3 : { color_lips : part.color_lips } } );

		if( part.texture ) this.parts[ key ].graphics_object.set_texture( part.texture );
		else{
			if( key == 'body' ) this.parts[ key ].graphics_object.add_effects({ effects : [ '_no_texture_main' ] });
		}

		if( part.bumpmap ){
			this.parts[ key ].graphics_object.set_texture( part.bumpmap, { type : 'bumpmap' } );
			this.parts[ key ].graphics_object.add_effects({ effects : [ '_bumpmap' ] });
		}

		if( part.bumpmap_mag ){
			this.parts[ key ].graphics_object.add_effects({ effects : [ '_bumpmap_mag' ] });
			JL.functions.recursive_assign( graphics_object_properties, { frags_float : { bumpmap_mag : part.bumpmap_mag } } );
		}

		for( var i = 1; i <= 2; i++ ){
			var texture_name = 'overlay_' + JL.functions.pad( i, 2 );
			var texture_key  = 'texture_' + texture_name;
			if( part[ texture_key ] ){
				this.parts[ key ].graphics_object.set_texture( part[ texture_key ], { type : texture_name } );
				this.parts[ key ].graphics_object.add_effects({ effects : [ '_' + texture_key ] });
			}
		}

		Object.assign( this.parts[ key ].graphics_object, graphics_object_properties );

		if( this.parts[ key ].graphics_object.v ){
			if( !this.parts[ key ].graphics_object.original_v ){
				this.parts[ key ].graphics_object.original_v = this.parts[ key ].graphics_object.v.slice();
			}
		}
	}

	this.animated = this.animated || 'freeze';
	this.camera_config = { lat : 20, lon : 180, rad : 10, offset : [ 0, 0.9 * ( this.size || 1 ), 0 ] };
	if( p.camera_config ) Object.assign( this.camera_config, p.camera_config );
	this.add_graphics_object( this.parts.body.graphics_object );

	this.reshape_config = $.extend( [], true, JL.webgl.space_object._person.default_reshape_config );

	if( this.shape ){
		Object.keys( this.shape ).forEach(function( shape_name ){
			this.set_reshape_val( shape_name, this.shape[ shape_name ] );
		}, this);
		this.reshape_update();
	}

	for( var key of this.parts_names ){
		var graphics_object = this.parts[ key ].graphics_object;
		if( graphics_object ){
			if( key !== 'body' ) this.add_graphics_object( graphics_object );
			if( graphics_object.v ) graphics_object.create_buffers();
		}
	}

	this.select_animation( this.animated );
};

JL.webgl.space_object._person.prototype.get_random_color_hair = function( a ){
	var a     = ( a === undefined ? Math.random() : a );
	var group =                     Math.random();

	if     ( group < 0.35 ){ // Brown
		return [
			JL.functions.interpolate( 90, 35, a ) / 255,
			JL.functions.interpolate( 56, 18, a ) / 255,
			JL.functions.interpolate( 37, 11, a ) / 255,
			0
		];
	}
	else if( group < 0.7 ){ // Black
		return [
			JL.functions.interpolate( 40, 0, a ) / 255,
			JL.functions.interpolate( 40, 0, a ) / 255,
			JL.functions.interpolate( 40, 0, a ) / 255,
			0
		];
	}
	else if( group < 0.9 ){ // Blonde
		return [
			JL.functions.interpolate( 251, 179, a ) / 255,
			JL.functions.interpolate( 231, 139, a ) / 255,
			JL.functions.interpolate( 161, 103, a ) / 255,
			0
		];
	}
	else if( group < 0.96 ){ // Gray
		return [
			JL.functions.interpolate( 180, 130, a ) / 255,
			JL.functions.interpolate( 180, 130, a ) / 255,
			JL.functions.interpolate( 180, 130, a ) / 255,
			0
		];
	}
	else if( group < 0.995 ){ // Red
		return [
			JL.functions.interpolate( 124, 93, a ) / 255,
			JL.functions.interpolate(  10, 25, a ) / 255,
			JL.functions.interpolate(   2, 22, a ) / 255,
			0
		];
	}

	// Any color

	return [
		Math.random(),
		Math.random(),
		Math.random(),
		0
	];
};

JL.webgl.space_object._person.prototype.get_random_color_lips = function( a ){
	var a = ( a === undefined ? Math.random() : a );

	return [
		JL.functions.interpolate( 207, 174, a ) / 255,
		JL.functions.interpolate( 110, 103, a ) / 255,
		JL.functions.interpolate( 112,  77, a ) / 255,
	];
};

JL.webgl.space_object._person.prototype.get_random_color_skin = function( a ){
	var a = ( a === undefined ? Math.random() : a );

	var r = JL.functions.random_number( 0.05, 0.3  );
	var y = JL.functions.random_number( 0   , 0.15 ) * ( r / 0.3 );

	return [
		Math.max( r, y ) + JL.functions.interpolate( 250, 72, a ) / 255,
		               y + JL.functions.interpolate( 231, 55, a ) / 255,
		                   JL.functions.interpolate( 208, 40, a ) / 255,
	];
};

JL.webgl.space_object._person.prototype.get_reshape_config = function( name ){
	return this.reshape_config.find(function( g ){
		return ( g.name == name );
	});
};

JL.webgl.space_object._person.prototype.set_reshape_val = function( type, val ){
	var cfg = this.get_reshape_config( type );

	if( !cfg ){
		console.log( 'Error : could not find "' + type + '" in reshape_config.' );
		return;
	}

	cfg.value = val;
};

JL.webgl.space_object._person.prototype.on_kinematic_walk = function(){
	try{ this.animation_parameters.walk_mag = Math.sqrt( Math.abs( this.kinematic_walk_mag ) / 0.125 ); }
	catch(e){}
};

JL.webgl.space_object._person.prototype.reshape_update = function(){
	this.parts_names.forEach(function( part_name ){
		var graphics_object = this.parts[ part_name ].graphics_object;
		if( graphics_object.v ){
			graphics_object.v      = graphics_object.original_v.slice();
			graphics_object.curr_v = graphics_object.original_v.slice();
		}
	}, this);

	this.reshape_config.forEach(function( cfg ){
		this.parts_names.forEach(function( part_name ){
			var graphics_object = this.parts[ part_name ].graphics_object;

			if( graphics_object.v ){
				for( var i = 0; i < graphics_object.v.length; i+=3 ){
					var x_idx = ( i     );
					var y_idx = ( i + 1 );
					var z_idx = ( i + 2 );

					var curr_x = graphics_object.curr_v[ x_idx ];
					var curr_y = graphics_object.curr_v[ y_idx ];
					var curr_z = graphics_object.curr_v[ z_idx ];

					var original_x = graphics_object.original_v[ x_idx ];
					var original_y = graphics_object.original_v[ y_idx ];
					var original_z = graphics_object.original_v[ z_idx ];

					if( cfg.match( part_name, original_x, original_y, original_z ) ){
						cfg.change( cfg.value, graphics_object, part_name, curr_x, curr_y, curr_z, x_idx, y_idx, z_idx );
					}
				}

				graphics_object.curr_v = graphics_object.v.slice();
			}
		}, this);
	}, this);
};

JL.webgl.space_object._path = JL.functions.inherit_class( function(){}, JL.webgl.space_object._physics, {
	_inputs_exclude : [ 'graphics_objects' ].map( key => ({ key }) ),
	_inputs         : [
		{ key : 'path_type', type : 'dropdown', options : [ 'pipe', 'wall', 'road' ], optional : true, ui_order : '1_0', },

		...JL.webgl.space_object._wall.prototype.get_inputs({ fields : [ 'no_physics', ] }),

		{ key : 'segment_graphics_object', type : 'webgl.graphics_object', optional : true },
		{ key : 'segment_size'           , type : 'float'                , optional : true },
		{ key : 'max_segments'           , type : 'int', default : 1000 },
		{ key : 'flat_shading_angle'     , type : 'float'                , default : 40 },

		{ key : 'capped'    , type : 'bool', custom_init : function( p ){ p.structure.hidden = ![ 'pipe', undefined ].includes( p.json_edit.get_value([ 'path_type' ]) ); }, },
		{ key : 'flip_cap_s', type : 'bool', custom_init : function( p ){ p.structure.hidden = ![ 'pipe', undefined ].includes( p.json_edit.get_value([ 'path_type' ]) ); }, },
		{ key : 'flip_cap_e', type : 'bool', custom_init : function( p ){ p.structure.hidden = ![ 'pipe', undefined ].includes( p.json_edit.get_value([ 'path_type' ]) ); }, },

		{ key : 'road_params', type : 'obj', optional : true, 
			custom_init : function( p ){ p.structure.hidden = ( 'road' != p.json_edit.get_value([ 'path_type' ]) ); },
			structure : [
				{ key : 'width', type : 'float', default : 1, },
				{ key : 'depth', type : 'float', optional : true, },
				{ key : 'repeating', type : 'obj', optional : true, structure : [
					...JL.webgl.graphics_object.road.prototype.get_inputs({ fields : [ 'vt_style', 'vt_scale', ] }),
					{ key : 'graphics_object', no_label : 1, type : 'webgl.graphics_object', get_default : function( p ){ return JL.webgl.space_object._path.create_graphics_object(); }, }
				] },
			]
		},
		Object.assign( JL.webgl.graphics_object.road.prototype.get_inputs({ fields : [ 'points', ] })[ 0 ], {
			custom_init : function( p ){ // Recursive structure for branches of points.
				var branches_input = JL.functions.deep_copy( p.structure );
				delete branches_input.custom_init;
				delete branches_input.get_default;
				delete branches_input.structure;
				branches_input.key           = 'branches';
				branches_input.optional      = true;
				branches_input.get_structure = function( _p ){ return JL.functions.deep_copy( p.structure.structure, [] ); };
				p.structure.structure.push( branches_input );
				delete p.structure.custom_init;
			},
		}),
		...[ 'left', 'right' ].map(function( side ){
			return { key : side + '_wall', type : 'obj', optional : true, structure : [
				{ key : 'segment_graphics_object', type : 'webgl.graphics_object', },
				{ key : 'segment_size'           , type : 'float'   , optional : true },
				{ key : 'radius'                 , type : 'float'   , optional : true },
				{ key : 'depth'                  , type : 'float'   , optional : true, },
				{ key : 'height'                 , type : 'float'   , optional : true, },
				{ key : 'flat_shading_angle'     , type : 'float'   , default : 40 },
			] };
		}),

		{ key : 'followers', type : 'arr', optional : true, 
			structure : [
				{ key : 'space_object', type : 'webgl.space_object', default : 1, },
				// TODO : Might want to add a "type" field eventually.
				// 	-People walking along a path might behave differently than a cart on a roller coaster track.
				// TODO : Might want to add fields for determining the object's speed with respect to points along the path.
				// 	-Ex: roller coaster might go faster / slower at different parts.
				// 	-Some values might make more sense attached to the individual points.
			]
		},
	]
} );

JL.webgl.space_object._path.create_graphics_object = function(){
	var base_label = JL.webgl.functions.get_derived_graphics_objects_label().concat([ '_path', ]);

	var label;
	var idx = 1;
	while( JL.webgl.functions.get_graphics_object( label = base_label.concat([ idx ]) ) ) idx++;

	return JL.webgl.functions.create_graphics_object({ type : 'road', label, });
};

JL.webgl.space_object._path.prototype.on_physics_init = function( p ){
	var self = this;

	this.draw_xyz   = true;
	this.ignore_xyz = true;

	var road_params = p.road_params || {};

	if( p.segment_graphics_object ) this.add_graphics_objects( this.construct_graphics_object( p ) );
	else if( road_params.repeating ){
		var cfg = road_params.repeating || {};

		try       { var g_o_cfg = cfg.graphics_object._config || {}; }
		catch( e ){ var g_o_cfg = {}; }

		if( !this.no_physics ) p.points = this.derive_points_metadata_and_return_transformed_points( p );

		var points = JL.functions.deep_copy( p.points, [] );
		for( var pt of points ){
			if( pt.args ){
				if( pt.args.scl_x !== undefined ) pt.args.scl_x *= road_params.width;
			}
			// if( pt.scl_x !== undefined ) pt.scl_x *= road_params.width;
		}

		var cfg_from_s_o = {
			points,
			width    : road_params.width,
			vt_style : cfg.vt_style,
			vt_scale : cfg.vt_scale,
		};
		cfg_from_s_o._paths_to_exclude_from_save = Object.keys( cfg_from_s_o ).map( k => ([ k ]) );

		var g_o = new JL.webgl.graphics_object.road( Object.assign( JL.functions.deep_copy( g_o_cfg ), cfg_from_s_o ) );

		this.add_graphics_object( g_o );
	}
	else{
		if( !this.no_physics ) p.points = this.derive_points_metadata_and_return_transformed_points( p );
	}

	for( var w of [
		{ side : 'left' , dir : -1, transforms : [                                 { type : 'rotate', val : -90, axis : 'y', }], },
		{ side : 'right', dir :  1, transforms : [{ type : 'translate', x : -1, }, { type : 'rotate', val :  90, axis : 'y', }], },
	] ){
		var key = w.side + '_wall';
		if( p[ key ] ){
			if( !this._walls ) this._walls = {};

			this._walls[ w.side ] = { path_type : 'wall', };

			var wall_cfg = p[ key ];

			var wall_radius = undefined;
			if( road_params.repeating ) wall_radius = road_params.width / 2;
			if( wall_radius === undefined                                    ) wall_radius = wall_cfg.radius;
			if( wall_radius === undefined && road_params.width !== undefined ) wall_radius = ( p.segment_size || 1 ) * road_params.width / 2;
			if( wall_radius === undefined                                    ) wall_radius = 0.5;

			if( wall_cfg.segment_graphics_object ){
				var args = JL.functions.deep_copy( wall_cfg );

				Object.assign( this._walls[ w.side ], args );

				args.self   = this._walls[ w.side ];
				args.points = JL.functions.deep_copy( p.points, [] );
				args.offset = { right : w.dir * wall_radius };

				for( var pt of args.points ){
					if( pt.args ){
						delete pt.args.graphics_object;
					}
				}

				var segment_g_o = JL.webgl.functions.get_graphics_object( wall_cfg.segment_graphics_object ).copy();
				segment_g_o.apply_transforms( w.transforms );

				args.segment_graphics_object = segment_g_o;

				for( var k of [ 'derive_points_metadata_and_return_transformed_points' ] ) this._walls[ w.side ][ k ] = this[ k ];
				this.add_graphics_objects( this._walls[ w.side ].graphics_object = this.construct_graphics_object( args ) );

				this._walls[ w.side ].points = args.points;
			}
		}
	}
	if( wall_radius === undefined ) wall_radius = 0.5;

	this.camera_config = { lat : 0, lon : -90, rad : 10 };
	if( p.attr ) Object.assign( this, p.attr );

	if( !this.no_physics ){
		if( !p.collider ) p.collider = {};

		if( p.collider.motion           === undefined ) p.collider.motion           = 'static';
		if( p.collider.friction         === undefined ) p.collider.friction         = 0;
		if( p.collider.rolling_friction === undefined ) p.collider.rolling_friction = 0;
		if( p.collider.shapes           === undefined ) p.collider.shapes           = [];
		if( p.collider.collision_filter === undefined ) p.collider.collision_filter = JL.webgl.active_environment.collision_filters.still;

		if( !p.collider.shapes.length ){
			p.collider.shapes = p.collider.shapes.concat( this.get_collider_shapes( p ) );

			if( this._walls ){
				for( var w of Object.values( this._walls ) ){
					p.collider.shapes = p.collider.shapes.concat( this.get_collider_shapes( w ) );
				}
			}
		}
	}
};

JL.webgl.space_object._path.prototype.add_follower = function( follower ){
};

JL.webgl.space_object._path.prototype.add_followers = function( followers ){
};

JL.webgl.space_object._path.prototype.get_collider_shapes = function( p ){
	var p = p || {};

	var output = [];

	var points          = ( p.points          || this.points          );
	var points_metadata = ( p.points_metadata || this.points_metadata );

	switch( p.path_type || this.path_type ){
		case 'road':
			var road_params = ( p.road_params || this.road_params || {} );
			var road_depth  = road_params.depth || 0.05;
			var road_width  = ( ( p.segment_size || 1 ) * ( road_params.width || 1 ) ) / 2;

			var curr_scl_x = 1;

			for( var i = 0; i < points.length; i++ ){
				var pt       = points[ i ];
				var metadata = points_metadata[ i ];

				if( pt.args ){
					if( pt.args.scl_x !== undefined ) curr_scl_x = pt.args.scl_x;
				}

				var right = JL.functions.scalar_multiply( road_width * curr_scl_x, metadata.right.slice() );
				var up    = JL.functions.scalar_multiply( road_depth             , metadata.up.slice() );

				pt.u_left = {
					x : -right[0] + pt.x,
					y : -right[1] + pt.y,
					z : -right[2] + pt.z,
				};

				pt.u_right = {
					x :  right[0] + pt.x,
					y :  right[1] + pt.y,
					z :  right[2] + pt.z,
				};

				pt.l_left = {
					x : -right[0] - up[0] + pt.x,
					y : -right[1] - up[1] + pt.y,
					z : -right[2] - up[2] + pt.z,
				};

				pt.l_right = {
					x :  right[0] - up[0] + pt.x,
					y :  right[1] - up[1] + pt.y,
					z :  right[2] - up[2] + pt.z,
				};
			}

			for( var i = 0; i < points.length - 1; i++ ){
				var curr = points[ i     ];
				var next = points[ i + 1 ];

				output.push({ type : 'convex_hull', points : [
					[ curr.l_left.x , curr.l_left.y , curr.l_left.z  ],
					[ curr.l_right.x, curr.l_right.y, curr.l_right.z ],
					[ curr.u_left.x , curr.u_left.y , curr.u_left.z  ],
					[ curr.u_right.x, curr.u_right.y, curr.u_right.z ],
					[ next.l_left.x , next.l_left.y , next.l_left.z  ],
					[ next.l_right.x, next.l_right.y, next.l_right.z ],
					[ next.u_left.x , next.u_left.y , next.u_left.z  ],
					[ next.u_right.x, next.u_right.y, next.u_right.z ],
				] });
			}
			break;
		case 'wall':
			var wall_depth  = p.depth  || 0.05;
			var wall_height = p.height || 1;

			for( var i = 0; i < points.length; i++ ){
				var pt       = points[ i ];
				var metadata = points_metadata[ i ];

				var right = JL.functions.scalar_multiply( wall_depth , metadata.right.slice() );
				var up    = JL.functions.scalar_multiply( wall_height, metadata.up.slice() );

				pt.u_left = {
					x : -right[0] + pt.x,
					y : -right[1] + pt.y,
					z : -right[2] + pt.z,
				};

				pt.u_right = {
					x :  right[0] + pt.x,
					y :  right[1] + pt.y,
					z :  right[2] + pt.z,
				};

				pt.l_left = {
					x : -right[0] + up[0] + pt.x,
					y : -right[1] + up[1] + pt.y,
					z : -right[2] + up[2] + pt.z,
				};

				pt.l_right = {
					x :  right[0] + up[0] + pt.x,
					y :  right[1] + up[1] + pt.y,
					z :  right[2] + up[2] + pt.z,
				};
			}

			for( var i = 0; i < points.length - 1; i++ ){
				var curr = points[ i     ];
				var next = points[ i + 1 ];

				output.push({ type : 'convex_hull', points : [
					[ curr.l_left.x , curr.l_left.y , curr.l_left.z  ],
					[ curr.l_right.x, curr.l_right.y, curr.l_right.z ],
					[ curr.u_left.x , curr.u_left.y , curr.u_left.z  ],
					[ curr.u_right.x, curr.u_right.y, curr.u_right.z ],
					[ next.l_left.x , next.l_left.y , next.l_left.z  ],
					[ next.l_right.x, next.l_right.y, next.l_right.z ],
					[ next.u_left.x , next.u_left.y , next.u_left.z  ],
					[ next.u_right.x, next.u_right.y, next.u_right.z ],
				] });
			}

			break;
		default:  // pipe
			var pipe_slices = 12;

			var slice_angle = 2 * Math.PI / pipe_slices;

			var pipe_rad_x = 1;
			var pipe_rad_y = 1;

			for( var i = 0; i < points.length; i++ ){
				var pt       = points[ i ];
				var metadata = points_metadata[ i ];

				if( metadata.scl_x !== undefined ) pipe_rad_x = metadata.scl_x / 2;
				if( metadata.scl_y !== undefined ) pipe_rad_y = metadata.scl_y / 2;

				var right = JL.functions.scalar_multiply( pipe_rad_x, metadata.right.slice() );
				var up    = JL.functions.scalar_multiply( pipe_rad_y, metadata.up.slice() );

				pt.verts = [];

				for( var slice_i = 0; slice_i < pipe_slices; slice_i++ ){
					var curr_angle = slice_angle * slice_i;

					var cos_angle = Math.cos( curr_angle );
					var sin_angle = Math.sin( curr_angle );

					pt.verts.push([
						( cos_angle * right[0] ) + ( sin_angle * up[0] ) + pt.x,
						( cos_angle * right[1] ) + ( sin_angle * up[1] ) + pt.y,
						( cos_angle * right[2] ) + ( sin_angle * up[2] ) + pt.z,
					]);
				}
			}

			for( var i = 0; i < points.length - 1; i++ ){
				var curr = points[ i     ];
				var next = points[ i + 1 ];

				for( var s_i = 0; s_i < curr.verts.length; s_i++ ){
					var s_i_1 = ( s_i + 1 ) % curr.verts.length;
					output.push({ type : 'convex_hull', points : [
						[ curr.verts[ s_i   ][0], curr.verts[ s_i   ][1], curr.verts[ s_i   ][2], ],
						[ curr.verts[ s_i_1 ][0], curr.verts[ s_i_1 ][1], curr.verts[ s_i_1 ][2], ],
						[ next.verts[ s_i   ][0], next.verts[ s_i   ][1], next.verts[ s_i   ][2], ],
						[ next.verts[ s_i_1 ][0], next.verts[ s_i_1 ][1], next.verts[ s_i_1 ][2], ],
					] });
				}
			}

			break;
	}

	return output;
};

JL.webgl.space_object._path.prototype.derive_points_metadata_and_return_transformed_points = function( p ){
	if( !this.points_metadata ){
		var scl_x              = 1;
		var scl_y              = 1;
		var up                 = [ 0, 1, 0 ];
		this.points_metadata  = [];
		var transformed_points = new Array( p.points.length );
		for( var pt_idx = 0; pt_idx < p.points.length; pt_idx++ ){
			var prev_pt = p.points[ pt_idx - 1 ];
			var curr_pt = p.points[ pt_idx     ];
			var next_pt = p.points[ pt_idx + 1 ];

			var look_at = JL.webgl.mat.get_look_at({
				view_pos        : ( prev_pt ? [ prev_pt.x, prev_pt.y, prev_pt.z ] : [ curr_pt.x, curr_pt.y, curr_pt.z ] ),
				target_pos      : ( next_pt ? [ next_pt.x, next_pt.y, next_pt.z ] : [ curr_pt.x, curr_pt.y, curr_pt.z ] ),
				use_view_matrix : true,
				up : [
					Math.round( up[ 0 ] ),
					Math.round( up[ 1 ] ),
					Math.round( up[ 2 ] ),
				],
			});

			up          = JL.webgl.functions.get_up_vector(      look_at );
			var right   = JL.webgl.functions.get_right_vector(   look_at );
			var forward = JL.webgl.functions.get_forward_vector( look_at );

			if( curr_pt.args ){
				if( curr_pt.args.scl_x !== undefined ) scl_x = curr_pt.args.scl_x;
				if( curr_pt.args.scl_y !== undefined ) scl_y = curr_pt.args.scl_y;
			}

			var curr_dir = { up, right, forward, scl_x, scl_y, };

			if( p.offset ){
				curr_pt = JL.functions.deep_copy( curr_pt );

				if( p.offset.right ){
					curr_pt.x += scl_x * p.offset.right * right[ 0 ];
					curr_pt.y += scl_x * p.offset.right * right[ 1 ];
					curr_pt.z += scl_x * p.offset.right * right[ 2 ];
				} 
				curr_dir.scl_x = 1;
				curr_dir.scl_y = 1;
			}

			transformed_points[ pt_idx ] = curr_pt;

			this.points_metadata.push( curr_dir );
		}
		return transformed_points;
	}
	return p.points;
};

JL.webgl.space_object._path.prototype.construct_graphics_object = function( p ){
	var _this = p.self || this;

	var output = [];
	var curr_output_g_o;

	var curr_segment_size = p.segment_size;

	var segment_g_o = JL.webgl.functions.get_graphics_object( p.segment_graphics_object ).copy();
	segment_g_o.reload_attrs_from_buffers();
	if( curr_segment_size !== undefined ){
		for( var i = 0; i < segment_g_o.v.length; i++ ) segment_g_o.v[ i ] *= curr_segment_size;
	}

	var segment_count = 0;

	var cap_s_vertex_indices_offset = 0;
	var edge_vertex_indices_s;
	var edge_vertex_indices_e;
	if( p.capped ){
		var mesh = segment_g_o;

		var edge_vertex_indices = JL.functions.filter_duplicates( mesh.vertex_indices.filter(function( x ){
			return ( JL.functions.num_matches_in_array( mesh.vertex_indices, x ) < 5 );
		}) );

		var tmp_indices = {};
		var min_z =  10;
		var max_z = -10;
		edge_vertex_indices.forEach(function( idx ){
			if( !tmp_indices[ idx ] ){
				var z = mesh.v[ 3 * idx + 2 ];
				if( z < min_z ) min_z = z;
				if( z > max_z ) max_z = z;
				tmp_indices[ idx ] = { neighbors : [], idx, z, };
			}
		});
		for( var i = 0; i < mesh.vertex_indices.length; i+=3 ){
			var idx_0 = mesh.vertex_indices[ i     ];
			var idx_1 = mesh.vertex_indices[ i + 1 ];
			var idx_2 = mesh.vertex_indices[ i + 2 ];
			if( tmp_indices[ idx_0 ] ){
				if( tmp_indices[ idx_1 ] && !tmp_indices[ idx_0 ].neighbors.includes( idx_1 ) ) tmp_indices[ idx_0 ].neighbors.push( idx_1 );
				if( tmp_indices[ idx_2 ] && !tmp_indices[ idx_0 ].neighbors.includes( idx_2 ) ) tmp_indices[ idx_0 ].neighbors.push( idx_2 );
			}
			if( tmp_indices[ idx_1 ] ){
				if( tmp_indices[ idx_0 ] && !tmp_indices[ idx_1 ].neighbors.includes( idx_0 ) ) tmp_indices[ idx_1 ].neighbors.push( idx_0 );
				if( tmp_indices[ idx_2 ] && !tmp_indices[ idx_1 ].neighbors.includes( idx_2 ) ) tmp_indices[ idx_1 ].neighbors.push( idx_2 );
			}
			if( tmp_indices[ idx_2 ] ){
				if( tmp_indices[ idx_1 ] && !tmp_indices[ idx_2 ].neighbors.includes( idx_1 ) ) tmp_indices[ idx_2 ].neighbors.push( idx_1 );
				if( tmp_indices[ idx_0 ] && !tmp_indices[ idx_2 ].neighbors.includes( idx_0 ) ) tmp_indices[ idx_2 ].neighbors.push( idx_0 );
			}
		}

		var s_indices = Object.values( tmp_indices ).filter(function( x ){ return ( x.z <= min_z ); });
		var e_indices = Object.values( tmp_indices ).filter(function( x ){ return ( x.z >= max_z ); });

		var curr_index_s = s_indices.sort( (a,b) => ( a.neighbors.length > b.neighbors.length ? 1 : -1 ) )[ 0 ];
		var curr_index_e = e_indices.sort( (a,b) => ( a.neighbors.length > b.neighbors.length ? 1 : -1 ) )[ 0 ];

		s_indices = s_indices.map( x => x.idx );
		e_indices = e_indices.map( x => x.idx );

		edge_vertex_indices_s = [];
		edge_vertex_indices_e = [];

		while( !edge_vertex_indices_s.includes( curr_index_s.idx ) ){
			edge_vertex_indices_s.push(     curr_index_s.idx );
			var next_idx = curr_index_s.neighbors.find(function( x ){ return s_indices.includes( x ) && !edge_vertex_indices_s.includes( x ); });
			if( next_idx !== undefined ) curr_index_s = tmp_indices[ next_idx ];
		}
		while( !edge_vertex_indices_e.includes( curr_index_e.idx ) ){
			edge_vertex_indices_e.push(     curr_index_e.idx );
			var next_idx = curr_index_e.neighbors.find(function( x ){ return e_indices.includes( x ) && !edge_vertex_indices_e.includes( x ); });
			if( next_idx !== undefined ) curr_index_e = tmp_indices[ next_idx ];
		}
	}

	p.points = _this.derive_points_metadata_and_return_transformed_points( p );

	// var scl_x              = 1;
	// var scl_y              = 1;
	// var up                 = [ 0, 1, 0 ];
	// _this.points_metadata  = [];
	// var transformed_points = new Array( p.points.length );
	// for( var pt_idx = 0; pt_idx < p.points.length; pt_idx++ ){
        //         var prev_pt = p.points[ pt_idx - 1 ];
        //         var curr_pt = p.points[ pt_idx     ];
        //         var next_pt = p.points[ pt_idx + 1 ];

	// 	var look_at = JL.webgl.mat.get_look_at({
	// 		view_pos        : ( prev_pt ? [ prev_pt.x, prev_pt.y, prev_pt.z ] : [ curr_pt.x, curr_pt.y, curr_pt.z ] ),
	// 		target_pos      : ( next_pt ? [ next_pt.x, next_pt.y, next_pt.z ] : [ curr_pt.x, curr_pt.y, curr_pt.z ] ),
	// 		use_view_matrix : true,
	// 		up : [
	// 			Math.round( up[ 0 ] ),
	// 			Math.round( up[ 1 ] ),
	// 			Math.round( up[ 2 ] ),
	// 		],
	// 	});

	// 	up          = JL.webgl.functions.get_up_vector(      look_at );
	// 	var right   = JL.webgl.functions.get_right_vector(   look_at );
	// 	var forward = JL.webgl.functions.get_forward_vector( look_at );

	// 	if( curr_pt.args ){
	// 		if( curr_pt.args.scl_x !== undefined ) scl_x = curr_pt.args.scl_x;
	// 		if( curr_pt.args.scl_y !== undefined ) scl_y = curr_pt.args.scl_y;
	// 	}

	// 	var curr_dir = { up, right, forward, scl_x, scl_y, };

	// 	if( p.offset ){
	// 		curr_pt = JL.functions.deep_copy( curr_pt );

	// 		if( p.offset.right ){
	// 			curr_pt.x += scl_x * p.offset.right * right[ 0 ];
	// 			curr_pt.y += scl_x * p.offset.right * right[ 1 ];
	// 			curr_pt.z += scl_x * p.offset.right * right[ 2 ];
	// 		} 
	// 		curr_dir.scl_x = 1;
	// 		curr_dir.scl_y = 1;
	// 	}

	// 	transformed_points[ pt_idx ] = curr_pt;

	// 	_this.points_metadata.push( curr_dir );
	// }
	// p.points = transformed_points;

	var curr_z = 0;
	for( var pt_idx = 0; pt_idx < p.points.length; pt_idx++ ){
                var prev_pt = p.points[ pt_idx - 1 ];
                var curr_pt = p.points[ pt_idx     ];
                var next_pt = p.points[ pt_idx + 1 ];

		if( curr_pt.args ){
			if( curr_pt.args.graphics_object ){
				segment_g_o = JL.webgl.functions.get_graphics_object( curr_pt.args.graphics_object ).copy();
				segment_g_o.reload_attrs_from_buffers();
				if( curr_segment_size !== undefined ){
					for( var i = 0; i < segment_g_o.v.length; i++ ) segment_g_o.v[ i ] *= curr_segment_size;
				}

				if( curr_output_g_o ) curr_output_g_o.create_buffers();
				output.push( curr_output_g_o );
				curr_output_g_o = undefined;
			}
		}

                var curr_dir = _this.points_metadata[ pt_idx     ];
                var next_dir = _this.points_metadata[ pt_idx + 1 ];

		var smooth_shading = true;
		var flat_up, flat_right, flat_forward;
		if( next_dir ){
			var dir_angle = Math.max(
				JL.functions.get_angle_mag_between_3d_vectors( curr_dir.up, next_dir.up ),
				JL.functions.get_angle_mag_between_3d_vectors( curr_dir.forward, next_dir.forward ),
				JL.functions.get_angle_mag_between_3d_vectors( curr_dir.right, next_dir.right ),
			);
			smooth_shading = ( dir_angle < p.flat_shading_angle );
			if( !smooth_shading ){
				flat_up = [
					JL.functions.interpolate( curr_dir.up[ 0 ], next_dir.up[ 0 ], 0.5 ),
					JL.functions.interpolate( curr_dir.up[ 1 ], next_dir.up[ 1 ], 0.5 ),
					JL.functions.interpolate( curr_dir.up[ 2 ], next_dir.up[ 2 ], 0.5 ),
				];

				flat_right = [
					JL.functions.interpolate( curr_dir.right[ 0 ], next_dir.right[ 0 ], 0.5 ),
					JL.functions.interpolate( curr_dir.right[ 1 ], next_dir.right[ 1 ], 0.5 ),
					JL.functions.interpolate( curr_dir.right[ 2 ], next_dir.right[ 2 ], 0.5 ),
				];

				flat_forward = [
					JL.functions.interpolate( curr_dir.forward[ 0 ], next_dir.forward[ 0 ], 0.5 ),
					JL.functions.interpolate( curr_dir.forward[ 1 ], next_dir.forward[ 1 ], 0.5 ),
					JL.functions.interpolate( curr_dir.forward[ 2 ], next_dir.forward[ 2 ], 0.5 ),
				];
			}
		}

		var cap_s   = ( p.capped && ( pt_idx == 0                       ) ? { type : 'start', indices : [] } : false );
		var cap_e   = ( p.capped && ( pt_idx == ( p.points.length - 1 ) ) ? { type : 'end'  , indices : [] } : false );
		var has_cap = ( cap_s || cap_e );
		if( has_cap ){
			var segment_v = segment_g_o.v;

			if( cap_s ){
				var min_z = 1;
				for( var idx of edge_vertex_indices_s ){
					var curr_v_z = segment_v[ 3 * idx + 2 ];
					if( curr_v_z < min_z ) min_z = curr_v_z;
				}
				for( var idx of edge_vertex_indices_s ){
					var curr_v_z = segment_v[ 3 * idx + 2 ];
					if( curr_v_z <= min_z ) cap_s.indices.push( idx ); 
				}
			}
			if( cap_e ){
				var max_z = 0;
				for( var idx of edge_vertex_indices_e ){
					var curr_v_z = segment_v[ 3 * idx + 2 ];
					if( curr_v_z > max_z ) max_z = curr_v_z;
				}
				for( var idx of edge_vertex_indices_e ){
					var curr_v_z = segment_v[ 3 * idx + 2 ];
					if( curr_v_z >= max_z ) cap_e.indices.push( idx );
				}
			}
		}

		if( cap_s ){
			var _curr_pt = p.points[ 0 ];
			var _next_pt = p.points[ 1 ];

			cap_s.dir      = JL.functions.cartesian_to_spherical( _next_pt.x - _curr_pt.x, _next_pt.y - _curr_pt.y, _next_pt.z - _curr_pt.z );
			cap_s.dir.lat *= JL.functions.constants.to_radians;
			cap_s.dir.lon *= JL.functions.constants.to_radians;
		}
		if( cap_e ){
			if( p.points.length >= 2 ){
				var i = p.points.length - 2;
				var _curr_pt = p.points[ i     ];
				var _next_pt = p.points[ i + 1 ];

				cap_e.dir      = JL.functions.cartesian_to_spherical( _next_pt.x - _curr_pt.x, _next_pt.y - _curr_pt.y, _next_pt.z - _curr_pt.z );
				cap_e.dir.lat *= JL.functions.constants.to_radians;
				cap_e.dir.lon *= JL.functions.constants.to_radians;
			}
		}

		if( pt_idx < p.points.length - 1 ){
			var next_pt = p.points[ pt_idx + 1 ];
			var dist    = JL.functions.distance_xyz( curr_pt, next_pt );
			
			var start_z = curr_z;

			var section_length = dist;

			var mesh;

			while( dist > 0 ){
				mesh = segment_g_o.copy();

				mesh.apply_transforms([{ type : 'translate', z : curr_z }]);

				segment_count++;
				if( segment_count > p.max_segments ){
					console.log( 'JL.webgl.space_object._path: too many segments (hit maximum length of ' + p.max_segments + ' segments)' );
					return output;
				}

				for( var i = 0; i < mesh.v.length; i+=3 ){
					var curr_v_x = mesh.v[ i     ];
					var curr_v_y = mesh.v[ i + 1 ];
					var curr_v_z = mesh.v[ i + 2 ];

					var alpha = Math.min( ( ( curr_v_z - start_z ) / section_length ), 1 );

					mesh.v[ i     ] = JL.functions.interpolate( curr_pt.x, next_pt.x, alpha );
					mesh.v[ i + 1 ] = JL.functions.interpolate( curr_pt.y, next_pt.y, alpha );
					mesh.v[ i + 2 ] = JL.functions.interpolate( curr_pt.z, next_pt.z, alpha );

					curr_v_x *= JL.functions.interpolate( curr_dir.scl_x, next_dir.scl_x, alpha );
					curr_v_y *= JL.functions.interpolate( curr_dir.scl_y, next_dir.scl_y, alpha );

					var interpolated_up = [
						JL.functions.interpolate( curr_dir.up[ 0 ], next_dir.up[ 0 ], alpha ),
						JL.functions.interpolate( curr_dir.up[ 1 ], next_dir.up[ 1 ], alpha ),
						JL.functions.interpolate( curr_dir.up[ 2 ], next_dir.up[ 2 ], alpha ),
					];

					var interpolated_right = [
						JL.functions.interpolate( curr_dir.right[ 0 ], next_dir.right[ 0 ], alpha ),
						JL.functions.interpolate( curr_dir.right[ 1 ], next_dir.right[ 1 ], alpha ),
						JL.functions.interpolate( curr_dir.right[ 2 ], next_dir.right[ 2 ], alpha ),
					];

					var interpolated_forward = [
						JL.functions.interpolate( curr_dir.forward[ 0 ], next_dir.forward[ 0 ], alpha ),
						JL.functions.interpolate( curr_dir.forward[ 1 ], next_dir.forward[ 1 ], alpha ),
						JL.functions.interpolate( curr_dir.forward[ 2 ], next_dir.forward[ 2 ], alpha ),
					];

					var up_offset = JL.functions.scalar_multiply( curr_v_y, interpolated_up ); 

					mesh.v[ i     ] += up_offset[ 0 ];
					mesh.v[ i + 1 ] += up_offset[ 1 ];
					mesh.v[ i + 2 ] += up_offset[ 2 ];

					var right_offset = JL.functions.scalar_multiply( -curr_v_x, interpolated_right ); 

					mesh.v[ i     ] += right_offset[ 0 ];
					mesh.v[ i + 1 ] += right_offset[ 1 ];
					mesh.v[ i + 2 ] += right_offset[ 2 ];

					var curr_vn_x = mesh.vn[ i     ];
					var curr_vn_y = mesh.vn[ i + 1 ];
					var curr_vn_z = mesh.vn[ i + 2 ];

					if( smooth_shading ){
						mesh.vn[ i     ] = -interpolated_right[0] * curr_vn_x + interpolated_up[0] * curr_vn_y + interpolated_forward[0] * curr_vn_z;
						mesh.vn[ i + 1 ] = -interpolated_right[1] * curr_vn_x + interpolated_up[1] * curr_vn_y + interpolated_forward[1] * curr_vn_z;
						mesh.vn[ i + 2 ] = -interpolated_right[2] * curr_vn_x + interpolated_up[2] * curr_vn_y + interpolated_forward[2] * curr_vn_z;
					}
					else{
						mesh.vn[ i     ] = -flat_right[0] * curr_vn_x + flat_up[0] * curr_vn_y + flat_forward[0] * curr_vn_z;
						mesh.vn[ i + 1 ] = -flat_right[1] * curr_vn_x + flat_up[1] * curr_vn_y + flat_forward[1] * curr_vn_z;
						mesh.vn[ i + 2 ] = -flat_right[2] * curr_vn_x + flat_up[2] * curr_vn_y + flat_forward[2] * curr_vn_z;
					}
				}

				// TODO : test
				// 	-Eventually redesign so curr_output_g_o is an array of mesh segments at this point.
				// 	-When checking for intersections, only check against the segment(s) that would make sense to check.
				// if( curr_output_g_o ) console.log( 's_o path is_intersecting [' + this.name + ':' + pt_idx + '] - ', mesh.is_intersecting( curr_output_g_o ) );

				curr_output_g_o = JL.webgl.functions.append_graphics_object( curr_output_g_o, mesh );
			
				var segment_delta = ( p.segment_size || 1 );
				curr_z += Math.min( dist, segment_delta );

				dist -= segment_delta;
			}
		}

		if( has_cap ){
			var all_v  = curr_output_g_o.v.slice();
			var all_vt = [];
			if( has_vt ) all_vt = curr_output_g_o.vt.slice();
			for( var cap_cfg of [ cap_e, cap_s ].filter( x => x ) ){
				var cap = {};

				var has_vt = curr_output_g_o.shader.attr.includes( 'vt' );

				cap.v  = [];
				cap.vn = [];

				if( has_vt ) cap.vt = [];

				var vertex_indices_offset = 0;
				if( cap_cfg.type == 'end' ){
					vertex_indices_offset = ( all_v.length - segment_g_o.v.length ) / 3;
					if( pt_idx <= 1 ) vertex_indices_offset -= cap_s_vertex_indices_offset;
				}

				var min_z = 0;
				for( var idx of cap_cfg.indices ){
					idx += vertex_indices_offset;
					var i = 3 * idx;
					var curr_v_x = all_v[ i     ];
					var curr_v_y = all_v[ i + 1 ];
					var curr_v_z = all_v[ i + 2 ];

					cap.v.push( curr_v_x, curr_v_y, curr_v_z );

					cap.vn.push( 0, 0, ( cap_cfg.type == 'end' ? -1 : 1 ) * 1 );

					if( has_vt ){
						var i2 = 2 * idx; 
						var curr_vt_x = all_vt[ i2     ] || 0;
						var curr_vt_y = all_vt[ i2 + 1 ] || 0;
						cap.vt.push( curr_vt_x, curr_vt_y );
					}
				};

				cap.vertex_indices = JL.webgl.graphics_object.triangulate.get_vert_indices( cap.v, false, 3 );
				if( !cap.vertex_indices.length ){
					cap.vertex_indices = JL.webgl.graphics_object.triangulate.get_vert_indices( cap.v.slice().reverse(), false, 3 );
					if( !cap.vertex_indices.length ){
						var tmp_v = [];
						for( var i = 0; i < cap.v.length; i += 3 ) tmp_v.push( cap.v[ i ], cap.v[ i + 2 ] );
						cap.vertex_indices = JL.webgl.graphics_object.triangulate.get_vert_indices( tmp_v, false );
						if( cap_cfg.dir ){
							if( cap_cfg.dir.lat > 0 ) cap.vertex_indices.reverse();
						}
					}
					else{
						cap.vertex_indices.reverse();
					}
				}
				if( cap_cfg.dir ){
					if( cap_cfg.dir.lon > 0 ) cap.vertex_indices = cap.vertex_indices.reverse();
				}
				if( cap_cfg.type == 'start' ){
					cap.vertex_indices = cap.vertex_indices.reverse();
					cap_s_vertex_indices_offset = cap.v.length / 3;
					if( p.flip_cap_s ) cap.vertex_indices = cap.vertex_indices.reverse();
				}
				else if( cap_cfg.type == 'end' ){
					if( p.flip_cap_e ) cap.vertex_indices = cap.vertex_indices.reverse();
				}

				curr_output_g_o = JL.webgl.functions.append_graphics_object( curr_output_g_o, cap );
			}
		}
	}

	if( curr_output_g_o ) curr_output_g_o.create_buffers();

	output.push( curr_output_g_o );

	return output;
};

JL.webgl.space_object._particle_system = JL.functions.inherit_class( function(){}, JL.webgl.space_object._regular, { _inputs : [] } );

JL.webgl.space_object._particle_system.prototype._on_init = function( p ){
	var self = this;

	var preset = JL.webgl.graphics_object.presets.get_preset( this.g_o_preset );

	if( p.graphics_objects && p.graphics_objects.length ){
		for( var g_o of p.graphics_objects ){
			g_o = JL.webgl.functions.get_graphics_object( g_o );

			if( preset.randomized_instanced_vals ){
				g_o._config._paths_to_exclude_from_save = ( g_o._config._paths_to_exclude_from_save || [] ).concat(
					Object.keys( preset.randomized_instanced_vals ).map( k => ([ 'instanced_vals', k ]) )
				);
			}

			g_o.apply_preset( this.init_preset_config( preset, { params : g_o._config, }, ) );
		}
	}
	else{
		this.add_graphics_object(
			JL.webgl.functions.create_graphics_object(
				JL.webgl.graphics_object._main.prototype.apply_preset_to_config( this.init_preset_config( preset, ) )
			)
		);
	}

	// TODO : Consider moving sprite-sheet code into s_o.regular. It might be useful for non-particle g_o's.
	if( this.sprite_num_cols !== undefined && this.sprite_num_rows !== undefined ){ // animated sprite-sheet texture
		this.sprite_frame_width  = 1 / this.sprite_num_cols;
		this.sprite_frame_height = 1 / this.sprite_num_rows;

		this.sprite_steps = [];
		for        ( var y = 0; y < this.sprite_num_rows; y++ ){
			for( var x = 0; x < this.sprite_num_cols; x++ ){
				this.sprite_steps.push([
					  x * this.sprite_frame_width ,
					      this.sprite_frame_width ,
					  y * this.sprite_frame_height,
					      this.sprite_frame_height,
				]);
			}
		}

		if( this.sprite_trim_frames ) this.sprite_steps.splice( -this.sprite_trim_frames );

		var max_idx            = this.sprite_steps.length - 1;
		var is_async_particles = false;

		// ----------------------
		// TODO : test
		if( p.graphics_objects ){
			for( var g_o of p.graphics_objects ){
				// var g_o = JL.webgl.functions.get_graphics_object( g );

				// console.log( g_o );
				if( g_o.num_instances && g_o.uv_bounds ){
					is_async_particles = true;
					g_o._uv_bounds_indices = new Array( g_o.num_instances );
					for( var i = 0; i < g_o.num_instances; i++ ){
						g_o._uv_bounds_indices[ i ] = JL.functions.random_integer( 0, max_idx );
					}

					// Note: neither of the following objects are passing values to this.graphics_objects g_o's in this.add_per_frame_function.
					if( !g_o.attr ) g_o.attr = {};
					g_o.attr._uv_bounds_indices = g_o._uv_bounds_indices.slice();

					if( g_o._config ){
						if( !g_o._config.attr ) g_o._config.attr = {};
						g_o._config.attr._uv_bounds_indices = g_o._uv_bounds_indices.slice();
					}
				}
			}
		}
		// ----------------------

		if( this.graphics_objects ){
			for( var g_o of this.graphics_objects ){
				if( g_o.num_instances && g_o.uv_bounds ){
					is_async_particles = true;
					// g_o._uv_bounds_indices = new Array( g_o.num_instances );
					// for( var i = 0; i < g_o.num_instances; i++ ){
					// 	g_o._uv_bounds_indices[ i ] = JL.functions.random_integer( 0, max_idx );
					// }
					// if( this.name == 'Question Marks' ) console.log( 'set _uv_bounds_indices : ', g_o._uv_bounds_indices );
				}
			}
		}

		if( is_async_particles ){
			this.add_per_frame_function(function(){
				if( this.graphics_objects ){
					for( var g_o of this.graphics_objects ){
						if( !g_o._uv_bounds_indices ){
							g_o._uv_bounds_indices = new Array( g_o.num_instances );
							for( var i = 0; i < g_o.num_instances; i++ ){
								g_o._uv_bounds_indices[ i ] = JL.functions.random_integer( 0, max_idx );
							}
						}

						for( var i = 0; i < g_o.num_instances; i++ ){
							g_o._uv_bounds_indices[ i ]++;
							g_o._uv_bounds_indices[ i ] %= this.sprite_steps.length;
						}

						g_o.uv_bounds = g_o._uv_bounds_indices.map(function( i ){ return this.sprite_steps[ i ]; }, this).flat();
					}
				}
			});
		}
		else{
			this.sprite_curr_frame = 0;

			this.add_per_frame_function(function(){
				this.set_uniforms( 'frags_vec4', { uv_bounds : this.sprite_steps[ this.sprite_curr_frame ] } );
				
				this.sprite_curr_frame++;
				this.sprite_curr_frame %= this.sprite_steps.length;
			});
		}
	}
};

JL.webgl.space_object._particle_system.prototype.init_preset_config = function( preset, assign ){
	var preset_config = { name : this.g_o_preset, assign, };

	for( var v of preset.vars_defs ) JL.functions.set_nested_object( preset_config, [ 'assign' ].concat( v.path ), this[ v.key ] );

	return preset_config;
};

JL.webgl.space_object._particle_system.prototype.add_emitter_particle = function( p ){
	var p = p || {};

	if( this.graphics_objects ){
		var vals = p.vals || {};

		if( vals.emitter_time === undefined ) vals.emitter_time = ( ( new Date() ).getTime() - JL.webgl.constants.start_time ) / 1000;

		if( vals.emitter_pos === undefined ) vals.emitter_pos = [ this.x, this.y, this.z ];

		for( var g_o of this.graphics_objects ){
			var instanced_fields = JL.webgl.functions.get_instanced_fields( g_o.shader.properties.effects );
			if( instanced_fields.length ){
				for( var k of g_o.shader.instanced ){
					var attr_cfg = JL.webgl.shaders.config.attr[ k ];

					if( vals[ k ] !== undefined ) g_o[ k ] = [ vals[k] ].flat().concat( g_o[ k ] );
					else{
						for( var lbl of attr_cfg.labels ){
							if( lbl.default ) g_o[ k ].unshift( lbl.default );
							else              g_o[ k ].unshift( 0           );
						}
					}

					g_o[ k ] = g_o[ k ].slice( 0, g_o.num_instances * attr_cfg.item_size );
				}
			}
		}
	}
};

JL.webgl.space_object._particle_system.prototype.remove_emitter_particle = function( p ){
	for( var g_o of this.graphics_objects ){
		var instanced_fields = JL.webgl.functions.get_instanced_fields( g_o.shader.properties.effects );
		if( instanced_fields.length ){
			for( var k of g_o.shader.instanced ){
				var attr_cfg = JL.webgl.shaders.config.attr[ k ];

				for( var i = 0; i < attr_cfg.item_size; i++ ) g_o[ k ].pop();
			}
		}
	}
};

JL.webgl.ui.ar = {};

JL.webgl.ui.ar.init = function(){
	JL.functions.add_css(`
		.jl-webgl-ar-camera-container{
			position:fixed;
			width :50%;
			height:100%;
			display:none;
			overflow:hidden;
			top:0;
			pointer-events:none;
			z-index:-1;
		}

		.jl-webgl-ar-camera-container.full{
			width:100%;
		}

		.jl-webgl-ar-container-left{
			left : 0;
		}

		.jl-webgl-ar-container-right{
			left : 50%;
		}

		.jl-webgl-ar-camera-container.full.jl-webgl-ar-container-right{
			display:none !important;
		}

		.jl-webgl-ar-camera{
			width  : auto;
			height : auto;

			min-width  : 100%;
			min-height : 100%;

			top  : 50%;
			left : 0;

			position       : absolute;
			pointer-events : none;

			-webkit-transform : translate(-25%, -50%);
			   -moz-transform : translate(-25%, -50%);
			    -ms-transform : translate(-25%, -50%);
				transform : translate(-25%, -50%);
		}

		.jl-webgl-ar-camera-container.full .jl-webgl-ar-camera{
			-webkit-transform : translate(0%, -50%);
			   -moz-transform : translate(0%, -50%);
			    -ms-transform : translate(0%, -50%);
				transform : translate(0%, -50%);
		}
	`);

	$( JL.webgl.html_parent ).append(`
<div class="jl-webgl-ar-camera-container jl-webgl-ar-container-left" ><video id="jl-webgl-ar-left"  class="jl-webgl-ar-camera" muted="muted"></video></div>
<div class="jl-webgl-ar-camera-container jl-webgl-ar-container-right"><video id="jl-webgl-ar-right" class="jl-webgl-ar-camera" muted="muted"></video></div>
	`);

	this.background_html_elements = JL.webgl.html_parent + ', #' + JL.webgl.canvas_ids.primary + ', #' + JL.webgl.canvas_ids.secondary + ', html, body';

	delete this.init;
};

JL.webgl.ui.ar.format_one = function(){ $( JL.webgl.html_parent + " .jl-webgl-ar-camera-container" ).addClass(    'full' ); };
JL.webgl.ui.ar.format_two = function(){ $( JL.webgl.html_parent + " .jl-webgl-ar-camera-container" ).removeClass( 'full' ); };

JL.webgl.ui.ar.turn_on = function(){
	if( this.init ) this.init();

	this.on = true;

	( JL.webgl.device.is('vr') ? this.format_two() : this.format_one() );

	try{ JL.webgl.gl.clearColor(0,0,0,0); } catch(e){}

	$( this.background_html_elements ).css( 'background', 'transparent' );
	$( JL.webgl.html_parent + " .jl-webgl-ar-camera-container" ).show();

	JL.webgl.ui.webcam.load();

	// For compass direction : https://stackoverflow.com/questions/16048514/can-i-use-javascript-to-get-the-compass-heading-for-ios-and-android
};

JL.webgl.ui.ar.turn_off = function(){
	this.on = false;

	try{
		var color = JL.webgl.active_environment.clear_color || [0,0,0];

		JL.webgl.gl.clearColor( color[0], color[1], color[2], 1 );
	} catch(e){}

	$( this.background_html_elements ).css( 'background', '#000' );
	$( JL.webgl.html_parent + " .jl-webgl-ar-camera-container" ).hide();

	JL.webgl.ui.webcam.unload();
};

