JL.webgl.ui.intermediate_loading.canvas_fade_out = function( duration, callback ){
	// TODO : Try to come up with an approach that also works for VR headsets
	$( '#' + JL.webgl.canvas_ids.primary + ', #' + JL.webgl.canvas_ids.secondary ).css({ 'transition' : duration + 's filter' }).css({ 'filter' : 'brightness(0%)' });
	if( callback ) setTimeout( function(){ callback(); }, duration * 1000 );
};

JL.webgl.ui.intermediate_loading.canvas_fade_in = function( duration, callback ){
	$( '#' + JL.webgl.canvas_ids.primary + ', #' + JL.webgl.canvas_ids.secondary ).css({ 'transition' : duration + 's filter' }).css({ 'filter' : 'brightness(100%)' });
	if( callback ) setTimeout( function(){ callback(); }, duration * 1000 );
};

