JL.webgl.ui.key_bindings.get = function( names ){
	var keys = {};

	for( var name of names ){
		var binding = this.bindings[ name ];
		for( var key of binding ){
			keys[ key.name ] = Object.assign( keys[ key.name ] || {}, key );
		}
	}

	return Object.keys( keys ).map(function( k ){ return keys[ k ]; });
};

JL.webgl.ui.key_bindings.set = function( names ){
	var id = names.sort( (a,b) => ( a > b ? 1 : -1 ) ).join(',');

	if( id !== this.prev_bindings ){
		var bindings = this.get( names );

		JL.webgl.ui.controllers.set_bindings( bindings.filter( b => ( b.controllers ) ) );
		JL.webgl.ui.keyboard.set_bindings(    bindings );

		if( JL.webgl.ui.mouse ){
			JL.webgl.ui.mouse.ctrl_key  = JL.webgl.ui.keyboard.get( "CTRL"  );
			JL.webgl.ui.mouse.shift_key = JL.webgl.ui.keyboard.get( "SHIFT" );
		}

		this.prev_bindings = id;
	}
};

JL.webgl.ui.key_bindings.enable = function(){
	JL.webgl.ui[ 'controllers' ].enable();
	JL.webgl.ui[ 'keyboard'    ].enable();
};

JL.webgl.ui.key_bindings.disable = function(  disabled_exceptions ){
	JL.webgl.ui[ 'controllers' ].disable( disabled_exceptions );
	JL.webgl.ui[ 'keyboard'    ].disable( disabled_exceptions );
};

JL.webgl.ui.webcam = { video : {} };

JL.webgl.ui.webcam.params = {
	video : {
		facingMode : { ideal : "environment", acceptable : "user" },
		width      : 1280,
		height     : 720
	}
};

JL.webgl.ui.webcam.load = function(){
	var self = this;

	this.video.cam_left  = $( JL.webgl.html_parent + ' #jl-webgl-ar-left'  )[0];
	this.video.cam_right = $( JL.webgl.html_parent + ' #jl-webgl-ar-right' )[0];

	if( navigator.mediaDevices.getUserMedia === undefined ){ // Legacy API
		navigator.getMedia = ( navigator.getUserMedia || navigator.webkitGetUserMedia || navigator.mozGetUserMedia || navigator.msGetUserMedia );

		if( navigator.getMedia ){
			navigator.getMedia(
				this.params,
				function( stream ){ self.stream( stream ); },
				function( err ){ console.log( err ); }
			);
		}
	}
	else{ // Current API
		navigator.mediaDevices.getUserMedia( this.params ).then( function( stream ){ self.stream( stream ); });
	}
};

JL.webgl.ui.webcam.stream = function( stream ){
	Object.keys( this.video ).forEach(function( id ){
		this.video[ id ].srcObject = stream;
		this.video[ id ].play();
	}, this );
};

JL.webgl.ui.webcam.unload = function(){
	Object.keys( this.video ).forEach(function( id ){
		try{ this.video[ id ].stop(); } catch(e){}
	}, this);
};

JL.webgl.ui.item.edit = function( p ){
	this.init( p );
};

