JL.webgl.ui.item.edit.camera_position_fields = [
	[
		{ key : 'x', },
		{ key : 'y', },
		{ key : 'z', },
	],
	[
		{ key : 'lat', },
		{ key : 'lon', },
		{ key : 'rad', },
	],
];

JL.webgl.ui.item.edit.item_types = {};

JL.webgl.ui.item.edit.history = [];

JL.webgl.ui.item.edit.history_index = 0;

JL.webgl.ui.item.edit.history_add_snapshot = function(){
	this.history = this.history.slice( 0, this.history_index + 1 );
	this.history.push( this.get_save_output() );
	this.history_index = this.history.length - 1;
	this.history_update_arrow_buttons();
};

JL.webgl.ui.item.edit.history_load = function( idx ){
	var self = this;

	JL.webgl.ui.intermediate_loading.show();

	var history_index = ( idx !== undefined ? idx : this.history_index );

	this.item_types.space_object.remove_all_space_objects();

	var snapshot = JSON.parse( this.history[ history_index ] );
	JL.webgl.active_environment.init_from_environment_config( snapshot );
	this.history_update_arrow_buttons();
	JL.webgl.active_environment.set_environment_config( snapshot );

	this.item_types.graphics_object.update_all_graphics_objects({
		callback : function(){
			self.item_types.space_object.update_space_objects({ no_select : true });

			JL.webgl.ui.intermediate_loading.hide();
		},
	});

	if( this.curr_item_type ) this.item_types[ this.curr_item_type ].draw_overview();
};

JL.webgl.ui.item.edit.history_go_back = function(){
	if( this.history_can_go_back() ){
		this.history_index--;
		this.history_load();
	}
};

JL.webgl.ui.item.edit.history_go_forward = function(){
	if( this.history_can_go_forward() ){
		this.history_index++;
		this.history_load();
	}
};

JL.webgl.ui.item.edit.history_can_go_back = function(){
	if( this.history.length ){
		if( this.history_index > 0 ) return true;
	}
	return false;
};

JL.webgl.ui.item.edit.history_can_go_forward = function(){
	if( this.history.length ){
		if( this.history_index < this.history.length - 1 ) return true;
	}
	return false;
};

JL.webgl.ui.item.edit.history_update_arrow_buttons = function(){
	$( '#history-back-button'    )[ ( this.history_can_go_back()    ? 'remove' : 'add' ) + 'Class' ]( 'disabled' );
	$( '#history-forward-button' )[ ( this.history_can_go_forward() ? 'remove' : 'add' ) + 'Class' ]( 'disabled' );
};

JL.webgl.ui.item.edit.clean_up_graphics_objects = function(){
	var save_output = this.get_save_output();

	var found_graphics_objects = {};

	var traverse_item_config = function( cls, item ){
		JL.json_edit.prototype.traverse_values({
			structure : cls.prototype._inputs,
			value     : item,
			on_step   : function( step_value, step_structure, step_p ){
				if( step_structure.type == 'webgl.graphics_object' ){
					if( JL.functions.is_int( step_value ) ) found_graphics_objects[ step_value ] = true;
				}
			},
		});
	};

	var cfg = JL.webgl.active_environment._environment_config;
	Object.keys( cfg.space_objects ).forEach(function( class_name ){
		var cls = JL.webgl.functions.get_space_object_class( class_name );

		// 2025-09-25
		for( var item of cfg.space_objects[ class_name ] ) traverse_item_config( cls, item );
		// cfg.space_objects[ class_name ].forEach(function( item ){
		// 	JL.json_edit.prototype.traverse_values({
		// 		structure : cls.prototype._inputs,
		// 		value     : item,
		// 		on_step   : function( step_value, step_structure, step_p ){
		// 			if( step_structure.type == 'webgl.graphics_object' ){
		// 				if( JL.functions.is_int( step_value ) ) found_graphics_objects[ step_value ] = true;
		// 			}
		// 		},
		// 	});
		// });
	});

	for( var g_o of Object.values( cfg.graphics_objects ) ) traverse_item_config( JL.webgl.graphics_object[ g_o._type ], g_o );

	Object.keys( JL.webgl.active_environment._environment_config.graphics_objects ).forEach(function( g_o_id ){
		if( !found_graphics_objects[ g_o_id ] ) delete JL.webgl.active_environment._environment_config.graphics_objects[ g_o_id ];
	});

	this.draw_top_menu_bar();
};

JL.webgl.ui.item.edit.index_graphics_object = function( g_o ){
	if( g_o === undefined ) return;

	this.draw_top_menu_bar();

	return JL.webgl.functions.index_graphics_object( g_o );
};

JL.webgl.ui.item.edit.update_all_graphics_objects = function(){
	JL.webgl.ui.intermediate_loading.show();

	var cfgs = Object.values( JL.webgl.active_environment._environment_config.graphics_objects );

	var recursive_helper = function(){
		if( !cfgs.length ){
			JL.webgl.ui.intermediate_loading.hide();
			return;
		}

		var cfg = cfgs.shift();

		var prev_graphics_object = JL.functions.get_nested_object( JL.webgl.graphics_objects, ( cfg.label || cfg.keys ) );

		prev_graphics_object.remove();

		JL.webgl.functions.create_graphics_object( Object.assign( { callback : function( next_graphics_object ){
			JL.webgl.active_environment.get_all_space_objects().forEach(function( obj ){
				obj.search_and_replace_graphics_object( prev_graphics_object, next_graphics_object );
			});

			Object.keys( JL.webgl.ui.item.edit.item_types.space_object._space_objects ).forEach(function( item_type ){
				JL.webgl.ui.item.edit.item_types.space_object._space_objects[ item_type ].forEach(function( space_object, item_index ){
					if( space_object.has_graphics_object( next_graphics_object ) ){
						JL.webgl.ui.item.edit.item_types.space_object.update_space_object( item_type, item_index );
					}
				});
			});

			recursive_helper();
		} }, cfg ) );
	};

	recursive_helper();
};

JL.webgl.ui.item.edit.get_num_space_objects = function( type ){
	var groups;
	if( type ) groups = [];
	else       groups = Object.keys( JL.webgl.active_environment._environment_config.space_objects );

	var total = 0;
	groups.forEach(function( g ){ total += JL.webgl.active_environment._environment_config.space_objects[ g ].length; });
	
	return total;
};

JL.webgl.ui.item.edit.hide_surroundings = function( p ){
	if( !this.surroundings_are_hidden ){
		var p = p || {};

		var hide_condition = p.hide_condition || function(){ return true; };

		this.surroundings_are_hidden = true;
		this.surroundings_to_restore = [];
		for( var s_o of JL.webgl.active_environment.get_all_space_objects() ){
			if( s_o._added_to_draw ){
				if( hide_condition( s_o ) ){
					var obj = { space_object : s_o, draw_condition : s_o.draw_condition };

					s_o.draw_condition = function(){ return false; };
					
					this.surroundings_to_restore.push( obj );
				}
			}
		}
	}
};

JL.webgl.ui.item.edit.show_surroundings = function(){
	if( this.surroundings_are_hidden ){
		delete this.surroundings_are_hidden;
		for( var o of this.surroundings_to_restore ){
			if( !o.draw_condition ) delete o.space_object.draw_condition;
			else                    o.space_object.draw_condition = o.draw_condition;
		}
		delete this.surroundings_to_restore;
	}
};

JL.webgl.ui.item.edit.focus_on_point = function( p ){
	Object.assign( JL.webgl.active_camera, p );
	this.update_camera_position();
};

JL.webgl.ui.item.edit.reset_view = function(){
	try{ this.item_types[ this.curr_item_type ].reset_view(); } catch(e){}
};

JL.webgl.ui.item.edit.reset_camera = function(){
	JL.webgl.active_camera.reset_view();
	this.update_camera_position();
};

JL.webgl.ui.item.edit.set_camera_position = function(){
	JL.webgl.ui.item.edit.camera_position_fields.forEach(function( group ){
		group.forEach(function( field ){
			JL.webgl.active_camera[ field.key ] = Number( $( '#edit-camera-' + field.key ).val() );
		});
	});
};

JL.webgl.ui.item.edit.update_camera_position = function(){
	JL.webgl.ui.item.edit.camera_position_fields.forEach(function( group ){
		group.forEach(function( field ){
			$( '#edit-camera-' + field.key ).val( JL.webgl.active_camera[ field.key ] );
		});
	});
};

JL.webgl.ui.item.edit.get_save_output = function(){
	var self = this;

	var cfg = $.extend( true, {}, JL.webgl.active_environment._environment_config );

	cfg.graphics_objects = $.extend( true, {}, JL.webgl.active_environment._environment_config.graphics_objects );

	for( var m of Object.values( cfg.graphics_objects ) ){
		try{ delete m.params.async; } catch(e){}

		if( m._paths_to_exclude_from_save ){
			for( var path of m._paths_to_exclude_from_save ) JL.functions.remove_nested_object( m, path );
			delete m._paths_to_exclude_from_save;
		}

		JL.json_edit.prototype.traverse_values({
			structure : JL.webgl.graphics_object[ m._type || 'obj' ].prototype._inputs,
			value     : m,
			on_step   : function( step_value, step_structure, step_p ){
				if( step_structure.type == 'function' ){ // stringify functions
					if( step_value ){
						if( JL.functions.is_function( step_value ) ) step_p.set( step_value.toString() );
					}
				}
			},
		});
	}

	try{
		return JSON.stringify( cfg );
	}
	catch(e){
		console.log( 'Error: JL.webgl.ui.item.edit.get_save_output failed to stringify environment config.' );
		console.log( e );
		console.log( cfg );
	}
};

JL.webgl.ui.item.edit.save = function( p ){
	var p = p || {};

	var self = this;

	this.clean_up_graphics_objects();

	var output_str = this.get_save_output();
	var output_obj = JSON.parse( output_str );

	if( p.curr_space_object ){
		output_obj = output_obj.space_objects[ this.item_types.space_object.curr_space_object.type ][ this.item_types.space_object.curr_space_object.index ];
		if( this.item_types.space_object.curr_space_object.type !== '_regular' ) output_obj._type = this.item_types.space_object.curr_space_object.type;
		output_str = JL.functions.format_json( output_obj );
	}
	else if( p.curr_graphics_object ){
		output_obj = output_obj.graphics_objects[ JL.webgl.functions.get_graphics_object_id( this.item_types.graphics_object.curr_graphics_object ) ] || this.item_types.graphics_object.curr_graphics_object._config;
		output_str = JL.functions.format_json( output_obj );
	}
	else if( p.curr_environment ){
		output_obj = output_obj.environment;
		output_str = JL.functions.format_json( output_obj );
	}
	else if( p.curr_animation ){
		output_obj = this.item_types.animation.get_value({ stringify_functions : true, });
		for( var k of [ 'update' ] ) delete output_obj[ k ];
		output_str = JL.functions.format_json( output_obj );
	}
	else if( p.curr_action ){
		output_obj = this.item_types.action.get_value({ stringify_functions : true, });
		output_str = JL.functions.format_json( output_obj );
	}
	else{
		for( var k in output_obj.space_objects ){
			if( !output_obj.space_objects[ k ].length ) delete output_obj.space_objects[ k ];
		}
		for( var k in output_obj ){
			if( !Object.keys( output_obj[ k ] ).length ) delete output_obj[ k ];
		}
		output_str = JSON.stringify( output_obj );
	}

	console.log(                    output_obj );
	JL.functions.copy_to_clipboard( output_str );
};

JL.webgl.ui.item.edit.change_environment = function(){
	JL.webgl.functions.load_and_select_environment({
		keys : $( $( '#edit-set-environment input' )[ 0 ] ).val().split('/'),
	});
};

JL.webgl.ui.item.edit.toggle = function(){
	this.is_hidden = !this.is_hidden;

	$( '#edit-ui-toggle' ).html( ( this.is_hidden ? 'Show' : 'Hide' ) + ' Edit Interface' );

	$( '#edit-item' )[ ( this.is_hidden ? 'add' : 'remove' ) + 'Class' ]( 'collapsed' );
};

JL.webgl.ui.item.edit.toggle_fullscreen = function(){
	this.is_fullscreen = !this.is_fullscreen;

	$( '#edit-item' )[ ( this.is_fullscreen ? 'add' : 'remove' ) + 'Class' ]( 'fullscreen' );

	$( '#jl-webgl-curr-item-ui' ).css( 'z-index', ( this.is_fullscreen ? 9999999 : 1 ) );
};

JL.webgl.ui.item.edit.start_test = function(){
	JL.webgl.variables.is_editing = false;

	JL.webgl.active_environment.select();

	$( JL.webgl.html_parent ).append( '<div id="jl-webgl-stop-test" onclick="JL.webgl.ui.item.edit.stop_test();">Back to Edit</div>' );
};

JL.webgl.ui.item.edit.stop_test = function(){
	JL.webgl.variables.is_editing = true;

	$( '#jl-webgl-stop-test' ).remove();

	JL.webgl.active_environment.select();
};

