JL.webgl.ui.item.edit.overview_search = function( value ){ // Not actually used by main; used by space_object, graphics_object overviews
	this.search_filter = ( !value && value != 0 ? '' : String( value ).toLowerCase() );
	this.draw_overview();
	JL.webgl.ui.item.edit.focus_on_search_bar();
};

JL.webgl.ui.item.edit.preserve_scroll_position = function( update_fn ){
	var elements = [
		{ id : '#current-config-edit-fields .panel-contents', },
		{ id : '#space-objects-overview .panel-contents'    , },
	];

	for( var ele of elements ) ele.scroll_top = $( ele.id ).scrollTop();

	update_fn();

	for( var ele of elements ){
		if( ele.scroll_top !== undefined && ele.scroll_top !== null ) $( ele.id ).scrollTop( ele.scroll_top );
	}
};

JL.webgl.ui.item.edit.focus_on_search_bar = function(){
	$( $( '.ui-edit input.search' )[ 0 ] ).focus();
};

JL.webgl.ui.item.edit.draw_json_edit = function( p ){
	$( '#edit-item-view' ).html(
		'<div class="panel-header" id="edit-item-actions">' +
			'Edit ' + ( p.title || '' ) +
			( !p.back    ? '' : '<div class="button no-highlight              " onclick="' + p.back    + '"><i class="fa fa-arrow-left"></i></div>' ) +
			( !p.update  ? '' : '<div class="button no-highlight update-button" onclick="JL.webgl.ui.item.edit.preserve_scroll_position(function(){' + p.update + '});">Update</div>' ) +
			( !p.save    ? '' : '<div class="button no-highlight              " onclick="' + p.save    + '"><i class="fa fa-download"></i></div>' ) +
			( !p.presets ? '' : 
				'<select id="edit-item-presets">' + 
					p.presets.map(function( x ){
						return '<option>' + x.name + '</option>';
					}).join('') +
				'</select>' +
				'<div class="button no-highlight" onclick="' + p.apply_preset + '">Apply Preset</div>'
			) +
		'</div>' +
		'<div id="current-config-edit-fields" class="panel-contents"></div>'
	);

	p.self.json_edit = new JL.json_edit({
		parent        : { id : '#current-config-edit-fields' },
		structure     : p.structure,
		target_object : p.target_object,
		value         : p.value,
		on_change     : function(){
			$( '#edit-item .panel-header .update-button' ).addClass( 'blink' );
		},
	});
};

JL.webgl.ui.item.edit.on_select_overview = function(){
	for( var key in JL.webgl.ui.item.edit.item_types ){
		try{
			JL.webgl.ui.item.edit.item_types[ key ].on_stop_editing();
		} catch(e){}

		if( JL.webgl.ui.item.edit.item_types[ key ].search_filter === undefined ) JL.webgl.ui.item.edit.item_types[ key ].search_filter = '';
	}
};

