JL.webgl.ui.item.edit.item_types.graphics_object.add_graphics_object = function( p ){
	var p = p || {};

	var new_g_o = this.create_new_graphics_object();

	this.update_list();

	if( p.external ) this.draw();

	if( !p.no_ui ){
		var edit_params = {
			idx : this.graphics_objects.findIndex(function( m ){ return ( m.graphics_object === new_g_o ); })
		};

		if( p.edit_params ) edit_params = Object.assign( edit_params, p.edit_params );

		JL.webgl.ui.item.edit.item_types.graphics_object.edit_graphics_object( edit_params );
	}

	return new_g_o;
};

JL.webgl.ui.item.edit.item_types.graphics_object.create_new_graphics_object = function(){
	var name = 'new_graphics_object_';
	var idx  = 1;
	var key;
	while( JL.webgl.graphics_objects[ key = name + idx ] ) idx++;

	return JL.webgl.graphics_objects[ key ] = new JL.webgl.graphics_object.cube({
		label : [ key ],
		x : 0.1, y : 0.1, z : 0.1, 
	});
};

JL.webgl.ui.item.edit.item_types.graphics_object.clone = function( p ){
	var p = p || {};

	var original_g_o = this.curr_graphics_object;

	if     ( p.idx !== undefined ) original_g_o = JL.functions.get_nested_object( JL.webgl.graphics_objects, this.graphics_objects[ p.idx ].path );
	else if( p.graphics_object   ) original_g_o = p.graphics_object;

	var cloned_g_o = original_g_o.copy({ unique_label : true });

	this.draw_overview();

	return cloned_g_o;
};

JL.webgl.ui.item.edit.item_types.graphics_object.edit_graphics_object = function( p ){
	var p = p || {};

	[ 'curr_graphics_object', 'curr_graphics_object_environment_config_id' ].forEach(function( k ){
		delete this[ k ];
	}, this);

	if( !p.preserve_back_button ) this.back_button = p.back_button;

	if( p.idx !== undefined && p.idx >= 0 ){
		var idx = p.idx;

		var curr_graphics_object_cfg                    = this.graphics_objects[ idx ];
		this.original_curr_graphics_object              = JL.functions.get_nested_object( JL.webgl.graphics_objects, curr_graphics_object_cfg.path ).copy();
		this.curr_graphics_object                       = JL.functions.get_nested_object( JL.webgl.graphics_objects, curr_graphics_object_cfg.path ).copy();
		this.curr_graphics_object_environment_config_id = JL.webgl.functions.get_graphics_object_id( this.curr_graphics_object._config );

		try     { var effects = JL.webgl.functions.get_full_effects_list( this.curr_graphics_object.properties.effects ) || []; }
		catch(e){ var effects = []; }

		var s_o_params = {	
			graphics_objects : [ this.curr_graphics_object ],
			attr             : { is_edit_graphics_object_target : true },
		};
		if( effects.includes( '_animated' ) ) s_o_params.animated = 'freeze';

		JL.webgl.active_environment.add_space_object( s_o_params );

		this.on_start_editing();
	}

	this.draw();
};

JL.webgl.ui.item.edit.item_types.graphics_object.edit_graphics_object_by_path = function( path, p ){
	if( !this.graphics_objects ) this.update_list();

	var curr_path = path.join(' / ');

	this.edit_graphics_object( Object.assign({
		idx : this.graphics_objects.findIndex(function( m ){
			return ( ( m.path || m.label || m.keys ).join(' / ') == curr_path );
		})
	}, p || {} ) );
};

JL.webgl.ui.item.edit.item_types.graphics_object.on_start_editing = function(){
	this.is_editing = true;

	JL.webgl.ui.item.edit.hide_surroundings({
		hide_condition : function( s_o ){
			if( s_o.type == 'Background'           ) return false;
			if( s_o.is_edit_graphics_object_target ) return false;
			return true;
		},
	});
	JL.webgl.ui.item.edit.focus_on_point({ x : 0, y : 0, z : 0 });
};

JL.webgl.ui.item.edit.item_types.graphics_object.on_stop_editing = function(){
	delete this.is_editing;

	for( var s of JL.webgl.active_environment.get_all_space_objects() ){
		if( s.is_edit_graphics_object_target ) s.remove();
	}

	JL.webgl.ui.item.edit.show_surroundings();
};

JL.webgl.ui.item.edit.item_types.graphics_object.update_all_graphics_objects = function( p ){
	var p = p || {};

	var graphics_objects_keys = Object.keys( JL.webgl.active_environment._environment_config.graphics_objects );

	var recursive_helper = function(){
		if( !graphics_objects_keys.length ){
			if( p.callback ) p.callback();
			return;
		}

		var key = graphics_objects_keys.pop();

		var m = JL.webgl.active_environment._environment_config.graphics_objects[ key ];

		$.extend( true, {}, JL.functions.get_nested_object( JL.webgl.graphics_objects, ( m.label || m.keys ) ) ).reload({
			new_config : $.extend( true, {}, m ),
			callback   : function( next_graphics_object ){
				if( p.update_space_objects ){
					Object.keys( JL.webgl.ui.item.edit.item_types.space_object._space_objects ).forEach(function( item_type ){
						JL.webgl.ui.item.edit.item_types.space_object._space_objects[ item_type ].forEach(function( space_object, item_index ){
							if( space_object.has_graphics_object( next_graphics_object ) ){
								JL.webgl.ui.item.edit.item_types.space_object.update_space_object( item_type, item_index );
							}
						});
					});
				}

				recursive_helper();
			},
		});
	};

	recursive_helper();
};

JL.webgl.ui.item.edit.item_types.graphics_object.update_curr_graphics_object = function( p ){
	var self = this;

	var p = p || {};

	this.curr_graphics_object.reload({
		new_config     : $.extend( true, {}, this.json_edit.value ),
		error_callback : function(){
			alert( 'Neither label / keys were set.' );
			self.curr_graphics_object = $.extend( true, {}, self.original_curr_graphics_object );
			self.draw();
		},
		callback       : function( next_graphics_object ){
			self.curr_graphics_object = next_graphics_object;

			self.json_edit.traverse_values({
				value   : self.curr_graphics_object._config,
				on_step : function( step_value, step_structure, step_p ){
					if( step_structure.type == 'webgl.graphics_object' ){
						if( !JL.functions.is_int( step_value ) && step_value !== undefined ){
							var m_config  = ( step_value || { _config : step_value } );
							var g_o_idx = JL.webgl.ui.item.edit.index_graphics_object( m_config );
							step_p.set( g_o_idx );
						}
					}
				},
			});

			if( self.curr_graphics_object_environment_config_id !== undefined ){
				JL.webgl.active_environment._environment_config.graphics_objects[ self.curr_graphics_object_environment_config_id ] = $.extend( true, {}, self.curr_graphics_object._config );
			}

			var new_path;
			if     ( ( self.curr_graphics_object._config.label || [] ).length ) new_path = self.curr_graphics_object._config.label;
			else if( ( self.curr_graphics_object._config.keys  || [] ).length ) new_path = self.curr_graphics_object._config.keys;

			self.update_list();

			self.edit_graphics_object({
				idx : self.graphics_objects.findIndex(function( m ){ return JL.functions.arrays_equal( m.path, new_path ); }),
				preserve_back_button : true,
			});

			Object.keys( JL.webgl.ui.item.edit.item_types.space_object._space_objects ).forEach(function( item_type ){
				JL.webgl.ui.item.edit.item_types.space_object._space_objects[ item_type ].forEach(function( space_object, item_index ){
					if( space_object.has_graphics_object( next_graphics_object ) ){
						var prev_draw_condition = space_object.draw_condition;

						JL.webgl.ui.item.edit.item_types.space_object.update_space_object( item_type, item_index );

						if( JL.webgl.ui.item.edit.surroundings_to_restore ){
							var new_space_object = JL.webgl.ui.item.edit.item_types.space_object._space_objects[ item_type ][ item_index ];
							for( var o of JL.webgl.ui.item.edit.surroundings_to_restore ){
								if( o.space_object._id == space_object._id ){
									new_space_object.draw_condition = prev_draw_condition;
									o.space_object = new_space_object;
								}
							}
						}
					}
				});
			});

			JL.webgl.ui.item.edit.focus_on_point({ x : 0, y : 0, z : 0 });

			if( p.callback ) p.callback();
		},
	});
};

JL.webgl.ui.item.edit.item_types.graphics_object.update_list = function(){
	this.graphics_objects = JL.webgl.functions.list_graphics_objects().sort( (a,b) => ( a.path.join('/') > b.path.join('/') ? 1 : -1 ) );
};

JL.webgl.ui.item.edit.item_types.graphics_object.update = function(){
	this.update_curr_graphics_object({ callback : function(){ JL.webgl.ui.item.edit.history_add_snapshot(); } });
};

JL.webgl.ui.item.edit.item_types.graphics_object.search = JL.webgl.ui.item.edit.overview_search;

JL.webgl.ui.item.edit.item_types.graphics_object.apply_preset = function(){
	JL.webgl.graphics_object._main.prototype.apply_preset_to_config({
		name   : $( '#edit-item-presets' ).val(),
		config : this.json_edit.value,
	});

	this.update();
};

JL.webgl.ui.item.edit.item_types.graphics_object.draw_overview = function(){
	var self = this;

	if( this.right_click_menus ) this.right_click_menus.forEach(function( m ){ m.destroy(); });
	this.right_click_menus = [];

	JL.webgl.ui.item.edit.on_select_overview();

	JL.webgl.ui.item.edit.curr_item_type = 'graphics_object';

	$( '#edit-item-view' ).html(`
		<div id="graphics-object-overview">
			<div class="panel-title">
				All Graphics Objects
				<div class="button no-highlight" onclick="JL.webgl.ui.item.edit.item_types.graphics_object.add_graphics_object();">+ Graphics Object</div>
				<input id="graphics-object-search" class="search" placeholder="Search..." onkeyup="if( event.keyCode == 13 ){ JL.webgl.ui.item.edit.item_types.graphics_object.search( this.value ); }"></input>
				<hr>
			</div>
			<div id="all-graphics-objects"></div>
		</div>
		<div id="graphics-objects-in-environment"></div>
	`);

	this.update_list();

	var graphics_objects = this.graphics_objects.slice();
	for( var i = 0; i < graphics_objects.length; i++ ){
		graphics_objects[ i ]._index = i;
	}
	if( this.search_filter !== '' ){
		graphics_objects = graphics_objects.map(function( g ){
			for( var x of g.path ){
				var x_lower = x.toLowerCase();
				if( x_lower.includes( self.search_filter ) ) return g;
				if( self.search_filter.includes( x_lower ) ) return g;
			}
		});
	}

	graphics_objects = graphics_objects.sort(function( a, b ){
		if( a.graphics_object._id[ 0 ] == '_' && b.graphics_object._id[ 0 ] != '_' ) return  1;
		if( a.graphics_object._id[ 0 ] != '_' && b.graphics_object._id[ 0 ] == '_' ) return -1;
		return ( a.graphics_object._id > b.graphics_object._id ? 1 : -1 );
	});

	$( '#edit-item-view #all-graphics-objects' ).html(
		'<table>' +
			graphics_objects.map(function( m ){
				if( !m ) return '';

				var id = 'all-g_o-' + m._index;

				self.right_click_menus.push({
					target  : '#' + id,
					// 2025-10-02
					options : [{ label : 'Clone', onclick : function(){ self.clone({ graphics_object : m.graphics_object }); } }],
					// options : [{ label : 'Clone', onclick : function(){ self.clone({ idx : i }); } }],
				});

				if( m.path[ 0 ] == '_in_library' ) return '';
				return '<tr>' +
					'<td id="' + id + '" class="edit-item" onclick="JL.webgl.ui.item.edit.item_types.graphics_object.edit_graphics_object({ idx : ' + m._index + ' });">' + m.path.join(' / ') + '</td>' +
				'</tr>';
			}).join('') +
		'</table>'
	);

	$( '#edit-item-view #graphics-objects-in-environment' ).html(
		'<table>' +
			'<tr>' + 
				[ 'Key', 'Graphics Objects in Use', ].map( x => '<th>' + x + '</th>' ).join('') +
			'</tr>' +
			Object.keys( JL.webgl.active_environment._environment_config.graphics_objects ).sort( (a,b) => ( Number( a ) > Number( b ) ? 1 : -1 ) ).map(function( key ){
				var m = JL.webgl.active_environment._environment_config.graphics_objects[ key ];

				var path = ( m.label || m.keys );
				if( !path ){
					if( m.params ) path = ( m.params.label || m.params.keys );
					if( !path ) return '';
				}
				path = path.join('/');

				var g_o_idx = self.graphics_objects.findIndex(function( x ){ return ( x.path || [] ).join('/') == path; });

				var onclick = 'onclick="JL.webgl.ui.item.edit.item_types.graphics_object.edit_graphics_object({ idx : ' + g_o_idx + ' });"';
				
				return '<tr>' +
					'<td ' + onclick + ' class="edit-item graphics-object-key">' + key + '</td>' +
					'<td ' + onclick + ' class="edit-item graphics-object-name" style="text-align:left;">' + ( m.label || m.keys || m.params.label || m.params.keys ).join(' / ') + '</td>' +
				'</tr>';
			}).join('') +
		'</table>'
	);

	$( '#graphics-object-search' ).val( this.search_filter );

	this.right_click_menus.forEach(function( c, i ){
		this.right_click_menus[ i ] = new JL.right_click_menu( c );
	}, this);
};

JL.webgl.ui.item.edit.item_types.graphics_object.draw = function(){
	var self = this;

	JL.webgl.ui.item.edit.curr_item_type = 'graphics_object';

	if( this.curr_graphics_object ){
		var scroll_top = $( '#current-config-edit-fields' ).scrollTop() || 0;

		try     { var back_button = this.back_button; }
		catch(e){ var back_button; }

		if( this.curr_graphics_object._config.texture ){
			this.curr_graphics_object._config.textures = JL.webgl.functions.add_or_replace_to_textures_config( this.curr_graphics_object._config.textures, { filename : this.curr_graphics_object._config.texture } );
			delete this.curr_graphics_object._config.texture;
		}

		JL.webgl.ui.item.edit.draw_json_edit({
			self          : this,
			title         : 'Graphics Object',
			update        : 'JL.webgl.ui.item.edit.item_types.graphics_object.update();',
			save          : 'JL.webgl.ui.item.edit.save({ curr_graphics_object : true });',
			presets       : JL.webgl.graphics_object.presets.get_all_options(),
			apply_preset  : 'JL.webgl.ui.item.edit.item_types.graphics_object.apply_preset();',
			back          : ( back_button ? 'JL.webgl.ui.item.edit.item_types.graphics_object.on_stop_editing();' + back_button.onclick : undefined ),
			structure     : JL.webgl.graphics_object[ this.curr_graphics_object._config._type || this.curr_graphics_object._config.type || 'obj' ].prototype._inputs,
			target_object : this.curr_graphics_object,
			value         : $.extend( true, {}, this.curr_graphics_object._config ),
		});

		if( scroll_top ) $( '#current-config-edit-fields' ).scrollTop( scroll_top );
	}
};

JL.webgl.ui.item.edit.item_types.animation = {};

JL.webgl.ui.item.edit.item_types.animation.edit = function( name ){
	this.remove_space_objects();

	this.selected_animation_index = JL.webgl.animations.findIndex( a => a.name == name );

	var selected_animation = JL.webgl.animations[ this.selected_animation_index ];

	this.curr_graphics_object = JL.webgl.graphics_objects._in_library.edit.animation[ selected_animation.graphics_object || '2_leg' ];

	this.curr_space_object = JL.webgl.active_environment.add_space_object({ animated : name, graphics_objects : [ this.curr_graphics_object ], attr : { for_edit_animation : true } });

	this.curr_animation = this.curr_space_object.animations[ 0 ];

	JL.webgl.active_environment.add_space_object({ graphics_objects : [ JL.webgl.graphics_objects._default_item ], scale : [2,0,2], attr : { for_edit_animation : true } });

	this.on_start_editing();

	this.draw();
};

JL.webgl.ui.item.edit.item_types.animation.get_new_animation_name = function( base ){
	var base = base || 'new_animation_';
	var idx  = 1;
	var name;
	while( !name || JL.webgl.animations.find( a => a.name == name ) ){
		name = base + idx;
		idx++;
	}

	return name;
};

JL.webgl.ui.item.edit.item_types.animation.create_new = function(){
	var name = this.get_new_animation_name();

	var animation = { name };

	JL.webgl.animations.push( animation );

	this.edit( name );
};

JL.webgl.ui.item.edit.item_types.animation.clone = function( p ){
	if( p.animation ){
		JL.webgl.animations.push(
			Object.assign(
				JL.functions.deep_copy( p.animation ),
				{ name : this.get_new_animation_name( p.animation.name + '.copy_' ), }
			)
		);
	}

	this.draw_overview();
};

JL.webgl.ui.item.edit.item_types.animation.get_value = function( p ){
	var p = p || {};

	var output = $.extend( true, {}, p.obj || this.curr_animation._config );

	for( var s of JL.webgl.animation.prototype._inputs ){
		if( p.stringify_functions ){
			if( s.type == 'function' ){
				if( output[ s.key ] ){
					output[ s.key ] = output[ s.key ].toString();
					continue;
				}
			}
		}
		if( s.hidden ) delete output[ s.key ];
	}

	return output;
};

JL.webgl.ui.item.edit.item_types.animation.update_and_redraw = function(){
	var new_animation = this.get_value({ obj : this.current_config });

	JL.webgl.animations[ this.selected_animation_index ] = new_animation;

	this.edit( new_animation.name );
};

JL.webgl.ui.item.edit.item_types.animation.reset_view = function(){
	JL.webgl.ui.item.edit.focus_on_point({ x : 0, y : 0.25, z : 0, lat : 25, lon : 0, rad : 2 });
};

JL.webgl.ui.item.edit.item_types.animation.on_start_editing = function(){
	JL.webgl.ui.item.edit.hide_surroundings({
		hide_condition : function( s_o ){
			if( s_o.type == 'Background' ) return false;
			if( s_o.for_edit_animation   ) return false;
			return true;
		},
	});

	this.reset_view();
};

JL.webgl.ui.item.edit.item_types.animation.remove_space_objects = function(){
	for( var s of JL.webgl.active_environment.get_all_space_objects() ){
		if( s.for_edit_animation ) s.remove();
	}
};

JL.webgl.ui.item.edit.item_types.animation.on_stop_editing = function(){
	this.remove_space_objects();

	JL.webgl.ui.item.edit.show_surroundings();
};

JL.webgl.ui.item.edit.item_types.animation.draw_overview = function(){
	var self = this;

	if( this.right_click_menus ) this.right_click_menus.forEach(function( m ){ m.destroy(); });
	this.right_click_menus = [];

	JL.webgl.ui.item.edit.on_select_overview();

	JL.webgl.ui.item.edit.curr_item_type = 'animation';

	$( '#edit-item-view' ).html(
		'<div class="panel-header">' +
			'<div class="button no-highlight" onclick="JL.webgl.ui.item.edit.item_types.animation.create_new();">Create New Animation +</div>' +
		'</div>' +
		'<div class="panel-contents">' +
			'<table>' +
				JL.webgl.animations.sort( (a,b) => ( a.name > b.name ? 1 : -1 ) ).map(function( animation, animation_index ){
					var edit_onclick = 'onclick="JL.webgl.ui.item.edit.item_types.animation.edit(\'' + animation.name + '\');"';

					var id = 'all-animations-' + animation_index;

					self.right_click_menus.push({
						target  : '#' + id,
						options : [{ label : 'Clone', onclick : function(){ self.clone({ animation, }); } }],
					});

					return '<tr>' +
						'<td id="' + id + '" class="edit-item full" ' + edit_onclick + ' >' + 
							animation.name + 
						'</td>' +
					'</tr>';
				}).join('') +
			'</table>' +
		'</div>'
	);

	this.right_click_menus.forEach(function( c, i ){
		this.right_click_menus[ i ] = new JL.right_click_menu( c );
	}, this);
};

JL.webgl.ui.item.edit.item_types.animation.draw = function( self, p ){
	this.self = self;

	var p = p || {};

	JL.webgl.ui.item.edit.curr_item_type = 'animation';

	var curr_animation = this.curr_animation;

	this.current_config = $.extend( true, {}, this.curr_space_object.animations[ 0 ]._config );

	JL.webgl.ui.item.edit.draw_json_edit({
		self      : this,
		title     : JL.functions.title_case( this.item_type ),
		update    : 'JL.webgl.ui.item.edit.item_types.animation.update_and_redraw();',
		save      : 'JL.webgl.ui.item.edit.save({ curr_animation : true });',
		structure : JL.webgl.animation.prototype._inputs,
		value     : this.current_config,
	});
};

JL.webgl.ui.item.edit.item_types.action = {};

JL.webgl.ui.item.edit.item_types.action.edit = function( p ){
	var p = p || {};

	if( p.name !== undefined ){
		this.selected_action_index = JL.webgl.active_environment._environment_config.actions.findIndex( a => a.name == p.name );
	}

	this.current_config = JL.webgl.active_environment._environment_config.actions[ this.selected_action_index ];

	this.draw();
};

JL.webgl.ui.item.edit.item_types.action.create_new = function(){
	var base = 'new_action_';
	var idx  = 1;
	var name;
	while( !name || JL.webgl.active_environment._environment_config.actions.find( a => a.name == name ) ){
		name = base + idx;
		idx++;
	}

	JL.webgl.active_environment._environment_config.actions.push({ name });

	this.edit({ name });
};

JL.webgl.ui.item.edit.item_types.action.get_value = function( p ){
	var p = p || {};

	var output = $.extend( true, {}, p.obj || this.current_config );

	for( var s of JL.action.prototype._inputs ){
		if( p.stringify_functions ){
			if( s.type == 'function' ){
				if( output[ s.key ] ){
					output[ s.key ] = output[ s.key ].toString();
					continue;
				}
			}
		}
		if( s.hidden ) delete output[ s.key ];
	}

	return output;
};

JL.webgl.ui.item.edit.item_types.action.update = function(){
	JL.webgl.active_environment._environment_config.actions[ this.selected_action_index ] = this.get_value({ stringify_functions : true });

	this.edit();

	JL.webgl.active_environment.init_actions_from_environment_config();

	JL.webgl.ui.item.edit.draw_top_menu_bar();
};

JL.webgl.ui.item.edit.item_types.action.draw_overview = function(){
	var self = this;

	JL.webgl.ui.item.edit.on_select_overview();

	JL.webgl.ui.item.edit.curr_item_type = 'action';

	$( '#edit-item-view' ).html(
		'<div class="panel-header">' +
			'<div class="button no-highlight" onclick="JL.webgl.ui.item.edit.item_types.action.create_new();">Create New Action +</div>' +
		'</div>' +
		'<div class="panel-contents">' +
			'<table>' +
				JL.webgl.active_environment._environment_config.actions.sort( (a,b) => ( a.name > b.name ? 1 : -1 ) ).map(function( action ){
					var edit_onclick = 'onclick="JL.webgl.ui.item.edit.item_types.action.edit({ name : \'' + action.name + '\' });"';

					return '<tr>' +
						'<td class="edit-item full" ' + edit_onclick + ' >' + 
							action.name + 
						'</td>' +
					'</tr>';
				}).join('') +
			'</table>' +
		'</div>'
	);
};

JL.webgl.ui.item.edit.item_types.action.draw = function( self, p ){
	this.self = self;

	var p = p || {};

	JL.webgl.ui.item.edit.curr_item_type = 'action';

	JL.webgl.ui.item.edit.draw_json_edit({
		self      : this,
		title     : JL.functions.title_case( this.item_type ),
		update    : 'JL.webgl.ui.item.edit.item_types.action.update();',
		save      : 'JL.webgl.ui.item.edit.save({ curr_action : true });',
		structure : JL.action.prototype._inputs,
		value     : this.current_config,
	});
};

