JL.webgl.ui.item.mobile_arrow_keys.ui_framework = function(){
	var ui_info = this.ui_info || {};

	var keys = [ 'W', 'A', 'S', 'D' ].map(function( x ){ return 'JL.webgl.ui.keyboard.get(\'' + x + '\')'; });

	var tc = function( x ){ return 'try{' + x + '} catch(e){}'; };

	var press   = '.pressed =  true;';
	var release = '.pressed = false;';

	return '<div class="jl-webgl-mobile-arrow-keys">' +
		[ 'up', 'left', 'down', 'right' ].map(function( dir, i ){
			return '<div class="arrow-' + dir + '" ' + 
				'ontouchstart ="event.preventDefault();' + tc( keys[i] + press   ) + tc( keys[i] + '.down();' ) + '" ' + 
				'ontouchend   ="event.preventDefault();' + tc( keys[i] + release ) + tc( keys[i] + '.up();  ' ) + '" ' + 
				' >' + 
				'<i class="fa fa-caret-' + dir + '"/>' + 
			'</div>';
		}).join('') +
	'</div>';
};

